UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "الحمد لله رب العالمين، والعاقبة للمتقين، ولا عدوان إلا على الظالمين، اللهم صل وسلم وبارك على عبدك ونبيك محمد وعلى آله وصحبه أجمعين، أما بعد..", "page": 5, "id": "unit-01__lesson-00__b01"}, {"type": "paragraph", "md": "ما منهاج «على بصيرة» وما آلية تدريسه؟", "page": 5, "id": "unit-01__lesson-00__b02", "inline": [{"t": "text", "s": "ما منهاج "}, {"t": "quote", "s": "على بصيرة"}, {"t": "text", "s": " وما آلية تدريسه؟"}]}, {"type": "paragraph", "md": "يأتي هذا المنهاج المخصص للشباب المسلم؛ لينقل الأخ الشاب من دائرة الفراغ إلى العمل، ومن الكسل إلى الجد، وذلك بدراسة أهم الأمور الشرعية التي يحتاجها في دينه ودنياه وهي (القرآن والتفسير، العقيدة، الحديث، الفقه، الأخلاق والآداب)، وتأتي هذه المواد في قالبٍ علمي وعملي مدعم بالتقويمات والأنشطة العلمية والعملية المفيدة والنافعة للطلاب من الرجال والنساء الدارسين لهذا الكتاب.", "page": 5, "id": "unit-01__lesson-00__b03", "inline": [{"t": "text", "s": "يأتي هذا المنهاج المخصص للشباب المسلم؛ لينقل الأخ الشاب من دائرة الفراغ إلى العمل، ومن الكسل إلى الجد، وذلك بدراسة أهم الأمور الشرعية التي يحتاجها في دينه ودنياه وهي "}, {"t": "emphasis", "s": "(القرآن والتفسير، العقيدة، الحديث، الفقه، الأخلاق والآداب)", "role": "emphasis"}, {"t": "text", "s": "، وتأتي هذه المواد في قالبٍ علمي وعملي مدعم بالتقويمات والأنشطة العلمية والعملية المفيدة والنافعة للطلاب من الرجال والنساء الدارسين لهذا الكتاب."}]}, {"type": "paragraph", "md": "ويقع هذا المنهاج في مرحلته الأولى ضمن أربع وعشرين مجلسًا -مقسمة على ستة أشهر أو سنة كاملة، في كل أسبوع مجلس، وبالحد الأعلى في كل أسبوعين مجلس واحد فقط-، وباعتبار أنَّ كل مجلس يتضمن خمسة دروس؛ فقد بلغت الدروس التي تضمنها هذا المنهاج: (120) درسًا، وعلى هذا فيُفترض أن هذا المنهاج يُدرس في مدة لا تقل عن ستة أشهر، ولا تزيد عن سنة.", "page": 5, "id": "unit-01__lesson-00__b04"}, {"type": "paragraph", "md": "تخريج الأحاديث والآثار: اشترطنا في هذا الكتاب النافع -بحول الله- ألا نضع فيه إلا حديثًا صحيحًا أو مقبولًا، ويكون الحديث (بين قوسين مغمقين)، والأثر بين «قوسين» صغيرين، ولم نُخَرِّج الأحاديث، اكتفاءً بهذا الشرط، وذلك لسهولة الوصول للتخريج اليوم عبر الوسائل البحثية الحديثة، ولأنَّ الكتاب ليس للمتخصصين؛ فليهنأ قارئه بصحة كل ما فيه من أحدايث وآثار بفضل الله.", "page": 5, "id": "unit-01__lesson-00__b05", "inline": [{"t": "emphasis", "s": "تخريج الأحاديث والآثار", "role": "emphasis"}, {"t": "text", "s": ": اشترطنا في هذا الكتاب النافع -بحول الله- ألا نضع فيه إلا حديثًا صحيحًا أو مقبولًا، ويكون الحديث "}, {"t": "emphasis", "s": "(بين قوسين مغمقين)", "role": "emphasis"}, {"t": "text", "s": "، والأثر بين "}, {"t": "quote", "s": "قوسين"}, {"t": "text", "s": " صغيرين، ولم نُخَرِّج الأحاديث، اكتفاءً بهذا الشرط، وذلك لسهولة الوصول للتخريج اليوم عبر الوسائل البحثية الحديثة، ولأنَّ الكتاب ليس للمتخصصين؛ فليهنأ قارئه بصحة كل ما فيه من أحدايث وآثار بفضل الله."}]}, {"type": "paragraph", "md": "ونوصي الإخوة المدرسين لهذا الكتاب بالوصايا الآتية لتحقيق أفضل الثمار المرجوة منه:", "page": 5, "id": "unit-01__lesson-00__b06"}, {"type": "paragraph", "md": "1- ضرورة التحضير الجيد للمادة: فمن لم يمتلِئ بالمادة المُلقاة على الطلاب فلن يحسن إفادتهم، ومن الغش للطلاب عدم إعطاء المادة حقها في التجهيز والتهيئة، مع مراعاة استعمال الوسائل النافعة في التعليم إن وُجدت؛ مثل السبورة والشاشة والحوار والقصة الهادفة وضرب المثال.", "page": 5, "id": "unit-01__lesson-00__b07", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- التلاوة: يبدأ كل درسٍ مقرر بتلاوة آيات من القرآن الكريم؛ بأن يقرأ بعض الطلبة آيات قرآنية في مطلع المجلس، ولا بأس بشيء من تفسيرها؛ بما لا يزيد عن ربع الوقت المخصص للمجلس كله، حتى لو كان الدرس حديثًا أو عقيدة؛ فلا بد من افتتاحه بتلاوة شيء من القرآن ربطًا للطالب بالقرآن.", "page": 6, "id": "unit-01__lesson-00__b08", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- التجويد: لم يُضف للكتاب علم التجويد، وهو مهم جدا، وعلى المعلم أن يُدَرسه للطلاب في حلقته مِن كتاب: «مورد الظمآن في تجويد القرآن»، حيثُ يُعطي فصلا يسيرًا في اليوم المخصص لتدريس مادة القرآن والتفسير؛ فيخصص ربع وقت ذلك الدرس لمادة التجويد، حتى ينهيَها كلها.", "page": 6, "id": "unit-01__lesson-00__b09", "inline": [{"t": "text", "s": "3- التجويد: لم يُضف للكتاب علم التجويد، وهو مهم جدا، وعلى المعلم أن يُدَرسه للطلاب في حلقته مِن كتاب: "}, {"t": "quote", "s": "مورد الظمآن في تجويد القرآن"}, {"t": "text", "s": "، حيثُ يُعطي فصلا يسيرًا في اليوم المخصص لتدريس مادة القرآن والتفسير؛ فيخصص ربع وقت ذلك الدرس لمادة التجويد، حتى ينهيَها كلها."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- الأنشطة: تخلَّل كل درس عددٌ من الأنشطة العلمية والعملية والتطبيقية، وهي الثمرة العملية لكل درس؛ فينبغي للمعلم أن يحرص على تطبيقها بالكامل وعدم إهمالها، والزيادة عليها بما يفتح الله عليه، وأن يعرفَ الأجوبة عن هذه الأنشطة سلفًا قبل إلقائها على الطلبة، وأن يحرص على تثوير أفكار المتلقين فيها من خلال أسليب التعلم النشط؛ القائم على إشراك المتعلم في العملية التعليمية، وليس على مجرد تلقينه المعلومة لهم، فالتلقين لوحده لا يفي بالغرض ولا يحقق المقصود.", "page": 6, "id": "unit-01__lesson-00__b10", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- الجانب التربوي والبرامج المصاحبة: يُركز مشروع الكتاب على تحقيق معالم تربوية غاية في الأهمية، هذه المعالم تزيد أهمية عن الجانب العلمي المجرد.. فيجب على المعلم أن يحرصَ على تفعيل الجانب التربوي المرتكز على ربط الشباب بالمسجد، وتفعيل باب الزيارات، وصلة الرحم العلمية، وعيادة المريض من شباب الحلقة أو أهل الحي، والتواصي بالأيتام وأبناء الشهداء.. حيثُ نسعى للوصول إلى صورة المجتمع المسلم الذي يُحبه الله ويَرضى عنه؛ بما فيه من تآلف وتحابٍّ في الله؛ فهذه الدروس تربط الشباب المسلم ببعضهم، وتجعل منهم إخوة ورفقاء في الخير.", "page": 6, "id": "unit-01__lesson-00__b11", "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "فإذا كان حظُّ المتلقي (6) ساعات أسبوعيًّا في المجالس العلمية المتقررة في هذا الكتاب؛ فينبغي أن يكون حظُّ الطالب في الأنشطة المصاحبة خارج الحلقة العلمية -والمقررة في دليل العمل المسجدي الموجود مرفقًا مع الكتاب- بما قدره ثلثي هذا الوقت؛ أي ما قدره حوالي (4) ساعات على الأقل، وبهذا يتحقق المقصودُ من المنهاج الدراسي هنا؛ فلا تكفي الحلقات العلمية.", "page": 6, "id": "unit-01__lesson-00__b12"}, {"type": "paragraph", "md": "6- المساجد أم البيوت: تُعتبر المساجد هي الركيزة الأساسية في العمل لتحقيق البناء الإيماني فيها، وجذب الشباب المسلم إلى الحلق التربوية من خلالها؛ فيُلزِمُ المعلِّمُ الشَّبابَ بصلوات الجماعة كاملة في المساجد، وأما الدروس فنحرص على أن تكون في المنازل والبيوت وذلك لمحاربة الغزو الفكري الذي حصل فيها؛ حيثُ نسعى لتفعيل نصف دروس الكتاب على الأقل في المنازل.", "page": 7, "id": "unit-01__lesson-00__b13", "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "وعلى هذا تكون مادتي القرآن والتجويد والفقه في المسجد ولا يُمنع غير المنتسبين إلى الحلقة من حضورها، وتُدَرَّس المواد الثلاثة المتبقية في البيوت ولا يحضرها سوى المنتسبين للحلقة رسميا.. هكذا يرتبط الشباب بالمسجدِ، وتعمر بيوت المسلمين بالذكر، ويحرص المعلم على التنقل في البيوت كل مرة عند أحد المنتسبين للحلقة أو في بيت الشيخ؛ فيتعرف على عوائلهم، ويعرف وضعهم الاجتماعي والثقافي، وتُشرَك أُسَرَهم في الدعوةِ ونشر العلم، مع إعطاء المُضِيف الفرصة لاستضافة بعض معارفه وأقاربه لحضور المجلس العلمي؛ بعد استئذان الشيخ في أسماء الحضور.", "page": 7, "id": "unit-01__lesson-00__b14"}, {"type": "paragraph", "md": "7- خطة مقترحة لتدريس الكتاب: يمكن تدريسه خلال ستة أشهر، وفق الجدول الآتي الذي ينتهي فيه المجلس كاملًا بمواده الستة في أسبوع واحد، وبالتالي ينتهي الكتاب كاملًا خلال نصف سنة:", "page": 7, "id": "unit-01__lesson-00__b15", "inline": [{"t": "emphasis", "s": "7- خطة مقترحة لتدريس الكتاب", "role": "emphasis"}, {"t": "text", "s": ": يمكن تدريسه خلال ستة أشهر، وفق الجدول الآتي الذي ينتهي فيه المجلس كاملًا بمواده الستة في أسبوع واحد، وبالتالي ينتهي الكتاب كاملًا خلال نصف سنة:"}], "list": {"type": "ordered", "marker": "7"}}, {"type": "table", "rows": [["اليوم", "المادة", "الوقت المقدر"], ["السبت", "فقه - عقيدة", "ساعتين"], ["الاثنين", "تجويد – تفسير وتلاوة", "ساعتين"], ["الأربعاء", "الحديث - الأخلاق", "ساعتين"]], "html": "<table dir=\"rtl\"><tr><td>اليوم</td><td>المادة</td><td>الوقت المقدر</td></tr><tr><td>السبت</td><td>فقه - عقيدة</td><td>ساعتين</td></tr><tr><td>الاثنين</td><td>تجويد – تفسير وتلاوة</td><td>ساعتين</td></tr><tr><td>الأربعاء</td><td>الحديث - الأخلاق</td><td>ساعتين</td></tr></table>", "page": 7, "id": "unit-01__lesson-00__b16"}, {"type": "paragraph", "md": "أو يُدرَّس في سنة وهو الأفضل؛ حيثُ يُدرس المجلس الواحد في أسبوعين كاملًا، هكذا مثلا:", "page": 7, "id": "unit-01__lesson-00__b17"}, {"type": "table", "rows": [["اليوم", "المادة", "الوقت المقدر"], ["الأسبوع الأول", "السبت", "فقه", "ساعة"], ["الأسبوع الأول", "الاثنين", "تجويد وتلاوة", "ساعة"], ["الأسبوع الأول", "الأربعاء", "حديث", "ساعة"], ["الأسبوع الثاني", "السبت", "عقيدة", "ساعة"], ["الأسبوع الثاني", "الاثنين", "تفسير", "ساعة"], ["الأسبوع الثاني", "الأربعاء", "أخلاق", "ساعة"]], "html": "<table dir=\"rtl\"><tr><td>اليوم</td><td>المادة</td><td>الوقت المقدر</td></tr><tr><td>الأسبوع الأول</td><td>السبت</td><td>فقه</td><td>ساعة</td></tr><tr><td>الأسبوع الأول</td><td>الاثنين</td><td>تجويد وتلاوة</td><td>ساعة</td></tr><tr><td>الأسبوع الأول</td><td>الأربعاء</td><td>حديث</td><td>ساعة</td></tr><tr><td>الأسبوع الثاني</td><td>السبت</td><td>عقيدة</td><td>ساعة</td></tr><tr><td>الأسبوع الثاني</td><td>الاثنين</td><td>تفسير</td><td>ساعة</td></tr><tr><td>الأسبوع الثاني</td><td>الأربعاء</td><td>أخلاق</td><td>ساعة</td></tr></table>", "page": 7, "id": "unit-01__lesson-00__b18"}, {"type": "paragraph", "md": "وهذا البرنامج مقترح فقط؛ مع ضرورة عدم إعطائه كاملا في أقل من ستة أشهر، أو أكثر من سنة.", "page": 7, "id": "unit-01__lesson-00__b19"}, {"type": "paragraph", "md": "لماذا الشباب دون غيرهم؟", "page": 7, "id": "unit-01__lesson-00__b20"}, {"type": "paragraph", "md": "فقد أوصى نبينا صلى الله عليه وسلم بالشباب خيرًا، فكانوا عمود دولته، وأساسَ قوته، وبابَ دعوته؛ كانوا في الجهاد أسودًا ميامين، وفي الدعوة والعلم باذلين محتسبين، متمثلين بأصحاب الكهف الذين مدحهم الله بأنهم: ﴿فِتۡيَةٌ ءَامَنُواْ بِرَبِّهِمۡ وَزِدۡنَٰهُمۡ هُدٗى ۝١٣﴾، عالمين بما تتميز به هذه المرحلة من القوة؛ فاستغلوها على وجهها، كما قال تعالى: ﴿۞ٱللَّهُ ٱلَّذِي خَلَقَكُم مِّن ضَعۡفٖ ثُمَّ جَعَلَ مِنۢ بَعۡدِ ضَعۡفٖ قُوَّةٗ ثُمَّ جَعَلَ مِنۢ بَعۡدِ قُوَّةٖ ضَعۡفٗا وَشَيۡبَةٗۚ﴾، ومرحلة القوة التي تقع بين مرحلتي ضعف، هي مرحلة الشباب.", "page": 8, "id": "unit-01__lesson-00__b21", "inline": [{"t": "text", "s": "فقد أوصى نبينا "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بالشباب خيرًا، فكانوا عمود دولته، وأساسَ قوته، وبابَ دعوته؛ كانوا في الجهاد أسودًا ميامين، وفي الدعوة والعلم باذلين محتسبين، متمثلين بأصحاب الكهف الذين مدحهم الله بأنهم: "}, {"t": "ayah", "s": "فِتۡيَةٌ ءَامَنُواْ بِرَبِّهِمۡ وَزِدۡنَٰهُمۡ هُدٗى ۝١٣", "ayah": [13], "verses": [{"n": 13, "text": "فِتۡيَةٌ ءَامَنُواْ بِرَبِّهِمۡ وَزِدۡنَٰهُمۡ هُدٗى", "surah": 18, "ref_api": "https://api.quran.com/api/v4/verses/by_key/18:13", "surah_name": "الكهف", "ayah_canonical": 13, "match": "contained", "ref": "18:13"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، عالمين بما تتميز به هذه المرحلة من القوة؛ فاستغلوها على وجهها، كما قال تعالى: "}, {"t": "ayah", "s": "۞ٱللَّهُ ٱلَّذِي خَلَقَكُم مِّن ضَعۡفٖ ثُمَّ جَعَلَ مِنۢ بَعۡدِ ضَعۡفٖ قُوَّةٗ ثُمَّ جَعَلَ مِنۢ بَعۡدِ قُوَّةٖ ضَعۡفٗا وَشَيۡبَةٗۚ", "ayah": [], "verses": [{"n": 54, "text": "۞ٱللَّهُ ٱلَّذِي خَلَقَكُم مِّن ضَعۡفٖ ثُمَّ جَعَلَ مِنۢ بَعۡدِ ضَعۡفٖ قُوَّةٗ ثُمَّ جَعَلَ مِنۢ بَعۡدِ قُوَّةٖ ضَعۡفٗا وَشَيۡبَةٗۚ", "surah": 30, "surah_name": "الروم", "ref": "30:54", "ref_api": "https://api.quran.com/api/v4/verses/by_key/30:54"}], "surah": 30, "ref_api": "https://api.quran.com/api/v4/verses/by_key/30:54", "surah_name": "الروم", "ayah_canonical": 54, "match": "contained", "ref": "30:54"}, {"t": "text", "s": "، ومرحلة القوة التي تقع بين مرحلتي ضعف، هي مرحلة الشباب."}]}, {"type": "paragraph", "md": "ومعنى الشباب: النماء والقوة والفُتُوَّة مع حرارةٍ وهِمَّة تعتريه؛ يقال: شَبَّ الغُلَامُ يَشِبُّ شَبَابًا وشُبُوبًا، وشباب الشيء: أوله، فهي أول قوة الإنسان، وهو ضد الشَّيْب، وجمعه: شَبَاب، وشُبَّانُ، وشَبَبَةٌ.", "page": 8, "id": "unit-01__lesson-00__b22"}, {"type": "paragraph", "md": "ومرحلة الشباب: تبدأ من البلوغ – سن (14) عامًا-، حتى بلوغ الأربعين؛ لأن القرآن الكريم جعل الأربعين نهاية النَّماء؛ الذي هو معنى الشباب، كما في قوله تعالى: ﴿حَتَّىٰٓ إِذَا بَلَغَ أَشُدَّهُۥ وَبَلَغَ أَرۡبَعِينَ سَنَةٗ﴾، أي أنه قد قوي وشب وارتجل، فإذا بلغ ﴿أَرۡبَعِينَ سَنَةٗ﴾ تناهى عقله وكمل فهمه، وتتميز هذه المرحلة بالآتي:", "page": 8, "id": "unit-01__lesson-00__b23", "inline": [{"t": "emphasis", "s": "ومرحلة الشباب", "role": "emphasis"}, {"t": "text", "s": ": تبدأ من البلوغ – سن (14) عامًا-، حتى بلوغ الأربعين؛ لأن القرآن الكريم جعل الأربعين نهاية النَّماء؛ الذي هو معنى الشباب، كما في قوله تعالى: "}, {"t": "ayah", "s": "حَتَّىٰٓ إِذَا بَلَغَ أَشُدَّهُۥ وَبَلَغَ أَرۡبَعِينَ سَنَةٗ", "ayah": [], "verses": [{"n": 15, "text": "حَتَّىٰٓ إِذَا بَلَغَ أَشُدَّهُۥ وَبَلَغَ أَرۡبَعِينَ سَنَةٗ", "surah": 46, "surah_name": "الأحقاف", "ref": "46:15", "ref_api": "https://api.quran.com/api/v4/verses/by_key/46:15"}], "surah": 46, "ref_api": "https://api.quran.com/api/v4/verses/by_key/46:15", "surah_name": "الأحقاف", "ayah_canonical": 15, "match": "contained", "ref": "46:15"}, {"t": "text", "s": "، أي أنه قد قوي وشب وارتجل، فإذا بلغ "}, {"t": "ayah", "s": "أَرۡبَعِينَ سَنَةٗ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": " تناهى عقله وكمل فهمه، وتتميز هذه المرحلة بالآتي:"}]}, {"type": "paragraph", "md": "‌‌1- الشبابُ بداية التكليف: فعن عليٍّ رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: (رُفِعَ القَلَمُ عَن ثلاثةٍ: عَنِ النَّائِمِ حتَّى يَسْتَيْقِظ، وعَنِ الصَّبيِّ حتَّى يَشبّ، وعَنِ المَعْتوهِ حتَّى يَعْقِل)، ذَلك لأنَّ مرحلة الشباب يحصل فيها العلم والقدرة على التكليف الشرعي، فلم يكلف الصبي العاجز عن ذلك رحمةً به، فإذا شبَّ واكتملت حواسُّ إدراكه كُلِّف؛ فلم تعد أيها الشاب صغيرًا كما كنتَ في الصّبا؛ بل بتَّ مكلفًا في أقوالك وأفعالك.", "page": 8, "id": "unit-01__lesson-00__b24", "inline": [{"t": "text", "s": "‌‌1- الشبابُ بداية التكليف: فعن عليٍّ "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " أن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قال: "}, {"t": "emphasis", "s": "(رُفِعَ القَلَمُ عَن ثلاثةٍ: عَنِ النَّائِمِ حتَّى يَسْتَيْقِظ، وعَنِ الصَّبيِّ حتَّى يَشبّ، وعَنِ المَعْتوهِ حتَّى يَعْقِل)", "role": "emphasis"}, {"t": "text", "s": "، ذَلك لأنَّ مرحلة الشباب يحصل فيها العلم والقدرة على التكليف الشرعي، فلم يكلف الصبي العاجز عن ذلك رحمةً به، فإذا شبَّ واكتملت حواسُّ إدراكه كُلِّف؛ فلم تعد أيها الشاب صغيرًا كما كنتَ في الصّبا؛ بل بتَّ مكلفًا في أقوالك وأفعالك."}]}, {"type": "paragraph", "md": "ولما كانت مرحلة الشباب هي بداية سلوك طريق العبادة الاختيارية التي تنبع من الإنسان نفسه، ويجري عليه القلم فيها بالحسنات والسيئات، فلا بد لهذا الشاب من رعاية خاصة تعينه على بداية سلوك الطريق، وتوضح له معالمه، وتذلل له مصاعبه، وتبين له زاده؛ حتى يسير الشاب إلى ربه آمنًا مطمئنًا على هُدًى وبصيرة، وهذا ما حرصنا عليه في هذا الكتاب «على بصيرة» ليفوز الشابُّ بالجنة العظيمة.", "page": 8, "id": "unit-01__lesson-00__b25", "inline": [{"t": "text", "s": "ولما كانت مرحلة الشباب هي بداية سلوك طريق العبادة الاختيارية التي تنبع من الإنسان نفسه، ويجري عليه القلم فيها بالحسنات والسيئات، فلا بد لهذا الشاب من رعاية خاصة تعينه على بداية سلوك الطريق، وتوضح له معالمه، وتذلل له مصاعبه، وتبين له زاده؛ حتى يسير الشاب إلى ربه آمنًا مطمئنًا على هُدًى وبصيرة، وهذا ما حرصنا عليه في هذا الكتاب "}, {"t": "quote", "s": "على بصيرة"}, {"t": "text", "s": " ليفوز الشابُّ بالجنة العظيمة."}]}, {"type": "paragraph", "md": "ولأهمية هذه المرحلة؛ فقد جعلها الله تعالى أطول مراحل العمل؛ فإذا كان عمر الإنسان في هذه الأمة بين الستين والسبعين؛ فإن الوسط الحسابي لهذين العددين (60 - 70) هو 65 سنة. وإذا كان زمن سن الغلومية هو من الولادة حتى سن الشباب، وسن الشباب من الرابعة عشرة -غالبًا- إلى الأربعين، ثم زمن الكهولة من انتهاء الشباب إلى تمام الخمسين، ثم الشيخوخة من بعد الخمسين إلى الموت؛ فمرحلة الشباب أطول هذه المراحل، حيثُ تبلغ النسبة الكلية لها قرابة 50% من مجموع عمر الإنسان.", "page": 8, "id": "unit-01__lesson-00__b26"}, {"type": "paragraph", "md": "‌‌2 – الشباب فترة القوة: يمر الإنسان في حياته بمراحل تتفاوت قوةً وضعفًا؛ فهو يخرج إلى الدنيا ضعيفًا لا يعلم شيئًا، ثم يكبر ويقوى جسمه، ويزداد عقله، حتى يبلغ أشده وقوته؛ قال تعالى في ذلك: ﴿وَٱللَّهُ أَخۡرَجَكُم مِّنۢ بُطُونِ أُمَّهَٰتِكُمۡ لَا تَعۡلَمُونَ شَيۡـٔٗا وَجَعَلَ لَكُمُ ٱلسَّمۡعَ وَٱلۡأَبۡصَٰرَ وَٱلۡأَفۡـِٔدَةَ لَعَلَّكُمۡ تَشۡكُرُونَ﴾.", "page": 9, "id": "unit-01__lesson-00__b27", "inline": [{"t": "text", "s": "‌‌2 – الشباب فترة القوة: يمر الإنسان في حياته بمراحل تتفاوت قوةً وضعفًا؛ فهو يخرج إلى الدنيا ضعيفًا لا يعلم شيئًا، ثم يكبر ويقوى جسمه، ويزداد عقله، حتى يبلغ أشده وقوته؛ قال تعالى في ذلك: "}, {"t": "ayah", "s": "وَٱللَّهُ أَخۡرَجَكُم مِّنۢ بُطُونِ أُمَّهَٰتِكُمۡ لَا تَعۡلَمُونَ شَيۡـٔٗا وَجَعَلَ لَكُمُ ٱلسَّمۡعَ وَٱلۡأَبۡصَٰرَ وَٱلۡأَفۡـِٔدَةَ لَعَلَّكُمۡ تَشۡكُرُونَ", "ayah": [], "verses": [{"n": 78, "text": "وَٱللَّهُ أَخۡرَجَكُم مِّنۢ بُطُونِ أُمَّهَٰتِكُمۡ لَا تَعۡلَمُونَ شَيۡـٔٗا وَجَعَلَ لَكُمُ ٱلسَّمۡعَ وَٱلۡأَبۡصَٰرَ وَٱلۡأَفۡـِٔدَةَ لَعَلَّكُمۡ تَشۡكُرُونَ", "surah": 16, "surah_name": "النحل", "ref": "16:78", "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:78"}], "surah": 16, "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:78", "surah_name": "النحل", "ayah_canonical": 78, "match": "exact", "ref": "16:78"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ولكن هذه المرحلة من القوة لا تدوم مع الإنسان، بل إذا طال به العمر عاد مرة أخرى إلى الضعف، كما في قوله سبحانه: ﴿وَمَن نُّعَمِّرۡهُ نُنَكِّسۡهُ فِي ٱلۡخَلۡقِۚ أَفَلَا يَعۡقِلُونَ﴾، وقال تعالى: ﴿مِنۢ بَعۡدِ ضَعۡفٖ قُوَّةٗ﴾: أي أنَّه تعالى يجعل بعد ضعف الطفولة قوة الشباب، ثم جعل من بعد قوة الشباب ضعف الكبر والشيب.", "page": 9, "id": "unit-01__lesson-00__b28", "inline": [{"t": "text", "s": "ولكن هذه المرحلة من القوة لا تدوم مع الإنسان، بل إذا طال به العمر عاد مرة أخرى إلى الضعف، كما في قوله سبحانه: "}, {"t": "ayah", "s": "وَمَن نُّعَمِّرۡهُ نُنَكِّسۡهُ فِي ٱلۡخَلۡقِۚ أَفَلَا يَعۡقِلُونَ", "ayah": [], "verses": [{"n": 68, "text": "وَمَن نُّعَمِّرۡهُ نُنَكِّسۡهُ فِي ٱلۡخَلۡقِۚ أَفَلَا يَعۡقِلُونَ", "surah": 36, "surah_name": "يس", "ref": "36:68", "ref_api": "https://api.quran.com/api/v4/verses/by_key/36:68"}], "surah": 36, "ref_api": "https://api.quran.com/api/v4/verses/by_key/36:68", "surah_name": "يس", "ayah_canonical": 68, "match": "exact", "ref": "36:68"}, {"t": "text", "s": "، وقال تعالى: "}, {"t": "ayah", "s": "مِنۢ بَعۡدِ ضَعۡفٖ قُوَّةٗ", "ayah": [], "verses": [{"n": 54, "text": "مِنۢ بَعۡدِ ضَعۡفٖ قُوَّةٗ", "surah": 30, "surah_name": "الروم", "ref": "30:54", "ref_api": "https://api.quran.com/api/v4/verses/by_key/30:54"}], "surah": 30, "ref_api": "https://api.quran.com/api/v4/verses/by_key/30:54", "surah_name": "الروم", "ayah_canonical": 54, "match": "contained", "ref": "30:54"}, {"t": "text", "s": ": أي أنَّه تعالى يجعل بعد ضعف الطفولة قوة الشباب، ثم جعل من بعد قوة الشباب ضعف الكبر والشيب."}]}, {"type": "paragraph", "md": "وقد ورد في السنة ما يدل على أن الشباب مرحلة القوة؛ ففي حديث عبد الله بن عمرو بن العاص رضي الله عنهما قال: «جمعت القرآن كله في ليلة؛ فقال النبي صلى الله عليه وسلم : (إنِّي أخْشَى أنْ يَطُولَ عَلَيْكَ الزَّمان، وأنْ تَمِلَّ فاقرأْهُ في شَهرٍ)، فقلت: دعني أستمتع من قوتي وشبابي، قال: (فاقْرأهُ في عَشْرةٍ) قلت: دعني أستمتع من قوتي وشبابي. قال: (فاقْرأهُ في سَبْعٍ) قلت: دعني أستمتع من قوتي وشبابي. فأبى النبي صلى الله عليه وسلم ذلك، قال ابن عمرو: قال: فشدَّدْت؛ فشُدِّدَ علي، قال: وقال لي النبي صلى الله عليه وسلم : (إنك لا تدري لعلك يطول بك عمر)، فصرت إلى الذي قال لي النبي صلى الله عليه وسلم ؛ فلما كبرت وددت أني كنت قبلت رخصة نبي الله صلى الله عليه وسلم ».", "page": 9, "id": "unit-01__lesson-00__b29", "inline": [{"t": "text", "s": "وقد ورد في السنة ما يدل على أن الشباب مرحلة القوة؛ ففي حديث عبد الله بن عمرو بن العاص "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " قال: "}, {"t": "quote", "s": "جمعت القرآن كله في ليلة؛ فقال النبي صلى الله عليه وسلم : (إنِّي أخْشَى أنْ يَطُولَ عَلَيْكَ الزَّمان، وأنْ تَمِلَّ فاقرأْهُ في شَهرٍ)، فقلت: دعني أستمتع من قوتي وشبابي، قال: (فاقْرأهُ في عَشْرةٍ) قلت: دعني أستمتع من قوتي وشبابي. قال: (فاقْرأهُ في سَبْعٍ) قلت: دعني أستمتع من قوتي وشبابي. فأبى النبي صلى الله عليه وسلم ذلك، قال ابن عمرو: قال: فشدَّدْت؛ فشُدِّدَ علي، قال: وقال لي النبي صلى الله عليه وسلم : (إنك لا تدري لعلك يطول بك عمر)، فصرت إلى الذي قال لي النبي صلى الله عليه وسلم ؛ فلما كبرت وددت أني كنت قبلت رخصة نبي الله صلى الله عليه وسلم"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "والقوة في هذه المرحلة في كل شيء: في البدن، والحواس، وعلى العمل والتكسب، وطلب العلم.", "page": 9, "id": "unit-01__lesson-00__b30"}, {"type": "paragraph", "md": "وقد قال عبد الله بن أحمد بن حنبل رحمه الله : «قلت لأبي: يا أبت، ما الحفاظ؟ قال: يا بني شباب كانوا عندنا من أهل خراسان وقد تفرقوا»؛ هكذا كان حفاظ الإسلام وعلماؤه من الشباب الحذاق الأذكياء.", "page": 9, "id": "unit-01__lesson-00__b31", "inline": [{"t": "text", "s": "وقد قال عبد الله بن أحمد بن حنبل "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "قلت لأبي: يا أبت، ما الحفاظ؟ قال: يا بني شباب كانوا عندنا من أهل خراسان وقد تفرقوا"}, {"t": "text", "s": "؛ هكذا كان حفاظ الإسلام وعلماؤه من الشباب الحذاق الأذكياء."}]}, {"type": "paragraph", "md": "وقد راعت الشريعة حوائج الشباب الخاصة؛ فلما كانت مرحلة الشباب مرحلة قوة في الشهوة الجنسية دعت لتحصين الشباب من الوقوع في معصية الزنا ومقدماتها من النظر والسماع؛ ففي حديث عبد الله بن مسعود رضي الله عنه قال: كنا مع النبي صلى الله عليه وسلم شبابًا لا نجد شيئًا، فقال لنا رسول الله صلى الله عليه وسلم : (يا مَعْشَرَ الشَّبَابِ من اسْتَطَاعَ مِنْكُمُ الْبَاءَةَ فَلْيَتَزَوَّجْ؛ فإنَّه أغضُّ للبَصَرِ، وأحْصَنُ للفَرْجِ، وَمَنْ لم يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ فإنَّه لهُ وِجَاءٌ)، وعن أبي هريرة رضي الله عنه : (أن رجلًا سأل النبي صلى الله عليه وسلم عن المباشرة للصائم، فرخَّص له، وأتاه آخر فسأله فنهاه، فإذا الذي رخص له شيخ، والذي نهاه شاب)؛ فلكلِّ حالٍ فتوى بحسب المَقام.", "page": 9, "id": "unit-01__lesson-00__b32", "inline": [{"t": "text", "s": "وقد راعت الشريعة حوائج الشباب الخاصة؛ فلما كانت مرحلة الشباب مرحلة قوة في الشهوة الجنسية دعت لتحصين الشباب من الوقوع في معصية الزنا ومقدماتها من النظر والسماع؛ ففي حديث عبد الله بن مسعود "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: كنا مع النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " شبابًا لا نجد شيئًا، فقال لنا رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(يا مَعْشَرَ الشَّبَابِ من اسْتَطَاعَ مِنْكُمُ الْبَاءَةَ فَلْيَتَزَوَّجْ؛ فإنَّه أغضُّ للبَصَرِ، وأحْصَنُ للفَرْجِ، وَمَنْ لم يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ فإنَّه لهُ وِجَاءٌ)", "role": "emphasis"}, {"t": "text", "s": "، وعن أبي هريرة "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(أن رجلًا سأل النبي", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "عن المباشرة للصائم، فرخَّص له، وأتاه آخر فسأله فنهاه، فإذا الذي رخص له شيخ، والذي نهاه شاب)", "role": "emphasis"}, {"t": "text", "s": "؛ فلكلِّ حالٍ فتوى بحسب المَقام."}]}, {"type": "paragraph", "md": "ومن هنا يتأكد الاهتمام بالشباب من أولياء أمورهم ومن المربين والدعاة، والسعي إلى تحصينهم، وأن يبعدوا عنهم كل ما شأنه إثارة شهواتهم ووقوعهم فيما حرم الله عليهم، ويستغلوا قوتهم في طاعة الله.", "page": 9, "id": "unit-01__lesson-00__b33"}, {"type": "paragraph", "md": "3 – الشباب أفضل فترات العمر: تعود الأفضلية لهذه المرحلة لما يجتمع للإنسان فيها من القوة والنشاط، دون غيرها، ولما يتوافر له فيها من كمال الحواس، والقدرة على التعلم والكسب، ولكن هذه الأفضلية ليست مطلقة لكل الناس، بل وربما كانت بعض الفترات عند بعض الناس أفضل من فترة الشباب، وذلك عندما يتحقق له في تلك المرحلة قوة الإيمان ودوام الصلة بالله سبحانه وتعالى ، ففي هذه الحال تكون الأفضلية الحقيقية. وتكتمل الأفضلية عندما تجتمع مرحلة الشباب مع قوة الإيمان فيها.", "page": 10, "id": "unit-01__lesson-00__b34", "inline": [{"t": "text", "s": "3 – الشباب أفضل فترات العمر: تعود الأفضلية لهذه المرحلة لما يجتمع للإنسان فيها من القوة والنشاط، دون غيرها، ولما يتوافر له فيها من كمال الحواس، والقدرة على التعلم والكسب، ولكن هذه الأفضلية ليست مطلقة لكل الناس، بل وربما كانت بعض الفترات عند بعض الناس أفضل من فترة الشباب، وذلك عندما يتحقق له في تلك المرحلة قوة الإيمان ودوام الصلة بالله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، ففي هذه الحال تكون الأفضلية الحقيقية. وتكتمل الأفضلية عندما تجتمع مرحلة الشباب مع قوة الإيمان فيها."}]}, {"type": "paragraph", "md": "ومما يدل على فضل هذه المرحلة؛ أنها هي الحال التي يكون عليها أهل الجنة، فقد قال النبي صلى الله عليه وسلم : (ينادِي مُنَادٍ، إنَّ لَكُم أنْ تَصِحُّوا فَلا تَسْقَمُوا أبَدًا، وإنَّ لكُم أنْ تَحْيوا فلا تَمُوتُوا أبَدًا، وإنَّ لكُم أن تَشبُّوا فلا تَهْرَمُوا أبَدًا، وإنَّ لَكُمْ أنْ تَنْعَمُوا فلا تبأسُوا أبَدًا)، وراحة الحياة وبهجتها في الدنيا غالبًا ما تكون في مرحلة الشباب؛ فهي مرحلة يتطلع الصغير أن يصل إليها، ويتمنى الكبير أن يرجع إليها، هي مرحلة بكى عليها الشيوخ وتغنَّى بها الشعراء، وسمت لها قرائحهم؛ كما يقول أبو العتاهية:", "page": 10, "id": "unit-01__lesson-00__b35", "inline": [{"t": "text", "s": "ومما يدل على فضل هذه المرحلة؛ أنها هي الحال التي يكون عليها أهل الجنة، فقد قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(ينادِي مُنَادٍ، إنَّ لَكُم أنْ تَصِحُّوا فَلا تَسْقَمُوا أبَدًا، وإنَّ لكُم أنْ تَحْيوا فلا تَمُوتُوا أبَدًا، وإنَّ لكُم أن تَشبُّوا فلا تَهْرَمُوا أبَدًا، وإنَّ لَكُمْ أنْ تَنْعَمُوا فلا تبأسُوا أبَدًا)", "role": "emphasis"}, {"t": "text", "s": "، وراحة الحياة وبهجتها في الدنيا غالبًا ما تكون في مرحلة الشباب؛ فهي مرحلة يتطلع الصغير أن يصل إليها، ويتمنى الكبير أن يرجع إليها، هي مرحلة بكى عليها الشيوخ وتغنَّى بها الشعراء، وسمت لها قرائحهم؛ كما يقول أبو العتاهية:"}]}, {"type": "table", "rows": [["بكيتُ على الشبابِ بدمعِ عيني", "", "فلم يُغن البكاء ولا النحيب"], ["فيا أسفًا أسفت على الشباب", "", "نعاه الشيبُ والرأس الخضيبُ"], ["عَرِيت من الشباب وكنت غضًّا", "", "كما يعرى من الورق القضيب"], ["فيا ليت الشبابَ يعود يومًا", "", "فأخبره بما فعل المشيب"]], "html": "<table dir=\"rtl\"><tr><td>بكيتُ على الشبابِ بدمعِ عيني</td><td></td><td>فلم يُغن البكاء ولا النحيب</td></tr><tr><td>فيا أسفًا أسفت على الشباب</td><td></td><td>نعاه الشيبُ والرأس الخضيبُ</td></tr><tr><td>عَرِيت من الشباب وكنت غضًّا</td><td></td><td>كما يعرى من الورق القضيب</td></tr><tr><td>فيا ليت الشبابَ يعود يومًا</td><td></td><td>فأخبره بما فعل المشيب</td></tr></table>", "page": 10, "id": "unit-01__lesson-00__b36", "subtype": "poem", "abyat": [{"sadr": "بكيتُ على الشبابِ بدمعِ عيني", "ajuz": "فلم يُغن البكاء ولا النحيب"}, {"sadr": "فيا أسفًا أسفت على الشباب", "ajuz": "نعاه الشيبُ والرأس الخضيبُ"}, {"sadr": "عَرِيت من الشباب وكنت غضًّا", "ajuz": "كما يعرى من الورق القضيب"}, {"sadr": "فيا ليت الشبابَ يعود يومًا", "ajuz": "فأخبره بما فعل المشيب"}]}, {"type": "paragraph", "md": "واللهو الباطل مذموم للشباب وغيرهم، والعاقل من يستغل أفضل مراحل عمره لما ينفعه في دنياه وأخراه؛ من بناء المعارف، وتحصيل العلوم، والترقي في الطاعات، مع ما أباحه الله من الاستمتاع بطيبات الحياة؛ من زواجٍ أو طعامٍ أو غيرها، فهذا جابر بن عبد الله رضي الله عنه لما تزوج سأله رسول الله صلى الله عليه وسلم قائلًا: (هل تزوَّجتَ بِكْرًا أمْ ثَيِّبًا؟). قال جابر: تزوجت ثيبًا، قال: (فهلا تَزوَّجْتَ بِكرًا تُلاعِبُها وتُلاعِبُك؟).", "page": 10, "id": "unit-01__lesson-00__b37", "inline": [{"t": "text", "s": "واللهو الباطل مذموم للشباب وغيرهم، والعاقل من يستغل أفضل مراحل عمره لما ينفعه في دنياه وأخراه؛ من بناء المعارف، وتحصيل العلوم، والترقي في الطاعات، مع ما أباحه الله من الاستمتاع بطيبات الحياة؛ من زواجٍ أو طعامٍ أو غيرها، فهذا جابر بن عبد الله "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " لما تزوج سأله رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قائلًا: "}, {"t": "emphasis", "s": "(هل تزوَّجتَ بِكْرًا أمْ ثَيِّبًا؟)", "role": "emphasis"}, {"t": "text", "s": ". قال جابر: تزوجت ثيبًا، قال: "}, {"t": "emphasis", "s": "(فهلا تَزوَّجْتَ بِكرًا تُلاعِبُها وتُلاعِبُك؟)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وقال رسول الله صلى الله عليه وسلم : (عَلَيْكُم بالأبْكارِ، فإنَّهُنَّ أعْذَبُ أفْواهًا، وأنْتَقُ أرْحامًا، وأرضَى باليسير).", "page": 10, "id": "unit-01__lesson-00__b38", "inline": [{"t": "text", "s": "وقال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(عَلَيْكُم بالأبْكارِ، فإنَّهُنَّ أعْذَبُ أفْواهًا، وأنْتَقُ أرْحامًا، وأرضَى باليسير)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وإنَّ سببَ وقوعِ الشبابِ فيما يقعونَ فيهِ من الأخطاءٍ، إنما هوَ لوفورِ الصحةِ وكمالِ القوةِ، وكثرة النشاطِ، معَ داومِ الفراغِ وقلةِ الشغلِ، وتوفرِ المالِ لهم من أولياءِ الأمورِ أو من مصادرَ أخرى، كمَا قيل:", "page": 10, "id": "unit-01__lesson-00__b39"}, {"type": "table", "rows": [["إنَّ الشبابَ والفراغَ والجدة", "", "مفسدةٌ للمرءِ أيُّ مفسدة"]], "html": "<table dir=\"rtl\"><tr><td>إنَّ الشبابَ والفراغَ والجدة</td><td></td><td>مفسدةٌ للمرءِ أيُّ مفسدة</td></tr></table>", "page": 10, "id": "unit-01__lesson-00__b40", "subtype": "poem", "abyat": [{"sadr": "إنَّ الشبابَ والفراغَ والجدة", "ajuz": "مفسدةٌ للمرءِ أيُّ مفسدة"}]}, {"type": "paragraph", "md": "فإذا توفرت هذه الثلاث؛ لا سيما في أوقاتِ الإجازاتِ، فسيكثر الفساد، وحريٌّ بنا وقتها أن نستنفر الجهود ونوجه هذه الطاقات العظيمة نحو الوجهةَ السليمةَ، ونسعى لأن يحققَ شباب الإسلام أكبرَ قدرٍ منَ الفائدةِ، لا أن يخرجوا من إجازاتهم وقدِ اكتسبوا منَ الأخلاقِ أرذلها، ومنَ العاداتِ أسوأها.", "page": 10, "id": "unit-01__lesson-00__b41"}, {"type": "paragraph", "md": "دور الشباب في بناء الأمة المسلمة:", "page": 11, "id": "unit-01__lesson-00__b42"}, {"type": "paragraph", "md": "لقد كان للشباب المسلم الدورالأعظم في بناء الأمة المسلمة؛ فعلى أكتافهم قامت حضارتنا، وبأيديهم نهضت أمتنا؛ على مر العصور وفي سائر المجالات، ويظهر ذلك بما يأتي:", "page": 11, "id": "unit-01__lesson-00__b43", "inline": [{"t": "emphasis", "s": "لقد كان للشباب المسلم الدورالأعظم في بناء الأمة المسلمة؛ فعلى أكتافهم قامت حضارتنا، وبأيديهم نهضت أمتنا؛ على مر العصور وفي سائر المجالات، ويظهر ذلك بما يأتي:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1 – كان الشباب هم أسبق الأمم إلى قبول الدعوات الإصلاحية، وأكثر مَن واجهوا الباطل، وأسرع ال' WHERE id='unit-01__lesson-00';
UPDATE manhaj_lessons SET blocks = blocks || 'ناس إلى قبول الحق؛ لأن الشباب أرق قلوبا وأهدأ نفسا، وليس لهم أطماع في الحياة؛ كحال الكبراء والسادة الذين كانوا كلما جاءهم رسول كذبوه، فقد قال تعالى في شأن المترفين: ﴿وَكَذَٰلِكَ مَآ أَرۡسَلۡنَا مِن قَبۡلِكَ فِي قَرۡيَةٖ مِّن نَّذِيرٍ إِلَّا قَالَ مُتۡرَفُوهَآ إِنَّا وَجَدۡنَآ ءَابَآءَنَا عَلَىٰٓ أُمَّةٖ وَإِنَّا عَلَىٰٓ ءَاثَٰرِهِم مُّقۡتَدُونَ ۝٢٣﴾، أما الشباب فتصدوا للباطل بإيمان وثبات؛ كما حدث مع سيدنا إبراهيم عليه السلام ، ومع أصحاب الكهف الفِتية كذلك.", "page": 11, "id": "unit-01__lesson-00__b44", "inline": [{"t": "text", "s": "1 – كان الشباب هم أسبق الأمم إلى قبول الدعوات الإصلاحية، وأكثر مَن واجهوا الباطل، وأسرع الناس إلى قبول الحق؛ لأن الشباب أرق قلوبا وأهدأ نفسا، وليس لهم أطماع في الحياة؛ كحال الكبراء والسادة الذين كانوا كلما جاءهم رسول كذبوه، فقد قال تعالى في شأن المترفين: "}, {"t": "ayah", "s": "وَكَذَٰلِكَ مَآ أَرۡسَلۡنَا مِن قَبۡلِكَ فِي قَرۡيَةٖ مِّن نَّذِيرٍ إِلَّا قَالَ مُتۡرَفُوهَآ إِنَّا وَجَدۡنَآ ءَابَآءَنَا عَلَىٰٓ أُمَّةٖ وَإِنَّا عَلَىٰٓ ءَاثَٰرِهِم مُّقۡتَدُونَ ۝٢٣", "ayah": [23], "verses": [{"n": 23, "text": "وَكَذَٰلِكَ مَآ أَرۡسَلۡنَا مِن قَبۡلِكَ فِي قَرۡيَةٖ مِّن نَّذِيرٍ إِلَّا قَالَ مُتۡرَفُوهَآ إِنَّا وَجَدۡنَآ ءَابَآءَنَا عَلَىٰٓ أُمَّةٖ وَإِنَّا عَلَىٰٓ ءَاثَٰرِهِم مُّقۡتَدُونَ", "surah": 43, "ref_api": "https://api.quran.com/api/v4/verses/by_key/43:23", "surah_name": "الزخرف", "ayah_canonical": 23, "match": "exact", "ref": "43:23"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، أما الشباب فتصدوا للباطل بإيمان وثبات؛ كما حدث مع سيدنا إبراهيم "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " ، ومع أصحاب الكهف الفِتية كذلك."}]}, {"type": "paragraph", "md": "2 - الشباب أغلى ما تمتلك الأمة؛ فإذا كانت الأمة تمتلك كثيرًا من المقدرات؛ الاقتصادية والعسكرية والجغرافية والإنسانية، فإن أغلى ما تمتلكه من ذلك: الإنسانية، والشباب على قمة هرمها. وإذا أردت أن تعرف مستقبل أي أمة فلا تسل عن ذهبها ومالها؛ بل إلى شبابها واهتماماتهم؛ فإذا رأيته شبابًا متدينًا صالحًا؛ فاعلم أنها أمة جليلة الشأن قوية البناء، وإذا رأيته شبابًا هابط الخلق، منشغلًا بسفاسف الأمور والرذائل؛ فاعلم أنها أمة ضعيفة مفككة، سرعان ما تنهار أمام عدوها؛ فالشباب عنوان الأمة، وعِمَادُ نهضتها، وسِرُّ قُوَّتها، فهم الذين حمَلوا راية الدعوة إلى الله، ورَفَعوا لواءَ الجهاد المقدَّس، فحقَّق الله على أيديهم النصر الأكبر، حتى قامت دولة الإسلام الفتيَّة في مطلع الزمان.", "page": 11, "id": "unit-01__lesson-00__b45", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "ودونكم بعض القدوات الشبابية العظيمة التي قدمت للأمة بطولاتٍ رائعةً:", "page": 11, "id": "unit-01__lesson-00__b46", "inline": [{"t": "emphasis", "s": "ودونكم بعض القدوات الشبابية العظيمة التي قدمت للأمة بطولاتٍ رائعةً:", "role": "emphasis"}]}, {"type": "paragraph", "md": "لو تصفحنا السيرة النبوية الشريفة لوجدنا كل من واجهوا جبابرة مكة وكسرى وقيصر من الشباب، ولوجدنا أنَّ السابقين للإسلام من الشباب، ولوجدنا السفراء والقضاة والعلماء والقادة من الشباب:", "page": 11, "id": "unit-01__lesson-00__b47"}, {"type": "paragraph", "md": "فهذا الزبير بن العوام رضي الله عنه من العشرة المبشرين بالجنة أسلم وعمره (15) سنة، وطلحة بن عبيد الله من العشرة أسلم وعمره (16) سنة، وسعد بن أبي وقاص أسلم وعمره (17) سنة، والأرقم بن أبي الأرقم (16) سنة، وقد جعل بيته مركزًا لرسول الله صلى الله عليه وسلم ؛ يُعَلِّم فيه المسلمين ويربيهم علي الإسلام.", "page": 11, "id": "unit-01__lesson-00__b48", "inline": [{"t": "text", "s": "فهذا الزبير بن العوام "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " من العشرة المبشرين بالجنة أسلم وعمره (15) سنة، وطلحة بن عبيد الله من العشرة أسلم وعمره (16) سنة، وسعد بن أبي وقاص أسلم وعمره (17) سنة، والأرقم بن أبي الأرقم (16) سنة، وقد جعل بيته مركزًا لرسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ؛ يُعَلِّم فيه المسلمين ويربيهم علي الإسلام."}]}, {"type": "paragraph", "md": "وقد ضرب السلف الصالح أروع الأمثلة في مجال التضحية والتسابق إلى ساحات الجهاد، وهم لم يزالوا شبابًا لم يبلغوا بعد سن العشرين؛ فلم يتذرعوا بصغر السن، ولا قلة الخبرة، ومن ذلك:", "page": 11, "id": "unit-01__lesson-00__b49", "inline": [{"t": "text", "s": "وقد ضرب السلف الصالح أروع الأمثلة في مجال التضحية والتسابق إلى ساحات الجهاد، وهم لم يزالوا شبابًا لم يبلغوا بعد سن العشرين؛ فلم يتذرعوا بصغر السن، ولا قلة الخبرة، "}, {"t": "emphasis", "s": "ومن ذلك:", "role": "emphasis"}]}, {"type": "paragraph", "md": "- عبد الله بن عمر رضي الله عنهما : ردَّه النبي صلى الله عليه وسلم في غزوة أحد، وأجازه في غزوة الخندق، وعمره (15) سنة.", "page": 12, "id": "unit-01__lesson-00__b50", "inline": [{"t": "text", "s": "- عبد الله بن عمر "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " : ردَّه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في غزوة أحد، وأجازه في غزوة الخندق، وعمره (15) سنة."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وكذلك فعل النبي صلى الله عليه وسلم هذا الأمر مع أسامة بن زيد رضي الله عنهما ، والبراء بن عازب رضي الله عنه ، وغيرهم.", "page": 12, "id": "unit-01__lesson-00__b51", "inline": [{"t": "text", "s": "- وكذلك فعل النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " هذا الأمر مع أسامة بن زيد "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " ، والبراء بن عازب "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ، وغيرهم."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- زيد بن ثابت رضي الله عنه : كان عمره عندما هاجر النبي صلى الله عليه وسلم إلى المدينة (11) سنة فقط، وأراد أن يشهد غزوة بدر وَسِنه (13) سنة؛ فاستصغره النبي صلى الله عليه وسلم وردَّه، وأراد أن يشهد غزوة أُحُد، وكان عمره (14) سنة، وردَّه النبي صلى الله عليه وسلم أيضًا، فكانت أول مشاهده: الخندق، وعمره يومئذ (15) سنة؛ فأي همة هذه؟!", "page": 12, "id": "unit-01__lesson-00__b52", "inline": [{"t": "text", "s": "- زيد بن ثابت "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " : كان عمره عندما هاجر النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " إلى المدينة (11) سنة فقط، وأراد أن يشهد غزوة بدر وَسِنه (13) سنة؛ فاستصغره النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وردَّه، وأراد أن يشهد غزوة أُحُد، وكان عمره (14) سنة، وردَّه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أيضًا، فكانت أول مشاهده: الخندق، وعمره يومئذ (15) سنة؛ فأي همة هذه؟!"}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- عُمير بن أبي وقاص -أخو سعد بن أبي وقاص- رضي الله عنهما : أراد أن يشهد غزوة بدر، وكان عمره (14) سنة، وقيل: (16) سنة، فردَّه النبي صلى الله عليه وسلم واستصغره، فذهب يبكي فَرَقَّ له النبي صلى الله عليه وسلم فأجازه، يقول سعد: «كنت أعقد له حمائل سيفه من صغره»، وقتل شهيدًا ببدر، قتله «عمرو بن عبد وُد» أحد صناديد قريش.", "page": 12, "id": "unit-01__lesson-00__b53", "inline": [{"t": "text", "s": "- عُمير بن أبي وقاص -أخو سعد بن أبي وقاص- "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " : أراد أن يشهد غزوة بدر، وكان عمره (14) سنة، وقيل: (16) سنة، فردَّه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " واستصغره، فذهب يبكي فَرَقَّ له النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " فأجازه، يقول سعد: "}, {"t": "hadith", "s": "كنت أعقد له حمائل سيفه من صغره", "narrator": null, "source": null, "confidence": "high", "ref_api": null}, {"t": "text", "s": "، وقتل شهيدًا ببدر، قتله "}, {"t": "hadith", "s": "عمرو بن عبد وُد", "narrator": null, "source": null, "confidence": "high", "ref_api": null}, {"t": "text", "s": " أحد صناديد قريش."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وردَّ النبي صلى الله عليه وسلم رافع بن خديج، وسمرة بن جندب واستصغرهما؛ فلما كانت غزوة أُحُد ردَّهما النبي صلى الله عليه وسلم ، وهما ابنا (15) سنة، فقيل: يا رسول الله، إن رافعًا رامٍ، فأجازه النبي صلى الله عليه وسلم ، فجاء سمرة إلى النبي صلى الله عليه وسلم وقال: يا رسول الله، أجزت رافعًا ولم تجزني، ولو صارعتُ رافعًا لصرعتُه؛ فأجازه النبي صلى الله عليه وسلم . وفي هذه الغزوة أصاب رافعًا سهمٌ في صدره؛ فجاء إلى النبي صلى الله عليه وسلم ، فقال له النبي صلى الله عليه وسلم : (إن شئت نزعتُ السهم والقُطْبة، وإن شئتَ نزعتُ السهم وتركت القطبة داخل جسمك، وأشهد لك يوم القيامة إنك شهيد)، فقال - مقال الذي يتطلع للجَنَّة-: «يا رسول الله انزع السهم واترك القطبة في جسدي»؛ فبقيت القطبة في جسده حتى التئم الجرح عليها، وانفتق عليها في زمن معاوية، فمات رضي الله عنه شهيدًا بشهادة النبي صلى الله عليه وسلم .", "page": 12, "id": "unit-01__lesson-00__b54", "inline": [{"t": "text", "s": "- وردَّ النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " رافع بن خديج، وسمرة بن جندب واستصغرهما؛ فلما كانت غزوة أُحُد ردَّهما النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، وهما ابنا (15) سنة، فقيل: يا رسول الله، إن رافعًا رامٍ، فأجازه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، فجاء سمرة إلى النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وقال: يا رسول الله، أجزت رافعًا ولم تجزني، ولو صارعتُ رافعًا لصرعتُه؛ فأجازه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " . وفي هذه الغزوة أصاب رافعًا سهمٌ في صدره؛ فجاء إلى النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، فقال له النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إن شئت نزعتُ السهم والقُطْبة، وإن شئتَ نزعتُ السهم وتركت القطبة داخل جسمك، وأشهد لك يوم القيامة إنك شهيد)", "role": "emphasis"}, {"t": "text", "s": "، فقال - مقال الذي يتطلع للجَنَّة-: "}, {"t": "quote", "s": "يا رسول الله انزع السهم واترك القطبة في جسدي", "speaker": "الذي يتطلع للجنة-"}, {"t": "text", "s": "؛ فبقيت القطبة في جسده حتى التئم الجرح عليها، وانفتق عليها في زمن معاوية، فمات "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " شهيدًا بشهادة النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}], "list": {"type": "unordered"}}, {"type": "table", "rows": [["أولئك آبائي فجئني بمثلهم", "", "إذا جمعتنا يا جرير المجامع"]], "html": "<table dir=\"rtl\"><tr><td>أولئك آبائي فجئني بمثلهم</td><td></td><td>إذا جمعتنا يا جرير المجامع</td></tr></table>", "page": 12, "id": "unit-01__lesson-00__b55", "subtype": "poem", "abyat": [{"sadr": "أولئك آبائي فجئني بمثلهم", "ajuz": "إذا جمعتنا يا جرير المجامع"}]}, {"type": "paragraph", "md": "- وعندما نتكلم عن الشباب ورفع راية الجهاد لا ننسى أن نتكلم عن البطل المغوار: علي بن أبي طالب رضي الله عنه ؛ فقد كان اللواء بيده في كثير من المشاهد والغزوات، ودفع الرسول صلى الله عليه وسلم الراية يوم بدر إليه، وهو ابن عشرين سنة، وكان حامل الراية يوم خيبر وسنه بالكاد بلغ (25) سنة، وفي غزوة بدر بارز عليٌّ رضي الله عنه شيبة بن ربيعة وقتله، وفي غزوة الخندق بارز عمرو بن عبد ود فارس قريش وقتله.", "page": 12, "id": "unit-01__lesson-00__b56", "inline": [{"t": "text", "s": "- وعندما نتكلم عن الشباب ورفع راية الجهاد لا ننسى أن نتكلم عن البطل المغوار: علي بن أبي طالب "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ؛ فقد كان اللواء بيده في كثير من المشاهد والغزوات، ودفع الرسول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " الراية يوم بدر إليه، وهو ابن عشرين سنة، وكان حامل الراية يوم خيبر وسنه بالكاد بلغ (25) سنة، وفي غزوة بدر بارز عليٌّ "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " شيبة بن ربيعة وقتله، وفي غزوة الخندق بارز عمرو بن عبد ود فارس قريش وقتله."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وهذا سعد بن أبي وقاص رضي الله عنه وهو أول مَن رمى بسهم في الإسلام، عمره حين استبسل في بدر (17) سنة، حتى إنَّ رسول الله صلى الله عليه وسلم قال له يومها: (ارمِ، فداك أبي وأمي)، ولم يفد صلى الله عليه وسلم أحد بأبويه غيرَه.", "page": 12, "id": "unit-01__lesson-00__b57", "inline": [{"t": "text", "s": "- وهذا سعد بن أبي وقاص "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " وهو أول مَن رمى بسهم في الإسلام، عمره حين استبسل في بدر (17) سنة، حتى إنَّ رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قال له يومها: "}, {"t": "emphasis", "s": "(ارمِ، فداك أبي وأمي)", "role": "emphasis"}, {"t": "text", "s": "، ولم يفد "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أحد بأبويه غيرَه."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وآخر بَعْث أرسله النبي صلى الله عليه وسلم كان بعث أسامة بن زيد رضي الله عنهما ، وكان وقت عينه على إمارة الجيش: شابًا في (17) من عمره وقيل (18) عامًا؛ فعينه النبي صلى الله عليه وسلم على رأس جيش فيه كبار الصحابة رضي الله عنهم ، وعندما تكلَّم بعضُ الناس في إمرته لصغر سنه قال صلى الله عليه وسلم : (لئن تكلموا في إمرته، لقد تكلَّموا في إمرة أبيه من قبل).", "page": 13, "id": "unit-01__lesson-00__b58", "inline": [{"t": "text", "s": "- وآخر بَعْث أرسله النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " كان بعث أسامة بن زيد "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " ، وكان وقت عينه على إمارة الجيش: شابًا في (17) من عمره وقيل (18) عامًا؛ فعينه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " على رأس جيش فيه كبار الصحابة "}, {"t": "honorific", "s": "رضي الله عنهم"}, {"t": "text", "s": " ، وعندما تكلَّم بعضُ الناس في إمرته لصغر سنه قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لئن تكلموا في إمرته، لقد تكلَّموا في إمرة أبيه من قبل)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وأول عمل ابتدأ به أبو بكر رضي الله عنه خلافتَه: إنفاذ جيش أسامة؛ فسيَّره إلى البلقاء ومؤتة وقاتل الروم وانتصر عليهم، وقتل وأسر منهم الكثير، ولم يصب أحدٌ من جيشه بأذى، وكانوا يقولون: «ما رأينا جيشًا أسلم من جيش أسامة».", "page": 13, "id": "unit-01__lesson-00__b59", "inline": [{"t": "text", "s": "- وأول عمل ابتدأ به أبو بكر "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " خلافتَه: إنفاذ جيش أسامة؛ فسيَّره إلى البلقاء ومؤتة وقاتل الروم وانتصر عليهم، وقتل وأسر منهم الكثير، ولم يصب أحدٌ من جيشه بأذى، وكانوا يقولون: "}, {"t": "quote", "s": "ما رأينا جيشًا أسلم من جيش أسامة"}, {"t": "text", "s": "."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- في يوم بدرٍ كان النبي صلى الله عليه وسلم يقول: (مَن فعل كذا وكذا، فله كذا وكذا)، فتسارع إليه الشبان وثبت الشيوخ عند الرايات، وهذا هو الذي جعل النبي صلى الله عليه وسلم يأخذ برأي الشباب في يوم أُحُد ولا يحتقر رأيهَم مع علمه بأنَّ فيه خطرًا؛ فنزل على رأيهم فقاتل خارج المدينة، وهكذا ربَّى النبي صلى الله عليه وسلم أصحابه على الاهتمام بالشباب وأخذ رأيهم، حتى قال الإمام الزهري رحمه الله مُحدِّثًا الشباب: «لا تحتقروا أنفسكم لحداثة أسنانكم، فإن عمرَ رضي الله عنه كان إذا نزل به الأمر المعضل؛ دعا الفتيان واستشارهم يبتغى حدة عقولهم».", "page": 13, "id": "unit-01__lesson-00__b60", "inline": [{"t": "text", "s": "- في يوم بدرٍ كان النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يقول: "}, {"t": "emphasis", "s": "(مَن فعل كذا وكذا، فله كذا وكذا)", "role": "emphasis"}, {"t": "text", "s": "، فتسارع إليه الشبان وثبت الشيوخ عند الرايات، وهذا هو الذي جعل النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يأخذ برأي الشباب في يوم أُحُد ولا يحتقر رأيهَم مع علمه بأنَّ فيه خطرًا؛ فنزل على رأيهم فقاتل خارج المدينة، وهكذا ربَّى النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أصحابه على الاهتمام بالشباب وأخذ رأيهم، حتى قال الإمام الزهري "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " مُحدِّثًا الشباب: "}, {"t": "hadith", "s": "لا تحتقروا أنفسكم لحداثة أسنانكم، فإن عمرَ رضي الله عنه كان إذا نزل به الأمر المعضل؛ دعا الفتيان واستشارهم يبتغى حدة عقولهم", "narrator": null, "source": null, "confidence": "high", "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- ولا ننسى هنا أن نتكلَّم عن معاذ بن عمرو بن الجموح، ومعوذ بن عفراء (ابن الحارث)، فقد كانت نهاية أبي جهل -فرعون هذه الأمة- على يد هذين الغلامين، ففي البخاري عن عبد الرحمن بن عوف رضي الله عنه قال: «إني لفي الصف يوم بدر، إذ التفتُ فإذا عن يميني وعن يساري فتيان حديثا السن، فكأني لم آمن بمكانهما، إذ قال لي أحدهما سرًّا من صاحبه: يا عم، أرني أبا جهل، فقلت: يا ابن أخي، فما تصنع به؟ قال: أُخبرتُ أنه يسب رسول الله صلى الله عليه وسلم ، والذي نفسي بيده، لئن رأيته لا يفارق سوادي سواده حتى يموت الأعجل منَّا، فتعجبت لذلك، وغمزني الآخر فقال لي مثلها -فما سرني أني بين رجلين مكانهما- فلم أنشب أن نظرت إلى أبي جهل يجول في الناس، فقلت: ألا تريان؟ هذا صاحبكما الذي تسألاني عنه - فشدَّا عليه مثل الصقرين - فابتدراه بسيفيهما فضرباه حتى قتلاه، ثم انصرفا إلى رسول الله صلى الله عليه وسلم ، فقال: أيكما قتله؟ فقال كل واحد منهما: أنا قتلته، قال: (هل مسحتما سيفكما؟) فقالا: لا، فنظر رسول الله صلى الله عليه وسلم إلى سيفيهما، فقال: (كِلَاكما قتله)»، وقضى رسول الله بسلبه لمعاذ بن عمرو بن الجموح؛ لأن معوذ بن عفراء قتل شهيدًا في المعركة؛ فانظر أُخيَّ لهذين الشابين عندما غارا على سبَّ النبي صلى الله عليه وسلم ، فقتلا أبا جهل.", "page": 13, "id": "unit-01__lesson-00__b61", "inline": [{"t": "text", "s": "- ولا ننسى هنا أن نتكلَّم عن معاذ بن عمرو بن الجموح، ومعوذ بن عفراء "}, {"t": "emphasis", "s": "(ابن الحارث)", "role": "emphasis"}, {"t": "text", "s": "، فقد كانت نهاية أبي جهل -فرعون هذه الأمة- على يد هذين الغلامين، ففي البخاري عن عبد الرحمن بن عوف "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: "}, {"t": "quote", "s": "إني لفي الصف يوم بدر، إذ التفتُ فإذا عن يميني وعن يساري فتيان حديثا السن، فكأني لم آمن بمكانهما، إذ قال لي أحدهما سرًّا من صاحبه: يا عم، أرني أبا جهل، فقلت: يا ابن أخي، فما تصنع به؟ قال: أُخبرتُ أنه يسب رسول الله صلى الله عليه وسلم ، والذي نفسي بيده، لئن رأيته لا يفارق سوادي سواده حتى يموت الأعجل منَّا، فتعجبت لذلك، وغمزني الآخر فقال لي مثلها -فما سرني أني بين رجلين مكانهما- فلم أنشب أن نظرت إلى أبي جهل يجول في الناس، فقلت: ألا تريان؟ هذا صاحبكما الذي تسألاني عنه - فشدَّا عليه مثل الصقرين - فابتدراه بسيفيهما فضرباه حتى قتلاه، ثم انصرفا إلى رسول الله صلى الله عليه وسلم ، فقال: أيكما قتله؟ فقال كل واحد منهما: أنا قتلته، قال: (هل مسحتما سيفكما؟) فقالا: لا، فنظر رسول الله صلى الله عليه وسلم إلى سيفيهما، فقال: (كِلَاكما قتله)"}, {"t": "text", "s": "، وقضى رسول الله بسلبه لمعاذ بن عمرو بن الجموح؛ لأن معوذ بن عفراء قتل شهيدًا في المعركة؛ فانظر أُخيَّ لهذين الشابين عندما غارا على سبَّ النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، فقتلا أبا جهل."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "وهنا نسأل شباب الإسلام اليوم: هل وجدتَ دمعة في عينيك أو غصة في حلقك، أو حرقة في قلبك عندما سُبَّ النبي صلى الله عليه وسلم في هذا الزمان من قِبل أعداء الإسلام؟ أم أنك تضحك ملء فيك، وتنام ملء عينيك؟ هل وجدت غصة في قلبك حين انتهكت الحرمات؟ واحتل الأقصى؟ وغُيِّب شرع الله عن الحكم في كل بلاد الإسلام؟ والله لا عذر لنا عند الله غدًا إن خلص إلى دين الله تعالى ومقدساتنا، وفينا عين تطرف.", "page": 14, "id": "unit-01__lesson-00__b62", "inline": [{"t": "emphasis", "s": "وهنا نسأل شباب الإسلام اليوم", "role": "emphasis"}, {"t": "text", "s": ": هل وجدتَ دمعة في عينيك أو غصة في حلقك، أو حرقة في قلبك عندما سُبَّ النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في هذا الزمان من قِبل أعداء الإسلام؟ أم أنك تضحك ملء فيك، وتنام ملء عينيك؟ هل وجدت غصة في قلبك حين انتهكت الحرمات؟ واحتل الأقصى؟ وغُيِّب شرع الله عن الحكم في كل بلاد الإسلام؟ والله لا عذر لنا عند الله غدًا إن خلص إلى دين الله تعالى ومقدساتنا، وفينا عين تطرف."}]}, {"type": "paragraph", "md": "تلك نماذج من الصحابة رضي الله عنهم ، وهم قدوتنا الأعظم، ومثلنا الأكمل؛ ونتمم بذكر أمثلة من غيرهم:", "page": 14, "id": "unit-01__lesson-00__b63", "inline": [{"t": "emphasis", "s": "تلك نماذج من الصحابة", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "رضي الله عنهم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "، وهم قدوتنا الأعظم، ومثلنا الأكمل؛ ونتمم بذكر أمثلة من غيرهم:", "role": "emphasis"}]}, {"type": "paragraph", "md": "- القائد الشاب محمد بن القاسم الثقفي: وهو أشهر الفاتحين في زمن بني أمية، قاد الجيوش وهو ابن سبع عشرة سنة، وفتح السند (باكستان) والهند، ووصلت فتوحاته إلى مشارق الأرض.", "page": 14, "id": "unit-01__lesson-00__b64", "inline": [{"t": "text", "s": "- القائد الشاب محمد بن القاسم الثقفي: وهو أشهر الفاتحين في زمن بني أمية، قاد الجيوش وهو ابن سبع عشرة سنة، وفتح السند "}, {"t": "emphasis", "s": "(باكستان)", "role": "emphasis"}, {"t": "text", "s": " والهند، ووصلت فتوحاته إلى مشارق الأرض."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- قتيبة بن مسلم: الذي فتح الحصون، ووصلت فتوحاته إلى الصين، وإلى الجمهوريات المشهورة الآن في روسيا، قاد الجيوش وعمره دون الثلاثين.", "page": 14, "id": "unit-01__lesson-00__b65", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- محمد الفاتح: القائد العظيم، الذي فتح القسطنطينية وهو في (25) من عمره بعدما استعصت على المسلمين طيلة (800) سنة، ونال بذلك بركة دعوة النبي صلى الله عليه وسلم : (لتفتحن القسطنطينية، ولنعم الأمير أميرها، ولنعم الجيش ذلك الجيش) فحقق هذا الشرف وهو في مقتبل شبابه بخطة عبقرية خلدها التاريخ.", "page": 14, "id": "unit-01__lesson-00__b66", "inline": [{"t": "text", "s": "- محمد الفاتح: القائد العظيم، الذي فتح القسطنطينية وهو في (25) من عمره بعدما استعصت على المسلمين طيلة (800) سنة، ونال بذلك بركة دعوة النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لتفتحن القسطنطينية، ولنعم الأمير أميرها، ولنعم الجيش ذلك الجيش)", "role": "emphasis"}, {"t": "text", "s": " فحقق هذا الشرف وهو في مقتبل شبابه بخطة عبقرية خلدها التاريخ."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "فعلى الشباب المسلم أن يعتزَّ بهويته وانتمائه إلى دينه وتراث أمته، ويفتخر ويقتدي بأبطال الإسلام وأعلامه العظام على مر السنين والأعوام.", "page": 14, "id": "unit-01__lesson-00__b67"}, {"type": "paragraph", "md": "فيا شباب الإسلام... يا أملًا يداعب فجرنا الزاهر... ويا صوتا يشيع الرعب في قلب العدو الغادر... ويا درعًا يصون الدين ويحمى عرضنا الطاهر: عودوا إلى ربكم؛ لتعود لنا السيادة والقيادة.", "page": 14, "id": "unit-01__lesson-00__b68"}, {"type": "paragraph", "md": "قال الله تعالى: ﴿هُوَ ٱلَّذِيٓ أَرۡسَلَ رَسُولَهُۥ بِٱلۡهُدَىٰ وَدِينِ ٱلۡحَقِّ لِيُظۡهِرَهُۥ عَلَى ٱلدِّينِ كُلِّهِۦ وَلَوۡ كَرِهَ ٱلۡمُشۡرِكُونَ ۝٩﴾، قال الشافعي رحمه الله : «لَيُظْهِرن الله تعالى دينه على الأديان حتى لا يدانَ اللهُ إلا به، وذلك متى شاء الله تعالى»، والأمة اليوم مستضعفة، وهذا الظهور في الأرض كلها لم يتحقق فلا تزال بلدان كثيرة لم يصلها الدين، وقد وعد النبي صلى الله عليه وسلم بأنه: (ليبْلُغَنَّ هذا الأمر ما بلغ الليل والنهار، ولا يبقى بيت مَدَر ولا وبر إلا أدخلَهُ الله هذا الدين بعزِّ عزيزٍ، أو بذُلِّ ذليل، عزًّا يعزُّ الله به الإسلام، وذلًا يذل به الكفر)، ومن لهذا الفضل وهذه الخيرية إلا شباب المسلمين؛ يحملون الدين على أعناقهم، ويمضون به غيرَ هيابين، حتى يفصل الله بينهم وبين عدوهم، ويعزَّ بهم دينَه، ويُعلي بهم راية شريعته.. أين من يقول؟ أنا لها.. أنا لها.. أنا لها؟!", "page": 14, "id": "unit-01__lesson-00__b69", "inline": [{"t": "text", "s": "قال الله تعالى: "}, {"t": "ayah", "s": "هُوَ ٱلَّذِيٓ أَرۡسَلَ رَسُولَهُۥ بِٱلۡهُدَىٰ وَدِينِ ٱلۡحَقِّ لِيُظۡهِرَهُۥ عَلَى ٱلدِّينِ كُلِّهِۦ وَلَوۡ كَرِهَ ٱلۡمُشۡرِكُونَ ۝٩", "ayah": [9], "verses": [{"n": 9, "text": "هُوَ ٱلَّذِيٓ أَرۡسَلَ رَسُولَهُۥ بِٱلۡهُدَىٰ وَدِينِ ٱلۡحَقِّ لِيُظۡهِرَهُۥ عَلَى ٱلدِّينِ كُلِّهِۦ وَلَوۡ كَرِهَ ٱلۡمُشۡرِكُونَ", "surah": 61, "ref_api": "https://api.quran.com/api/v4/verses/by_key/61:9", "surah_name": "الصف", "ayah_canonical": 9, "match": "exact", "ref": "61:9"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، قال الشافعي "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "لَيُظْهِرن الله تعالى دينه على الأديان حتى لا يدانَ اللهُ إلا به، وذلك متى شاء الله تعالى", "speaker": "الشافعي رحمه الله"}, {"t": "text", "s": "، والأمة اليوم مستضعفة، وهذا الظهور في الأرض كلها لم يتحقق فلا تزال بلدان كثيرة لم يصلها الدين، وقد وعد النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بأنه: "}, {"t": "emphasis", "s": "(ليبْلُغَنَّ هذا الأمر ما بلغ الليل والنهار، ولا يبقى بيت مَدَر ولا وبر إلا أدخلَهُ الله هذا الدين بعزِّ عزيزٍ، أو بذُلِّ ذليل، عزًّا يعزُّ الله به الإسلام، وذلًا يذل به الكفر)", "role": "emphasis"}, {"t": "text", "s": "، ومن لهذا الفضل وهذه الخيرية إلا شباب المسلمين؛ يحملون الدين على أعناقهم، ويمضون به غيرَ هيابين، حتى يفصل الله بينهم وبين عدوهم، ويعزَّ بهم دينَه، ويُعلي بهم راية شريعته.. "}, {"t": "emphasis", "s": "أين من يقول؟ أنا لها.. أنا لها.. أنا لها؟!", "role": "emphasis"}]}, {"type": "paragraph", "md": "اللهم علمنا ما ينفعنا، وزدنًا علمًا وعملًا وجهادًا وإخلاصًا، والحمد لله رب العالمين..", "page": 14, "id": "unit-01__lesson-00__b70"}]' WHERE id='unit-01__lesson-00';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 14, "id": "unit-02__lesson-01__b01", "role": "objectives"}, {"type": "paragraph", "md": "يذكر الهدف العام لجزء عم، ولسورة الفاتحة والناس، ويتعرف على خصائص القرآن المكي.", "page": 14, "id": "unit-02__lesson-01__b02"}, {"type": "paragraph", "md": "يبين فضل سورة الفاتحة، المعوذتين ويتعود أن يتلوا هذه السور العظيمة في كل حين.", "page": 14, "id": "unit-02__lesson-01__b03"}, {"type": "paragraph", "md": "يحفظ هذه السور بضبط وإتقان، بعد معرفة الألفاظ الغريبة الواردة فيها.", "page": 14, "id": "unit-02__lesson-01__b04"}, {"type": "heading", "level": 3, "text": "مقدمة عن جزء عمَّ «الجزء الثلاثون من القرآن الكريم»:", "page": 14, "id": "unit-02__lesson-01__b05", "role": "intro"}, {"type": "paragraph", "md": "هو الجزء الثلاثون والأخير من القرآن الكريم، وقد بدأنا به لسهولة حفظه، ولأن عادة السلف في تحفيظ أبنائهم أن يبدأوا بقصار السور، وهو جزء غالب سوره مكية إلا عددا يسيرا من سوره نزلت في المدينة.", "page": 14, "id": "unit-02__lesson-01__b06"}, {"type": "paragraph", "md": "ومن خصائص القرآن المكي والسور المكية أنها تتميز بعدة خصائص، منها:", "page": 14, "id": "unit-02__lesson-01__b07", "inline": [{"t": "emphasis", "s": "ومن خصائص القرآن المكي والسور المكية أنها تتميز بعدة خصائص، منها:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1-تتناول العقيدة الإسلامية وأنها الحق المنزلة من عند الله تعالى، وأما عقيدة الكفار فهي فاسدة باطلة.", "page": 14, "id": "unit-02__lesson-01__b08"}, {"type": "paragraph", "md": "2-تنبه إلى الأفعال المرفوضة في الإسلام مثل قتل البنات والتلاعب في الميزان واستغلال أموال اليتامى والمساكين وسفك الدماء البريئة، وتوجِّه المشركين إلى قيم وأخلاقيات صحيحة جاء بها الإسلام.", "page": 14, "id": "unit-02__lesson-01__b09"}, {"type": "paragraph", "md": "3-تحتوي على قصص الأنبياء والأمم السابقة كعبرة وعظة لمن يتذكر هلاك المكذبين السابقين.", "page": 14, "id": "unit-02__lesson-01__b10"}, {"type": "paragraph", "md": "4-تتميز بقصر آياتها ليسهل على المؤمنين حفظها وتلاوتها بسهولة ويُسر.", "page": 14, "id": "unit-02__lesson-01__b11"}, {"type": "paragraph", "md": "عدد سور جزء عمَّ: 37 سورة، وتسمى السور من الضحى إلى الناس: «قصار السور» أو «قصار المفصل».", "page": 14, "id": "unit-02__lesson-01__b12", "inline": [{"t": "emphasis", "s": "عدد سور جزء عمَّ", "role": "emphasis"}, {"t": "text", "s": ": 37 سورة، وتسمى السور من الضحى إلى الناس: "}, {"t": "quote", "s": "قصار السور"}, {"t": "text", "s": " أو "}, {"t": "quote", "s": "قصار المفصل"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "تفسير سورة الفاتحة", "page": 14, "id": "unit-02__lesson-01__b13", "role": "tafsir"}, {"type": "paragraph", "md": "أسماؤها: 1-فاتحة الكِتاب. 2-أمُّ القرآن. 3-أُمُّ الكِتاب. 4-السَّبْع المَثاني. 5-القُرآن العظيم. 6-سورة الحَمْد.", "page": 14, "id": "unit-02__lesson-01__b14"}, {"type": "heading", "level": 3, "text": "فضل سورة الفاتحة -لها فضائل كثيرة في السنة نذكر بعضها-:", "page": 14, "id": "unit-02__lesson-01__b15", "role": "virtues"}, {"type": "paragraph", "md": "1- أنَّها نور، ولم يُؤْتَها نبيٌّ قبل محمَّدٍ صلى الله عليه وسلم ، فعن ابن عباس رضي الله عنهما قال: (بينما جبريلُ قاعدٌ عند النبيِّ صلى الله عليه وسلم ، سمِع نقيضًا من فوقه؛ فرفَع رأسَه، فقال: هذا بابٌ من السَّماء فُتِح اليوم، لم يُفتح قطُّ إلَّا اليوم، فنزل منه مَلَك، فقال: هذا ملَكٌ نزل إلى الأرض، لم ينزلْ قطُّ إلَّا اليوم، فسلَّم، وقال: أبشِرْ بنورَينِ أوتيتَهما، لم يُؤتَهما نبيٌّ قبلك: فاتحة الكتاب، وخواتيم سورة البقرة، لن تَقرأ بحرفٍ منهما إلَّا أُعطيتَه).", "page": 15, "id": "unit-02__lesson-01__b16", "inline": [{"t": "text", "s": "1- أنَّها نور، ولم يُؤْتَها نبيٌّ قبل محمَّدٍ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، فعن ابن عباس "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " قال: "}, {"t": "emphasis", "s": "(بينما جبريلُ قاعدٌ عند النبيِّ", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "، سمِع نقيضًا من فوقه؛ فرفَع رأسَه، فقال: هذا بابٌ من السَّماء فُتِح اليوم، لم يُفتح قطُّ إلَّا اليوم، فنزل منه مَلَك، فقال: هذا ملَكٌ نزل إلى الأرض، لم ينزلْ قطُّ إلَّا اليوم، فسلَّم، وقال: أبشِرْ بنورَينِ أوتيتَهما، لم يُؤتَهما نبيٌّ قبلك: فاتحة الكتاب، وخواتيم سورة البقرة، لن تَقرأ بحرفٍ منهما إلَّا أُعطيتَه)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- بقِراءتها تحصُل المناجاةُ في الصَّلاة بين العَبدِ وربِّه؛ بل هي الصلاة بذاتها كما في حديث أبي هُرَيرَة رضي الله عنه ، عن النبيَّ صلى الله عليه وسلم قال: (مَن صلَّى صلاةً لم يقرأْ فيها بأُمِّ القرآن، فهي خداجٌ -ثلاثًا- غير تمام، فقيل لأبي هُرَيرَة: إنَّا نكونُ وراءَ الإمام، فقال: اقرأْ بها في نفسِك؛ فإنِّي سمعتُ رسولَ الله صلى الله عليه وسلم يقول: قال الله تعالى: قسمتُ الصلاة بَيني وبَين عبدي نِصفين، ولعَبدي ما سأل، فإذا قال العبدُ: الحمدُ لله ربِّ العالَمين، قال الله تعالى: حمَدني عَبدي، وإذا قال: الرَّحمن الرَّحيم، قال الله تعالى: أثْنَى عليَّ عبدي، وإذا قال: مالِك يومِ الدِّين، قال: مَجَّدني عبدي، فإذا قال: إيَّاك نعبُدُ وإيَّاك نستعين، قال: هذا بَيني وبَين عبدي، ولعَبدي ما سأل، فإذا قال: اهدِنا الصِّراطَ المستقيمَ صِراطَ الذين أنعمت عليهم غير المغضوب عليهم ولا الضالِّين، قال: هذا لعَبدي، ولعبدي ما سألَ).", "page": 15, "id": "unit-02__lesson-01__b17", "inline": [{"t": "text", "s": "2- بقِراءتها تحصُل المناجاةُ في الصَّلاة بين العَبدِ وربِّه؛ بل هي الصلاة بذاتها كما في حديث أبي هُرَيرَة "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ، عن النبيَّ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قال: "}, {"t": "emphasis", "s": "(مَن صلَّى صلاةً لم يقرأْ فيها بأُمِّ القرآن، فهي خداجٌ -ثلاثًا- غير تمام،", "role": "emphasis"}, {"t": "text", "s": " فقيل لأبي هُرَيرَة: إنَّا نكونُ وراءَ الإمام، فقال: اقرأْ بها في نفسِك؛ فإنِّي سمعتُ رسولَ الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يقول: "}, {"t": "emphasis", "s": "قال الله تعالى: قسمتُ الصلاة بَيني وبَين عبدي نِصفين، ولعَبدي ما سأل، فإذا قال العبدُ: الحمدُ لله ربِّ العالَمين، قال الله تعالى: حمَدني عَبدي، وإذا قال: الرَّحمن الرَّحيم، قال الله تعالى: أثْنَى عليَّ عبدي، وإذا قال: مالِك يومِ الدِّين، قال: مَجَّدني عبدي، فإذا قال: إيَّاك نعبُدُ وإيَّاك نستعين، قال: هذا بَيني وبَين عبدي، ولعَبدي ما سأل، فإذا قال: اهدِنا الصِّراطَ المستقيمَ صِراطَ الذين أنعمت عليهم غير المغضوب عليهم ولا الضالِّين، قال: هذا لعَبدي، ولعبدي ما سألَ", "role": "emphasis"}, {"t": "text", "s": ")."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أنَّه لا صَلاةَ لِمَن لم يقرأْ بها: فقد قال صلى الله عليه وسلم : (لا صَلاةَ لِمَن لم يقرأْ بفاتحةِ الكِتابِ).", "page": 15, "id": "unit-02__lesson-01__b18", "inline": [{"t": "text", "s": "3- أنَّه لا صَلاةَ لِمَن لم يقرأْ بها: فقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لا صَلاةَ لِمَن لم يقرأْ بفاتحةِ الكِتابِ)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- أنها رقيةٌ شافيةٌ بإذن الله تعالى: فقد رقى بها بعض أصحاب النبي صلى الله عليه وسلم رجلا ملدوغًا، ثم سألوا النبي صلى الله عليه وسلم عن ذلك، فأقرهم عليها، وقال: (وما يُدريك أنَّها رُقيةٌ؟! قد أصبتُم).", "page": 15, "id": "unit-02__lesson-01__b19", "inline": [{"t": "text", "s": "4- أنها رقيةٌ شافيةٌ بإذن الله تعالى: فقد رقى بها بعض أصحاب النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " رجلا ملدوغًا، ثم سألوا النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " عن ذلك، فأقرهم عليها، وقال: "}, {"t": "emphasis", "s": "(وما يُدريك أنَّها رُقيةٌ؟! قد أصبتُم)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "من أهم الموضوعات التي اشتملت عليها هذه السورة:", "page": 15, "id": "unit-02__lesson-01__b20", "role": "main_themes"}, {"type": "paragraph", "md": "1- صفات الله عز وجل . 2- اليوم الآخر. 3- إِفراد الله تعالى بالعبادة، ومن ذلك: الاستعانة، والدُّعاء.", "page": 15, "id": "unit-02__lesson-01__b21", "inline": [{"t": "text", "s": "1- صفات الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " . 2- اليوم الآخر. 3- إِفراد الله تعالى بالعبادة، ومن ذلك: الاستعانة، والدُّعاء."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "4- التعريف بالصِّراط المستقيم؛ طريقِ المهتدين. 5-تجنُّب طريق الغاوين المغضوبِ عليهم والضالِّين.", "page": 15, "id": "unit-02__lesson-01__b22", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "افتَتح الله كتابه بهذه السورة؛ لأنَّها جمَعتْ مقاصد القرآن، ولأنَّ فيها إجمالَ ما يحويه القرآن مفصلًا؛ فجميع القرآن تفصيل لِمَا أجملتْه، وفي ذلك براعة استهلال؛ فهي مثل دِيباجة الخطبة أو الكتاب.", "page": 15, "id": "unit-02__lesson-01__b23"}, {"type": "paragraph", "md": "الاستعاذة: مشروعة قبل تلاوة القرآن بلفظ: «أعوذ بالله من الشيطان الرجيم»، وهي ليست آية، ومعناه: أستجير وألتجئ بالله المعبودِ الحق سبحانه من كل شطيانٍ جان متمرد، مطرود عن كل خير.", "page": 15, "id": "unit-02__lesson-01__b24", "inline": [{"t": "text", "s": "الاستعاذة: مشروعة قبل تلاوة القرآن بلفظ: "}, {"t": "quote", "s": "أعوذ بالله من الشيطان الرجيم"}, {"t": "text", "s": "، وهي ليست آية، ومعناه: أستجير وألتجئ بالله المعبودِ الحق سبحانه من كل شطيانٍ جان متمرد، مطرود عن كل خير."}]}, {"type": "paragraph", "md": "والشيطان في اللغة مشتق من شَطَن إذا بعد؛ فهو بعيد بطبعه عن طباع البشر، وبعيد بفسقه عن كل خير.", "page": 15, "id": "unit-02__lesson-01__b25", "inline": [{"t": "emphasis", "s": "والشيطان", "role": "emphasis"}, {"t": "text", "s": " في اللغة مشتق من شَطَن إذا بعد؛ فهو بعيد بطبعه عن طباع البشر، وبعيد بفسقه عن كل خير."}]}, {"type": "paragraph", "md": "البسملة؛ قول «بسم الله الرحمن الرحيم»، وتعني: باسم الله وحده أقرأ أو أتلو، متبركًا بالبداءة باسم المعبود الحق تبارك وتعالى، ذي الرحمة الواسعة لجميع خلقه، وذي الرحمة الخاصة بعباده المؤمنين.", "page": 15, "id": "unit-02__lesson-01__b26", "inline": [{"t": "text", "s": "البسملة؛ قول "}, {"t": "quote", "s": "بسم الله الرحمن الرحيم"}, {"t": "text", "s": "، وتعني: باسم الله وحده أقرأ أو أتلو، متبركًا بالبداءة باسم المعبود الحق "}, {"t": "honorific", "s": "تبارك وتعالى"}, {"t": "text", "s": "، ذي الرحمة الواسعة لجميع خلقه، وذي الرحمة الخاصة بعباده المؤمنين."}]}, {"type": "paragraph", "md": "والبسملة آية من الفاتحة عند الشافعية، وليست آية منها عند الجمهور، ولكل أدلته لكن دليل الجمهور أقوى وهو حديث أبي هريرة المتقدم (جعلت الصلاة بيني وبين عبدي نصفين) ولم يذكر منها البسملة، وبهذا يجعلون الآية السابعة تبدأ بـ: ﴿غَيۡرِ ٱلۡمَغۡضُوبِ﴾ وهذا الخلاف بين المذاهب امتد كذلك للقراءات.", "page": 15, "id": "unit-02__lesson-01__b27", "inline": [{"t": "text", "s": "والبسملة آية من الفاتحة عند الشافعية، وليست آية منها عند الجمهور، ولكل أدلته لكن دليل الجمهور أقوى وهو حديث أبي هريرة المتقدم ("}, {"t": "emphasis", "s": "جعلت الصلاة بيني وبين عبدي نصفين", "role": "emphasis"}, {"t": "text", "s": ") ولم يذكر منها البسملة، وبهذا يجعلون الآية السابعة تبدأ بـ: "}, {"t": "ayah", "s": "غَيۡرِ ٱلۡمَغۡضُوبِ", "ayah": [], "verses": [{"n": 7, "text": "غَيۡرِ ٱلۡمَغۡضُوبِ", "surah": 1, "surah_name": "الفاتحة", "ref": "1:7", "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:7"}], "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:7", "surah_name": "الفاتحة", "ayah_canonical": 7, "match": "contained", "ref": "1:7"}, {"t": "text", "s": " وهذا الخلاف بين المذاهب امتد كذلك للقراءات."}]}, {"type": "heading", "level": 3, "text": "تفسير السورة وغريبها:", "page": 16, "id": "unit-02__lesson-01__b28", "role": "vocabulary"}, {"type": "paragraph", "md": "﴿ٱلۡحَمۡدُۖ﴾ هو وصفُ المحمود سبحانه بالكَمال، مع محبَّته، وتعظيمِه جل وعلا .", "page": 16, "id": "unit-02__lesson-01__b29", "inline": [{"t": "ayah", "s": "ٱلۡحَمۡدُۖ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": " هو وصفُ المحمود سبحانه بالكَمال، مع محبَّته، وتعظيمِه "}, {"t": "honorific", "s": "جل وعلا"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "﴿ٱللَّهُ﴾: اسمٌ ثابتٌ له سبحانه، يتضمَّن صِفةَ الألوهيَّة له عز وجل ، ومعناه: المألوه، أي: المعبود سبحانه وتعالى .", "page": 16, "id": "unit-02__lesson-01__b30", "inline": [{"t": "ayah", "s": "ٱللَّهُ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": ": اسمٌ ثابتٌ له سبحانه، يتضمَّن صِفةَ الألوهيَّة له "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، ومعناه: المألوه، أي: المعبود "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "﴿الرَّبُّ﴾: السيِّد، والمالِك، والمربِّي، والخالِق، والمعبود.", "page": 16, "id": "unit-02__lesson-01__b31", "inline": [{"t": "ayah", "s": "الرَّبُّ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": ": السيِّد، والمالِك، والمربِّي، والخالِق، والمعبود."}]}, {"type": "paragraph", "md": "﴿ٱلرَّحۡمَٰنُ ٱلرَّحِيمُ﴾: اسمانِ مشتقَّان من الرَّحمة على وجه المبالَغة، ورحمن أشدُّ مبالغةً من رَحيم؛ لأنَّ «رحمن» على وزن فعلان، وهذه الصيغة تفيد الكثرة والسعة؛ فالرَّحْمَن: ذو الرَّحمة الواسِعة لجميع خلقه، والرَّحِيم: ذو رحمةٍ خاصَّة، يختصُّ بها عبادَه المؤمنين، قال تعالى: ﴿وَكَانَ بِٱلۡمُؤۡمِنِينَ رَحِيمٗا﴾ [الأحزاب: 43].", "page": 16, "id": "unit-02__lesson-01__b32", "inline": [{"t": "ayah", "s": "ٱلرَّحۡمَٰنُ ٱلرَّحِيمُ", "ayah": [], "verses": [{"n": 3, "text": "ٱلرَّحۡمَٰنُ ٱلرَّحِيمُ", "surah": 1, "surah_name": "الفاتحة", "ref": "1:3", "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:3"}], "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:3", "surah_name": "الفاتحة", "ayah_canonical": 3, "match": "exact", "ref": "1:3"}, {"t": "text", "s": ": اسمانِ مشتقَّان من الرَّحمة على وجه المبالَغة، ورحمن أشدُّ مبالغةً من رَحيم؛ لأنَّ "}, {"t": "quote", "s": "رحمن"}, {"t": "text", "s": " على وزن فعلان، وهذه الصيغة تفيد الكثرة والسعة؛ فالرَّحْمَن: ذو الرَّحمة الواسِعة لجميع خلقه، والرَّحِيم: ذو رحمةٍ خاصَّة، يختصُّ بها عبادَه المؤمنين، قال تعالى: "}, {"t": "ayah", "s": "وَكَانَ بِٱلۡمُؤۡمِنِينَ رَحِيمٗا", "ayah": [], "verses": [{"n": 43, "text": "وَكَانَ بِٱلۡمُؤۡمِنِينَ رَحِيمٗا", "surah": 33, "surah_name": "الأحزاب", "ref": "33:43", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:43"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:43", "surah_name": "الأحزاب", "ayah_canonical": 43, "match": "contained", "ref": "33:43"}, {"t": "text", "s": " [الأحزاب: 43]."}]}, {"type": "paragraph", "md": "﴿مَٰلِكِ يَوۡمِ ٱلدِّينِ ۝٤﴾ أي: إنَّ اللهَ عز وجل هو المتصرِّف في جميع خلْقِه بالقول والفِعل، و﴿يَوۡمِ ٱلدِّينِ﴾؛ أي: يوم القيامة وهو يوم الجَزاء والحِساب؛ مأخوذ من الإدانة وهي المحاسبة.", "page": 16, "id": "unit-02__lesson-01__b33", "inline": [{"t": "ayah", "s": "مَٰلِكِ يَوۡمِ ٱلدِّينِ ۝٤", "ayah": [4], "verses": [{"n": 4, "text": "مَٰلِكِ يَوۡمِ ٱلدِّينِ", "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:4", "surah_name": "الفاتحة", "ayah_canonical": 4, "match": "exact", "ref": "1:4"}], "surah": null, "ref_api": null}, {"t": "text", "s": " أي: إنَّ اللهَ "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " هو المتصرِّف في جميع خلْقِه بالقول والفِعل، و"}, {"t": "ayah", "s": "يَوۡمِ ٱلدِّينِ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ أي: يوم القيامة وهو يوم الجَزاء والحِساب؛ مأخوذ من الإدانة وهي المحاسبة."}]}, {"type": "paragraph", "md": "﴿ٱلصِّرَٰطَ ٱلۡمُسۡتَقِيمَ ۝١١٨﴾: الطَّريق الواضح الذي لا اعوجاجَ فيه؛ فهو طريق واحد مستقيم وما سواه مُعْوَجٌّ.", "page": 16, "id": "unit-02__lesson-01__b34", "inline": [{"t": "ayah", "s": "ٱلصِّرَٰطَ ٱلۡمُسۡتَقِيمَ ۝١١٨", "ayah": [118], "verses": [{"n": 118, "text": "ٱلصِّرَٰطَ ٱلۡمُسۡتَقِيمَ", "surah": 37, "ref_api": "https://api.quran.com/api/v4/verses/by_key/37:118", "surah_name": "الصافات", "ayah_canonical": 118, "match": "contained", "ref": "37:118"}], "surah": null, "ref_api": null}, {"t": "text", "s": ": الطَّريق الواضح الذي لا اعوجاجَ فيه؛ فهو طريق واحد مستقيم وما سواه مُعْوَجٌّ."}]}, {"type": "paragraph", "md": "﴿صِرَٰطَ ٱلَّذِينَ أَنۡعَمۡتَ عَلَيۡهِمۡ﴾ أي: طريق الذين أَنعمَ الله تعالى عليهم بالهِداية إليه، وهم الذين علِموا الحقَّ وعمِلوا به؛ امتثالًا لأمرِ عز وجل ، واجتنابًا لنهيه سبحانه وتعالى ، بإخلاصٍ لله تعالى، ومتابعةٍ للرَّسول صلى الله عليه وسلم .", "page": 16, "id": "unit-02__lesson-01__b35", "inline": [{"t": "ayah", "s": "صِرَٰطَ ٱلَّذِينَ أَنۡعَمۡتَ عَلَيۡهِمۡ", "ayah": [], "verses": [{"n": 7, "text": "صِرَٰطَ ٱلَّذِينَ أَنۡعَمۡتَ عَلَيۡهِمۡ", "surah": 1, "surah_name": "الفاتحة", "ref": "1:7", "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:7"}], "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:7", "surah_name": "الفاتحة", "ayah_canonical": 7, "match": "contained", "ref": "1:7"}, {"t": "text", "s": " أي: طريق الذين أَنعمَ الله تعالى عليهم بالهِداية إليه، وهم الذين علِموا الحقَّ وعمِلوا به؛ امتثالًا لأمرِ "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، واجتنابًا لنهيه "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، بإخلاصٍ لله تعالى، ومتابعةٍ للرَّسول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "﴿غَيۡرِ ٱلۡمَغۡضُوبِ عَلَيۡهِمۡ﴾ أي: إنَّ مِن صفات الذين أَنعم الله تعالى عليهم، أنَّهم ليسوا كاليهود، ومَن سلَك طريقتَهم في ترْك العمل بالحقِّ بعد معرفته؛ فأخصُّ أوصاف اليهود: غضبُ الله عليهم.", "page": 16, "id": "unit-02__lesson-01__b36", "inline": [{"t": "ayah", "s": "غَيۡرِ ٱلۡمَغۡضُوبِ عَلَيۡهِمۡ", "ayah": [], "verses": [{"n": 7, "text": "غَيۡرِ ٱلۡمَغۡضُوبِ عَلَيۡهِمۡ", "surah": 1, "surah_name": "الفاتحة", "ref": "1:7", "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:7"}], "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:7", "surah_name": "الفاتحة", "ayah_canonical": 7, "match": "contained", "ref": "1:7"}, {"t": "text", "s": " أي: إنَّ مِن صفات الذين أَنعم الله تعالى عليهم، أنَّهم ليسوا كاليهود، ومَن سلَك طريقتَهم في ترْك العمل بالحقِّ بعد معرفته؛ فأخصُّ أوصاف اليهود: غضبُ الله عليهم."}]}, {"type": "paragraph", "md": "﴿وَلَا ٱلضَّآلِّينَ ۝٧﴾: أي: إنَّ من صِفات الذين أنعمَ الله تعالى عليهم، أنَّهم ليسوا كالنَّصارى، ومَن سلك طريقتَهم ممَّن جهِلوا الحقَّ، فعبَدوا الله تعالى بغير عِلم؛ فأخصُّ أوصاف النصارى: الضلال في عملهم.", "page": 16, "id": "unit-02__lesson-01__b37", "inline": [{"t": "ayah", "s": "وَلَا ٱلضَّآلِّينَ ۝٧", "ayah": [7], "verses": [{"n": 7, "text": "وَلَا ٱلضَّآلِّينَ", "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:7", "surah_name": "الفاتحة", "ayah_canonical": 7, "match": "contained", "ref": "1:7"}], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي: إنَّ من صِفات الذين أنعمَ الله تعالى عليهم، أنَّهم ليسوا كالنَّصارى، ومَن سلك طريقتَهم ممَّن جهِلوا الحقَّ، فعبَدوا الله تعالى بغير عِلم؛ فأخصُّ أوصاف النصارى: الضلال في عملهم."}]}, {"type": "paragraph", "md": "المعنى الإجمالي: يخبر اللهُ عبادَه بأنَّ الحمد الكامل مستحَقٌّ له وحده، ويرشدهم إلى أن يُثنوا عليه، ويمجِّدوه، ويَحمَدوه بجميع المحامِد التي لا يستحقُّها إلَّا هو، لأنه سبحانه ذو الرَّحمة والمُلك، ويُرشدهم سبحانه وتعالى إلى إفرادِه بالعبادة والاستعانة، وطلبِ الهِداية منه وحْده للطَّريق الواضحة التي لا اعوجاجَ فيها، وهي طريق الذين أنعم الله عليهم، لا طريق اليهود المغضوب عليهم، ولا طريق النَّصارى الضالِّين.", "page": 16, "id": "unit-02__lesson-01__b38", "inline": [{"t": "emphasis", "s": "المعنى الإجمالي:", "role": "lemma"}, {"t": "text", "s": " يخبر اللهُ عبادَه بأنَّ الحمد الكامل مستحَقٌّ له وحده، ويرشدهم إلى أن يُثنوا عليه، ويمجِّدوه، ويَحمَدوه بجميع المحامِد التي لا يستحقُّها إلَّا هو، لأنه سبحانه ذو الرَّحمة والمُلك، ويُرشدهم "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " إلى إفرادِه بالعبادة والاستعانة، وطلبِ الهِداية منه وحْده للطَّريق الواضحة التي لا اعوجاجَ فيها، وهي طريق الذين أنعم الله عليهم، لا طريق اليهود المغضوب عليهم، ولا طريق النَّصارى الضالِّين."}]}, {"type": "heading", "level": 3, "text": "الفوائد التربوية:", "page": 16, "id": "unit-02__lesson-01__b39", "role": "benefits"}, {"type": "paragraph", "md": "1- لما كان أوَّلُ السُّورة مشتملًا على الحمد لله، وتمجيده، وآخرُها مشتملًا على الذمِّ للمعرضين عن الإيمان به، والإقرار بطاعته؛ دلَّ ذلك على أنَّ: مَطلع الخيرات، وعُنوان السعادات، هو الإقبالُ على الله عز وجل ، ومطلعَ الآفات، ورأس المخالفات، هو الإعراضُ عنه سبحانه، والبعدُ عن طاعته.", "page": 17, "id": "unit-02__lesson-01__b40", "inline": [{"t": "text", "s": "1- لما كان أوَّلُ السُّورة مشتملًا على الحمد لله، وتمجيده، وآخرُها مشتملًا على الذمِّ للمعرضين عن الإيمان به، والإقرار بطاعته؛ دلَّ ذلك على أنَّ: مَطلع الخيرات، وعُنوان السعادات، هو الإقبالُ على الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، ومطلعَ الآفات، ورأس المخالفات، هو الإعراضُ عنه سبحانه، والبعدُ عن طاعته."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- أنَّ الله تعالى مستحقٌّ للحَمدِ الكامِل، ومختصٌّ به من جميع الوجوه، ولذا ينبغي على العبد أن يستشعرَ بأنَّ كلَّ قضاءٍ لله تعالى؛ فهو محمودٌ عليه جل وعلا .", "page": 17, "id": "unit-02__lesson-01__b41", "inline": [{"t": "text", "s": "2- أنَّ الله تعالى مستحقٌّ للحَمدِ الكامِل، ومختصٌّ به من جميع الوجوه، ولذا ينبغي على العبد أن يستشعرَ بأنَّ كلَّ قضاءٍ لله تعالى؛ فهو محمودٌ عليه "}, {"t": "honorific", "s": "جل وعلا"}, {"t": "text", "s": " ."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أنَّ في قوله: ﴿مَٰلِكِ يَوۡمِ ٱلدِّينِ ۝٤﴾ حثٌّ بلإنسانِ على أنْ يعملَ لذلك اليوم الذي يُدان فيه العاملون.", "page": 17, "id": "unit-02__lesson-01__b42", "inline": [{"t": "text", "s": "3- أنَّ في قوله: "}, {"t": "ayah", "s": "مَٰلِكِ يَوۡمِ ٱلدِّينِ ۝٤", "ayah": [4], "verses": [{"n": 4, "text": "مَٰلِكِ يَوۡمِ ٱلدِّينِ", "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:4", "surah_name": "الفاتحة", "ayah_canonical": 4, "match": "exact", "ref": "1:4"}], "surah": null, "ref_api": null}, {"t": "text", "s": " حثٌّ بلإنسانِ على أنْ يعملَ لذلك اليوم الذي يُدان فيه العاملون."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "5- قوله تعالى: ﴿إِيَّاكَ نَعۡبُدُ﴾ تبرؤ من الشرك، وقوله: ﴿وَإِيَّاكَ نَسۡتَعِينُ ۝٥﴾ تبرؤ من الحول والقوة، وتفويض إلى الله عز وجل ، وهذا كقوله تعالى: ﴿فَٱعۡبُدۡهُ وَتَوَكَّلۡ عَلَيۡهِۚ﴾؛ لذا فالفاتحة سرُّ القرآن، وسرُّها هذه الآية.", "page": 17, "id": "unit-02__lesson-01__b43", "inline": [{"t": "text", "s": "5- قوله تعالى: "}, {"t": "ayah", "s": "إِيَّاكَ نَعۡبُدُ", "ayah": [], "verses": [{"n": 5, "text": "إِيَّاكَ نَعۡبُدُ", "surah": 1, "surah_name": "الفاتحة", "ref": "1:5", "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:5"}], "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:5", "surah_name": "الفاتحة", "ayah_canonical": 5, "match": "contained", "ref": "1:5"}, {"t": "text", "s": " تبرؤ من الشرك، وقوله: "}, {"t": "ayah", "s": "وَإِيَّاكَ نَسۡتَعِينُ ۝٥", "ayah": [5], "verses": [{"n": 5, "text": "وَإِيَّاكَ نَسۡتَعِينُ", "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:5", "surah_name": "الفاتحة", "ayah_canonical": 5, "match": "contained", "ref": "1:5"}], "surah": null, "ref_api": null}, {"t": "text", "s": " تبرؤ من الحول والقوة، وتفويض إلى الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، وهذا كقوله تعالى: "}, {"t": "ayah", "s": "فَٱعۡبُدۡهُ وَتَوَكَّلۡ عَلَيۡهِۚ", "ayah": [], "verses": [{"n": 123, "text": "فَٱعۡبُدۡهُ وَتَوَكَّلۡ عَلَيۡهِۚ", "surah": 11, "surah_name": "هود", "ref": "11:123", "ref_api": "https://api.quran.com/api/v4/verses/by_key/11:123"}], "surah": 11, "ref_api": "https://api.quran.com/api/v4/verses/by_key/11:123", "surah_name": "هود", "ayah_canonical": 123, "match": "contained", "ref": "11:123"}, {"t": "text", "s": "؛ لذا فالفاتحة سرُّ القرآن، وسرُّها هذه الآية."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- تربية المسلم على اللُّجوء إلى الله عز وجل ، ومِن ذلك استعانتُه به على العبادة، ودعاؤه دومًا أن يَهديَه.", "page": 17, "id": "unit-02__lesson-01__b44", "inline": [{"t": "text", "s": "6- تربية المسلم على اللُّجوء إلى الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، ومِن ذلك استعانتُه به على العبادة، ودعاؤه دومًا أن يَهديَه."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "heading", "level": 3, "text": "الفوا ئد العلمية واللطائف:", "page": 17, "id": "unit-02__lesson-01__b45", "role": "section"}, {"type": "paragraph", "md": "1- في قوله تعالى: ﴿ٱلۡحَمۡدُ لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ ۝٦٥﴾ تقديم وصْفِ الله تعالى بالألوهيَّة على وصفه بالربوبية؛ لأنَّ (الله) هو الاسمُ العَلَم الخاصُّ به، والذي تتبعه كل الأسماء؛ وإمَّا لأنَّ الذين جاءتهم الرُّسُل يُنكرون الألوهيَّة، ولأن اسم الله تعالى دالٌّ على كونه مألوهًا معبودًا، تؤلِّهه الخلائق محبَّةً وتعظيمًا وخضوعًا.", "page": 17, "id": "unit-02__lesson-01__b46", "inline": [{"t": "text", "s": "1- في قوله تعالى: "}, {"t": "ayah", "s": "ٱلۡحَمۡدُ لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ ۝٦٥", "ayah": [65], "verses": [{"n": 65, "text": "ٱلۡحَمۡدُ لِلَّهِ رَبِّ ٱلۡعَٰلَمِينَ", "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:2", "surah_name": "الفاتحة", "ayah_canonical": 2, "match": "exact", "ref": "1:2"}], "surah": null, "ref_api": null}, {"t": "text", "s": " تقديم وصْفِ الله تعالى بالألوهيَّة على وصفه بالربوبية؛ لأنَّ "}, {"t": "emphasis", "s": "(الله)", "role": "emphasis"}, {"t": "text", "s": " هو الاسمُ العَلَم الخاصُّ به، والذي تتبعه كل الأسماء؛ وإمَّا لأنَّ الذين جاءتهم الرُّسُل يُنكرون الألوهيَّة، ولأن اسم الله تعالى دالٌّ على كونه مألوهًا معبودًا، تؤلِّهه الخلائق محبَّةً وتعظيمًا وخضوعًا."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- في قوله تعالى: ﴿يَوۡمُ ٱلدِّينِ ۝١٨﴾ إثباتُ البَعث والجزاء؛ فالدِّين هو الحساب الذي يكون يوم القيامة.", "page": 17, "id": "unit-02__lesson-01__b47", "inline": [{"t": "text", "s": "2- في قوله تعالى: "}, {"t": "ayah", "s": "يَوۡمُ ٱلدِّينِ ۝١٨", "ayah": [18], "verses": [{"n": 18, "text": "يَوۡمُ ٱلدِّينِ", "surah": 82, "ref_api": "https://api.quran.com/api/v4/verses/by_key/82:18", "surah_name": "الإنفطار", "ayah_canonical": 18, "match": "contained", "ref": "82:18"}], "surah": null, "ref_api": null}, {"t": "text", "s": " إثباتُ البَعث والجزاء؛ فالدِّين هو الحساب الذي يكون يوم القيامة."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ذكر الله إلهيته وربوبيته ورحمته ومُلكَه؛ لأن هذه الصفات الأربع مستلزمة لجميع صفات كماله عز وجل .", "page": 17, "id": "unit-02__lesson-01__b48", "inline": [{"t": "text", "s": "3- ذكر الله إلهيته وربوبيته ورحمته ومُلكَه؛ لأن هذه الصفات الأربع مستلزمة لجميع صفات كماله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- إسنادُ النِّعمة إلى الله تعالى وحْدَه في هِداية الَّذين أنعم عليهم؛ لأنَّها فضلٌ محضٌ من الله.", "page": 17, "id": "unit-02__lesson-01__b49", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "6- قدَّم المغضوب عليهم اليهود على الضالِّين النصارى؛ لأنَّهم أشدُّ مخالفةً للحقِّ من الضالِّين؛ فإنَّ المخالف عن علم يصعُب رجوعُه، بخلاف المخالِف عن جهل، ولأنَّ أخص الموصوفين بـالمَغضُوبِ عَلَيهِمْ هم اليهود وأخص الموصوفين بـالضَّالِّينَ هم النصارى، واليهود سابقون على النصارى في الزمن.", "page": 17, "id": "unit-02__lesson-01__b50", "list": {"type": "ordered", "marker": "6"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 17, "id": "unit-02__lesson-01__b51", "role": "assessment"}, {"type": "paragraph", "md": "1- ما موضوع سورة الفاتحة؟ ولماذا قدم الله تعالى هذه السورة على غيرها من سور القرآن؟", "page": 17, "id": "unit-02__lesson-01__b52", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- اذكر فضيليتن لسورة الفاتحة، وفائدتين تربويتين، وفائدتين علميتين كما تعملتَ في الدرس؟", "page": 17, "id": "unit-02__lesson-01__b53", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3-اذكر معنى الألفاظ الآتية: ﴿ٱللَّهُ﴾، ﴿مَٰلِكِ يَوۡمِ ٱلدِّينِ ۝٤﴾، ﴿ٱلۡمَغۡضُوبِ عَلَيۡهِمۡ﴾، ﴿ٱلضَّآلِّينَ ۝٩٢﴾", "page": 17, "id": "unit-02__lesson-01__b54", "inline": [{"t": "text", "s": "3-اذكر معنى الألفاظ الآتية: "}, {"t": "ayah", "s": "ٱللَّهُ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "مَٰلِكِ يَوۡمِ ٱلدِّينِ ۝٤", "ayah": [4], "verses": [{"n": 4, "text": "مَٰلِكِ يَوۡمِ ٱلدِّينِ", "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:4", "surah_name": "الفاتحة", "ayah_canonical": 4, "match": "exact", "ref": "1:4"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "ٱلۡمَغۡضُوبِ عَلَيۡهِمۡ", "ayah": [], "verses": [{"n": 7, "text": "ٱلۡمَغۡضُوبِ عَلَيۡهِمۡ", "surah": 1, "surah_name": "الفاتحة", "ref": "1:7", "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:7"}], "surah": 1, "ref_api": "https://api.quran.com/api/v4/verses/by_key/1:7", "surah_name": "الفاتحة", "ayah_canonical": 7, "match": "contained", "ref": "1:7"}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "ٱلضَّآلِّينَ ۝٩٢", "ayah": [92], "verses": [{"n": 92, "text": "ٱلضَّآلِّينَ", "surah": 56, "ref_api": "https://api.quran.com/api/v4/verses/by_key/56:92", "surah_name": "الواقعة", "ayah_canonical": 92, "match": "contained", "ref": "56:92"}], "surah": null, "ref_api": null}], "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط في المجلس", "page": 17, "id": "unit-02__lesson-01__b55", "role": "activity"}, {"type": "paragraph", "md": "نقول بعد الفاتحة (آمِينْ) فما معناها؟ ابحث عن ذلك وأجب في المجلس، وكيف نلفظها في الصلاة؟", "page": 17, "id": "unit-02__lesson-01__b56", "inline": [{"t": "text", "s": "نقول بعد الفاتحة "}, {"t": "emphasis", "s": "(آمِينْ)", "role": "emphasis"}, {"t": "text", "s": " فما معناها؟ ابحث عن ذلك وأجب في المجلس، وكيف نلفظها في الصلاة؟"}], "item_role": "activity_step"}, {"type": "heading", "level": 3, "text": "سورة الناس", "page": 18, "id": "unit-02__lesson-01__b57", "role": "section"}, {"type": "paragraph", "md": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: ﴿قُلۡ أَعُوذُ بِرَبِّ ٱلنَّاسِ ۝١ مَلِكِ ٱلنَّاسِ ۝٢ إِلَٰهِ ٱلنَّاسِ ۝٣ مِن شَرِّ ٱلۡوَسۡوَاسِ ٱلۡخَنَّاسِ ۝٤ ٱلَّذِي يُوَسۡوِسُ فِي صُدُورِ ٱلنَّاسِ ۝٥ مِنَ ٱلۡجِنَّةِ وَٱلنَّاسِ ۝٦﴾", "page": 18, "id": "unit-02__lesson-01__b58", "inline": [{"t": "text", "s": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيم' WHERE id='unit-02__lesson-01';
UPDATE manhaj_lessons SET blocks = blocks || 'ِ: "}, {"t": "ayah", "s": "قُلۡ أَعُوذُ بِرَبِّ ٱلنَّاسِ ۝١ مَلِكِ ٱلنَّاسِ ۝٢ إِلَٰهِ ٱلنَّاسِ ۝٣ مِن شَرِّ ٱلۡوَسۡوَاسِ ٱلۡخَنَّاسِ ۝٤ ٱلَّذِي يُوَسۡوِسُ فِي صُدُورِ ٱلنَّاسِ ۝٥ مِنَ ٱلۡجِنَّةِ وَٱلنَّاسِ ۝٦", "ayah": [1, 2, 3, 4, 5, 6], "verses": [{"n": 1, "text": "قُلۡ أَعُوذُ بِرَبِّ ٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:1", "surah_name": "الناس", "ayah_canonical": 1, "match": "exact", "ref": "114:1"}, {"n": 2, "text": "مَلِكِ ٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:2", "surah_name": "الناس", "ayah_canonical": 2, "match": "exact", "ref": "114:2"}, {"n": 3, "text": "إِلَٰهِ ٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:3", "surah_name": "الناس", "ayah_canonical": 3, "match": "exact", "ref": "114:3"}, {"n": 4, "text": "مِن شَرِّ ٱلۡوَسۡوَاسِ ٱلۡخَنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:4", "surah_name": "الناس", "ayah_canonical": 4, "match": "exact", "ref": "114:4"}, {"n": 5, "text": "ٱلَّذِي يُوَسۡوِسُ فِي صُدُورِ ٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:5", "surah_name": "الناس", "ayah_canonical": 5, "match": "exact", "ref": "114:5"}, {"n": 6, "text": "مِنَ ٱلۡجِنَّةِ وَٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:6", "surah_name": "الناس", "ayah_canonical": 6, "match": "exact", "ref": "114:6"}], "surah": null, "ref_api": null}]}, {"type": "heading", "level": 3, "text": "فضل سورتي الفلق والناس «المعوذتين»:", "page": 18, "id": "unit-02__lesson-01__b59", "role": "virtues"}, {"type": "paragraph", "md": "1- من قرأ المعوذات حين يمسي وحين يصبح ثلاثا كفاه الله من كل شيء؛ فعن عبد الله بن خبيب رضي الله عنه ، قال: (خرجنا في ليلة مطيرة وظلمة شديدة نطلب رسول الله صلى الله عليه وسلم يصلي لنا، فأدركته فقال: قل. فلم أقل شيئا، ثم قال: قل. فلم أقل شيئا، ثم قال: قل. قلت: ما أقول؟ قال: قل: قل هو الله أحد، والمعوذتين حين تمسي وحين تصبح ثلاث مرات تكفيك من كل شيء).", "page": 18, "id": "unit-02__lesson-01__b60", "inline": [{"t": "text", "s": "1- من قرأ المعوذات حين يمسي وحين يصبح ثلاثا كفاه الله من كل شيء؛ فعن عبد الله بن خبيب "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ، قال: "}, {"t": "emphasis", "s": "(خرجنا في ليلة مطيرة وظلمة شديدة نطلب رسول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "يصلي لنا، فأدركته فقال: قل. فلم أقل شيئا، ثم قال: قل. فلم أقل شيئا، ثم قال: قل. قلت: ما أقول؟ قال: قل: قل هو الله أحد، والمعوذتين حين تمسي وحين تصبح ثلاث مرات تكفيك من كل شيء)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- وتستحب قراءتها في دبر كل صلاة، فعن عقبة بن عامر رضي الله عنه ، قال: (أمرني رسول الله صلى الله عليه وسلم أن أقرأ بالمعوذات في دبر كل صلاة).", "page": 18, "id": "unit-02__lesson-01__b61", "inline": [{"t": "text", "s": "2- وتستحب قراءتها في دبر كل صلاة، فعن عقبة بن عامر "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ، قال: "}, {"t": "emphasis", "s": "(أمرني رسول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "أن أقرأ بالمعوذات في دبر كل صلاة)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "من أهم الموضوعات التي اشتملت عليها هذه السورة:", "page": 18, "id": "unit-02__lesson-01__b62", "role": "main_themes"}, {"type": "paragraph", "md": "الاستعاذة بالله رب الناس وملكهم وإلههم من شر الشيطان، والذي من صفاته أنه وسواس خناس، يوسوس في صدور الناس، وأن هذا الشيطان قد يكون من الجن ويكون من الإنس.", "page": 18, "id": "unit-02__lesson-01__b63"}, {"type": "heading", "level": 3, "text": "تفسير السورة وغريبها:", "page": 18, "id": "unit-02__lesson-01__b64", "role": "vocabulary"}, {"type": "paragraph", "md": "﴿أَعُوذُ﴾ أعتصم وألتجئ. ﴿ٱلۡخَنَّاسِ ۝٤﴾: الشيطان الذي يخنس -أي: يرجع ويتأخر ويستتر- إذا ذكر الله.", "page": 18, "id": "unit-02__lesson-01__b65", "inline": [{"t": "ayah", "s": "أَعُوذُ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": " أعتصم وألتجئ. "}, {"t": "ayah", "s": "ٱلۡخَنَّاسِ ۝٤", "ayah": [4], "verses": [{"n": 4, "text": "ٱلۡخَنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:4", "surah_name": "الناس", "ayah_canonical": 4, "match": "contained", "ref": "114:4"}], "surah": null, "ref_api": null}, {"t": "text", "s": ": الشيطان الذي يخنس -أي: يرجع ويتأخر ويستتر- إذا ذكر الله."}]}, {"type": "paragraph", "md": "افتتح الله تعالى هذه السورة الكريمة بقوله: قل -يا محمد- متعوذًا بالله وحده: ألتجئ وأستجير برب الناس، ملك الناس، معبود الناس الحق؛ من شر الشيطان الذي يوسوس بالشر ويرجع عن العبد إذا ذكر ربه، الذي يلقي وساوسه في صدور الناس، من شياطين الجن وشياطين الإنس.", "page": 18, "id": "unit-02__lesson-01__b66"}, {"type": "paragraph", "md": "فائدة تربوية: تُعِلُّمُ الآياتُ المسلمين التعوذ بالله سبحانه وتعالى ؛ أي انه سيقع لهم التعرض إلى الوسواس، ويسلمهم الله من شره بقدر تعوذهم منه، وهذا الوسواس يكون من الجن أو الإنس؛ فندب الاستعاذة منه.", "page": 18, "id": "unit-02__lesson-01__b67", "inline": [{"t": "text", "s": "فائدة تربوية: تُعِلُّمُ الآياتُ المسلمين التعوذ بالله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ؛ أي انه سيقع لهم التعرض إلى الوسواس، ويسلمهم الله من شره بقدر تعوذهم منه، وهذا الوسواس يكون من الجن أو الإنس؛ فندب الاستعاذة منه."}]}, {"type": "heading", "level": 3, "text": "الفوائد العلمية واللطائف:", "page": 18, "id": "unit-02__lesson-01__b68", "role": "benefits"}, {"type": "paragraph", "md": "1- كيف يوسوس الشيطان للعبد؛ إذا كان يخنس بسرعة عند ذكر الله؟", "page": 18, "id": "unit-02__lesson-01__b69", "inline": [{"t": "emphasis", "s": "1- كيف يوسوس الشيطان للعبد؛ إذا كان يخنس بسرعة عند ذكر الله؟", "role": "emphasis"}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "الجواب: يوسوس الشيطان للعبد عند غفلته عن ذكر ربه، ويخنس عند ذكر ربه سبحانه تعالى، فيختلف حاله باختلاف حال العبد حضورًا للذكر أو غيابًا عنه، دل على هذا قوله تعالى: ﴿وَمَن يَعۡشُ عَن ذِكۡرِ ٱلرَّحۡمَٰنِ نُقَيِّضۡ لَهُۥ شَيۡطَٰنٗا فَهُوَ لَهُۥ قَرِينٞ ۝٣٦﴾، وقوله تعالى: ﴿إِنَّهُۥ لَيۡسَ لَهُۥ سُلۡطَٰنٌ عَلَى ٱلَّذِينَ ءَامَنُواْ﴾.", "page": 19, "id": "unit-02__lesson-01__b70", "inline": [{"t": "emphasis", "s": "الجواب", "role": "emphasis"}, {"t": "text", "s": ": يوسوس الشيطان للعبد عند غفلته عن ذكر ربه، ويخنس عند ذكر ربه سبحانه تعالى، فيختلف حاله باختلاف حال العبد حضورًا للذكر أو غيابًا عنه، دل على هذا قوله تعالى: "}, {"t": "ayah", "s": "وَمَن يَعۡشُ عَن ذِكۡرِ ٱلرَّحۡمَٰنِ نُقَيِّضۡ لَهُۥ شَيۡطَٰنٗا فَهُوَ لَهُۥ قَرِينٞ ۝٣٦", "ayah": [36], "verses": [{"n": 36, "text": "وَمَن يَعۡشُ عَن ذِكۡرِ ٱلرَّحۡمَٰنِ نُقَيِّضۡ لَهُۥ شَيۡطَٰنٗا فَهُوَ لَهُۥ قَرِينٞ", "surah": 43, "ref_api": "https://api.quran.com/api/v4/verses/by_key/43:36", "surah_name": "الزخرف", "ayah_canonical": 36, "match": "exact", "ref": "43:36"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، وقوله تعالى: "}, {"t": "ayah", "s": "إِنَّهُۥ لَيۡسَ لَهُۥ سُلۡطَٰنٌ عَلَى ٱلَّذِينَ ءَامَنُواْ", "ayah": [], "verses": [{"n": 99, "text": "إِنَّهُۥ لَيۡسَ لَهُۥ سُلۡطَٰنٌ عَلَى ٱلَّذِينَ ءَامَنُواْ", "surah": 16, "surah_name": "النحل", "ref": "16:99", "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:99"}], "surah": 16, "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:99", "surah_name": "النحل", "ayah_canonical": 99, "match": "contained", "ref": "16:99"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "2- وسوسة الشيطان في صدر الإنسان بأنواع كثيرة؛ منها: إفساد الإيمان والتشكيك في العقائد، فإن لم يقدر على ذلك أمره بالمعاصي، فإن لم يقدر على ذلك ثبطه عن الطاعات، فإن لم يقدر على ذلك أدخل عليه الرياء في الطاعات ليحبطها، فإن سلم من ذلك أدخل عليه العجب بنفسه، واستكثار عمله، ومن ذلك أنه يوقد في القلب نار الحسد والحقد والغضب؛ حتى يقود الإنسان إلى شر الأعمال وأقبح الأحوال.", "page": 19, "id": "unit-02__lesson-01__b71", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "وعلاج وسوسته بثلاثة أشياء؛ أولها: الإكثار من ذكر الله. وثانيها: الإكثار من الاستعاذة بالله من الشيطان، ومن أنفع شيء في ذلك قراءة هذه السورة. وثالثها: مخالفته والعزم على عصيانه؛ شيطان إنس كان أو جن.", "page": 19, "id": "unit-02__lesson-01__b72", "inline": [{"t": "emphasis", "s": "وعلاج وسوسته بثلاثة أشياء", "role": "emphasis"}, {"t": "text", "s": "؛ أولها: الإكثار من ذكر الله. وثانيها: الإكثار من الاستعاذة بالله من الشيطان، ومن أنفع شيء في ذلك قراءة هذه السورة. وثالثها: مخالفته والعزم على عصيانه؛ شيطان إنس كان أو جن."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 19, "id": "unit-02__lesson-01__b73", "role": "assessment"}, {"type": "paragraph", "md": "1- ما موضوع سورة الناس.", "page": 19, "id": "unit-02__lesson-01__b74", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما معنى ﴿ٱلۡخَنَّاس﴾، ﴿أَعُوذُ﴾.", "page": 19, "id": "unit-02__lesson-01__b75", "inline": [{"t": "text", "s": "2- ما معنى "}, {"t": "ayah", "s": "ٱلۡخَنَّاس", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "أَعُوذُ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "."}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- اذكر فائدة تربوية وأخرى علمية تعلمتها من سورة الناس.", "page": 19, "id": "unit-02__lesson-01__b76", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4-لماذا أمرنا الله أن نستعيذ ﴿مِنَ ٱلۡجِنَّةِ وَٱلنَّاسِ ۝٦﴾ في السورة؟", "page": 19, "id": "unit-02__lesson-01__b77", "inline": [{"t": "text", "s": "4-لماذا أمرنا الله أن نستعيذ "}, {"t": "ayah", "s": "مِنَ ٱلۡجِنَّةِ وَٱلنَّاسِ ۝٦", "ayah": [6], "verses": [{"n": 6, "text": "مِنَ ٱلۡجِنَّةِ وَٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:6", "surah_name": "الناس", "ayah_canonical": 6, "match": "exact", "ref": "114:6"}], "surah": null, "ref_api": null}, {"t": "text", "s": " في السورة؟"}], "item_role": "question"}, {"type": "paragraph", "md": "5-اذكر فضل سورة الناس.", "page": 19, "id": "unit-02__lesson-01__b78", "item_role": "question"}, {"type": "paragraph", "md": "6- اتل غيبًا على شيخك، مراعيًا أحكام التجويد: سورتي الفاتحة والناس.", "page": 19, "id": "unit-02__lesson-01__b79", "item_role": "question", "list": {"type": "ordered", "marker": "6"}}, {"type": "heading", "level": 3, "text": "نشاط خارج المجلس", "page": 19, "id": "unit-02__lesson-01__b80", "role": "activity"}, {"type": "paragraph", "md": "اقرأ تفسير سورة الناس من المختصر في التفسير أو تفسير السعدي واكتب أهم الفوائد التي أعجبتك.", "page": 19, "id": "unit-02__lesson-01__b81", "item_role": "activity_step"}, {"type": "paragraph", "md": "لماذا أمرنا الله تعالى أن نتعوذ من ﴿ٱلۡوَسۡوَاسِ ٱلۡخَنَّاسِ ۝٤﴾ ابحث عن ذلك في الكتب وبسؤال العلماء.", "page": 19, "id": "unit-02__lesson-01__b82", "inline": [{"t": "text", "s": "لماذا أمرنا الله تعالى أن نتعوذ من "}, {"t": "ayah", "s": "ٱلۡوَسۡوَاسِ ٱلۡخَنَّاسِ ۝٤", "ayah": [4], "verses": [{"n": 4, "text": "ٱلۡوَسۡوَاسِ ٱلۡخَنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:4", "surah_name": "الناس", "ayah_canonical": 4, "match": "contained", "ref": "114:4"}], "surah": null, "ref_api": null}, {"t": "text", "s": " ابحث عن ذلك في الكتب وبسؤال العلماء."}], "item_role": "activity_step"}, {"type": "paragraph", "md": "في بداية السورة ذكر الله عزوجل ﴿إِلَٰهِ ٱلنَّاسِ ۝٣﴾ و﴿مَلِكِ ٱلنَّاسِ ۝٢﴾ لماذا، ابحث عن ذلك في كتب التفسير المختصرة أو اسأل أهل العلم.", "page": 19, "id": "unit-02__lesson-01__b83", "inline": [{"t": "text", "s": "في بداية السورة ذكر الله عزوجل "}, {"t": "ayah", "s": "إِلَٰهِ ٱلنَّاسِ ۝٣", "ayah": [3], "verses": [{"n": 3, "text": "إِلَٰهِ ٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:3", "surah_name": "الناس", "ayah_canonical": 3, "match": "exact", "ref": "114:3"}], "surah": null, "ref_api": null}, {"t": "text", "s": " و"}, {"t": "ayah", "s": "مَلِكِ ٱلنَّاسِ ۝٢", "ayah": [2], "verses": [{"n": 2, "text": "مَلِكِ ٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:2", "surah_name": "الناس", "ayah_canonical": 2, "match": "exact", "ref": "114:2"}], "surah": null, "ref_api": null}, {"t": "text", "s": " لماذا، ابحث عن ذلك في كتب التفسير المختصرة أو اسأل أهل العلم."}], "item_role": "activity_step"}, {"type": "paragraph", "md": "ابحث عن فضائل أخرى لسورة الناس غير التي ذكرت في الدرس.", "page": 19, "id": "unit-02__lesson-01__b84", "item_role": "activity_step"}]' WHERE id='unit-02__lesson-01';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "عَنْ عُمَرَ بْنِ الْخَطَّابِ رضي الله عنه قَالَ: سَمِعْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم يقول: «إِنَّمَا ‌الْأَعْمَالُ ‌بِالنِّيَّاتِ، وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى، فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ، فَهجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ. وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا أَوِ امْرَأَةٍ يَنْكِحُهَا، فَهِجْرَتُهُ إِلَى ما هاجر إليه» [رواه البخاري ومسلم].", "page": 20, "id": "unit-02__lesson-02__b01", "inline": [{"t": "text", "s": "عَنْ عُمَرَ بْنِ الْخَطَّابِ "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قَالَ: سَمِعْتُ رَسُولَ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يقول: "}, {"t": "hadith", "s": "إِنَّمَا ‌الْأَعْمَالُ ‌بِالنِّيَّاتِ، وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى، فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ، فَهجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ. وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا أَوِ امْرَأَةٍ يَنْكِحُهَا، فَهِجْرَتُهُ إِلَى ما هاجر إليه", "narrator": "عمر بن الخطاب", "source": "البخاري ومسلم", "confidence": "high", "ref_api": null}, {"t": "text", "s": " "}, {"t": "citation", "s": "[رواه البخاري ومسلم]", "source": "البخاري ومسلم"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 20, "id": "unit-02__lesson-02__b02", "role": "objectives"}, {"type": "paragraph", "md": "أن يخلص النية لله في أعماله، ويعرف أهمية تعدد النيات في العمل، ويتعرف على الرياء ليجتنبه", "page": 20, "id": "unit-02__lesson-02__b03"}, {"type": "paragraph", "md": "يعرف معنى النية والهجرة إلى الله، ويستعد لذلك.", "page": 20, "id": "unit-02__lesson-02__b04"}, {"type": "heading", "level": 3, "text": "أهمية الحديث:", "page": 20, "id": "unit-02__lesson-02__b05", "role": "hadith_importance"}, {"type": "paragraph", "md": "هذا الحديث ثلث العلم؛ فإنَّ كسب العبد يكون بقلبه ولسانه وجوارحه، والنية أحد الأقسام الثلاثة، وذكر بعضهم أنه نصف الدين، لأنه ميزان للأعمال الباطنة، بينما حديث: (من عمل عملا ليس عليه أمرنا فهو رد) ميزان للأعمال الظاهرة، ولا يقبل العمل عند الله تعالى إلا بالإخلاص لله، والموافقة لرسوله صلى الله عليه وسلم .", "page": 20, "id": "unit-02__lesson-02__b06", "inline": [{"t": "text", "s": "هذا الحديث ثلث العلم؛ فإنَّ كسب العبد يكون بقلبه ولسانه وجوارحه، والنية أحد الأقسام الثلاثة، وذكر بعضهم أنه نصف الدين، لأنه ميزان للأعمال الباطنة، بينما حديث: "}, {"t": "emphasis", "s": "(من عمل عملا ليس عليه أمرنا فهو رد)", "role": "emphasis"}, {"t": "text", "s": " ميزان للأعمال الظاهرة، ولا يقبل العمل عند الله تعالى إلا بالإخلاص لله، والموافقة لرسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "heading", "level": 3, "text": "شرح الحديث:", "page": 20, "id": "unit-02__lesson-02__b07", "role": "hadith_explanation"}, {"type": "paragraph", "md": "1- المقصود بالأعمال هنا: الأفعال الشرعية التي تصدر عن المكلف، وتدخل فيها الأقوال والأفعال معا.", "page": 20, "id": "unit-02__lesson-02__b08", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- النية: هي قصد القلب وإرادته ومبتغاه، كما قال تعالى: ﴿مَن كَانَ يُرِيدُ حَرۡثَ ٱلۡأٓخِرَةِ نَزِدۡ لَهُۥ فِي حَرۡثِهِۦۖ وَمَن كَانَ يُرِيدُ حَرۡثَ ٱلدُّنۡيَا نُؤۡتِهِۦ مِنۡهَا وَمَا لَهُۥ فِي ٱلۡأٓخِرَةِ مِن نَّصِيبٍ ۝٢٠﴾.", "page": 20, "id": "unit-02__lesson-02__b09", "inline": [{"t": "text", "s": "2- النية: هي قصد القلب وإرادته ومبتغاه، كما قال تعالى: "}, {"t": "ayah", "s": "مَن كَانَ يُرِيدُ حَرۡثَ ٱلۡأٓخِرَةِ نَزِدۡ لَهُۥ فِي حَرۡثِهِۦۖ وَمَن كَانَ يُرِيدُ حَرۡثَ ٱلدُّنۡيَا نُؤۡتِهِۦ مِنۡهَا وَمَا لَهُۥ فِي ٱلۡأٓخِرَةِ مِن نَّصِيبٍ ۝٢٠", "ayah": [20], "verses": [{"n": 20, "text": "مَن كَانَ يُرِيدُ حَرۡثَ ٱلۡأٓخِرَةِ نَزِدۡ لَهُۥ فِي حَرۡثِهِۦۖ وَمَن كَانَ يُرِيدُ حَرۡثَ ٱلدُّنۡيَا نُؤۡتِهِۦ مِنۡهَا وَمَا لَهُۥ فِي ٱلۡأٓخِرَةِ مِن نَّصِيبٍ", "surah": 42, "ref_api": "https://api.quran.com/api/v4/verses/by_key/42:20", "surah_name": "الشورى", "ayah_canonical": 20, "match": "exact", "ref": "42:20"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- النية في الشريعة يراد بها أحد معنيين؛ أولا: نية يقصد بها التعبد، وهي ركن في العبادات؛ لتمييز العادة عن العبادة، وتمييز العبادات عن بعضها. والتلفظ بها في العبادات بدعة، وفي العادات مرض وجنون.", "page": 20, "id": "unit-02__lesson-02__b10", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "ثانيًا: نية متجهة إلى المعبود، وهي الإخلاص له سبحانه في العبادة؛ فمن نوى غير وجه الله تعالى في عمله فهو مراء، والرياء الكامل لا يصدر إلا من منافق، ولا يكاد يصدر من مسلم، قال تعالى: ﴿إِنَّ ٱلۡمُنَٰفِقِينَ يُخَٰدِعُونَ ٱللَّهَ وَهُوَ خَٰدِعُهُمۡ وَإِذَا قَامُوٓاْ إِلَى ٱلصَّلَوٰةِ قَامُواْ كُسَالَىٰ يُرَآءُونَ ٱلنَّاسَ وَلَا يَذۡكُرُونَ ٱللَّهَ إِلَّا قَلِيلٗا ۝١٤٢﴾.", "page": 20, "id": "unit-02__lesson-02__b11", "inline": [{"t": "text", "s": "ثانيًا: نية متجهة إلى المعبود، وهي الإخلاص له سبحانه في العبادة؛ فمن نوى غير وجه الله تعالى في عمله فهو مراء، والرياء الكامل لا يصدر إلا من منافق، ولا يكاد يصدر من مسلم، قال تعالى: "}, {"t": "ayah", "s": "إِنَّ ٱلۡمُنَٰفِقِينَ يُخَٰدِعُونَ ٱللَّهَ وَهُوَ خَٰدِعُهُمۡ وَإِذَا قَامُوٓاْ إِلَى ٱلصَّلَوٰةِ قَامُواْ كُسَالَىٰ يُرَآءُونَ ٱلنَّاسَ وَلَا يَذۡكُرُونَ ٱللَّهَ إِلَّا قَلِيلٗا ۝١٤٢", "ayah": [142], "verses": [{"n": 142, "text": "إِنَّ ٱلۡمُنَٰفِقِينَ يُخَٰدِعُونَ ٱللَّهَ وَهُوَ خَٰدِعُهُمۡ وَإِذَا قَامُوٓاْ إِلَى ٱلصَّلَوٰةِ قَامُواْ كُسَالَىٰ يُرَآءُونَ ٱلنَّاسَ وَلَا يَذۡكُرُونَ ٱللَّهَ إِلَّا قَلِيلٗا", "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:142", "surah_name": "النساء", "ayah_canonical": 142, "match": "exact", "ref": "4:142"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "4- قوله: «إنما الأعمال بالنيات»: للحصر، أي أن الأعمال لا تقبل ولا تقع صحيحة إلا بإخلاص النية لله.", "page": 20, "id": "unit-02__lesson-02__b12", "inline": [{"t": "text", "s": "4- قوله: "}, {"t": "quote", "s": "إنما الأعمال بالنيات"}, {"t": "text", "s": ": للحصر، أي أن الأعمال لا تقبل ولا تقع صحيحة إلا بإخلاص النية لله."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- الهجرة معناها: الترك. والهجرة إلى الله تكون بالإخلاص وابتغاء ما عنده سبحانه، والهجرة إلى النبي صلى الله عليه وسلم تكون باتباعه، ولا تزال الهجرة باقية من دار الكفر لدار الإسلام، أو من دار القعود لدار الجهاد؛ ففي الحديث الصحيح: (لا تنقطع الهجرة حتى تنقطع التوبة، ولا تنقطع التوبة حتى تطلع الشمس من مغربها).", "page": 21, "id": "unit-02__lesson-02__b13", "inline": [{"t": "text", "s": "5- الهجرة معناها: الترك. والهجرة إلى الله تكون بالإخلاص وابتغاء ما عنده سبحانه، والهجرة إلى النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " تكون باتباعه، ولا تزال الهجرة باقية من دار الكفر لدار الإسلام، أو من دار القعود لدار الجهاد؛ ففي الحديث الصحيح: "}, {"t": "emphasis", "s": "(لا تنقطع الهجرة حتى تنقطع التوبة، ولا تنقطع التوبة حتى تطلع الشمس من مغربها)", "role": "lemma"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "heading", "level": 3, "text": "فوائد ومسائل مأخوذة من الحديث:", "page": 21, "id": "unit-02__lesson-02__b14", "role": "benefits"}, {"type": "paragraph", "md": "1- النية الطيبة لا تصلح العمل الفاسد؛ فمن قال قولا شركيا مثل (ما شاء الله وشئت)، أو (باسم الله والوطن) وزعم أن نيته صحيحة فلا يُقبل منه، فمعنى الحديث: إنما الأعمال الصالحة بالنيات الخالصة، لا أن الأعمال المخالفة للشريعة تنقلب إلى أعمال صالحة مشروعة بسبب اقتران النية الصالحة بها.", "page": 21, "id": "unit-02__lesson-02__b15", "inline": [{"t": "text", "s": "1- النية الطيبة لا تصلح العمل الفاسد؛ فمن قال قولا شركيا مثل "}, {"t": "emphasis", "s": "(ما شاء الله وشئت)", "role": "emphasis"}, {"t": "text", "s": "، أو "}, {"t": "emphasis", "s": "(باسم الله والوطن)", "role": "emphasis"}, {"t": "text", "s": " وزعم أن نيته صحيحة فلا يُقبل منه، فمعنى الحديث: إنما الأعمال الصالحة بالنيات الخالصة، لا أن الأعمال المخالفة للشريعة تنقلب إلى أعمال صالحة مشروعة بسبب اقتران النية الصالحة بها."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- حكم العبادة إذا خالطها الرياء، له أحوال ثلاثة:", "page": 21, "id": "unit-02__lesson-02__b16", "inline": [{"t": "emphasis", "s": "2- حكم العبادة إذا خالطها الرياء، له أحوال ثلاثة:", "role": "emphasis"}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "أ - أن يكون قصده مراءاة الناس من الأصل؛ كمن صلى لأجل الناس؛ فهذا شرك والعبادة باطلة.", "page": 21, "id": "unit-02__lesson-02__b17"}, {"type": "paragraph", "md": "ب - أن يكون الرياء مشاركا للعبادة في أثنائها؛ كمن صلى لأجل الله أول الأمر، ثم طرأ الرياء أثناء صلاته:", "page": 21, "id": "unit-02__lesson-02__b18"}, {"type": "paragraph", "md": "فهنا تفصيل؛ فإن كانت العبادة لا ينبني آخرها على أولها -كقراءة القرآن- فأولها صحيح بكل حال، والباطل آخرها. وأما إذا كانت العبادة ينبني آخرها على أولها -كالصلاة-؛ فإذا دافع الرياء وكرهه؛ فإنه لا يضره، وأما إذا لم يدافعه؛ فحينئذ تبطل كل العبادة؛ لأن آخرها مبني على أولها.", "page": 21, "id": "unit-02__lesson-02__b19"}, {"type": "paragraph", "md": "ج - إذا طرأ محبة الثناء والفرح به بعد انتهاء المرء من العبادة؛ فإنه لا يؤثر عليها شيئا، اللهم إلا أن يكون فيه عُدوان، كالمن والأذى بالصدقة؛ فإن هذا العدوان يكون إثمه مقابلا لأجر الصدقة والعبادة فيبطلها.", "page": 21, "id": "unit-02__lesson-02__b20"}, {"type": "paragraph", "md": "3- ليس من الرياء فرح الإنسان بعلم الناس بعبادته؛ لأن هذا طرأ بعد الفراغ من العبادة، فقد قيل للنبي صلى الله عليه وسلم : أرأيت الرجل يعمل من الخير؛ ويحمده الناس عليه؟ قال: (تلك عاجل بشرى المؤمن)، وقد كان السلف يكرهون التحديث بأعمالهم كراهة إصابتهم بالعُجب كما في قصة أبي موسى رضي الله عنه في ذات الرقاع.", "page": 21, "id": "unit-02__lesson-02__b21", "inline": [{"t": "text", "s": "3- ليس من الرياء فرح الإنسان بعلم الناس بعبادته؛ لأن هذا طرأ بعد الفراغ من العبادة، فقد قيل للنبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : أرأيت الرجل يعمل من الخير؛ ويحمده الناس عليه؟ قال: "}, {"t": "emphasis", "s": "(تلك عاجل بشرى المؤمن)", "role": "emphasis"}, {"t": "text", "s": "، وقد كان السلف يكرهون التحديث بأعمالهم كراهة إصابتهم بالعُجب كما في قصة أبي موسى "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " في ذات الرقاع."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 21, "id": "unit-02__lesson-02__b22", "role": "assessment"}, {"type": "paragraph", "md": "ما معنى الرياء والإخلاص؟ ولماذا نخلص لله تعالى في العمل؟", "page": 21, "id": "unit-02__lesson-02__b23", "item_role": "question"}, {"type": "paragraph", "md": "اذكر آية وحديثا في فضل الإخلاص، واقرأ حديث الباب غيبًا من حفظك.", "page": 21, "id": "unit-02__lesson-02__b24", "item_role": "question"}, {"type": "paragraph", "md": "ما رأيك بمن يقول: «المهم أن قلبي يحب الله» ويفعل الأفعال المحرمة؟", "page": 21, "id": "unit-02__lesson-02__b25", "inline": [{"t": "text", "s": "ما رأيك بمن يقول: "}, {"t": "quote", "s": "المهم أن قلبي يحب الله"}, {"t": "text", "s": " ويفعل الأفعال المحرمة؟"}], "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط خارج المجلس", "page": 21, "id": "unit-02__lesson-02__b26", "role": "activity"}, {"type": "paragraph", "md": "صلِّ لله ركعتين لا يراك فيهما أحد، محافظًا على الإخلاص فيهما.", "page": 21, "id": "unit-02__lesson-02__b27", "item_role": "activity_step"}, {"type": "paragraph", "md": "حافظ على عبادة سر بينك وبين الله، وأخبر فيها معلمك فقط لتوجيهك فيها وضبطها شرعًا.", "page": 21, "id": "unit-02__lesson-02__b28", "item_role": "activity_step"}]' WHERE id='unit-02__lesson-02';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 22, "id": "unit-02__lesson-03__b01", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على مقدمة توضح علم العقيدة، وبيان معنى الإيمان والتوحيد والعلاقة بينهما.", "page": 22, "id": "unit-02__lesson-03__b02"}, {"type": "paragraph", "md": "التعرف على موضوعات علم العقيدة، وحكم تعلمها بشكل مجمل، وفضل هذا العلم.", "page": 22, "id": "unit-02__lesson-03__b03"}, {"type": "paragraph", "md": "معرفة المصادر التي يتلقى منها المسلم عقيدته، والفوائد التربوية من تعلم العقيدة.", "page": 22, "id": "unit-02__lesson-03__b04"}, {"type": "heading", "level": 3, "text": "مقدمة بين يدي علم العقيدة والتوحيد:", "page": 22, "id": "unit-02__lesson-03__b05", "role": "intro"}, {"type": "paragraph", "md": "إنَّ أهم ما يُركز عليه المسلم في حياته: العقيدة الصحيحة التي تجعله يشعر بالسعادة في الدنيا والآخرة، وتكون هذه السعادة في الدنيا بأن تعبد الله بكل ما أمرك به، وتترك كل ما نهاك الله عز وجل عنه؛ فتشعر أنك مرتبط بالسماء، تسير بأوامر الخالق، وتشعر بالعبودية لله سبحانه وتعالى ، وتعلم أن الله أوجدك على هذا الدنيا لأمر عظيم ألا وهو عبادته وحده سبحانه وتعالى ، واستخلفك في الأرض حتى تقيم الدين على نفسك وعلى من حولك كما أمرك الله بذلك، يقول تعالى:﴿وَمَا خَلَقۡتُ ٱلۡجِنَّ وَٱلۡإِنسَ إِلَّا لِيَعۡبُدُونِ ۝٥٦﴾، أي ليوحدون، وقد قال النبي صلى الله عليه وسلم لمعاذ بن جبل رضي الله عنه : (يا معاذ! هل تدري ما حق الله على العباد؟ وما حق العباد على الله؟ قلتُ: الله ورسوله أعلم، قال: فإن حق الله على العباد أن يعبدوه ولا يُشركوا به شيئا، ثم قال: يا معاذ، هل تدري ما حقّ العباد على الله إذا هم فعلوا ذلك؟ قلتُ: الله ورسوله أعلم، قال: فإن حق العباد على الله إذا فعلوا ذلك أن يدخلهم الجنة)، وفي رواية أخرى: (فإن حق الله على العباد إذا فعلوا ذلك ألا يعذبهم).", "page": 22, "id": "unit-02__lesson-03__b06", "inline": [{"t": "text", "s": "إنَّ أهم ما يُركز عليه المسلم في حياته: العقيدة الصحيحة التي تجعله يشعر بالسعادة في الدنيا والآخرة، وتكون هذه السعادة في الدنيا بأن تعبد الله بكل ما أمرك به، وتترك كل ما نهاك الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " عنه؛ فتشعر أنك مرتبط بالسماء، تسير بأوامر الخالق، وتشعر بالعبودية لله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، وتعلم أن الله أوجدك على هذا الدنيا لأمر عظيم ألا وهو عبادته وحده "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، واستخلفك في الأرض حتى تقيم الدين على نفسك وعلى من حولك كما أمرك الله بذلك، يقول تعالى:"}, {"t": "ayah", "s": "وَمَا خَلَقۡتُ ٱلۡجِنَّ وَٱلۡإِنسَ إِلَّا لِيَعۡبُدُونِ ۝٥٦", "ayah": [56], "verses": [{"n": 56, "text": "وَمَا خَلَقۡتُ ٱلۡجِنَّ وَٱلۡإِنسَ إِلَّا لِيَعۡبُدُونِ", "surah": 51, "ref_api": "https://api.quran.com/api/v4/verses/by_key/51:56", "surah_name": "الذاريات", "ayah_canonical": 56, "match": "exact", "ref": "51:56"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، أي ليوحدون، وقد قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لمعاذ بن جبل "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(يا معاذ! هل تدري ما حق الله على العباد؟ وما حق العباد على الله؟ قلتُ: الله ورسوله أعلم، قال: فإن حق الله على العباد أن يعبدوه ولا يُشركوا به شيئا، ثم قال: يا معاذ، هل تدري ما حقّ العباد على الله إذا هم فعلوا ذلك؟ قلتُ: الله ورسوله أعلم، قال: فإن حق العباد على الله إذا فعلوا ذلك أن يدخلهم الجنة)", "role": "emphasis"}, {"t": "text", "s": "، وفي رواية أخرى: "}, {"t": "emphasis", "s": "(فإن حق الله على العباد إذا فعلوا ذلك ألا يعذبهم)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "العقيدة: هي الضابط الأمين الذي يحكم التصرفات، ويوجه السلوك، ويتوقف على مدى انضباطها وإحكامها كل ما يصدر عن النفس من كلمات أو حركات؛ بل حتى الخلجات التي تساور القلب والمشاعر التي تعمل في جنبات النفس؛ هذه كلها تتوقف على هذا الجهاز الحساس؛ فالعقيدة هي دماغ التصرفات، فإذا تعطل جزء منها أحدث فسادا كبيرا في التصرفات، وانفراجا هائلا عن سوي الصراط.", "page": 22, "id": "unit-02__lesson-03__b07"}, {"type": "paragraph", "md": "ولذا فقد عني القرآن الكريم ببناء العقيدة، فلا تكاد تخلو أية سورة - مكية كانت أو مدنية - من شد الإنسان بكليته إلى ربه، وربط كل تصرف بهذه العقيدة التي تمثل القاعدة الأساسية لهذا الدين الذي لا يقوم بدونها؛ فكل الانحرافات التي نعانيها في سلوكنا -أفرادا أو جماعات- راجعة بكليتها إلى الانحراف في التصور العقدي، فالناس في هذه الأيام بحاجة إلى بناء العقيدة من جديد، وإلى تصحيح التصور الاعتقادي، فلا بد من إفراد الله سبحانه بالألوهية، ولا بد من أن تستقر عظمة الله عز وجل في الأعماق، وأن يعمر النفوس حبه، ولا مناص من أن تحيا القلوب وهي تستشعر هيبته وجلاله.", "page": 23, "id": "unit-02__lesson-03__b08", "inline": [{"t": "text", "s": "ولذا فقد عني القرآن الكريم ببناء العقيدة، فلا تكاد تخلو أية سورة - مكية كانت أو مدنية - من شد الإنسان بكليته إلى ربه، وربط كل تصرف بهذه العقيدة التي تمثل القاعدة الأساسية لهذا الدين الذي لا يقوم بدونها؛ فكل الانحرافات التي نعانيها في سلوكنا -أفرادا أو جماعات- راجعة بكليتها إلى الانحراف في التصور العقدي، فالناس في هذه الأيام بحاجة إلى بناء العقيدة من جديد، وإلى تصحيح التصور الاعتقادي، فلا بد من إفراد الله سبحانه بالألوهية، ولا بد من أن تستقر عظمة الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " في الأعماق، وأن يعمر النفوس حبه، ولا مناص من أن تحيا القلوب وهي تستشعر هيبته وجلاله."}]}, {"type": "paragraph", "md": "ويقوم هذا الدين على: 1- حقيقة الألوهية. 2- حقيقة العبودية 3- الصلة بين العبد وربه.", "page": 23, "id": "unit-02__lesson-03__b09", "inline": [{"t": "emphasis", "s": "ويقوم هذا الدين على", "role": "emphasis"}, {"t": "text", "s": ": 1- حقيقة الألوهية. 2- حقيقة العبودية 3- الصلة بين العبد وربه."}]}, {"type": "paragraph", "md": "هذه أمور ثلاثة لا بد من استقرارها في النفوس؛ معرفة الله وقدره، ومعرفة العبد وَحَدُّه، والصلة بين الخالق والمخلوق، وعلى هذا فإنه من العبث تتبع فروع الشرع وطلبها من شخص لا ترسخ في قلبه حقيقة هذا الدين، ولا تستقر في كيانه عظمة الله، والحق أن الناس اليوم غابت عنهم حقيقة هذا الدين العظيم، وَمَثَل كثير منهم -حتى الذين يقيمون الشعائر التعبدية- كالأعمى الذي أمسك بذنب الفيل ويحسب أنه يمسك جِسم الفيل، حتى إذا طلبت منه أن يصف لك الفيل انبرى يصوره بأنه شعرات مرتبطة بعضلة قاسية، ولو اجتمع أهل الأرض لإقناعه أن الفيل ليس كذلك ما استطاعوا صرفه عن ظنه.", "page": 23, "id": "unit-02__lesson-03__b10"}, {"type": "paragraph", "md": "وقد أصبح اليوم لدينا شيء مألوف أن نرى شخصا يداوم على العبادات وهو في نفس الوقت يزاول أعمالا تخرجه من إطار هذا الدين؛ كالاستهزاء بسنة ثابتة عن رسول الله صلى الله عليه وسلم ، أو بفريضة وردت في محكم التنزيل، وهو لا يعلم أنه بالاستهزاء إنما يهزأ من أوامر الله وهو ردة تخرجه من الدين.", "page": 23, "id": "unit-02__lesson-03__b11", "inline": [{"t": "text", "s": "وقد أصبح اليوم لدينا شيء مألوف أن نرى شخصا يداوم على العبادات وهو في نفس الوقت يزاول أعمالا تخرجه من إطار هذا الدين؛ كالاستهزاء بسنة ثابتة عن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، أو بفريضة وردت في محكم التنزيل، وهو لا يعلم أنه بالاستهزاء إنما يهزأ من أوامر الله وهو ردة تخرجه من الدين."}]}, {"type": "paragraph", "md": "الحقيقة الكبرى أن كثيرًا من الناس لا يعرفون حقيقة هذا الدين، ويخلطون بين مناهج متعددة في حياتهم متأثرين بهزيمة المسلمين الحالية، وقسم ضئيل من منهاج حياتهم من دين الله، وأما معظم المنهاج الذي يوجه حياتهم؛ فهو من صنع هواه أو هوى غيره من البشر: ﴿أَرَءَيۡتَ مَنِ ٱتَّخَذَ إِلَٰهَهُۥ هَوَىٰهُ أَفَأَنتَ تَكُونُ عَلَيۡهِ وَكِيلًا ۝٤٣ أَمۡ تَحۡسَبُ أَنَّ أَكۡثَرَهُمۡ يَسۡمَعُونَ أَوۡ يَعۡقِلُونَۚ إِنۡ هُمۡ إِلَّا كَٱلۡأَنۡعَٰمِ بَلۡ هُمۡ أَضَلُّ سَبِيلًا ۝٤٤﴾،", "page": 23, "id": "unit-02__lesson-03__b12", "inline": [{"t": "text", "s": "الحقيقة الكبرى أن كثيرًا من الناس لا يعرفون حقيقة هذا الدين، ويخلطون بين مناهج متعددة في حياتهم متأثرين بهزيمة المسلمين الحالية، وقسم ضئيل من منهاج حياتهم من دين الله، وأما معظم المنهاج الذي يوجه حياتهم؛ فهو من صنع هواه أو هوى غيره من البشر: "}, {"t": "ayah", "s": "أَرَءَيۡتَ مَنِ ٱتَّخَذَ إِلَٰهَهُۥ هَوَىٰهُ أَفَأَنتَ تَكُونُ عَلَيۡهِ وَكِيلًا ۝٤٣ أَمۡ تَحۡسَبُ أَنَّ أَكۡثَرَهُمۡ يَسۡمَعُونَ أَوۡ يَعۡقِلُونَۚ إِنۡ هُمۡ إِلَّا كَٱلۡأَنۡعَٰمِ بَلۡ هُمۡ أَضَلُّ سَبِيلًا ۝٤٤", "ayah": [43, 44], "verses": [{"n": 43, "text": "أَرَءَيۡتَ مَنِ ٱتَّخَذَ إِلَٰهَهُۥ هَوَىٰهُ أَفَأَنتَ تَكُونُ عَلَيۡهِ وَكِيلًا", "surah": 25, "ref_api": "https://api.quran.com/api/v4/verses/by_key/25:43", "surah_name": "الفرقان", "ayah_canonical": 43, "match": "exact", "ref": "25:43"}, {"n": 44, "text": "أَمۡ تَحۡسَبُ أَنَّ أَكۡثَرَهُمۡ يَسۡمَعُونَ أَوۡ يَعۡقِلُونَۚ إِنۡ هُمۡ إِلَّا كَٱلۡأَنۡعَٰمِ بَلۡ هُمۡ أَضَلُّ سَبِيلًا", "surah": 25, "ref_api": "https://api.quran.com/api/v4/verses/by_key/25:44", "surah_name": "الفرقان", "ayah_canonical": 44, "match": "exact", "ref": "25:44"}], "surah": null, "ref_api": null}, {"t": "text", "s": "،"}]}, {"type": "heading", "level": 3, "text": "تعريفات مهمة في علم العقيدة، وبيان حكم تعلمه:", "page": 23, "id": "unit-02__lesson-03__b13", "role": "definitions"}, {"type": "paragraph", "md": "- العقيدة: هي جزم القلب وعقده على توحيد الله تعالى وما وجب الإيمان به دون شك.", "page": 23, "id": "unit-02__lesson-03__b14", "inline": [{"t": "emphasis", "s": "- العقيدة", "role": "lemma"}, {"t": "text", "s": ": هي جزم القلب وعقده على توحيد الله تعالى وما وجب الإيمان به دون شك."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- الإيمان: تصديق بالجنانِ، وقول باللسانِ، وعملٌ بالجوارح والأَركانِ، يزيدُ بالطاعةِ، وينقصُ بالمعصيةِ.", "page": 23, "id": "unit-02__lesson-03__b15", "inline": [{"t": "text", "s": "- "}, {"t": "emphasis", "s": "الإيمان", "role": "lemma"}, {"t": "text", "s": ": تصديق بالجنانِ، وقول باللسانِ، وعملٌ بالجوارح والأَركانِ، يزيدُ بالطاعةِ، وينقصُ بالمعصيةِ."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- التوحيد: إفراد الله سبحانه بما يختص به من الربوبية، والألوهية، والأسماء، والصفات.", "page": 23, "id": "unit-02__lesson-03__b16", "inline": [{"t": "text", "s": "- "}, {"t": "emphasis", "s": "التوحيد", "role": "lemma"}, {"t": "text", "s": ": إفراد الله سبحانه بما يختص به من الربوبية، والألوهية، والأسماء، والصفات."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "وهذه التعريفات الثلاثة متقاربة، وكلها تدل على العقيدة الذي تدور موضوعاته عند أهل السنة والجماعة حول: توحيد الله في العبادة، وفي أسمائه وصفاته، والإيمان بملائكته، ورسله، واليوم الآخر، والقضاء والقدر، وسائر أصول الدين والاعتقاد، وعدم الإشراك به، والعمل بما يقتضيه ذلك في الجوارح واللسان.", "page": 23, "id": "unit-02__lesson-03__b17", "inline": [{"t": "text", "s": "وهذه التعريفات الثلاثة متقاربة، وكلها تدل على العقيدة الذي تدور "}, {"t": "emphasis", "s": "موضوعاته", "role": "lemma"}, {"t": "text", "s": " عند أهل السنة والجماعة حول: توحيد الله في العبادة، وفي أسمائه وصفاته، والإيمان بملائكته، ورسله، واليوم الآخر، والقضاء والقدر، وسائر أصول الدين والاعتقاد، وعدم الإشراك به، والعمل بما يقتضيه ذلك في الجوارح واللسان."}]}, {"type": "paragraph", "md": "حكم تعلم العقيدة: إن تعلم العقيدة بطريقة إجمالية تصح بها عقيدة المسلم لينجو عند الله: فرض عين على كل مكلف من ذكر وأنثى، وأما معرفة تفاصيل كل مسائله ففرض كفاية على العلماء المتخصصين، ونحن في هذه الدروس نقصد بتعلم العقيدة أن نتقرب إلى الله تعالى ونحبه ونخافه ونرجوه ونخشاه.", "page": 24, "id": "unit-02__lesson-03__b18", "inline": [{"t": "emphasis", "s": "حكم تعلم العقيدة:", "role": "lemma"}, {"t": "text", "s": " إن تعلم العقيدة بطريقة إجمالية تصح بها عقيدة المسلم لينجو عند الله: فرض عين على كل مكلف من ذكر وأنثى، وأما معرفة تفاصيل كل مسائله ففرض كفاية على العلماء المتخصصين، ونحن في هذه الدروس نقصد بتعلم العقيدة أن نتقرب إلى الله تعالى ونحبه ونخافه ونرجوه ونخشاه."}]}, {"type": "heading", "level": 3, "text": "فضل تعلم علم العقيدة والتوحيد وفوائده:", "page": 24, "id": "unit-02__lesson-03__b19", "role": "virtues"}, {"type": "paragraph", "md": "1- أنه العلم الذي يدرس ما يجب لله تعالى وما يتعلق به من أسماء وصفات وما يجب لرسله عليهم السلام وملائكته الكرام، ويدرس القضايا الكبرى في حياة المسلم كالإيمان وقضية القدر واليوم الآخر.", "page": 24, "id": "unit-02__lesson-03__b20", "inline": [{"t": "text", "s": "1- أنه العلم الذي يدرس ما يجب لله تعالى وما يتعلق به من أسماء وصفات وما يجب لرسله "}, {"t": "honorific", "s": "عليهم السلام"}, {"t": "text", "s": " وملائكته الكرام، ويدرس القضايا الكبرى في حياة المسلم كالإيمان وقضية القدر واليوم الآخر."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- أغلب المخالفات في العقيدة تناقض قطعيات الشريعة، وبالتالي تؤدي إلى تكذيب الله ورسوله.", "page": 24, "id": "unit-02__lesson-03__b21", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أن كثيرًا من الخلافات في العقيدة تؤدي إلى الهلاك في النار والعياذ بالله؛ فقد قال النبي صلى الله عليه وسلم : (افترقت اليهود على إحدى وسبعين فرقة، فواحدة في الجنة وسبعين في النار، وافترقت النصارى على اثنتين وسبعين فرقة فواحدة في الجنة وإحدى وسبعين في النار، والذي نفسي بيده لتفترقن أمتي على ثلاث وسبعين فرقة، فواحدة في الجنة وثنتين وسبعين في النار، قيل يا رسول الله من هم؟ قال: هم الجماعة) وفي رواية: (من كان على ما أنا عليه وأصحابي) وسبب افتراق الأمة: الخلاف في العقيدة.", "page": 24, "id": "unit-02__lesson-03__b22", "inline": [{"t": "text", "s": "3- أن كثيرًا من الخلافات في العقيدة تؤدي إلى الهلاك في النار والعياذ بالله؛ فقد قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(افترقت اليهود على إحدى وسبعين فرقة، فواحدة في الجنة وسبعين في النار، وافترقت النصارى على اثنتين وسبعين فرقة فواحدة في الجنة وإحدى وسبعين في النار، والذي نفسي بيده لتفترقن أمتي على ثلاث وسبعين فرقة، فواحدة في الجنة وثنتين وسبعين في النار، قيل يا رسول الله من هم؟ قال: هم الجماعة)", "role": "emphasis"}, {"t": "text", "s": " وفي رواية: "}, {"t": "emphasis", "s": "(من كان على ما أنا عليه وأصحابي)", "role": "emphasis"}, {"t": "text", "s": " وسبب افتراق الأمة: الخلاف في العقيدة."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "ملاحظة مهمة: قوله صلى الله عليه وسلم : (من كان على ما أنا عليه وأصحابي) إشارة إلى أن الفرقة الناجية هي من تفهم الكتاب والسنة بفهم سلف الأمة؛ فأهل البدع يستدلون على باطلهم بالكتاب والسنة، كاستدلال الخوارج على تكفير مرتكب الكبيرة بأحاديث مثل: (لا يزني الزاني حين يزنى وهو مؤمن ولا يسرق السارق حين يسرق وهو مؤمن ولا يشرب الخمر حين يشرب وهو مؤمن)، واستدلال المرجئة على أن مرتكب الكبيرة كامل الإيمان بأحاديث كقوله صلى الله عليه وسلم : (ما مِن عبدٍ قال: لا إلهَ إلا اللهُ، ثم ماتَ على ذلك إلا دخَلَ الجنةَ. قلتُ: وإن زنى وإن سَرَقَ؟ قال: وإن زنى وإن سَرَقَ)؛ فأهل السنة والجماعة يستدلون بهذه الأحاديث وغيرها بفهم سلف الأمة رضي الله عليهم؛ كما أرشدنا إلى ذلك النبي صلى الله عليه وسلم بقوله: (وأصحابي)، فهنا يثبتون الإيمان الناقص لمرتكب الكبيرة؛ فلا يكفرونه، ولا يقولون إنه كامل الإيمان، وهذا هو فهم الصحابة والسلف الصالح رضي الله عليهم.", "page": 24, "id": "unit-02__lesson-03__b23", "inline": [{"t": "emphasis", "s": "ملاحظة مهمة", "role": "emphasis"}, {"t": "text", "s": ": قوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من كان على ما أنا عليه وأصحابي)", "role": "emphasis"}, {"t": "text", "s": " إشارة إلى أن الفرقة الناجية هي من تفهم الكتاب والسنة بفهم سلف الأمة؛ فأهل البدع يستدلون على باطلهم بالكتاب والسنة، كاستدلال الخوارج على تكفير مرتكب الكبيرة بأحاديث مثل: "}, {"t": "emphasis", "s": "(لا يزني الزاني حين يزنى وهو مؤمن ولا يسرق السارق حين يسرق وهو مؤمن ولا يشرب الخمر حين يشرب وهو مؤمن)", "role": "emphasis"}, {"t": "text", "s": "، واستدلال المرجئة على أن مرتكب الكبيرة كامل الإيمان بأحاديث كقوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(ما مِن عبدٍ قال: لا إلهَ إلا اللهُ، ثم ماتَ على ذلك إلا دخَلَ الجنةَ. قلتُ: وإن زنى وإن سَرَقَ؟ قال: وإن زنى وإن سَرَقَ)", "role": "emphasis"}, {"t": "text", "s": "؛ فأهل السنة والجماعة يستدلون بهذه الأحاديث وغيرها بفهم سلف الأمة رضي الله عليهم؛ كما أرشدنا إلى ذلك النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بقوله: "}, {"t": "emphasis", "s": "(وأصحابي)", "role": "emphasis"}, {"t": "text", "s": "، فهنا يثبتون الإيمان الناقص لمرتكب الكبيرة؛ فلا يكفرونه، ولا يقولون إنه كامل الإيمان، وهذا هو فهم الصحابة والسلف الصالح رضي الله عليهم."}]}, {"type": "paragraph", "md": "4- العقيدة سبب السعادة في الدنيا والآخرة وعزة الأمة ورفعتها وبسبب العقيدة استطاع المسلمون فتح العالم وما حصل لهم ما حصل إلا لبعدهم عنها.", "page": 24, "id": "unit-02__lesson-03__b24", "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "من أين يتلقى المسلم عقيدته:", "page": 24, "id": "unit-02__lesson-03__b25", "role": "section"}, {"type": "paragraph", "md": "المسلم الذي يؤمن بالله حق إيمان هو الذي يأخذ العقيدة من مصادر عدة، وهي كالآتي:", "page": 24, "id": "unit-02__lesson-03__b26"}, {"type": "paragraph", "md": "1- الوحي: القرآن والسنة الثابتة؛ فالمسلم ويعتقد أن الله عزوجل قد فصل لنا كل شيء في الوحي؛ لأنه خالقنا وهو أعلم بما يصلح لنا، كما قال تعالى: ﴿وَنَزَّلۡنَا عَلَيۡكَ ٱلۡكِتَٰبَ تِبۡيَٰنٗا لِّكُلِّ شَيۡءٖ﴾، وقال عن نبيه محمد صلى الله عليه وسلم : ﴿وَمَا يَنطِقُ عَنِ ٱلۡهَوَىٰٓ ۝٣ إِنۡ هُوَ إِلَّا وَحۡيٞ يُوحَىٰ ۝٤﴾.", "page": 25, "id": "unit-02__lesson-03__b27", "inline": [{"t": "emphasis", "s": "1- الوحي", "role": "emphasis"}, {"t": "text", "s": ": القرآن والسنة الثابتة؛ فالمسلم ويعتقد أن الله عزوجل قد فصل لنا كل شيء في الوحي؛ لأنه خالقنا وهو أعلم بما يصلح لنا، كما قال تعالى: "}, {"t": "ayah", "s": "وَنَزَّلۡنَا عَلَيۡكَ ٱلۡكِتَٰبَ تِبۡيَٰنٗا لِّكُلِّ شَيۡءٖ", "ayah": [], "verses": [{"n": 89, "text": "وَنَزَّلۡنَا عَلَيۡكَ ٱلۡكِتَٰبَ تِبۡيَٰنٗا لِّكُلِّ شَيۡءٖ", "surah": 16, "surah_name": "النحل", "ref": "16:89", "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:89"}], "surah": 16, "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:89", "surah_name": "النحل", "ayah_canonical": 89, "match": "contained", "ref": "16:89"}, {"t": "text", "s": "، وقال عن نبيه محمد "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "وَمَا يَنطِقُ عَنِ ٱلۡهَوَىٰٓ ۝٣ إِنۡ هُوَ إِلَّا وَحۡيٞ يُوحَىٰ ۝٤", "ayah": [3, 4], "verses": [{"n": 3, "text": "وَمَا يَنطِقُ عَنِ ٱلۡهَوَىٰٓ", "surah": 53, "ref_api": "https://api.quran.com/api/v4/verses/by_key/53:3", "surah_name": "النجم", "ayah_canonical": 3, "match": "exact", "ref": "53:3"}, {"n": 4, "text": "إِنۡ هُوَ إِلَّا وَحۡيٞ يُوحَىٰ", "surah": 53, "ref_api": "https://api.quran.com/api/v4/verses/by_key/53:4", "surah_name": "النجم", "ayah_canonical": 4, "match": "exact", "ref": "53:4"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- إجماع الصحابة ومن سار على نهجهم: قال الله تعالى: ﴿وَمَن يُشَاقِقِ ٱلرَّسُولَ مِنۢ بَعۡدِمَا تَبَيَّنَ لَهُ ٱلۡهُدَىٰ وَيَتَّبِعۡ غَيۡرَ سَبِيلِ ٱلۡمُؤۡمِنِينَ نُوَلِّهِۦ مَا تَوَلَّىٰ وَنُصۡلِهِۦ جَهَنَّمَۖ وَسَآءَتۡ مَصِيرًا ۝١١٥﴾؛ فإجماع السلف حجة.", "page": 25, "id": "unit-02__lesson-03__b28", "inline": [{"t": "emphasis", "s": "2- إجماع الصحابة ومن سار على نهجهم", "role": "emphasis"}, {"t": "text", "s": ": قال الله تعالى: "}, {"t": "ayah", "s": "وَمَن يُشَاقِقِ ٱلرَّسُولَ مِنۢ بَعۡدِمَا تَبَيَّنَ لَهُ ٱلۡهُدَىٰ وَيَتَّبِعۡ غَيۡرَ سَبِيلِ ٱلۡمُؤۡمِنِينَ نُوَلِّهِۦ مَا تَوَلَّىٰ وَنُصۡلِهِۦ جَهَنَّمَۖ وَسَآءَتۡ مَصِيرًا ۝١١٥", "ayah": [115], "verses": [{"n": 115, "text": "وَمَن يُشَاقِقِ ٱلرَّسُولَ مِنۢ بَعۡدِمَا تَبَيَّنَ لَهُ ٱلۡهُدَىٰ وَيَتَّبِعۡ غَيۡرَ سَبِيلِ ٱلۡمُؤۡمِنِينَ نُوَلِّهِۦ مَا تَوَلَّىٰ وَنُصۡلِهِۦ جَهَنَّمَۖ وَسَآءَتۡ مَصِيرًا", "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:115", "surah_name": "النساء", "ayah_canonical": 115, "match": "exact", "ref": "4:115"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فإجماع السلف حجة."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- العقل المسترشد بالشرع المنقاد للدين: لأن العقل وحدَه لا يصل إلى معرفة الدين إلا إذا أرشده الوحي لذلك؛ فالعقل مؤيد للشرع وليس مستقلا بمعرفة العقيدة تفصيلًا؛ فالوحي قائدُ العقل.", "page": 25, "id": "unit-02__lesson-03__b29", "inline": [{"t": "text", "s": "3- "}, {"t": "emphasis", "s": "العقل المسترشد بالشرع المنقاد للدين", "role": "emphasis"}, {"t": "text", "s": ": لأن العقل وحدَه لا يصل إلى معرفة الدين إلا إذا أرشده الوحي لذلك؛ فالعقل مؤيد للشرع وليس مستقلا بمعرفة العقيدة تفصيلًا؛ فالوحي قائدُ العقل."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- الفطرة السليمة: وَهي صفة غريزية خلق الله فيها الخليقة على قَبول الإسلام، والتهيؤ لتوحيد الله، وإدراك الحق، ويهدي بها اللهُ تعالى العبدَ إلى أصول التوحيد والإيمان دون استدلال أو برهان.", "page": 25, "id": "unit-02__lesson-03__b30", "inline": [{"t": "emphasis", "s": "4- الفطرة السليمة", "role": "emphasis"}, {"t": "text", "s": ": وَهي صفة غريزية خلق الله فيها الخليقة على قَبول الإسلام، والتهيؤ لتوحيد الله، وإدراك الحق، ويهدي بها اللهُ تعالى العبدَ إلى أصول التوحيد والإيمان دون استدلال أو برهان."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "الفوائد التربوية من تعلم العقيدة بشكل عام:", "page": 25, "id": "unit-02__lesson-03__b31", "role": "benefits"}, {"type": "paragraph", "md": "1- أن يزداد حبك لله سبحانه وتعالى وتخشاه وتعظمه أكثر، وتحب النبي صلى الله عليه وسلم الذي بلغنا العقيدة من عند الله سبحانه وتعالى .", "page": 25, "id": "unit-02__lesson-03__b32", "inline": [{"t": "text", "s": "1- أن يزداد حبك لله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " وتخشاه وتعظمه أكثر، وتحب النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " الذي بلغنا العقيدة من عند الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- النظر لما حولك في الكون من مخلوقات والتأمل فيها وربطها بقدرة الله؛ لأن الله خالق كل شيء.", "page": 25, "id": "unit-02__lesson-03__b33", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- التعرف على معاني أسماء الله سبحانه وتعالى وصفاته؛ كالرزاق الذي يرزقنا طعامنا وشرابنا، والرحمن الرحيم الذي يرحمنا ويشفق علينا ولا يرضى لنا الأذى والألم، والسميع البصير المطلع على أعمالنا ونوايانا.", "page": 25, "id": "unit-02__lesson-03__b34", "inline": [{"t": "text", "s": "3- التعرف على معاني أسماء الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " وصفاته؛ كالرزاق الذي يرزقنا طعامنا وشرابنا، والرحمن الرحيم الذي يرحمنا ويشفق علينا ولا يرضى لنا الأذى والألم، والسميع البصير المطلع على أعمالنا ونوايانا."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "5- الطاعة لله ورسوله صلى الله عليه وسلم ، ومساعدة الناس والسعي للخير والعمل على نشر الإسلام والدعوة إليه.", "page": 25, "id": "unit-02__lesson-03__b35", "inline": [{"t": "text", "s": "5- الطاعة لله ورسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، ومساعدة الناس والسعي للخير والعمل على نشر الإسلام والدعوة إليه."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- ضبط تصرفاتنا وسلوكياتنا أكثر عند تعلم العقيدة؛ لأن العقيدة تبين أن الله عز وجل الرقيب على كل شيء.", "page": 25, "id": "unit-02__lesson-03__b36", "inline": [{"t": "text", "s": "6- ضبط تصرفاتنا وسلوكياتنا أكثر عند تعلم العقيدة؛ لأن العقيدة تبين أن الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " الرقيب على كل شيء."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 25, "id": "unit-02__lesson-03__b37", "role": "assessment"}, {"type": "paragraph", "md": "1- اذكر معنى «العقيدة» و«التوحيد»، وبين لنا موضوعين من موضوعات علم العقيدة.", "page": 25, "id": "unit-02__lesson-03__b38", "inline": [{"t": "text", "s": "1- اذكر معنى "}, {"t": "quote", "s": "العقيدة"}, {"t": "text", "s": " و"}, {"t": "quote", "s": "التوحيد"}, {"t": "text", "s": "، وبين لنا موضوعين من موضوعات علم العقيدة."}], "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- اذكر فضلين لتعلم العقيدة، وأمرين يدلان على أهمية تعلم علم العقيدة والتوحيد.", "page": 25, "id": "unit-02__lesson-03__b39", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- اذكر ثلاث فوائد تربوية من تعلم العقيدة.", "page": 25, "id": "unit-02__lesson-03__b40", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "نشاط بحثي", "page": 25, "id": "unit-02__lesson-03__b41", "role": "activity"}, {"type": "paragraph", "md": "1- اسأل أهل العلم أو ابحث في كتبهم عن حديث نبوي شريف يعلمنا العقيدة الإسلامية.", "page": 25, "id": "unit-02__lesson-03__b42", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ابحث عن خمس آيات في القرآن الكريم تتكلم عن التوحيد.", "page": 25, "id": "unit-02__lesson-03__b43", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ابحث في القرآن أو السنة عن عقوبة الذي يترك التوحيد، وما مصيره يوم القيامة.", "page": 25, "id": "unit-02__lesson-03__b44", "item_role": "activity_step", "list": {"type": "ordered", "marker": "3"}}]' WHERE id='unit-02__lesson-03';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 26, "id": "unit-02__lesson-04__b01", "role": "objectives"}, {"type": "paragraph", "md": "تعريف الفقه وبيان معناه وشموليته.", "page": 26, "id": "unit-02__lesson-04__b02"}, {"type": "paragraph", "md": "بيان المعتمد في مذهب الشافعية.", "page": 26, "id": "unit-02__lesson-04__b03"}, {"type": "paragraph", "md": "تعريف الطهارة لغة وشرعًا، وبيان عناية الإسلام الطهارة، وذكر حكمة التشريع منها.", "page": 26, "id": "unit-02__lesson-04__b04"}, {"type": "paragraph", "md": "معرفة أقسام المياه وتعريف كل قسم وبيان حكمه.", "page": 26, "id": "unit-02__lesson-04__b05"}, {"type": "heading", "level": 3, "text": "تعريف الفقه وبيان معناه:", "page": 26, "id": "unit-02__lesson-04__b06", "role": "definitions"}, {"type": "paragraph", "md": "الفقه في الأصل هو: معرفة الأحكام الشرعية المتعلقة بأعمال المكلفين وأقوالهم، والمكتسبة من أدلتها التفصيلية، وهذه الأدلة التفصيلية هي: نصوص من القرآن والسنة وما يتفرع عنهما من إجماع واجتهاد.", "page": 26, "id": "unit-02__lesson-04__b07"}, {"type": "paragraph", "md": "ومثاله: معرفتنا أن حكم النية في الوضوء: الوجوب، أخذًا من قوله صلى الله عليه وسلم : (إنَّما الأعْمالُ بِالنيَّات)، وحكم الصلاة بعد العصر: الكراهة؛ أخذا من (نهيه صلى الله عليه وسلم عن الصلاة بعد العصر حتى تغرب الشمس)، وهكذا.", "page": 26, "id": "unit-02__lesson-04__b08", "inline": [{"t": "text", "s": "ومثاله: معرفتنا أن حكم النية في الوضوء: الوجوب، أخذًا من قوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إنَّما الأعْمالُ بِالنيَّات)", "role": "lemma"}, {"t": "text", "s": "، وحكم الصلاة بعد العصر: الكراهة؛ أخذا من "}, {"t": "emphasis", "s": "(نهيه", "role": "lemma"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "عن الصلاة بعد العصر حتى تغرب الشمس)", "role": "lemma"}, {"t": "text", "s": "، وهكذا."}]}, {"type": "paragraph", "md": "ويُطلق الفقه كذلك على الأحكام الشرعية نفسها، فنقول: درستُ الفقه؛ أي الأحكام الفقهية الشرعية الموجودة في كتب الفقه؛ كأحكام الوضوء والصلاة والبيع والشراء والزواج والجهاد.. وغيرها.", "page": 26, "id": "unit-02__lesson-04__b09"}, {"type": "paragraph", "md": "ففي المعنى الأول يطلق الفقه على معرفة الأحكام، وفي الثاني يُطلق على نفس الأحكام الشرعية.", "page": 26, "id": "unit-02__lesson-04__b10"}, {"type": "paragraph", "md": "المذهب المعتمد في هذا الكتاب هو مذهب السادة الشافعية، لكن مع اعتماد اختيارات فقهية تخالف المشهور المعتمد عند المتأخرين. وتنطلق هذه الاختيارات من أطروحة المؤلف في الماجستير (إعادة النظر في المعتمد عند الشافعية؛ الشيخ زكريا الأنصاري نموذجًا)، وتتلخص فكرتها وضوابطها في أنَّ الصوابَ توسيع دائرة الإفتاء والتقليد في المذهب، بحيث يُعدّ «معتمدًا»: كل قول أفتى به شيخ الإسلام زكريا الأنصاري، أو أحد تلاميذه، أو الشيخان (الرافعي والنووي)؛ شرط أن يكون هذا القول مستندًا إلى ما قاله أحد أصحاب الوجوه (المجتهدون في المذهب من أصحاب الشافعي إلى نهاية القرن الرابع الهجري)، وعليه: فالمعتمد ليس قولًا واحدًا بالضرورة؛ بل قد تتعدد الأقوال المعتمدة التي يسوغ للمفتي والمقلِّد التخيّر منها، ويُستثنى من ذلك فقط ما نصّ الأئمة على شذوذه في المذهب وهو قليل نادر.", "page": 26, "id": "unit-02__lesson-04__b11", "inline": [{"t": "text", "s": "المذهب المعتمد في هذا الكتاب هو مذهب السادة الشافعية، لكن مع اعتماد اختيارات فقهية تخالف المشهور المعتمد عند المتأخرين. وتنطلق هذه الاختيارات من أطروحة المؤلف في الماجستير (إعادة النظر في المعتمد عند الشافعية؛ الشيخ زكريا الأنصاري نموذجًا)، وتتلخص فكرتها وضوابطها في أنَّ الصوابَ توسيع دائرة الإفتاء والتقليد في المذهب، بحيث يُعدّ "}, {"t": "quote", "s": "معتمدًا"}, {"t": "text", "s": ": كل قول أفتى به شيخ الإسلام زكريا الأنصاري، أو أحد تلاميذه، أو الشيخان (الرافعي والنووي)؛ شرط أن يكون هذا القول مستندًا إلى ما قاله أحد أصحاب الوجوه (المجتهدون في المذهب من أصحاب الشافعي إلى نهاية القرن الرابع الهجري)، وعليه: فالمعتمد ليس قولًا واحدًا بالضرورة؛ بل قد تتعدد الأقوال المعتمدة التي يسوغ للمفتي والمقلِّد التخيّر منها، ويُستثنى من ذلك فقط ما نصّ الأئمة على شذوذه في المذهب وهو قليل نادر."}]}, {"type": "paragraph", "md": "فالعالِم المتأهل للنظر في الأدلة وبناء الفروع على الأصول لا يُلزم بمجرد تقليد المتأخرين؛ بل له التخريج والترجيح من مَعين المذهب بدءًا من الإمام الشافعي وأصحاب الوجوه، ولا يجوز له التقليد فيما صح عنده دليلُه وجرى على سنن أصول المذهب، وللوصول لهذه النتيجة درس المؤلف أكثر من (130) مسألة من باب القضاء، قارن فيها بين اختيارات الشيخ زكريا الأنصاري وأشهر محرري المذهب: (الرافعي والنووي، ابن حجر الهيتمي، الرملي)، وجاءت النتائج كالتالي:", "page": 27, "id": "unit-02__lesson-04__b12"}, {"type": "table", "rows": [["م", "حالة المسائل المحقَّقة", "العدد", "النسبة"], ["1", "ما توافق عليه الأربعة (الشيخان والمرجّحان) مع الشيخ زكريا.", "73", "47%"], ["2", "ما انفرد به الشيخ زكريا ترجيحًا على قواعد المذهب ومخالفةً للأربعة.", "8", "5%"], ["3", "ما خالف فيه الشيخ زكريا الشيخين وحدهما، أو مع أحد المرجِّحين.", "9", "6%"], ["4", "ما خالف فيه الشيخ زكريا تلميذَيه المرجحين (أو أحدهما) مع أحد الشيخين.", "5", "3%"], ["5", "ما خالف فيه الشيخ زكريا واحدًا فقط من الأربعة.", "7", "4%"], ["6", "ما انفرد الشيخ زكريا بذكر حكمه وأصله (مسائل بِكر) ولم يتعرض له الأربعة.", "32", "20%"], ["7", "ما ذكره الشيخ زكريا استقلالًا وتابعه المرجّحان (أو أحدهما) دون الشيخين.", "17", "11%"], ["8", "ما ذكره الشيخ زكريا متابعةً للشيخين (أو أحدهما) ولم يذكره المرجّحان.", "6", "4%"]], "html": "<table dir=\"rtl\"><tr><td>م</td><td>حالة المسائل المحقَّقة</td><td>العدد</td><td>النسبة</td></tr><tr><td>1</td><td>ما توافق عليه الأربعة (الشيخان والمرجّحان) مع الشيخ زكريا.</td><td>73</td><td>47%</td></tr><tr><td>2</td><td>ما انفرد به الشيخ زكريا ترجيحًا على قواعد المذهب ومخالفةً للأربعة.</td><td>8</td><td>5%</td></tr><tr><td>3</td><td>ما خالف فيه الشيخ زكريا الشيخين وحدهما، أو مع أحد المرجِّحين.</td><td>9</td><td>6%</td></tr><tr><td>4</td><td>ما خالف فيه الشيخ زكريا تلميذَيه المرجحين (أو أحدهما) مع أحد الشيخين.</td><td>5</td><td>3%</td></tr><tr><td>5</td><td>ما خالف فيه الشيخ زكريا واحدًا فقط من الأربعة.</td><td>7</td><td>4%</td></tr><tr><td>6</td><td>ما انفرد الشيخ زكريا بذكر حكمه وأصله (مسائل بِكر) ولم يتعرض له الأربعة.</td><td>32</td><td>20%</td></tr><tr><td>7</td><td>ما ذكره الشيخ زكريا استقلالًا وتابعه المرجّحان (أو أحدهما) دون الشيخين.</td><td>17</td><td>11%</td></tr><tr><td>8</td><td>ما ذكره الشيخ زكريا متابعةً للشيخين (أو أحدهما) ولم يذكره المرجّحان.</td><td>6</td><td>4%</td></tr></table>", "page": 27, "id": "unit-02__lesson-04__b13"}, {"type": "paragraph", "md": "فيظهر بهذه النتائج أنَّ الجهد الفقهي للشيخ زكريا وافق الأربعة في قرابة نصف المسائل، وانفرد بخُمسها وهي مسائل بكر لم يشر إليها ابن حجر والرملي؛ نظراً لتركيزهما على تراث الشيخين، في حين استوعب الشيخ زكريا تراث المذهب كله (من الشافعي، فالأصحاب، ومن وراءهم)، ونجده لسعة اطلاعه خالف الأربعة أو ثلاثة منهم في (14%) من المسائل منطلقًا من قواعد المذهب، وقوله في بعضها أسعد بالدليل، كما أن بعض المسائل التي انفرد بها تابعه عليها ابن حجر والرملي لاحقًا لقوتها. ومن ثمَّ فإغفال تراث الشيخ زكريا وعدم اعتباره من المعتمد تضييع لفقه كبير من المذهب؛ لذا فإنَّ الصحيح في «المعتمد»، أنَّ من ضمنِه اختيارات الشيخ زكريا وطلابه وأصحاب الوجوه الذين صحت أقوالهم في المذهب.", "page": 27, "id": "unit-02__lesson-04__b14", "inline": [{"t": "text", "s": "فيظهر بهذه النتائج أنَّ الجهد الفقهي للشيخ زكريا وافق الأربعة في قرابة نصف المسائل، وانفرد بخُمسها وهي مسائل بكر لم يشر إليها ابن حجر والرملي؛ نظراً لتركيزهما على تراث الشيخين، في حين استوعب الشيخ زكريا تراث المذهب كله (من الشافعي، فالأصحاب، ومن وراءهم)، ونجده لسعة اطلاعه خالف الأربعة أو ثلاثة منهم في (14%) من المسائل منطلقًا من قواعد المذهب، وقوله في بعضها أسعد بالدليل، كما أن بعض المسائل التي انفرد بها تابعه عليها ابن حجر والرملي لاحقًا لقوتها. ومن ثمَّ فإغفال تراث الشيخ زكريا وعدم اعتباره من المعتمد تضييع لفقه كبير من المذهب؛ لذا فإنَّ الصحيح في "}, {"t": "quote", "s": "المعتمد"}, {"t": "text", "s": "، أنَّ من ضمنِه اختيارات الشيخ زكريا وطلابه وأصحاب الوجوه الذين صحت أقوالهم في المذهب."}]}, {"type": "heading", "level": 3, "text": "مدخل إلى أحكام الطهارة:", "page": 27, "id": "unit-02__lesson-04__b15", "role": "rulings"}, {"type": "paragraph", "md": "الطهارة لغة: النظافة. وشرعًا: فعل ما تُستباح به الصلاة -أو ما في حكمها-.", "page": 27, "id": "unit-02__lesson-04__b16", "inline": [{"t": "emphasis", "s": "الطهارة لغة", "role": "emphasis"}, {"t": "text", "s": ": النظافة. و"}, {"t": "emphasis", "s": "شرعًا", "role": "emphasis"}, {"t": "text", "s": ": فعل ما تُستباح به الصلاة -أو ما في حكمها-."}]}, {"type": "paragraph", "md": "عناية الإسلام بالنظافة والطهارة، تتجلى في عدد من الأمور:", "page": 27, "id": "unit-02__lesson-04__b17", "inline": [{"t": "emphasis", "s": "عناية الإسلام بالنظافة والطهارة، تتجلى في عدد من الأمور:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- الأمر بالوضوء لأجل الصلاة كل يوم عدة مرات. 2- الحضُّ على الغسل في كثير من المناسبات.", "page": 28, "id": "unit-02__lesson-04__b18", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "3- الأمر بقص الأظفار، ونظافة الأسنان، وطهارة الثياب.", "page": 28, "id": "unit-02__lesson-04__b19", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "حكمة تشريع الطهارة:", "page": 28, "id": "unit-02__lesson-04__b20", "inline": [{"t": "emphasis", "s": "حكمة تشريع الطهارة:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- أن الطهارة من دواعي الفطرة، فالإنسان يميل إلى النظافة بفطرته وينفر بطبعه من الوساخة والقذارة.", "page": 28, "id": "unit-02__lesson-04__b21", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2 - المحافظة على كرامة المسلم وعزته؛ فالناس يميلون بطبعهم للنظيف ويرغبون بالاجتماع إليه، والجلوس معه، ويكرهون الوسِخ، ويحتقرونه، وينفرونه، وينفرون منه، ولا يرغبون بالجلوس إليه.", "page": 28, "id": "unit-02__lesson-04__b22", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3 - المحافظة على الصحة؛ فالأمراض أكثر ما تنتشر بين الناس بسبب الأوساخ والأقذار.", "page": 28, "id": "unit-02__lesson-04__b23", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4 - الوقوف بين يدي الله طاهرًا نظيفًا؛ فالله تعالى يحب التوابين ويحب المتطهرين.", "page": 28, "id": "unit-02__lesson-04__b24", "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "أقسام المياه:", "page": 28, "id": "unit-02__lesson-04__b25", "role": "section"}, {"type": "paragraph", "md": "الماءُ قسمان لا ثالث لهما -وهو مذهب الشافعي القديم-: طَاهِرٌ مُطَهِّرٌ، ونَجِسٌ مُنَجِّسٌّ.", "page": 28, "id": "unit-02__lesson-04__b26", "inline": [{"t": "emphasis", "s": "الماءُ قسمان", "role": "emphasis"}, {"t": "text", "s": " لا ثالث لهما -وهو مذهب الشافعي القديم-: طَاهِرٌ مُطَهِّرٌ، ونَجِسٌ مُنَجِّسٌّ."}]}, {"type": "paragraph", "md": "1- فالطاهر المُطَهِّر (الطَّهُور) هو ما كان على أصله كماء المطر والعيون والأنهار ونحو ذلك، وهو الماء المُطْلَق وهذا ماءٌ يرفع الأحداث كالجَنَابة وغيرها، وهذا مُجْمَعٌ عليه.", "page": 28, "id": "unit-02__lesson-04__b27", "inline": [{"t": "text", "s": "1- فالطاهر المُطَهِّر "}, {"t": "emphasis", "s": "(الطَّهُور)", "role": "emphasis"}, {"t": "text", "s": " هو ما كان على أصله كماء المطر والعيون والأنهار ونحو ذلك، وهو الماء المُطْلَق وهذا ماءٌ يرفع الأحداث كالجَنَابة وغيرها، وهذا مُجْمَعٌ عليه."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "والماء إذا خالَطَهُ طاهرٌ مثل الطين والطحالب فلم يخرجه عن اسم الماء: بَقيَ على طهوريَّته؛ فإن تَغَيَّرَ اسمُهُ كأنْ صَارَ مَائِعًا باسمٍ آخرَ كالشَّاي والقهوة: لم يَعُدْ ماءً مطلقًا.", "page": 28, "id": "unit-02__lesson-04__b28"}, {"type": "paragraph", "md": "والماء المُستَعْمَلُ في الطهارات كالوضوء والغسل: طاهِرٌ مُطَهِّرٌ، طالما بقي على أصله، ولم ينجس.", "page": 28, "id": "unit-02__lesson-04__b29"}, {"type": "paragraph", "md": "2- وأما النجس؛ فيَنْجُسُ بمخالطة النَّجاسة فَيَتَغَيَّرُ بها، والتغيُّر الذي يُعتبر به الماء غير مطهر يكون بتغير أحد أوصافه الثلاثة كاللون والرائحة والطَّعم.. وأما تغير رائحة الماء لمقاربته النجاسة فقط فلا يضر. ولا فرقَ بين كثير الماء وقليله في هذا الباب، لقوله صلى الله عليه وسلم : (الْمَاءُ طَهُورٌ لَا يُنَجِّسُهُ شَيْءٌ).", "page": 28, "id": "unit-02__lesson-04__b30", "inline": [{"t": "text", "s": "2- وأما النجس؛ فيَنْجُسُ بمخالطة النَّجاسة فَيَتَغَيَّرُ بها، والتغيُّر الذي يُعتبر به الماء غير مطهر يكون بتغير أحد أوصافه الثلاثة كاللون والرائحة والطَّعم.. وأما تغير رائحة الماء لمقاربته النجاسة فقط فلا يضر. ولا فرقَ بين كثير الماء وقليله في هذا الباب، لقوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(الْمَاءُ طَهُورٌ لَا يُنَجِّسُهُ شَيْءٌ)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "التقويم والأسئلة: 1-عرف الفقه، وهل يشمل الفقه كل ما يحتاجه الفرد المسلم أم لا؟. 2- ما الطهارة، ولماذا أمرنا الله تعالى بالتطهر دائمًا؟. 3- ما أقسام المياه؟ وهل إذا أصاب الماء طين فتغير قليلًا يُعتبر مُطهرًا أم غير مطهر؟!", "page": 28, "id": "unit-02__lesson-04__b31"}, {"type": "heading", "level": 3, "text": "نشاط حواري", "page": 28, "id": "unit-02__lesson-04__b32", "role": "activity"}, {"type": "paragraph", "md": "نتناقش سوية: هل الماء الموجود في المسابح يُعتبر طاهرًا مطهرا أم نجسًا؟ فصل في الأمر..", "page": 28, "id": "unit-02__lesson-04__b33", "item_role": "activity_step"}]' WHERE id='unit-02__lesson-04';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 29, "id": "unit-02__lesson-05__b01", "role": "objectives"}, {"type": "paragraph", "md": "أن يتعرف على معنى اتباع النبي صلى الله عليه وسلم .", "page": 29, "id": "unit-02__lesson-05__b02", "inline": [{"t": "text", "s": "أن يتعرف على معنى اتباع النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "أن يتبع النبي صلى الله عليه وسلم في أقواله وأفعاله وسائر أحواله.", "page": 29, "id": "unit-02__lesson-05__b03", "inline": [{"t": "text", "s": "أن يتبع النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في أقواله وأفعاله وسائر أحواله."}]}, {"type": "paragraph", "md": "أن يتعرف معنى البدعة ويتجنب سبيلها.", "page": 29, "id": "unit-02__lesson-05__b04"}, {"type": "heading", "level": 3, "text": "أهمية الاتباع وحرمة الابتداع:", "page": 29, "id": "unit-02__lesson-05__b05", "role": "section"}, {"type": "paragraph", "md": "ديننا دين اتباع لا ابتداع، فاتباع النبي صلى الله عليه وسلم فيما شرعه له ربُّه: هو أصل الأصول في ديننا، بل هو الدين كله: ﴿وَمَنۡ أَحۡسَنُ دِينٗا مِّمَّنۡ أَسۡلَمَ وَجۡهَهُۥ لِلَّهِ وَهُوَ مُحۡسِنٞ وَٱتَّبَعَ مِلَّةَ إِبۡرَٰهِيمَ حَنِيفٗاۗ﴾، ﴿ٱتَّبِعۡ مَآ أُوحِيَ إِلَيۡكَ مِن رَّبِّكَۖ﴾، وإذا كان رسول الله صلى الله عليه وسلم لا يملك في هذا الدين شيئا، فلا يعمل فيه شيئًا من عنده، ولا يحدث فيه حدثا؛ كما قال تعالى عنه: ﴿إِنۡ أَتَّبِعُ إِلَّا مَا يُوحَىٰٓ إِلَيَّۚ﴾؛ فمن باب أولى أنه لا يجوز لأحدٍ أن يترك اتباعه صلى الله عليه وسلم ويبتدع من عنده ما شاء؛ بغية زيادة التعبد، ويخترع محدثات جديدة باسم الفكر والتجديد أو البدعة الحسنة.", "page": 29, "id": "unit-02__lesson-05__b06", "inline": [{"t": "text", "s": "ديننا دين اتباع لا ابتداع، فاتباع النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " فيما شرعه له ربُّه: هو أصل الأصول في ديننا، بل هو الدين كله: "}, {"t": "ayah", "s": "وَمَنۡ أَحۡسَنُ دِينٗا مِّمَّنۡ أَسۡلَمَ وَجۡهَهُۥ لِلَّهِ وَهُوَ مُحۡسِنٞ وَٱتَّبَعَ مِلَّةَ إِبۡرَٰهِيمَ حَنِيفٗاۗ", "ayah": [], "verses": [{"n": 125, "text": "وَمَنۡ أَحۡسَنُ دِينٗا مِّمَّنۡ أَسۡلَمَ وَجۡهَهُۥ لِلَّهِ وَهُوَ مُحۡسِنٞ وَٱتَّبَعَ مِلَّةَ إِبۡرَٰهِيمَ حَنِيفٗاۗ", "surah": 4, "surah_name": "النساء", "ref": "4:125", "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:125"}], "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:125", "surah_name": "النساء", "ayah_canonical": 125, "match": "contained", "ref": "4:125"}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "ٱتَّبِعۡ مَآ أُوحِيَ إِلَيۡكَ مِن رَّبِّكَۖ", "ayah": [], "verses": [{"n": 106, "text": "ٱتَّبِعۡ مَآ أُوحِيَ إِلَيۡكَ مِن رَّبِّكَۖ", "surah": 6, "surah_name": "الأنعام", "ref": "6:106", "ref_api": "https://api.quran.com/api/v4/verses/by_key/6:106"}], "surah": 6, "ref_api": "https://api.quran.com/api/v4/verses/by_key/6:106", "surah_name": "الأنعام", "ayah_canonical": 106, "match": "contained", "ref": "6:106"}, {"t": "text", "s": "، وإذا كان رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لا يملك في هذا الدين شيئا، فلا يعمل فيه شيئًا من عنده، ولا يحدث فيه حدثا؛ كما قال تعالى عنه: "}, {"t": "ayah", "s": "إِنۡ أَتَّبِعُ إِلَّا مَا يُوحَىٰٓ إِلَيَّۚ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فمن باب أولى أنه لا يجوز لأحدٍ أن يترك اتباعه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ويبتدع من عنده ما شاء؛ بغية زيادة التعبد، ويخترع محدثات جديدة باسم الفكر والتجديد أو البدعة الحسنة."}]}, {"type": "paragraph", "md": "وقد كان سلفنا الصالح حريصون على ‌الاتباع وترك الابتداع؛ في كل شيء، فالابتداع لا يشمل العبادات فحسب، بل ويشمل الفكر الدخيل على الإسلام كذلك، فإنَّ الابتداع الفكري أخطر من التعبدي لأنه سبب الضلال في أصل الدين، كبدعة الخوارج والمعتزلة قديمًا، وبدعة الليبرالية والديمقراطية والعلمانية حديثًا.", "page": 29, "id": "unit-02__lesson-05__b07"}, {"type": "paragraph", "md": "ومصادر ‌الاتباع الشرعي هي: الكتاب، والسنة، ومنهج السلف الصالح، وقد ورد في القرآن نحو (50) آية تحث على الاتباع وتحذر من الابتداع أو اتباع الهوى والشيطان.", "page": 29, "id": "unit-02__lesson-05__b08"}, {"type": "paragraph", "md": "وعكس الاتباع: الابتداع، والبدعة: «طريقة في الدّين مخترعة تضاهي الطريقة الشّرعيّة يقصد بالسّلوك عليها المبالغة في التّعبّد لله تعالى»، فكل بدعة ضلالة، وكل ضلالة في النار، قال النّبيّ صلى الله عليه وسلم : (من رغب عن سنَّتي فليس منّي)، وقال صلى الله عليه وسلم : (إنَّ الله احتجز التّوبة عن صاحب كلّ بدعة).", "page": 29, "id": "unit-02__lesson-05__b09", "inline": [{"t": "text", "s": "وعكس الاتباع: الابتداع، والبدعة: "}, {"t": "quote", "s": "طريقة في الدّين مخترعة تضاهي الطريقة الشّرعيّة يقصد بالسّلوك عليها المبالغة في التّعبّد لله تعالى"}, {"t": "text", "s": "، فكل بدعة ضلالة، وكل ضلالة في النار، قال النّبيّ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من رغب عن سنَّتي فليس منّي)", "role": "emphasis"}, {"t": "text", "s": "، وقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إنَّ الله احتجز التّوبة عن صاحب كلّ بدعة)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وقال صلى الله عليه وسلم : (من عمل عملا ليس عليه أمرنا فهو رد)، وقوله (من أمرنا) يعني أنَّ البدعة لا تدخل في العادات والمباحات، فقد قال النبي صلى الله عليه وسلم : (أنتم أعلم بشؤون دنياكم)، وإنما تدخل البدعة المحرمة في أمور الدين زيادةً أو نقصًا، إذا كانت على طريقة يلتزمها المرء فتضاهي الطريقة الشرعية.", "page": 29, "id": "unit-02__lesson-05__b10", "inline": [{"t": "text", "s": "وقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(من عمل عملا ليس عليه أمرنا فهو رد)", "role": "emphasis"}, {"t": "text", "s": "، وقوله "}, {"t": "emphasis", "s": "(من أمرنا)", "role": "emphasis"}, {"t": "text", "s": " يعني أنَّ البدعة لا تدخل في العادات والمباحات، فقد قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(أنتم أعلم بشؤون دنياكم)", "role": "emphasis"}, {"t": "text", "s": "، وإنما تدخل البدعة المحرمة في أمور الدين زيادةً أو نقصًا، إذا كانت على طريقة يلتزمها المرء فتضاهي الطريقة الشرعية."}]}, {"type": "heading", "level": 3, "text": "‌‌من فوائد الاتباع ومضار الابتداع:", "page": 30, "id": "unit-02__lesson-05__b11", "role": "benefits"}, {"type": "paragraph", "md": "‌‌الاتباع دليل المحبة الكاملة للهِ عز وجل ولرسوله صلى الله عليه وسلم : ﴿قُلۡ إِن كُنتُمۡ تُحِبُّونَ ٱللَّهَ فَٱتَّبِعُونِي يُحۡبِبۡكُمُ ٱللَّهُ وَيَغۡفِرۡ لَكُمۡ ذُنُوبَكُمۡۚ﴾، واتباع الهوى دليل عدم محبة الله.", "page": 30, "id": "unit-02__lesson-05__b12", "inline": [{"t": "text", "s": "‌‌الاتباع دليل المحبة الكاملة للهِ "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ولرسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "قُلۡ إِن كُنتُمۡ تُحِبُّونَ ٱللَّهَ فَٱتَّبِعُونِي يُحۡبِبۡكُمُ ٱللَّهُ وَيَغۡفِرۡ لَكُمۡ ذُنُوبَكُمۡۚ", "ayah": [], "verses": [{"n": 31, "text": "قُلۡ إِن كُنتُمۡ تُحِبُّونَ ٱللَّهَ فَٱتَّبِعُونِي يُحۡبِبۡكُمُ ٱللَّهُ وَيَغۡفِرۡ لَكُمۡ ذُنُوبَكُمۡۚ", "surah": 3, "surah_name": "آل عمران", "ref": "3:31", "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:31"}], "surah": 3, "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:31", "surah_name": "آل عمران", "ayah_canonical": 31, "match": "contained", "ref": "3:31"}, {"t": "text", "s": "، واتباع الهوى دليل عدم محبة الله."}]}, {"type": "paragraph", "md": "يحصل للعبد به السّعادة وطيب العيش في الدَّارين", "page": 30, "id": "unit-02__lesson-05__b13"}, {"type": "paragraph", "md": "الخروج من هوى النّفس وعبادة الذَّات.", "page": 30, "id": "unit-02__lesson-05__b14"}, {"type": "paragraph", "md": "ضمان السّلامة والأمن من الخطأ لعصمة المتبوع صلى الله عليه وسلم ، فقد «خطَّ رسول الله صلى الله عليه وسلم خطّا، ثمّ قال: (هذا سبيل الله) ثمّ خطّ خطوطا عن يمينه وعن شماله، ثمّ قال: (هذه سبل متفرّقة على كلّ سبيل منها شيطان يدعو إليه، ثمَّ قرأ: ﴿وَأَنَّ هَٰذَا صِرَٰطِي مُسۡتَقِيمٗا فَٱتَّبِعُوهُۖ وَلَا تَتَّبِعُواْ ٱلسُّبُلَ فَتَفَرَّقَ بِكُمۡ عَن سَبِيلِهِۦۚ ذَٰلِكُمۡ وَصَّىٰكُم بِهِۦ لَعَلَّكُمۡ تَتَّقُونَ ۝١٥٣﴾).", "page": 30, "id": "unit-02__lesson-05__b15", "inline": [{"t": "text", "s": "ضمان السّلامة والأمن من الخطأ لعصمة المتبوع "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، فقد «خطَّ رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " خطّا، ثمّ قال: "}, {"t": "emphasis", "s": "(هذا سبيل الله)", "role": "emphasis"}, {"t": "text", "s": " ثمّ خطّ خطوطا عن يمينه وعن شماله، ثمّ قال: (هذه سبل متفرّقة على كلّ سبيل منها شيطان يدعو إليه، ثمَّ قرأ: "}, {"t": "ayah", "s": "وَأَنَّ هَٰذَا صِرَٰطِي مُسۡتَقِيمٗا فَٱتَّبِعُوهُۖ وَلَا تَتَّبِعُواْ ٱلسُّبُلَ فَتَفَرَّقَ بِكُمۡ عَن سَبِيلِهِۦۚ ذَٰلِكُمۡ وَصَّىٰكُم بِهِۦ لَعَلَّكُمۡ تَتَّقُونَ ۝١٥٣", "ayah": [153], "verses": [{"n": 153, "text": "وَأَنَّ هَٰذَا صِرَٰطِي مُسۡتَقِيمٗا فَٱتَّبِعُوهُۖ وَلَا تَتَّبِعُواْ ٱلسُّبُلَ فَتَفَرَّقَ بِكُمۡ عَن سَبِيلِهِۦۚ ذَٰلِكُمۡ وَصَّىٰكُم بِهِۦ لَعَلَّكُمۡ تَتَّقُونَ", "surah": 6, "ref_api": "https://api.quran.com/api/v4/verses/by_key/6:153", "surah_name": "الأنعام", "ayah_canonical": 153, "match": "exact", "ref": "6:153"}], "surah": null, "ref_api": null}, {"t": "text", "s": ")."}]}, {"type": "paragraph", "md": "الاتّباع لا يكون إلّا للصّالحين المتّقين الّذين يعرفون الشرع ويعملون به فيكونون قدوة للناس.", "page": 30, "id": "unit-02__lesson-05__b16"}, {"type": "paragraph", "md": "لا يجوز اتِّباع الكذّابين وطلّاب السّلطة والدنيا، الَّذين يقرءون القرآن لا يجاوز حناجرهم.", "page": 30, "id": "unit-02__lesson-05__b17"}, {"type": "paragraph", "md": "جنس البدعة أبغض إلى الله تعالى من جنس المعاصي؛ فالمعصية شهوة، والبدعة شبهة، والشبهات أشد خطرًا من الشهوات، ولذلك فالبدع تدخل على العباد أكثر من المعاصي.. ولكن هذا لا يعني أنَّ كل بدعة شر من المعصية، فكبيرة القتل مثلا أهون من بدعةِ التكفير المجرد بغير قتل؛ بينما البدعة الكبيرة شرُّ من المعصية الكبيرة، والمعصيرة الكبيرة شر من البدعة الصغيرة، وهذا باب دقيق يُنتبه له.", "page": 30, "id": "unit-02__lesson-05__b18"}, {"type": "paragraph", "md": "تؤدّي البدعة إلى خلط الحقّ بالباطل، مما يؤدي لتحير قليلي العلم في التّمييز بينهما.", "page": 30, "id": "unit-02__lesson-05__b19"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 30, "id": "unit-02__lesson-05__b20", "role": "assessment"}, {"type": "paragraph", "md": "عرف معنى الاتباع، ومعنى الابتداع.", "page": 30, "id": "unit-02__lesson-05__b21", "item_role": "question"}, {"type": "paragraph", "md": "لماذا أمرت الشريعة بالاتباع وحذرت من الابتداع؟", "page": 30, "id": "unit-02__lesson-05__b22", "item_role": "question"}, {"type": "paragraph", "md": "اذكر ثلاثة أمثلة على بدع فكرية معاصرة، وأخرى عملية.", "page": 30, "id": "unit-02__lesson-05__b23", "item_role": "question"}, {"type": "paragraph", "md": "عدد خمسًا من فوائد اتباع هدي النبي صلى الله عليه وسلم في تشريعه.", "page": 30, "id": "unit-02__lesson-05__b24", "inline": [{"t": "text", "s": "عدد خمسًا من فوائد اتباع هدي النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في تشريعه."}], "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط اجتماعي دعوي", "page": 30, "id": "unit-02__lesson-05__b25", "role": "activity"}, {"type": "paragraph", "md": "نتعرف على بدعة موجودة في منطقتنا ونسعى لتغييرها بصورة جماعية بإشراف المربي", "page": 30, "id": "unit-02__lesson-05__b26", "item_role": "activity_step"}]' WHERE id='unit-02__lesson-05';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: ﴿قُلۡ أَعُوذُ بِرَبِّ ٱلۡفَلَقِ ۝١ مِن شَرِّ مَا خَلَقَ ۝٢ وَمِن شَرِّ غَاسِقٍ إِذَا وَقَبَ ۝٣ وَمِن شَرِّ ٱلنَّفَّٰثَٰتِ فِي ٱلۡعُقَدِ ۝٤ وَمِن شَرِّ حَاسِدٍ إِذَا حَسَدَ ۝٥﴾", "page": 31, "id": "unit-03__lesson-01__b01", "inline": [{"t": "text", "s": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: "}, {"t": "ayah", "s": "قُلۡ أَعُوذُ بِرَبِّ ٱلۡفَلَقِ ۝١ مِن شَرِّ مَا خَلَقَ ۝٢ وَمِن شَرِّ غَاسِقٍ إِذَا وَقَبَ ۝٣ وَمِن شَرِّ ٱلنَّفَّٰثَٰتِ فِي ٱلۡعُقَدِ ۝٤ وَمِن شَرِّ حَاسِدٍ إِذَا حَسَدَ ۝٥", "ayah": [1, 2, 3, 4, 5], "verses": [{"n": 1, "text": "قُلۡ أَعُوذُ بِرَبِّ ٱلۡفَلَقِ", "surah": 113, "ref_api": "https://api.quran.com/api/v4/verses/by_key/113:1", "surah_name": "الفلق", "ayah_canonical": 1, "match": "exact", "ref": "113:1"}, {"n": 2, "text": "مِن شَرِّ مَا خَلَقَ", "surah": 113, "ref_api": "https://api.quran.com/api/v4/verses/by_key/113:2", "surah_name": "الفلق", "ayah_canonical": 2, "match": "exact", "ref": "113:2"}, {"n": 3, "text": "وَمِن شَرِّ غَاسِقٍ إِذَا وَقَبَ", "surah": 113, "ref_api": "https://api.quran.com/api/v4/verses/by_key/113:3", "surah_name": "الفلق", "ayah_canonical": 3, "match": "exact", "ref": "113:3"}, {"n": 4, "text": "وَمِن شَرِّ ٱلنَّفَّٰثَٰتِ فِي ٱلۡعُقَدِ", "surah": 113, "ref_api": "https://api.quran.com/api/v4/verses/by_key/113:4", "surah_name": "الفلق", "ayah_canonical": 4, "match": "exact", "ref": "113:4"}, {"n": 5, "text": "وَمِن شَرِّ حَاسِدٍ إِذَا حَسَدَ", "surah": 113, "ref_api": "https://api.quran.com/api/v4/verses/by_key/113:5", "surah_name": "الفلق", "ayah_canonical": 5, "match": "exact", "ref": "113:5"}], "surah": null, "ref_api": null}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 31, "id": "unit-03__lesson-01__b02", "role": "objectives"}, {"type": "paragraph", "md": "معرفة فضل سورة الفلق، ومقاصدها.", "page": 31, "id": "unit-03__lesson-01__b03"}, {"type": "paragraph", "md": "معرفة أهم موضوعات سورة الفلق والألفاظ الغريبة الواردة فيها.", "page": 31, "id": "unit-03__lesson-01__b04"}, {"type": "paragraph", "md": "معرفة المعنى الإجمالي للسورة، وأهم الفوائد التربوية والعلمية الواردة فيها.", "page": 31, "id": "unit-03__lesson-01__b05"}, {"type": "paragraph", "md": "يحفظ السورة بضبط وإتقان، بعد معرفة الألفاظ الغريبة الواردة فيها.", "page": 31, "id": "unit-03__lesson-01__b06"}, {"type": "heading", "level": 3, "text": "مقصد السورة، وأهم الموضوعات التي اشتملت عليها:", "page": 31, "id": "unit-03__lesson-01__b07", "role": "main_themes"}, {"type": "paragraph", "md": "أما مقصدها فهو: الاستعاذة من جميع أنواع الشرور عموما وخصوصا.", "page": 31, "id": "unit-03__lesson-01__b08"}, {"type": "paragraph", "md": "وموضوعاتها: الاستعاذة بالله من الشر، والأوقات التي يكثر فيها حدوثه، ومن شر السحرة والحاسدين.", "page": 31, "id": "unit-03__lesson-01__b09"}, {"type": "heading", "level": 3, "text": "غريب الكلمات:", "page": 31, "id": "unit-03__lesson-01__b10", "role": "vocabulary"}, {"type": "paragraph", "md": "- ﴿ٱلۡفَلَقِ ۝١﴾: أي: الصبح المتصدع عن الظلمة.", "page": 31, "id": "unit-03__lesson-01__b11", "inline": [{"t": "text", "s": "- "}, {"t": "ayah", "s": "ٱلۡفَلَقِ ۝١", "ayah": [1], "verses": [{"n": 1, "text": "ٱلۡفَلَقِ", "surah": 113, "ref_api": "https://api.quran.com/api/v4/verses/by_key/113:1", "surah_name": "الفلق", "ayah_canonical": 1, "match": "contained", "ref": "113:1"}], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي: الصبح المتصدع عن الظلمة."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- ﴿غَاسِقٍ إِذَا وَقَبَ ۝٣﴾: أي: الليل المظلم إذا دخل واشتد ظلامه.", "page": 31, "id": "unit-03__lesson-01__b12", "inline": [{"t": "text", "s": "- "}, {"t": "ayah", "s": "غَاسِقٍ إِذَا وَقَبَ ۝٣", "ayah": [3], "verses": [{"n": 3, "text": "غَاسِقٍ إِذَا وَقَبَ", "surah": 113, "ref_api": "https://api.quran.com/api/v4/verses/by_key/113:3", "surah_name": "الفلق", "ayah_canonical": 3, "match": "contained", "ref": "113:3"}], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي: الليل المظلم إذا دخل واشتد ظلامه."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- ﴿ٱلنَّفَّٰثَٰتِ فِي ٱلۡعُقَدِ ۝٤﴾: أي: السواحر اللاتي ينفثن في عقد الخيط حين يرقين عليها. والنفث: النفخ.", "page": 31, "id": "unit-03__lesson-01__b13", "inline": [{"t": "text", "s": "- "}, {"t": "ayah", "s": "ٱلنَّفَّٰثَٰتِ فِي ٱلۡعُقَدِ ۝٤", "ayah": [4], "verses": [{"n": 4, "text": "ٱلنَّفَّٰثَٰتِ فِي ٱلۡعُقَدِ", "surah": 113, "ref_api": "https://api.quran.com/api/v4/verses/by_key/113:4", "surah_name": "الفلق", "ayah_canonical": 4, "match": "contained", "ref": "113:4"}], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي: السواحر اللاتي ينفثن في عقد الخيط حين يرقين عليها. والنفث: النفخ."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- الحسد: هو كراهية نعمة الله على الغير؛ سواء تمنى زوالها أو لم يتمن.، فإن تمنى زوالها فهو شر أكبر، وهذا الحسد موجود في كثير من الناس وهو من خصال اليهود كما هو من خصال إبليس لعنه الله.", "page": 31, "id": "unit-03__lesson-01__b14", "inline": [{"t": "text", "s": "- "}, {"t": "emphasis", "s": "الحسد", "role": "lemma"}, {"t": "text", "s": ": هو كراهية نعمة الله على الغير؛ سواء تمنى زوالها أو لم يتمن.، فإن تمنى زوالها فهو شر أكبر، وهذا "}, {"t": "emphasis", "s": "الحسد", "role": "lemma"}, {"t": "text", "s": " موجود في كثير من الناس وهو من خصال اليهود كما هو من خصال إبليس لعنه الله."}], "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "المعنى الإجمالي:", "page": 31, "id": "unit-03__lesson-01__b15", "role": "overall_meaning"}, {"type": "paragraph", "md": "افتتح الله تعالى هذه السورة الكريمة بقوله: قل -يا محمد- متعوذا بالله وحده: ألتجئ وأستجير بخالق الصباح المتصدع عن الظلمة، من شر كل مخلوق، ومن شر الليل إذا دخل واشتد ظلامه، ومن شر الساحرات اللاتي ينفثن في عقد الخيوط وقت السحر، ومن شر حاسد إذا حسد.", "page": 31, "id": "unit-03__lesson-01__b16"}, {"type": "heading", "level": 3, "text": "الفوائد التربوية:", "page": 31, "id": "unit-03__lesson-01__b17", "role": "benefits"}, {"type": "paragraph", "md": "1- أتعلم من السورة ان ألتجئ دائمًا إلى الله وأستعيذ به من كل الشرور فهو الذي يحميني ويحفظني.", "page": 32, "id": "unit-03__lesson-01__b18", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- أتجنب الحسد؛ لأنه من الاخلاق السيئة، وإذا وجدت في قلبك حسدا على المسلمين جماعات أو أفرادًا فاعلم أن في قلبك خصلة من خصال اليهود والعياذ بالله، فطهر قلبك منه، واعلم أن الخير الذي فيه غيرك إنما هو فضل من الله فلا تكره فضل الله وأقداره: ﴿أَمۡ يَحۡسُدُونَ ٱلنَّاسَ عَلَىٰ مَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضۡلِهِۦۖ﴾.", "page": 32, "id": "unit-03__lesson-01__b19", "inline": [{"t": "text", "s": "2- أتجنب الحسد؛ لأنه من الاخلاق السيئة، وإذا وجدت في قلبك حسدا على المسلمين جماعات أو أفرادًا فاعلم أن في قلبك خصلة من خصال اليهود والعياذ بالله، فطهر قلبك منه، واعلم أن الخير الذي فيه غيرك إنما هو فضل من الله فلا تكره فضل الله وأقداره: "}, {"t": "ayah", "s": "أَمۡ يَحۡسُدُونَ ٱلنَّاسَ عَلَىٰ مَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضۡلِهِۦۖ", "ayah": [], "verses": [{"n": 54, "text": "أَمۡ يَحۡسُدُونَ ٱلنَّاسَ عَلَىٰ مَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضۡلِهِۦۖ", "surah": 4, "surah_name": "النساء", "ref": "4:54", "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:54"}], "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:54", "surah_name": "النساء", "ayah_canonical": 54, "match": "contained", "ref": "4:54"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "الفوائد العلمية واللطائف:", "page": 32, "id": "unit-03__lesson-01__b20", "role": "benefits"}, {"type": "paragraph", "md": "السِّر في الاستعاذة برب الفلق في هذا الموضع؛ فإن الفلق هو الصبح الذي هو مبدأ ظهور النور، وهو الذي يطرد جيش الظلام، وعسكر المفسدين في الليل، فيأوي كل خبيث ومفسد ولص وقاطع طريق إلى بيت أو غار، وتأوي الهوام إلى حُجرها، والشياطين التي انتشرت بالليل إلى أمكنتها؛ فأمر اللهُ تعالى عبادَه أن يستعيذوا برب النور الذي يقهر الظلمة ويزيلها، ويقهر عسكرها وجيشها؛ ولهذا ذكر سبحانه أنه يخرج عباده من الظلمات إلى النور، ويدع الكفار في ظلمات كفرهم؛ قال تعالى: ﴿ٱللَّهُ وَلِيُّ ٱلَّذِينَ ءَامَنُواْ يُخۡرِجُهُم مِّنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِۖ وَٱلَّذِينَ كَفَرُوٓاْ أَوۡلِيَآؤُهُمُ ٱلطَّٰغُوتُ يُخۡرِجُونَهُم مِّنَ ٱلنُّورِ إِلَى ٱلظُّلُمَٰتِۗ﴾.", "page": 32, "id": "unit-03__lesson-01__b21", "inline": [{"t": "emphasis", "s": "السِّر في الاستعاذة برب الفلق في هذا الموضع", "role": "emphasis"}, {"t": "text", "s": "؛ فإن الفلق هو الصبح الذي هو مبدأ ظهور النور، وهو الذي يطرد جيش الظلام، وعسكر المفسدين في الليل، فيأوي كل خبيث ومفسد ولص وقاطع طريق إلى بيت أو غار، وتأوي الهوام إلى حُجرها، والشياطين التي انتشرت بالليل إلى أمكنتها؛ فأمر اللهُ تعالى عبادَه أن يستعيذوا برب النور الذي يقهر الظلمة ويزيلها، ويقهر عسكرها وجيشها؛ ولهذا ذكر سبحانه أنه يخرج عباده من الظلمات إلى النور، ويدع الكفار في ظلمات كفرهم؛ قال تعالى: "}, {"t": "ayah", "s": "ٱللَّهُ وَلِيُّ ٱلَّذِينَ ءَامَنُواْ يُخۡرِجُهُم مِّنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِۖ وَٱلَّذِينَ كَفَرُوٓاْ أَوۡلِيَآؤُهُمُ ٱلطَّٰغُوتُ يُخۡرِجُونَهُم مِّنَ ٱلنُّورِ إِلَى ٱلظُّلُمَٰتِۗ", "ayah": [], "verses": [{"n": 257, "text": "ٱللَّهُ وَلِيُّ ٱلَّذِينَ ءَامَنُواْ يُخۡرِجُهُم مِّنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِۖ وَٱلَّذِينَ كَفَرُوٓاْ أَوۡلِيَآؤُهُمُ ٱلطَّٰغُوتُ يُخۡرِجُونَهُم مِّنَ ٱلنُّورِ إِلَى ٱلظُّلُمَٰتِۗ", "surah": 2, "surah_name": "البقرة", "ref": "2:257", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:257"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:257", "surah_name": "البقرة", "ayah_canonical": 257, "match": "contained", "ref": "2:257"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 32, "id": "unit-03__lesson-01__b22", "role": "assessment"}, {"type": "paragraph", "md": "1- ما موضوع سورة الفلق؟", "page": 32, "id": "unit-03__lesson-01__b23", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما معنى ﴿وَمِن شَرِّ ٱلنَّفَّٰثَٰتِ فِي ٱلۡعُقَدِ ۝٤﴾", "page": 32, "id": "unit-03__lesson-01__b24", "inline": [{"t": "text", "s": "2- ما معنى "}, {"t": "ayah", "s": "وَمِن شَرِّ ٱلنَّفَّٰثَٰتِ فِي ٱلۡعُقَدِ ۝٤", "ayah": [4], "verses": [{"n": 4, "text": "وَمِن شَرِّ ٱلنَّفَّٰثَٰتِ فِي ٱلۡعُقَدِ", "surah": 113, "ref_api": "https://api.quran.com/api/v4/verses/by_key/113:4", "surah_name": "الفلق", "ayah_canonical": 4, "match": "exact", "ref": "113:4"}], "surah": null, "ref_api": null}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- اذكر فائدة تربوية تعلمتها من سورة الفلق.", "page": 32, "id": "unit-03__lesson-01__b25", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4-لماذا ذكر لفظة «الفلق» في السورة؟", "page": 32, "id": "unit-03__lesson-01__b26", "inline": [{"t": "text", "s": "4-لماذا ذكر لفظة "}, {"t": "quote", "s": "الفلق"}, {"t": "text", "s": " في السورة؟"}], "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط بحثي علمي", "page": 32, "id": "unit-03__lesson-01__b27", "role": "activity"}, {"type": "paragraph", "md": "اقرأ تفسير سورة الفلق من المختصر في التفسير أو تفسير السعدي واكتب أهم الفوائد التي أعجبتك.", "page": 32, "id": "unit-03__lesson-01__b28", "item_role": "activity_step"}, {"type": "paragraph", "md": "لماذا أمرنا الله تعالى أن نتعوذ من «الغاسق إذا وقب»، أي: من الليل إذا هبط ابحث عن ذلك في كتب التفسير أو عن طريق سؤال أهل العلم.", "page": 32, "id": "unit-03__lesson-01__b29", "inline": [{"t": "text", "s": "لماذا أمرنا الله تعالى أن نتعوذ من "}, {"t": "quote", "s": "الغاسق إذا وقب"}, {"t": "text", "s": "، أي: من الليل إذا هبط ابحث عن ذلك في كتب التفسير أو عن طريق سؤال أهل العلم."}], "item_role": "activity_step"}, {"type": "paragraph", "md": "في بداية السورة ذكر الله عزوجل الفعل «قل»، من هو المخاطب به ولمن يجب أن يقول، ابحث عن ذلك في كتب التفسير المختصرة أو اسأل أهل العلم.", "page": 32, "id": "unit-03__lesson-01__b30", "inline": [{"t": "text", "s": "في بداية السورة ذكر الله عزوجل الفعل "}, {"t": "quote", "s": "قل"}, {"t": "text", "s": "، من هو المخاطب به ولمن يجب أن يقول، ابحث عن ذلك في كتب التفسير المختصرة أو اسأل أهل العلم."}], "item_role": "activity_step"}]' WHERE id='unit-03__lesson-01';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "عَنْ ابن عُمَرَ رضي الله عنهما قَالَ: قالَ رَسُولُ اللَّهِ صلى الله عليه وسلم : (‌بُنِيَ ‌الإِسْلامُ ‌عَلَى ‌خَمْسٍ: شَهادَةِ أَنْ لا إِلَهَ إلَّا اللَّهُ وأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ، وإِقامِ الصَّلاةِ، وإِيتاءِ الزَّكاةِ، والحَجِّ، وصَوْمِ رَمَضانَ) [رواه البخاري ومسلم].", "page": 33, "id": "unit-03__lesson-02__b01", "inline": [{"t": "text", "s": "عَنْ ابن عُمَرَ "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " قَالَ: قالَ رَسُولُ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : (‌بُنِيَ ‌الإِسْلامُ ‌عَلَى ‌خَمْسٍ: شَهادَةِ أَنْ لا إِلَهَ إلَّا اللَّهُ وأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ، وإِقامِ الصَّلاةِ، وإِيتاءِ الزَّكاةِ، والحَجِّ، وصَوْمِ رَمَضانَ) "}, {"t": "citation", "s": "[رواه البخاري ومسلم]", "source": "البخاري ومسلم"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 33, "id": "unit-03__lesson-02__b02", "role": "objectives"}, {"type": "paragraph", "md": "1- أن يعرف أركان الإسلام الخمسة وعلى رأسها توحيد الله تعالى.", "page": 33, "id": "unit-03__lesson-02__b03", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- أن يبدأ بأركان الإسلام الأهم فالأهم ويرتبها على ما رتبها الله تعالى.", "page": 33, "id": "unit-03__lesson-02__b04", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أن ينوع في عباداته بين الاعتقادات والقول والعمل؛ فهذا هو الإيمان.", "page": 33, "id": "unit-03__lesson-02__b05", "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "أهمية الحديث:", "page": 33, "id": "unit-03__lesson-02__b06", "role": "hadith_importance"}, {"type": "paragraph", "md": "تضمن هذا الحديث ذكر الأركان الخمسة التي وردت في الحديث مرتبة حسب أهميتها، وبدأ فيها بالشهادتين اللتين هما الأساس لكل عمل يتقرب به إلى الله عز وجل ، ثم ذكر الصلاة التي تتكرر في اليوم والليلة خمس مرات؛ فهي صلة وثيقة بين العبد وربه، ثم الزكاة التي تجب في المال إذا مضى عليه الحول لأن نفعها متعد، ثم الصيام الذي يجب شهرا في السنة، وهو عبادة غير متعدية النفع، ثم الحج الذي لا يجب في العمر إلا مرة واحدة -إن استطاع إلى ذلك سبيلا-.", "page": 33, "id": "unit-03__lesson-02__b07", "inline": [{"t": "text", "s": "تضمن هذا الحديث ذكر الأركان الخمسة التي وردت في الحديث مرتبة حسب أهميتها، وبدأ فيها بالشهادتين اللتين هما الأساس لكل عمل يتقرب به إلى الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، ثم ذكر الصلاة التي تتكرر في اليوم والليلة خمس مرات؛ فهي صلة وثيقة بين العبد وربه، ثم الزكاة التي تجب في المال إذا مضى عليه الحول لأن نفعها متعد، ثم الصيام الذي يجب شهرا في السنة، وهو عبادة غير متعدية النفع، ثم الحج الذي لا يجب في العمر إلا مرة واحدة -إن استطاع إلى ذلك سبيلا-."}]}, {"type": "heading", "level": 3, "text": "التعريف براوي الحديث:", "page": 33, "id": "unit-03__lesson-02__b08", "role": "definitions"}, {"type": "paragraph", "md": "‌عبد ‌الله ‌بن ‌عمر بن الخطاب بن نفيل العدوي: أسلم وهو صغير، ثم هاجر مع أبيه ولم يحتلم بعد، واستُصْغِر يوم أحد فرد من الغزوة، فأول غزواته الخندق، وهو ممن بايع تحت الشجرة.", "page": 33, "id": "unit-03__lesson-02__b09", "inline": [{"t": "emphasis", "s": "‌عبد ‌الله ‌بن ‌عمر بن الخطاب بن نفيل العدوي", "role": "lemma"}, {"t": "text", "s": ": أسلم وهو صغير، ثم هاجر مع أبيه ولم يحتلم بعد، واستُصْغِر يوم أحد فرد من الغزوة، فأول غزواته الخندق، وهو ممن بايع تحت الشجرة."}]}, {"type": "paragraph", "md": "من أكثر الصحابة رواية للحديث النبوي، فقد روى علما كثيرا نافعا عن: النبي صلى الله عليه وسلم وعن: أبيه، وأبي بكر، وعثمان، وعلي، وأم المؤمنين عائشة، وأخته أم المؤمنين حفصة، وغيرهم. كان مجاهدًا شجاعًا؛ فقد بارز رجلا في فتوح العراق؛ فقتله، وأخذ سلبه، وشهد فتح مصر وسكنها. وكان من أكثر الصحابة اتباعًا للنبي صلى الله عليه وسلم ، كثير النفقة والبذل حتى أعتق ألف عبد، متورعًا في دماء المسلمين لا يُقدم على شيءٍ منها ولو عُرض عليه ما عُرض. شهد فتح مكة، وله عشرون سنة، وتُوفي بمكة (73هـ)، عن عمر بلغَ 85 سنة رضي الله عنه .", "page": 33, "id": "unit-03__lesson-02__b10", "inline": [{"t": "text", "s": "من أكثر الصحابة رواية للحديث النبوي، فقد روى علما كثيرا نافعا عن: النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وعن: أبيه، وأبي بكر، وعثمان، وعلي، وأم المؤمنين عائشة، وأخته أم المؤمنين حفصة، وغيرهم. كان مجاهدًا شجاعًا؛ فقد بارز رجلا في فتوح العراق؛ فقتله، وأخذ سلبه، وشهد فتح مصر وسكنها. وكان من أكثر الصحابة اتباعًا للنبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، كثير النفقة والبذل حتى أعتق ألف عبد، متورعًا في دماء المسلمين لا يُقدم على شيءٍ منها ولو عُرض عليه ما عُرض. شهد فتح مكة، وله عشرون سنة، وتُوفي بمكة "}, {"t": "emphasis", "s": "(73هـ)", "role": "lemma"}, {"t": "text", "s": "، عن عمر بلغَ 85 سنة "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ."}]}, {"type": "heading", "level": 3, "text": "شرح الحديث:", "page": 33, "id": "unit-03__lesson-02__b11", "role": "hadith_explanation"}, {"type": "paragraph", "md": "الركن هو العمود الذي لا يقوم الشيء إلا به، وأول أركان الدين: كلمة التوحيد، ويدخل فيها عموم العقيدة وأركان الإيمان الستة: الإيمان بالله والملائكة والكتب والرسل والقدر واليوم الآخر؛ لأن المراد بالشهادتين تصديق الله ورسوله صلى الله عليه وسلم فيما جاء به؛ فيستلزم جميع ما ذكر من المعتقدات.", "page": 34, "id": "unit-03__lesson-02__b12", "inline": [{"t": "text", "s": "الركن هو العمود الذي لا يقوم الشيء إلا به، وأول أركان الدين: كلمة التوحيد، ويدخل فيها عموم العقيدة وأركان الإيمان الستة: الإيمان بالله والملائكة والكتب والرسل والقدر واليوم الآخر؛ لأن المراد بالشهادتين تصديق الله ورسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " فيما جاء به؛ فيستلزم جميع ما ذكر من المعتقدات."}]}, {"type": "paragraph", "md": "ومقتضى شهادة أن لا إله إلا الله: ألَّا يُعبد إلا الله؛ فلا يُسجد ولا يُذبح ولا يُنذر ولا يُدعى ولا يُستغاث إلا بالله، وأيضًا لا يكون الحكم إلا بشريعته، ولا الجهاد إلا في سبيله، ولا الولاء والبراء إلا لأجله سبحانه وتعالى .", "page": 34, "id": "unit-03__lesson-02__b13", "inline": [{"t": "emphasis", "s": "ومقتضى شهادة أن لا إله إلا الله", "role": "lemma"}, {"t": "text", "s": ": ألَّا يُعبد إلا الله؛ فلا يُسجد ولا يُذبح ولا يُنذر ولا يُدعى ولا يُستغاث إلا بالله، وأيضًا لا يكون الحكم إلا بشريعته، ولا الجهاد إلا في سبيله، ولا الولاء والبراء إلا لأجله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "ومقتضى شهادة أن محمدًا رسول الله: أن يُعبد الله وفقًا لما جاء به النبي صلى الله عليه وسلم وشرَعهُ لأمته؛ فهو الذي بين لنا كيف نعبد ربنا عز وجل ؛ فمن ابتدع ما لم يشرعه النبي صلى الله عليه وسلم فقد أخل بشهادة أن محمدا رسول الله.", "page": 34, "id": "unit-03__lesson-02__b14", "inline": [{"t": "emphasis", "s": "ومقتضى شهادة أن محمدًا رسول الله:", "role": "lemma"}, {"t": "text", "s": " أن يُعبد الله وفقًا لما جاء به النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وشرَعهُ لأمته؛ فهو الذي بين لنا كيف نعبد ربنا "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ؛ فمن ابتدع ما لم يشرعه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " فقد أخل بشهادة أن محمدا رسول الله."}]}, {"type": "paragraph", "md": "وهذان أصلان وركنان لا بُدَّ منهما في قبول أي عمل يعمله الإنسان: الإخلاص لله عز وجل ، ومتابعة النبي صلى الله عليه وسلم ؛ فمن أخل بأحدهما فقد بطلت عبادته أو نقصت بقدرِ ما أخل بهذين الركنين اللذين عليهما مدار الدين.", "page": 34, "id": "unit-03__lesson-02__b15", "inline": [{"t": "text", "s": "وهذان أصلان وركنان لا بُدَّ منهما في قبول أي عمل يعمله الإنسان: الإخلاص لله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، ومتابعة النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ؛ فمن أخل بأحدهما فقد بطلت عبادته أو نقصت بقدرِ ما أخل بهذين الركنين اللذين عليهما مدار الدين."}]}, {"type": "paragraph", "md": "الركن الثاني: إقامة الصلاة، وهي أهم أركان الإسلام بعد الشهادتين، وأول الأركان العملية في الدين؛ من تركها بالكلية فقد كفر، وهي عمود الإسلام وشعار الدين، والفيصل بين أهل الكفر والإيمان.", "page": 34, "id": "unit-03__lesson-02__b16", "inline": [{"t": "emphasis", "s": "الركن الثاني", "role": "lemma"}, {"t": "text", "s": ": "}, {"t": "emphasis", "s": "إقامة الصلاة", "role": "lemma"}, {"t": "text", "s": "، وهي أهم أركان الإسلام بعد الشهادتين، وأول الأركان العملية في الدين؛ من تركها بالكلية فقد كفر، وهي عمود الإسلام وشعار الدين، والفيصل بين أهل الكفر والإيمان."}]}, {"type": "paragraph", "md": "وإقامتها يقع باعتبارين: (1) إقامة القدر الواجب المجزئ في الصلاة من الأركان والواجبات.", "page": 34, "id": "unit-03__lesson-02__b17"}, {"type": "paragraph", "md": "(2) وإقامتها بكمالها؛ بالإتيان بكل ما هو مستحب فيها من النوافل والسنن.", "page": 34, "id": "unit-03__lesson-02__b18", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "وليس إقامة الصلاة مجرد أداء أركانها؛ بل أن تكون قويمة بخشوع وإخلاص؛ يقصد بها التعبد لله وحدَه.", "page": 34, "id": "unit-03__lesson-02__b19"}, {"type": "paragraph", "md": "الركن الثالث: الزكاة، وهي المال المفروض من الأموال الزكوية. وإيتاؤها: إعطاؤها من يستحقها، وهي قرينة الصلاة، قال عز وجل : ﴿فَإِن تَابُواْ وَأَقَامُواْ ٱلصَّلَوٰةَ وَءَاتَوُاْ ٱلزَّكَوٰةَ فَخَلُّواْ سَبِيلَهُمۡۚ﴾، وهي عبادة مالية نفعها متعدٍ، وقد أوجبها الله في أموال الأغنياء على وجه ينفع الفقير ولا يضر الغني؛ لأنها شيء يسير من مال كثير.", "page": 34, "id": "unit-03__lesson-02__b20", "inline": [{"t": "emphasis", "s": "الركن الثالث", "role": "lemma"}, {"t": "text", "s": ": "}, {"t": "emphasis", "s": "الزكاة", "role": "lemma"}, {"t": "text", "s": "، وهي المال المفروض من الأموال الزكوية. وإيتاؤها: إعطاؤها من يستحقها، وهي قرينة الصلاة، قال "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "فَإِن تَابُواْ وَأَقَامُواْ ٱلصَّلَوٰةَ وَءَاتَوُاْ ٱلزَّكَوٰةَ فَخَلُّواْ سَبِيلَهُمۡۚ", "ayah": [], "verses": [{"n": 5, "text": "فَإِن تَابُواْ وَأَقَامُواْ ٱلصَّلَوٰةَ وَءَاتَوُاْ ٱلزَّكَوٰةَ فَخَلُّواْ سَبِيلَهُمۡۚ", "surah": 9, "surah_name": "التوبة", "ref": "9:5", "ref_api": "https://api.quran.com/api/v4/verses/by_key/9:5"}], "surah": 9, "ref_api": "https://api.quran.com/api/v4/verses/by_key/9:5", "surah_name": "التوبة", "ayah_canonical": 5, "match": "contained", "ref": "9:5"}, {"t": "text", "s": "، وهي عبادة مالية نفعها متعدٍ، وقد أوجبها الله في أموال الأغنياء على وجه ينفع الفقير ولا يضر الغني؛ لأنها شيء يسير من مال كثير."}]}, {"type": "paragraph", "md": "الرابع: صوم رمضان، وهو التعبد لله تعالى بالإمساك عن المفطرات من طلوع الفجر إلى غروب الشمس، وهو عبادة بدنية تكون سرًّا بين العبد وبين ربه؛ فلا يطلع على الصوم إلا الله سبحانه وتعالى ؛ فمن الناس من يُفطر في رمضان وغيره يظنه صائمًا، ومنهم من يصوم نفلًا وغيره يظنه مفطرًا؛ ولهذا فالمسلم يجازى على الحسنة بعشر أمثالها، قال الله عز وجل : (إلا الصوم فإنه له وأنا أجزي به)؛ لما فيه من إخلاص فلا يطلع عليه إلا الله.", "page": 34, "id": "unit-03__lesson-02__b21", "inline": [{"t": "emphasis", "s": "الرابع", "role": "lemma"}, {"t": "text", "s": ": "}, {"t": "emphasis", "s": "صوم رمضان", "role": "lemma"}, {"t": "text", "s": "، وهو التعبد لله تعالى بالإمساك عن المفطرات من طلوع الفجر إلى غروب الشمس، وهو عبادة بدنية تكون سرًّا بين العبد وبين ربه؛ فلا يطلع على الصوم إلا الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ؛ فمن الناس من يُفطر في رمضان وغيره يظنه صائمًا، ومنهم من يصوم نفلًا وغيره يظنه مفطرًا؛ ولهذا فالمسلم يجازى على الحسنة بعشر أمثالها، قال الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إلا الصوم فإنه له وأنا أجزي به)", "role": "lemma"}, {"t": "text", "s": "؛ لما فيه من إخلاص فلا يطلع عليه إلا الله."}]}, {"type": "paragraph", "md": "الخامس: حج بيت الله الحرام، ومعناه: القصد إلى مكة لأداء المناسك، وهو عبادة مالية بدنية، أوجبها الله في العمر مرة واحدة، وبين النبي صلى الله عليه وسلم فضلها: (من حج فلم يرفث ولم يفسق رجع كيوم ولدته أمه)، وقال صلى الله عليه وسلم : (رمضان إلى رمضان، والعمرة إلى العمرة كفارة لما بينهما، والحج المبرور ليس له جزاء إلا الجنة).", "page": 35, "id": "unit-03__lesson-02__b22", "inline": [{"t": "emphasis", "s": "الخامس", "role": "lemma"}, {"t": "text", "s": ": "}, {"t": "emphasis", "s": "حج بيت الله الحرام", "role": "lemma"}, {"t": "text", "s": "، ومعناه: القصد إلى مكة لأداء المناسك، وهو عبادة مالية بدنية، أوجبها الله في العمر مرة واحدة، وبين النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " فضلها: "}, {"t": "emphasis", "s": "(من حج فلم يرفث ولم يفسق رجع كيوم ولدته أمه)", "role": "lemma"}, {"t": "text", "s": "، وقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(رمضان إلى رمضان، والعمرة إلى العمرة كفارة لما بينهما، والحج المبرور ليس له جزاء إلا الجنة)", "role": "lemma"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وأما العمرة ففيها خلافٌ بين العلماء، وظاهر الأقوال في مذهب الشافعية أنها واجبة مرةً في العمر كذلك.", "page": 35, "id": "unit-03__lesson-02__b23", "inline": [{"t": "emphasis", "s": "وأما العمرة", "role": "lemma"}, {"t": "text", "s": " ففيها خلافٌ بين العلماء، وظاهر الأقوال في مذهب الشافعية أنها واجبة مرةً في العمر كذلك."}]}, {"type": "heading", "level": 3, "text": "فوائد في الحديث:", "page": 35, "id": "unit-03__lesson-02__b24", "role": "benefits"}, {"type": "paragraph", "md": "في الحديث إظهار حكمة الله تعالى حيث جعل للإسلام مبانٍ وأصولًا عظاما يظهر بها إيمان العبد، وبه يكون الرجل مؤمنا أو كافرا؛ فمن كان من أهل الجنة فسيعمل بعمل أهلها، وإلا فيعمل بعمل أهل النار.", "page": 35, "id": "unit-03__lesson-02__b25"}, {"type": "paragraph", "md": "في الحديث بيان تنوع أعمال الإسلام؛ وقيامها بالعبد بقلبه ولسانه وجوارحه، وهي تتضمن فعلا وتركا، ومنها ما هو متعد النفع، ومنها ما هو لازم النفع لصاحبه فقط، ومنها ما هو ظاهر، ومنها ما هو سر بين العبد وربه، ومنها البدني، ومنها المالي.. وهذا التنوع هو المطلوب من العبد؛ ففي كل موضعٍ وثغرٍ ومكانٍ وزمانٍ يكون له حظ من العبودية لله؛ فيتحقق فيه معنى العبودية في المحيا والممات.", "page": 35, "id": "unit-03__lesson-02__b26"}, {"type": "paragraph", "md": "لم يُذكر الجهاد في أركان الإسلام الخمسة؛ لأنه لم يكن قد فُرض بعد، أو لأنَّ هذه الخمس لازمة باستمرار لكل مكلف؛ بخلاف الجهاد، فهو فرض كفاية، ولا يكون في كل وقت، فإذا صار فرض عين كزماننا فهو بمثابة أركان الإسلام في لزوم العمل بها على كل مكلف يجب عليه الجهاد.", "page": 35, "id": "unit-03__lesson-02__b27"}, {"type": "paragraph", "md": "أن الشهادتين أساس في ذاتيتهما، وهما أساس لغيرهما، فلا يقبل عمل إلا إذا بُنِي عليهما؛ فمن صلى وصام وهو نصراني أو نُصيري أو وثني فلا يُقبل منه شيء من ذلك؛ فإذا انهدم الأصل لم يقم بعده فرع.", "page": 35, "id": "unit-03__lesson-02__b28"}, {"type": "paragraph", "md": "في الحديثِ تقديم الصلاة على غيرها من الأعمال؛ لأنها علامة الإيمان وصلة وثيقة بين العبد وبين ربه.", "page": 35, "id": "unit-03__lesson-02__b29"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 35, "id": "unit-03__lesson-02__b30", "role": "assessment"}, {"type": "paragraph", "md": "اذكر أركان الإسلام الخمسة غيبًا؟ 4- ما حكم ترك الصلاة؟", "page": 35, "id": "unit-03__lesson-02__b31", "item_role": "question"}, {"type": "paragraph", "md": "لماذا لم يُذكر الجهاد ضمن أركان الإسلام الخمسة؟ وما حكم الجهاد اليوم؟", "page": 35, "id": "unit-03__lesson-02__b32", "item_role": "question"}, {"type": "paragraph", "md": "ما أهم ركنين من أركان الإسلام الخمسة بالترتيب؟ وهل يصح غيرهما بدونهما؟", "page": 35, "id": "unit-03__lesson-02__b33", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط دعوي خارج المجلس", "page": 35, "id": "unit-03__lesson-02__b34", "role": "activity"}, {"type": "paragraph", "md": "عرِّف خمسة من عائلتك وإخوانك بأركان الإسلام الخمسة مع شرحها لهم كما فهمتَه", "page": 35, "id": "unit-03__lesson-02__b35", "item_role": "activity_step"}]' WHERE id='unit-03__lesson-02';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 36, "id": "unit-03__lesson-03__b01", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على تعظيم القرآن والأنبياء والسلف الصالح، لله سبحانه وتعالى .", "page": 36, "id": "unit-03__lesson-03__b02", "inline": [{"t": "text", "s": "التعرف على تعظيم القرآن والأنبياء والسلف الصالح، لله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "تربية نفوسنا وإخواننا وأهلنا على تعظيم الله سبحانه وتعالى .", "page": 36, "id": "unit-03__lesson-03__b03", "inline": [{"t": "text", "s": "تربية نفوسنا وإخواننا وأهلنا على تعظيم الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "وبعد؛ فإن عظمة الله لا يعلمها إلا هو جل وعلا ، ولكنه جل وعلا بين لنا ما يدل على عظمته بقدر ما تتسع له عقولنا وإلا فإن عظمته سبحانه وتعالى لا يحيط بها إلا هو، وقد عَرَّفَنَا الله سبحانه وتعالى بعظمته في قرآنه وعلى لسان أنبيائه لنعظمه كما ينبغي:", "page": 36, "id": "unit-03__lesson-03__b04", "inline": [{"t": "text", "s": "وبعد؛ فإن عظمة الله لا يعلمها إلا هو "}, {"t": "honorific", "s": "جل وعلا"}, {"t": "text", "s": " ، ولكنه "}, {"t": "honorific", "s": "جل وعلا"}, {"t": "text", "s": " بين لنا ما يدل على عظمته بقدر ما تتسع له عقولنا وإلا فإن عظمته "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " لا يحيط بها إلا هو، وقد عَرَّفَنَا الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " بعظمته في قرآنه وعلى لسان أنبيائه لنعظمه كما ينبغي:"}]}, {"type": "heading", "level": 3, "text": "أولا: تعظيم القرآن لله سبحانه وتعالى :", "page": 36, "id": "unit-03__lesson-03__b05", "role": "section"}, {"type": "paragraph", "md": "لقد ذكر القرآن الكريم جوانب من عظمة الله سبحانه وتعالى في كثير من السور والآيات، فمثلًا: أعظم آية في كتاب الله سبحانه وتعالى هي آية الكرسي، وقد تضمنت من صور تعظيم الله سبحانه وتعالى شيءًا كثير؛ فمن ذلك:", "page": 36, "id": "unit-03__lesson-03__b06", "inline": [{"t": "text", "s": "لقد ذكر القرآن الكريم جوانب من عظمة الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " في كثير من السور والآيات، فمثلًا: أعظم آية في كتاب الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " هي آية الكرسي، وقد تضمنت من صور تعظيم الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " شيءًا كثير؛ فمن ذلك:"}]}, {"type": "paragraph", "md": "1-بيان أن الإله الحق هو الله سبحانه وتعالى ؛ لأنَّ من صفاته القيومية أي القائم على شؤون الخلق ورعايتهم، فهو الحي الذي لا يموت، ولا يكونُ إلهًا من ينام أو يغفل عن عبيده؛ لذلك فالله وحده المستحق للعبادة.", "page": 36, "id": "unit-03__lesson-03__b07", "inline": [{"t": "text", "s": "1-بيان أن الإله الحق هو الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ؛ لأنَّ من صفاته القيومية أي القائم على شؤون الخلق ورعايتهم، فهو الحي الذي لا يموت، ولا يكونُ إلهًا من ينام أو يغفل عن عبيده؛ لذلك فالله وحده المستحق للعبادة."}]}, {"type": "paragraph", "md": "2-ومن عظمته سبحانه وتعالى : أنه يدبر أمر الكون ولا ينام، ولا تأخذه حتى غفوة يسيرة: ﴿لَا تَأۡخُذُهُۥ سِنَةٞ وَلَا نَوۡمٞۚ﴾.", "page": 36, "id": "unit-03__lesson-03__b08", "inline": [{"t": "text", "s": "2-ومن عظمته "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : أنه يدبر أمر الكون ولا ينام، ولا تأخذه حتى غفوة يسيرة: "}, {"t": "ayah", "s": "لَا تَأۡخُذُهُۥ سِنَةٞ وَلَا نَوۡمٞۚ", "ayah": [], "verses": [{"n": 255, "text": "لَا تَأۡخُذُهُۥ سِنَةٞ وَلَا نَوۡمٞۚ", "surah": 2, "surah_name": "البقرة", "ref": "2:255", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:255"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:255", "surah_name": "البقرة", "ayah_canonical": 255, "match": "contained", "ref": "2:255"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "3-ومن عظمته سبحانه وتعالى : أنه يعلم كل شيء، وأحاط علمه بكل شيء؛ فلا تخفى عليه خافية في الأرض والسماء.", "page": 36, "id": "unit-03__lesson-03__b09", "inline": [{"t": "text", "s": "3-ومن عظمته "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : أنه يعلم كل شيء، وأحاط علمه بكل شيء؛ فلا تخفى عليه خافية في الأرض والسماء."}]}, {"type": "paragraph", "md": "4-ومن عظمته سبحانه وتعالى : أنَّ كرسيه أحاط بالسماوات والأرض على سعتهما وعظمتهما، والكرسي موضع قدمي الرب سبحانه وتعالى ، وكذلك فإنه لا يثقله ولا يشق عليه حفظهما؛ فهو العلي بذاته وقدره وقهره، العظيم في ملكه وسلطانه، يقول تعالى: ﴿وَسِعَ كُرۡسِيُّهُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَۖ وَلَا يَـُٔودُهُۥ حِفۡظُهُمَاۚ وَهُوَ ٱلۡعَلِيُّ ٱلۡعَظِيمُ ۝٢٥٥﴾.", "page": 36, "id": "unit-03__lesson-03__b10", "inline": [{"t": "text", "s": "4-ومن عظمته "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : أنَّ كرسيه أحاط بالسماوات والأرض على سعتهما وعظمتهما، والكرسي موضع قدمي الرب "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، وكذلك فإنه لا يثقله ولا يشق عليه حفظهما؛ فهو العلي بذاته وقدره وقهره، العظيم في ملكه وسلطانه، يقول تعالى: "}, {"t": "ayah", "s": "وَسِعَ كُرۡسِيُّهُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَۖ وَلَا يَـُٔودُهُۥ حِفۡظُهُمَاۚ وَهُوَ ٱلۡعَلِيُّ ٱلۡعَظِيمُ ۝٢٥٥", "ayah": [255], "verses": [{"n": 255, "text": "وَسِعَ كُرۡسِيُّهُ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَۖ وَلَا يَـُٔودُهُۥ حِفۡظُهُمَاۚ وَهُوَ ٱلۡعَلِيُّ ٱلۡعَظِيمُ", "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:255", "surah_name": "البقرة", "ayah_canonical": 255, "match": "contained", "ref": "2:255"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "ثانيًا: تعظيم الأنبياء والسلف الصالح لله سبحانه وتعالى :", "page": 36, "id": "unit-03__lesson-03__b11", "role": "section"}, {"type": "paragraph", "md": "مما يلفت الانتباه في حياة الأنبياء شدةُ تعظيمهم لله عز وجل ، وخوفهم منه؛ فترى تعظيمَ الله عزوجل في أدعيتهم وأقوالهم وأفعالهم وأحوالهم كلها؛ فهم أشد خلق الله له تعظيمًا، والأمثلة على ذلك كثيرة منها:", "page": 36, "id": "unit-03__lesson-03__b12", "inline": [{"t": "text", "s": "مما يلفت الانتباه في حياة الأنبياء شدةُ تعظيمهم لله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، وخوفهم منه؛ فترى تعظيمَ الله عزوجل في أدعيتهم وأقوالهم وأفعالهم وأحوالهم كلها؛ فهم أشد خلق الله له تعظيمًا، والأمثلة على ذلك كثيرة منها:"}]}, {"type": "paragraph", "md": "1- مناجاة نوح عليه السلام لربّه بشأن ابنه: قال تعالى: ﴿وَنَادَىٰ نُوحٞ رَّبَّهُۥ فَقَالَ رَبِّ إِنَّ ٱبۡنِي مِنۡ أَهۡلِي وَإِنَّ وَعۡدَكَ ٱلۡحَقُّ وَأَنتَ أَحۡكَمُ ٱلۡحَٰكِمِينَ ۝٤٥ قَالَ يَٰنُوحُ إِنَّهُۥ لَيۡسَ مِنۡ أَهۡلِكَۖ إِنَّهُۥ عَمَلٌ غَيۡرُ صَٰلِحٖۖ فَلَا تَسۡـَٔلۡنِ مَا لَيۡسَ لَكَ بِهِۦ عِلۡمٌۖ إِنِّيٓ أَعِظُكَ أَن تَكُونَ مِنَ ٱلۡجَٰهِلِينَ ۝٤٦ قَالَ رَبِّ إِنِّيٓ أَعُوذُ بِكَ أَنۡ أَسۡـَٔلَكَ مَا لَيۡسَ لِي بِهِۦ عِلۡمٞۖ وَإِلَّا تَغۡفِرۡ لِي وَتَرۡحَمۡنِيٓ أَكُن مِّنَ ٱلۡخَٰسِرِينَ ۝٤٧﴾، ويظهر من هذه الآيات علم نوح عليه السلام بربه عز وجل ، والذي أثمر عنده هذا الأدب العظيم مع ربه، والخوف منه سبحانه؛ فتراه وهو يدعو ربه بشأن ابنه الهالك مع الكافرين يختم دعاءه بقوله: ﴿وَأَنتَ أَحۡكَمُ ٱلۡحَٰكِمِينَ ۝٤٥﴾، ولم يقل: وأنت أرحم الراحمين، وهذا من كمال علمه عليه السلام بأسماء الله عز وجل وصفاته وآثارها؛ لأن المقام ليس مقام رحمة بل انتقام من الكافرين.", "page": 37, "id": "unit-03__lesson-03__b13", "inline": [{"t": "emphasis", "s": "1- مناجاة نوح", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "لربّه بشأن ابنه:", "role": "emphasis"}, {"t": "text", "s": " قال تعالى: "}, {"t": "ayah", "s": "وَنَادَىٰ نُوحٞ رَّبَّهُۥ فَقَالَ رَبِّ إِنَّ ٱبۡنِي مِنۡ أَهۡلِي وَإِنَّ وَعۡدَكَ ٱلۡحَقُّ وَأَنتَ أَحۡكَمُ ٱلۡحَٰكِمِينَ ۝٤٥ قَالَ يَٰنُوحُ إِنَّهُۥ لَيۡسَ مِنۡ أَهۡلِكَۖ إِنَّهُۥ عَمَلٌ غَيۡرُ صَٰلِحٖۖ فَلَا تَسۡـَٔلۡنِ مَا لَيۡسَ لَكَ بِهِۦ عِلۡمٌۖ إِنِّيٓ أَعِظُكَ أَن تَكُونَ مِنَ ٱلۡجَٰهِلِينَ ۝٤٦ قَالَ رَبِّ إِنِّيٓ أَعُوذُ بِكَ أَنۡ أَسۡـَٔلَكَ مَا لَيۡسَ لِي بِهِۦ عِلۡمٞۖ وَإِلَّا تَغۡفِرۡ لِي وَتَرۡحَمۡنِيٓ أَكُن مِّنَ ٱلۡخَٰسِرِينَ ۝٤٧", "ayah": [45, 46, 47], "verses": [{"n": 45, "text": "وَنَادَىٰ نُوحٞ رَّبَّهُۥ فَقَالَ رَبِّ إِنَّ ٱبۡنِي مِنۡ أَهۡلِي وَإِنَّ وَعۡدَكَ ٱلۡحَقُّ وَأَنتَ أَحۡكَمُ ٱلۡحَٰكِمِينَ", "surah": 11, "ref_api": "https://api.quran.com/api/v4/verses/by_key/11:45", "surah_name": "هود", "ayah_canonical": 45, "match": "exact", "ref": "11:45"}, {"n": 46, "text": "قَالَ يَٰنُوحُ إِنَّهُۥ لَيۡسَ مِنۡ أَهۡلِكَۖ إِنَّهُۥ عَمَلٌ غَيۡرُ صَٰلِحٖۖ فَلَا تَسۡـَٔلۡنِ مَا لَيۡسَ لَكَ بِهِۦ عِلۡمٌۖ إِنِّيٓ أَعِظُكَ أَن تَكُونَ مِنَ ٱلۡجَٰهِلِينَ", "surah": 11, "ref_api": "https://api.quran.com/api/v4/verses/by_key/11:46", "surah_name": "هود", "ayah_canonical": 46, "match": "exact", "ref": "11:46"}, {"n": 47, "text": "قَالَ رَبِّ إِنِّيٓ أَعُوذُ بِكَ أَنۡ أَسۡـَٔلَكَ مَا لَيۡسَ لِي بِهِۦ عِلۡمٞۖ وَإِلَّا تَغۡفِرۡ لِي وَتَرۡحَمۡنِيٓ أَكُن مِّنَ ٱلۡخَٰسِرِينَ", "surah": 11, "ref_api": "https://api.quran.com/api/v4/verses/by_key/11:47", "surah_name": "هود", "ayah_canonical": 47, "match": "exact", "ref": "11:47"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، ويظهر من هذه الآيات علم نوح "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " بربه "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، والذي أثمر عنده هذا الأدب العظيم مع ربه، والخوف منه سبحانه؛ فتراه وهو يدعو ربه بشأن ابنه الهالك مع الكافرين يختم دعاءه بقوله: "}, {"t": "ayah", "s": "وَأَنتَ أَحۡكَمُ ٱلۡحَٰكِمِينَ ۝٤٥", "ayah": [45], "verses": [{"n": 45, "text": "وَأَنتَ أَحۡكَمُ ٱلۡحَٰكِمِينَ", "surah": 11, "ref_api": "https://api.quran.com/api/v4/verses/by_key/11:45", "surah_name": "هود", "ayah_canonical": 45, "match": "contained", "ref": "11:45"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، ولم يقل: وأنت أرحم الراحمين، وهذا من كمال علمه "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " بأسماء الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " وصفاته وآثارها؛ لأن المقام ليس مقام رحمة بل انتقام من الكافرين."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- تعظيم موسى عليه السلام لربه: قال تعالى: ﴿وَلَمَّا جَآءَ مُوسَىٰ لِمِيقَٰتِنَا وَكَلَّمَهُۥ رَبُّهُۥ قَالَ رَبِّ أَرِنِيٓ أَنظُرۡ إِلَيۡكَۚ قَالَ لَن تَرَىٰنِي وَلَٰكِنِ ٱنظُرۡ إِلَى ٱلۡجَبَلِ فَإِنِ ٱسۡتَقَرَّ مَكَانَهُۥ فَسَوۡفَ تَرَىٰنِيۚ فَلَمَّا تَجَلَّىٰ رَبُّهُۥ لِلۡجَبَلِ جَعَلَهُۥ دَكّٗا وَخَرَّ مُوسَىٰ صَعِقٗاۚ فَلَمَّآ أَفَاقَ قَالَ سُبۡحَٰنَكَ تُبۡتُ إِلَيۡكَ وَأَنَا۠ أَوَّلُ ٱلۡمُؤۡمِنِينَ﴾، أي إذا ثبت الجبل في مكانه فسيتجلَّى الله له، فلما تجلى له وهو الجبل الأصمُّ الغليظ انهال الجبل مثل الرمل؛ لعدم احتماله رؤية الله، وعدم ثبوته لها، وحين رأى مُوسَى عليه السلام ذلك سقط مغشيًا عليه، فلما قام من إغمائه تبيّن له حينئذ أنه إذا لم يثبت الجبل لرؤية الله؛ فموسى أولى أن لا يثبت لذلك، فاستغفر ربه لما صدر منه من السؤال الذي لم يوافق موضعًا، ولذلك قال: ﴿سُبۡحَٰنَكَ﴾ أي: تنزيهًا لك، وتعظيمًا عما لا يليق بجلالك ﴿تُبۡتُ إِلَيۡكَ﴾ من جميع الذنوب، وسوء الأدب معك ﴿وَأَنَا۠ أَوَّلُ ٱلۡمُؤۡمِنِينَ﴾، فجدد عليه السلام إيمانه بما كمل الله له مما كان يجهله قبل ذلك.", "page": 37, "id": "unit-03__lesson-03__b14", "inline": [{"t": "emphasis", "s": "2- تعظيم موسى", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "لربه:", "role": "emphasis"}, {"t": "text", "s": " قال تعالى: "}, {"t": "ayah", "s": "وَلَمَّا جَآءَ مُوسَىٰ لِمِيقَٰتِنَا وَكَلَّمَهُۥ رَبُّهُۥ قَالَ رَبِّ أَرِنِيٓ أَنظُرۡ إِلَيۡكَۚ قَالَ لَن تَرَىٰنِي وَلَٰكِنِ ٱنظُرۡ إِلَى ٱلۡجَبَلِ فَإِنِ ٱسۡتَقَرَّ مَكَانَهُۥ فَسَوۡفَ تَرَىٰنِيۚ فَلَمَّا تَجَلَّىٰ رَبُّهُۥ لِلۡجَبَلِ جَعَلَهُۥ دَكّٗا وَخَرَّ مُوسَىٰ صَعِقٗاۚ فَلَمَّآ أَفَاقَ قَالَ سُبۡحَٰنَكَ تُبۡتُ إِلَيۡكَ وَأَنَا۠ أَوَّلُ ٱلۡمُؤۡمِنِينَ", "ayah": [], "verses": [{"n": 143, "text": "وَلَمَّا جَآءَ مُوسَىٰ لِمِيقَٰتِنَا وَكَلَّمَهُۥ رَبُّهُۥ قَالَ رَبِّ أَرِنِيٓ أَنظُرۡ إِلَيۡكَۚ قَالَ لَن تَرَىٰنِي وَلَٰكِنِ ٱنظُرۡ إِلَى ٱلۡجَبَلِ فَإِنِ ٱسۡتَقَرَّ مَكَانَهُۥ فَسَوۡفَ تَرَىٰنِيۚ فَلَمَّا تَجَلَّىٰ رَبُّهُۥ لِلۡجَبَلِ جَعَلَهُۥ دَكّٗا وَخَرَّ مُوسَىٰ صَعِقٗاۚ فَلَمَّآ أَفَاقَ قَالَ سُبۡحَٰنَكَ تُبۡتُ إِلَيۡكَ وَأَنَا۠ أَوَّلُ ٱلۡمُؤۡمِنِينَ", "surah": 7, "surah_name": "الأعراف", "ref": "7:143", "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:143"}], "surah": 7, "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:143", "surah_name": "الأعراف", "ayah_canonical": 143, "match": "exact", "ref": "7:143"}, {"t": "text", "s": "، أي إذا ثبت الجبل في مكانه فسيتجلَّى الله له، فلما تجلى له وهو الجبل الأصمُّ الغليظ انهال الجبل مثل الرمل؛ لعدم احتماله رؤية الله، وعدم ثبوته لها، وحين رأى مُوسَى "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " ذلك سقط مغشيًا عليه، فلما قام من إغمائه تبيّن له حينئذ أنه إذا لم يثبت الجبل لرؤية الله؛ فموسى أولى أن لا يثبت لذلك، فاستغفر ربه لما صدر منه من السؤال الذي لم يوافق موضعًا، ولذلك قال: "}, {"t": "ayah", "s": "سُبۡحَٰنَكَ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": " أي: تنزيهًا لك، وتعظيمًا عما لا يليق بجلالك "}, {"t": "ayah", "s": "تُبۡتُ إِلَيۡكَ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": " من جميع الذنوب، وسوء الأدب معك "}, {"t": "ayah", "s": "وَأَنَا۠ أَوَّلُ ٱلۡمُؤۡمِنِينَ", "ayah": [], "verses": [{"n": 143, "text": "وَأَنَا۠ أَوَّلُ ٱلۡمُؤۡمِنِينَ", "surah": 7, "surah_name": "الأعراف", "ref": "7:143", "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:143"}], "surah": 7, "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:143", "surah_name": "الأعراف", "ayah_canonical": 143, "match": "contained", "ref": "7:143"}, {"t": "text", "s": "، فجدد "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " إيمانه بما كمل الله له مما كان يجهله قبل ذلك."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- تعظيم نبينا محمد صلى الله عليه وسلم لربه سبحانه وخوفه منه: فقد قال رسول الله صلى الله عليه وسلم : (فوالله إنِّي لأعلمُهم بالله، وأشدُّهم له خشية)، وقال النبي صلى الله عليه وسلم : (لو تعلمونَ ما أعلمُ لضحكتم قليلًا ولبكيتم كثيرًا).", "page": 37, "id": "unit-03__lesson-03__b15", "inline": [{"t": "emphasis", "s": "3- تعظيم نبينا محمد", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "لربه سبحانه وخوفه منه:", "role": "emphasis"}, {"t": "text", "s": " فقد قال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(فوالله إنِّي لأعلمُهم بالله، وأشدُّهم له خشية)", "role": "emphasis"}, {"t": "text", "s": "، وقال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لو تعلمونَ ما أعلمُ لضحكتم قليلًا ولبكيتم كثيرًا)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- تعظيم السلف لله سبحانه وتعالى : كانوا أشد الناس تعظيمًا لله سبحانه وتعالى بعد الأنبياء عليهم السلام ، ومن أمثله ذلك في الصلاة فقط:", "page": 37, "id": "unit-03__lesson-03__b16", "inline": [{"t": "emphasis", "s": "4- تعظيم السلف لله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : كانوا أشد الناس تعظيمًا لله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " بعد الأنبياء "}, {"t": "honorific", "s": "عليهم السلام"}, {"t": "text", "s": " ، ومن أمثله ذلك في الصلاة فقط:"}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "أ- وكان ابن الزبير إذا قام في الصلاة كأنه عود من الخشوع، وكان يسجد؛ فأتى المنجنيق فأخذ طائفة من ثوبه وهو في الصلاة لا يرفع رأسه.", "page": 37, "id": "unit-03__lesson-03__b17"}, {"type": "paragraph", "md": "ب- وكان مسلمة بن بشار يصلي في المسجد فانهدم طائفة منه فقام الناس وهو في الصلاة لم يشعر.", "page": 37, "id": "unit-03__lesson-03__b18"}, {"type": "paragraph", "md": "ج- وكان علي بن أبي طالب رضي الله عنه إذا حضرت الصلاة يتزلزل ويتلون وجهه، فقيل له: مالك؟ فقال: جاء والله وقت أمانة عرضها الله على السماوات والأرض والجبال فأبين أن يحملنها وأشفقن منها وحملتها.", "page": 37, "id": "unit-03__lesson-03__b19", "inline": [{"t": "text", "s": "ج- وكان علي بن أبي طالب "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " إذا حضرت الصلاة يتزلزل ويتلون وجهه، فقيل له: مالك؟ فقال: جاء والله وقت أمانة عرضها الله على السماوات والأرض والجبال فأبين أن يحملنها وأشفقن منها وحملتها."}]}, {"type": "paragraph", "md": "د-وكان سعيد التنوخي إذا صلى لم تنقطع الدموع من خدَّيه على لحيته.", "page": 37, "id": "unit-03__lesson-03__b20"}, {"type": "paragraph", "md": "هـ-وكان شيخ الإسلام ابن تيمية رحمه الله إذا دخل في الصلاة ترتعد أعضاؤه؛ خشيةً لله، وتعظيمًا له.", "page": 37, "id": "unit-03__lesson-03__b21", "inline": [{"t": "text", "s": "هـ-وكان شيخ الإسلام ابن تيمية "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " إذا دخل في الصلاة ترتعد أعضاؤه؛ خشيةً لله، وتعظيمًا له."}]}, {"type": "paragraph", "md": "هذا غيض من فيض من أخبار سلفنا المعظمين لله، فاللهم كما رزقتهم فارزقنا تعظيمك يا سميع الدعاء.", "page": 37, "id": "unit-03__lesson-03__b22"}, {"type": "heading", "level": 3, "text": "ثالثًا: تربية النفوس على تعظيم الله سبحانه وتعالى :", "page": 37, "id": "unit-03__lesson-03__b23", "role": "section"}, {"type": "paragraph", "md": "لا بُدَّ مِن أمور يقوم بها المؤمن، حتى يربيَ نفسه على تعظيم الله سبحانه وتعالى ، وذلك من خلال:", "page": 37, "id": "unit-03__lesson-03__b24", "inline": [{"t": "text", "s": "لا بُدَّ مِن أمور يقوم بها المؤمن، حتى يربيَ نفسه على تعظيم الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، وذلك من خلال:"}]}, {"type": "paragraph", "md": "1- أن تستشعر عظمة الله جل وعلا من هو الله؟ فقدِّره وعظمه حق عظمته، ولن تستشعر عظمة الله جل وعلا إلا بعد أن تعلم أسماءه وصفاته جل وعلا ، فإنَّ من لا يعرف الله لا يُعظمه، قال تعالى عن نفسه: ﴿وَمَا قَدَرُواْ ٱللَّهَ حَقَّ قَدۡرِهِۦ﴾.", "page": 38, "id": "unit-03__lesson-03__b25", "inline": [{"t": "text", "s": "1- أن تستشعر عظمة الله "}, {"t": "honorific", "s": "جل وعلا"}, {"t": "text", "s": " من هو الله؟ فقدِّره وعظمه حق عظمته، ولن تستشعر عظمة الله "}, {"t": "honorific", "s": "جل وعلا"}, {"t": "text", "s": " إلا بعد أن تعلم أسماءه وصفاته "}, {"t": "honorific", "s": "جل وعلا"}, {"t": "text", "s": " ، فإنَّ من لا يعرف الله لا يُعظمه، قال تعالى عن نفسه: "}, {"t": "ayah", "s": "وَمَا قَدَرُواْ ٱللَّهَ حَقَّ قَدۡرِهِۦ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- التأمل في خلق السماوات والأرض، يزيدك تعظيمًا لله؛ لأن كل ما حولك من خلق الله الذي أحسن خلق كل شيء، قال الله عز وجل عن أهل الإيمان: ﴿وَيَتَفَكَّرُونَ فِي خَلۡقِ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ رَبَّنَا مَا خَلَقۡتَ هَٰذَا بَٰطِلٗا﴾، وقال سبحانه: ﴿إِنَّ فِي ذَٰلِكَ لَأٓيَٰتٖ لِّقَوۡمٖ يَتَفَكَّرُونَ ۝١٣﴾؛ ففي كل شيء له آية تدل على أنه واحد.", "page": 38, "id": "unit-03__lesson-03__b26", "inline": [{"t": "text", "s": "2- التأمل في خلق السماوات والأرض، يزيدك تعظيمًا لله؛ لأن كل ما حولك من خلق الله الذي أحسن خلق كل شيء، قال الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " عن أهل الإيمان: "}, {"t": "ayah", "s": "وَيَتَفَكَّرُونَ فِي خَلۡقِ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ رَبَّنَا مَا خَلَقۡتَ هَٰذَا بَٰطِلٗا", "ayah": [], "verses": [{"n": 191, "text": "وَيَتَفَكَّرُونَ فِي خَلۡقِ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضِ رَبَّنَا مَا خَلَقۡتَ هَٰذَا بَٰطِلٗا", "surah": 3, "surah_name": "آل عمران", "ref": "3:191", "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:191"}], "surah": 3, "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:191", "surah_name": "آل عمران", "ayah_canonical": 191, "match": "contained", "ref": "3:191"}, {"t": "text", "s": "، وقال سبحانه: "}, {"t": "ayah", "s": "إِنَّ فِي ذَٰلِكَ لَأٓيَٰتٖ لِّقَوۡمٖ يَتَفَكَّرُونَ ۝١٣", "ayah": [13], "verses": [{"n": 13, "text": "إِنَّ فِي ذَٰلِكَ لَأٓيَٰتٖ لِّقَوۡمٖ يَتَفَكَّرُونَ", "surah": 45, "ref_api": "https://api.quran.com/api/v4/verses/by_key/45:13", "surah_name": "الجاثية", "ayah_canonical": 13, "match": "contained", "ref": "45:13"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ ففي كل شيء له آية تدل على أنه واحد."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- انظر إلى عظمة الله عندما تكون لوحدك، وتدعوك نفسك للنظر لامرأة، أو استماع أغنية، أو تقوم لأذان الفجر ثم ترجع وتنام، وتذكر قوله تعالى ﴿أَلَمۡ يَعۡلَم بِأَنَّ ٱللَّهَ يَرَىٰ ۝١٤﴾؛ فهنا تربي نفسك على تعظيم الله.", "page": 38, "id": "unit-03__lesson-03__b27", "inline": [{"t": "text", "s": "3- انظر إلى عظمة الله عندما تكون لوحدك، وتدعوك نفسك للنظر لامرأة، أو استماع أغنية، أو تقوم لأذان الفجر ثم ترجع وتنام، وتذكر قوله تعالى "}, {"t": "ayah", "s": "أَلَمۡ يَعۡلَم بِأَنَّ ٱللَّهَ يَرَىٰ ۝١٤", "ayah": [14], "verses": [{"n": 14, "text": "أَلَمۡ يَعۡلَم بِأَنَّ ٱللَّهَ يَرَىٰ", "surah": 96, "ref_api": "https://api.quran.com/api/v4/verses/by_key/96:14", "surah_name": "العلق", "ayah_canonical": 14, "match": "exact", "ref": "96:14"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فهنا تربي نفسك على تعظيم الله."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "رابعًا: الفوائد التربوية من معرفة عظمة الله سبحانه وتعالى :", "page": 38, "id": "unit-03__lesson-03__b28", "role": "benefits"}, {"type": "paragraph", "md": "1- معرفة العبد أن الله عز وجل عظيمٌ في كل شيء: عظيم في ذاته، وفي أسمائه وصفاته، عظيمٌ في رحمته، عظيم في قدرته، عظيم في حكمته، عظيم في جبروته وكبريائه، عظيم في هبته وعطائه، عظيم في لطفه وخبرته، عظيم في بره وإحسانه، عظيم في عزته وعدله وحمده، فهو العظيم المطلق، فلا أحد يساويه، ولا عظيم يدانيه.", "page": 38, "id": "unit-03__lesson-03__b29", "inline": [{"t": "text", "s": "1- معرفة العبد أن الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " عظيمٌ في كل شيء: عظيم في ذاته، وفي أسمائه وصفاته، عظيمٌ في رحمته، عظيم في قدرته، عظيم في حكمته، عظيم في جبروته وكبريائه، عظيم في هبته وعطائه، عظيم في لطفه وخبرته، عظيم في بره وإحسانه، عظيم في عزته وعدله وحمده، فهو العظيم المطلق، فلا أحد يساويه، ولا عظيم يدانيه."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- من آمن باسم الله العظيم؛ وحَّد ربه بألوهيته وربوبيته وعظَّمه، ونفى الشركاء والأنداد عنه سُبْحَانَهُ.", "page": 38, "id": "unit-03__lesson-03__b30", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- تعظيم ما أمر الله بتعظيمه وتعظيم الله تَعَالَى يكون بتعظيم الله سبحانه وتعالى ، وتعظيم كل ما أمر العظيم بتعظيمه، ومن ذلك تعظيم أسماء الله وصفاته، وتعظيم كتابه العظيم، وتعظيم نبيه صلى الله عليه وسلم ، وتعظيم حرمات الله تعالى.", "page": 38, "id": "unit-03__lesson-03__b31", "inline": [{"t": "text", "s": "3- تعظيم ما أمر الله بتعظيمه وتعظيم الله تَعَالَى يكون بتعظيم الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، وتعظيم كل ما أمر العظيم بتعظيمه، ومن ذلك تعظيم أسماء الله وصفاته، وتعظيم كتابه العظيم، وتعظيم نبيه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، وتعظيم حرمات الله تعالى."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- ومن تعظيم الله: دفع الصائل عن دينه، وتحكيم شرعه وإعلاء كلمته، وألا يُجتمع إلا على ذلك.", "page": 38, "id": "unit-03__lesson-03__b32", "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة الإثرائية:", "page": 38, "id": "unit-03__lesson-03__b33", "role": "assessment"}, {"type": "paragraph", "md": "1-اذكر جانبًا من عظمة الله التي ذُكرت في القرآن الكريم، وكيف كان الأنبياء والسلف يعظمون ربهم.", "page": 38, "id": "unit-03__lesson-03__b34", "item_role": "question"}, {"type": "paragraph", "md": "2- اذكر فائدتين تربويتين من فوائد معرفة عظمة الله سبحانه وتعالى ، وكيف نغرسه في قلوبنا.", "page": 38, "id": "unit-03__lesson-03__b35", "inline": [{"t": "text", "s": "2- اذكر فائدتين تربويتين من فوائد معرفة عظمة الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، وكيف نغرسه في قلوبنا."}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط بحثي وحواري", "page": 38, "id": "unit-03__lesson-03__b36", "role": "activity"}, {"type": "paragraph", "md": "1- ابحث عن معنى اسم الله «العظيم» في كتب أهل العلم أو اسأل عنه أحد شيوخك.", "page": 38, "id": "unit-03__lesson-03__b37", "inline": [{"t": "text", "s": "1- ابحث عن معنى اسم الله "}, {"t": "quote", "s": "العظيم"}, {"t": "text", "s": " في كتب أهل العلم أو اسأل عنه أحد شيوخك."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- كيف يمكنك ان تعزز مفهوم عظمة الله بقلبك، تعاون أنت وأصدقاؤك على الإجابة.", "page": 38, "id": "unit-03__lesson-03__b38", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-03__lesson-03';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 39, "id": "unit-03__lesson-04__b01", "role": "objectives"}, {"type": "paragraph", "md": "بيان أحكام الأكل والشرب والتطهر في الأواني المستعملة بين الناس، خاصةً آنية الذهب والفضة.", "page": 39, "id": "unit-03__lesson-04__b02"}, {"type": "paragraph", "md": "معرفة حكم استعمال آنية الكفار في الأكل والشرب.", "page": 39, "id": "unit-03__lesson-04__b03"}, {"type": "heading", "level": 3, "text": "حكم الآنية في الأكل والشرب:", "page": 39, "id": "unit-03__lesson-04__b04", "role": "rulings"}, {"type": "paragraph", "md": "الأواني: الأوعية المستعملة في الشرب والأكل -وتُذكر في باب المياه لأنها تُستعمل في الوضوء غالبًا-.", "page": 39, "id": "unit-03__lesson-04__b05", "inline": [{"t": "emphasis", "s": "الأواني", "role": "emphasis"}, {"t": "text", "s": ": الأوعية المستعملة في الشرب والأكل -وتُذكر في باب المياه لأنها تُستعمل في الوضوء غالبًا-."}]}, {"type": "paragraph", "md": "حكمها: كل الأواني طاهرة، ولا يحرم منها إلا ما كان من الذهب أو الفضة على الرجال والنساء؛ لحديثِ أُمِّ سَلَمة أُمّ المؤمنين رضي الله عنها : (مَن شَرِبَ في إناءٍ مِنْ ذَهَبٍ أَوْ فِضَّةٍ، فَإِنَّما يُجَرْجِرُ في بَطْنِهِ نَارًا مِنْ جَهنَّمَ)، ويلحق بالأكل والشرب: استعمال الشوك والسكاكين والملاعق الذهبية؛ فهو حرام.", "page": 39, "id": "unit-03__lesson-04__b06", "inline": [{"t": "emphasis", "s": "حكمها", "role": "emphasis"}, {"t": "text", "s": ": كل الأواني طاهرة، ولا يحرم منها إلا ما كان من الذهب أو الفضة على الرجال والنساء؛ لحديثِ أُمِّ سَلَمة أُمّ المؤمنين "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(مَن شَرِبَ في إناءٍ مِنْ ذَهَبٍ أَوْ فِضَّةٍ، فَإِنَّما يُجَرْجِرُ في بَطْنِهِ نَارًا مِنْ جَهنَّمَ)", "role": "emphasis"}, {"t": "text", "s": "، ويلحق بالأكل والشرب: استعمال الشوك والسكاكين والملاعق الذهبية؛ فهو حرام."}]}, {"type": "paragraph", "md": "ومثل آنية الشرب والأكل في تحريم الذهب والفضة: ما يُسْتَعْمَلُ مثلها كالمِكْحَلَةِ والتَّطَيُّب، وما تُزَيَّنُ به في البيوت وغيرها، وما استُخْدِمَ للوضوء والغُسل؛ فكل هذا يحرم استعمال آنية الذهب والفضة فيه.", "page": 39, "id": "unit-03__lesson-04__b07"}, {"type": "paragraph", "md": "وكذلك لا يجوز استعمال هذه الأواني في الوضوء والغسل؛ فيصح الوضوء بها مع الإثم شرعًا.", "page": 39, "id": "unit-03__lesson-04__b08", "inline": [{"t": "text", "s": "وكذلك لا يجوز استعمال هذه الأواني في "}, {"t": "emphasis", "s": "الوضوء والغسل؛", "role": "emphasis"}, {"t": "text", "s": " فيصح الوضوء بها مع الإثم شرعًا."}]}, {"type": "paragraph", "md": "والسبب في تحريمها: ما في ذلك من كسر قلوب الفقراء، والسرف، والتشبه بالكافرين.", "page": 39, "id": "unit-03__lesson-04__b09", "inline": [{"t": "emphasis", "s": "والسبب في تحريمها", "role": "emphasis"}, {"t": "text", "s": ": ما في ذلك من كسر قلوب الفقراء، والسرف، والتشبه بالكافرين."}]}, {"type": "paragraph", "md": "حكم استعمال آنية الكفار: إما أنها أواني يصنعونها هم؛ فهي طاهرة ما لم تُصنع من مواد نجسة.", "page": 39, "id": "unit-03__lesson-04__b10", "inline": [{"t": "emphasis", "s": "حكم استعمال آنية الكفار:", "role": "emphasis"}, {"t": "text", "s": " إما أنها أواني يصنعونها هم؛ فهي طاهرة ما لم تُصنع من مواد نجسة."}]}, {"type": "paragraph", "md": "وإما أنهم يستعملونها؛ فهي طاهرة كذلك إلا إن ثبت أن فيها نجاسة فلا يحل استعمالها حتى يغسلَها.", "page": 39, "id": "unit-03__lesson-04__b11"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 39, "id": "unit-03__lesson-04__b12", "role": "assessment"}, {"type": "paragraph", "md": "لخص أحكام الأواني باختصار.", "page": 39, "id": "unit-03__lesson-04__b13", "item_role": "question"}, {"type": "paragraph", "md": "ما علة تحريم استعمال أواني الذهب والفضة", "page": 39, "id": "unit-03__lesson-04__b14", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط داخل الحلقة", "page": 39, "id": "unit-03__lesson-04__b15", "role": "activity"}, {"type": "paragraph", "md": "توجد أواني ثمينة تصنع من الياقوت والزبرجد واللؤلو؛ فما حكم استعمالها؟ نتناقش ونعلل الحكم", "page": 39, "id": "unit-03__lesson-04__b16", "item_role": "activity_step"}]' WHERE id='unit-03__lesson-04';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 40, "id": "unit-03__lesson-05__b01", "role": "objectives"}, {"type": "paragraph", "md": "أن يحرص المسلم على جمع كلمة المسلمين وعدم تفريق صفهم، محققا أمر الله بذلك.", "page": 40, "id": "unit-03__lesson-05__b02"}, {"type": "paragraph", "md": "أن يترك التعصبَ المذموم للجماعات والأحزاب والأفكار، ويتعصب للإسلام والشريعة.", "page": 40, "id": "unit-03__lesson-05__b03"}, {"type": "heading", "level": 3, "text": "أهمية جمع الكلمة على التوحيد والتقوى:", "page": 40, "id": "unit-03__lesson-05__b04", "role": "section"}, {"type": "paragraph", "md": "نصوص الوحي متضافرة في الدلالة على وجوب وحدة المسلمين وحرمة فُرقتهم؛ حتى ليحتار المرء كيف يترك المسلم كل هذه الأدلة الكثيرة الداعية لترك الاجتماع على نصرة المسلمين وتحقيق مقاصد الدين، خاصة في ظل ما تعانيه أمتنا اليوم من تغوِّل العدو عليها، والجاهلية المنظمة لا يوقفها إلا حق منظم، قال الله تعالى: ﴿وَٱعۡتَصِمُواْ بِحَبۡلِ ٱللَّهِ جَمِيعٗا وَلَا تَفَرَّقُواْۚ﴾، وقال تعالى: ﴿وَلَا تَكُونُواْ مِنَ ٱلۡمُشۡرِكِينَ ۝٣١ مِنَ ٱلَّذِينَ فَرَّقُواْ دِينَهُمۡ وَكَانُواْ شِيَعٗاۖ كُلُّ حِزۡبِۭ بِمَا لَدَيۡهِمۡ فَرِحُونَ ۝٣٢﴾، فذمَّ الله تبارك وتعالى المُفرِّقين لدينهم المُتفرقين فيه ممن كانوا شِيعًا وأحزابًا وطوائف متفرقة على غير هدى من الله تبارك وتعالى ، وبرَّأ رسوله صلى الله عليه وسلم منهم.", "page": 40, "id": "unit-03__lesson-05__b05", "inline": [{"t": "text", "s": "نصوص الوحي متضافرة في الدلالة على وجوب وحدة المسلمين وحرمة فُرقتهم؛ حتى ليحتار المرء كيف يترك المسلم كل هذه الأدلة الكثيرة الداعية لترك الاجتماع على نصرة المسلمين وتحقيق مقاصد الدين، خاصة في ظل ما تعانيه أمتنا اليوم من تغوِّل العدو عليها، والجاهلية المنظمة لا يوقفها إلا حق منظم، قال الله تعالى: "}, {"t": "ayah", "s": "وَٱعۡتَصِمُواْ بِحَبۡلِ ٱللَّهِ جَمِيعٗا وَلَا تَفَرَّقُواْۚ", "ayah": [], "verses": [{"n": 103, "text": "وَٱعۡتَصِمُواْ بِحَبۡلِ ٱللَّهِ جَمِيعٗا وَلَا تَفَرَّقُواْۚ", "surah": 3, "surah_name": "آل عمران", "ref": "3:103", "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:103"}], "surah": 3, "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:103", "surah_name": "آل عمران", "ayah_canonical": 103, "match": "contained", "ref": "3:103"}, {"t": "text", "s": "، وقال تعالى: "}, {"t": "ayah", "s": "وَلَا تَكُونُواْ مِنَ ٱلۡمُشۡرِكِينَ ۝٣١ مِنَ ٱلَّذِينَ فَرَّقُواْ دِينَهُمۡ وَكَانُواْ شِيَعٗاۖ كُلُّ حِزۡبِۭ بِمَا لَدَيۡهِمۡ فَرِحُونَ ۝٣٢", "ayah": [31, 32], "verses": [{"n": 31, "text": "وَلَا تَكُونُواْ مِنَ ٱلۡمُشۡرِكِينَ", "surah": 30, "ref_api": "https://api.quran.com/api/v4/verses/by_key/30:31", "surah_name": "الروم", "ayah_canonical": 31, "match": "contained", "ref": "30:31"}, {"n": 32, "text": "مِنَ ٱلَّذِينَ فَرَّقُواْ دِينَهُمۡ وَكَانُواْ شِيَعٗاۖ كُلُّ حِزۡبِۭ بِمَا لَدَيۡهِمۡ فَرِحُونَ", "surah": 30, "ref_api": "https://api.quran.com/api/v4/verses/by_key/30:32", "surah_name": "الروم", "ayah_canonical": 32, "match": "exact", "ref": "30:32"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، فذمَّ الله "}, {"t": "honorific", "s": "تبارك وتعالى"}, {"t": "text", "s": " المُفرِّقين لدينهم المُتفرقين فيه ممن كانوا شِيعًا وأحزابًا وطوائف متفرقة على غير هدى من الله "}, {"t": "honorific", "s": "تبارك وتعالى"}, {"t": "text", "s": " ، وبرَّأ رسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " منهم."}]}, {"type": "paragraph", "md": "وفضلًا عن كون التفرق والاختلاف معصية لله سبحانه؛ فإنه سببٌ للخذلان والهزيمة والفشل، كما في غزوة أحد، وقد أخبر تعالى: ﴿وَلَا تَنَٰزَعُواْ فَتَفۡشَلُواْ وَتَذۡهَبَ رِيحُكُمۡۖ﴾، وقال صلى الله عليه وسلم : (عَلَيْكُمْ بِالجَمَاعَةِ، وَإِيَّاكُمْ وَالفُرْقَةَ، فَإِنَّ الشَّيْطَانَ مَعَ الوَاحِدِ، وَهُوَ مِنَ الِاثْنَيْنِ أَبْعَدُ، مَنْ أَرَادَ بُحْبُوحَةَ الجَنَّةِ فَلْيَلْزَمُ الجَمَاعَةَ)، وقال: (عليك بالجماعة فإنما يأكل الذئب القاصية من الغنم).", "page": 40, "id": "unit-03__lesson-05__b06", "inline": [{"t": "text", "s": "وفضلًا عن كون التفرق والاختلاف معصية لله سبحانه؛ فإنه سببٌ للخذلان والهزيمة والفشل، كما في غزوة أحد، وقد أخبر تعالى: "}, {"t": "ayah", "s": "وَلَا تَنَٰزَعُواْ فَتَفۡشَلُواْ وَتَذۡهَبَ رِيحُكُمۡۖ", "ayah": [], "verses": [{"n": 46, "text": "وَلَا تَنَٰزَعُواْ فَتَفۡشَلُواْ وَتَذۡهَبَ رِيحُكُمۡۖ", "surah": 8, "surah_name": "الأنفال", "ref": "8:46", "ref_api": "https://api.quran.com/api/v4/verses/by_key/8:46"}], "surah": 8, "ref_api": "https://api.quran.com/api/v4/verses/by_key/8:46", "surah_name": "الأنفال", "ayah_canonical": 46, "match": "contained", "ref": "8:46"}, {"t": "text", "s": "، وقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(عَلَيْكُمْ بِالجَمَاعَةِ، وَإِيَّاكُمْ وَالفُرْقَةَ، فَإِنَّ الشَّيْطَانَ مَعَ الوَاحِدِ، وَهُوَ مِنَ الِاثْنَيْنِ أَبْعَدُ، مَنْ أَرَادَ بُحْبُوحَةَ الجَنَّةِ فَلْيَلْزَمُ الجَمَاعَةَ)", "role": "emphasis"}, {"t": "text", "s": "، وقال: "}, {"t": "emphasis", "s": "(عليك بالجماعة فإنما يأكل الذئب القاصية من الغنم)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "قال شيخ الإسلام ابن تيمية: «متى ترك الناس بعض ما أمرهم الله به وقعت بينهم العداوة والبغضاء وإذا تفرَّقَ القوم فسدوا وهلكوا وإذا اجتمعوا صلحوا وملكوا؛ فإنَّ الجماعة رحمة والفرقة عذاب».", "page": 40, "id": "unit-03__lesson-05__b07", "inline": [{"t": "text", "s": "قال شيخ الإسلام ابن تيمية: "}, {"t": "quote", "s": "متى ترك الناس بعض ما أمرهم الله به وقعت بينهم العداوة والبغضاء وإذا تفرَّقَ القوم فسدوا وهلكوا وإذا اجتمعوا صلحوا وملكوا؛ فإنَّ الجماعة رحمة والفرقة عذاب", "speaker": "شيخ الإسلام ابن تيمية"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "والمقصود بالجماعة هنا: لزوم الحق وأهله المجتمعين عليه، فأيُّ جماعةٍ قامت بثغر من ثغور الدين في الدعوة أو الجهاد وكان خيرها أكثر من شرها بالجملة فيحرصُ المرء على الاجتماع معها بالمعروف.", "page": 40, "id": "unit-03__lesson-05__b08"}, {"type": "paragraph", "md": "ولا يمكن أن تجتمع الأمة على الأهواء والآراء الشخصية، وإنما تجتمعُ على التقوى والتوحيد وطاعة الله، فالمعاصي والأثرة وحب الدنيا من أعظم ما يفرِّق الكلمة، ويملأ القلوب بالبغضاء والشحناء.", "page": 40, "id": "unit-03__lesson-05__b09"}, {"type": "paragraph", "md": "والسؤال الذي يطرح نفسه بعد هذا هو: أين المسلمون اليوم من مقتضيات هذه الأدلة؟ الله المستعان!", "page": 40, "id": "unit-03__lesson-05__b10", "inline": [{"t": "emphasis", "s": "والسؤال الذي يطرح نفسه بعد هذا هو: أين المسلمون اليوم من مقتضيات هذه الأدلة؟ الله المستعان!", "role": "emphasis"}]}, {"type": "heading", "level": 3, "text": "من فوائد الاجتماع:", "page": 41, "id": "unit-03__lesson-05__b11", "role": "benefits"}, {"type": "paragraph", "md": "يساعد المجتمع الإسلاميّ على مواجهة التّحدّيات الفكرية والعسكرية المعاصرة.", "page": 41, "id": "unit-03__lesson-05__b12"}, {"type": "paragraph", "md": "الاجتماع من أعظم وسائل إقامة دولة الإسلام الراشدة، التي تحفظ عقيدة الأمة وأخلاقها وهويتها.", "page": 41, "id": "unit-03__lesson-05__b13"}, {"type": "paragraph", "md": "القضاء على العصبيّة القبليّة، وعدّ القاعدة الدّينيّة الاجتماعيّة أساسا يتّسع لجميع الشّعوب المسلمة.", "page": 41, "id": "unit-03__lesson-05__b14"}, {"type": "paragraph", "md": "تحقيق الألفة بين المسلمين وانتشار التّعارف فيما بينهم، وبذلك تتحقّق المودّة ويسود التّعاون.", "page": 41, "id": "unit-03__lesson-05__b15"}, {"type": "paragraph", "md": "الاجتماع يخيف الأعداء ويلقي الرّعب في قلوبهم ويجعلهم يخشون شوكة الإسلام والمسلمين.", "page": 41, "id": "unit-03__lesson-05__b16"}, {"type": "paragraph", "md": "الاجتماع يذكي في الأفراد روح التّفوّق والرّغبة في إظهار قدراتهم، وهذا الدّافع لا يتحرّك إلَّا بجماعة.", "page": 41, "id": "unit-03__lesson-05__b17"}, {"type": "paragraph", "md": "في وجود الفرد داخل الجماعة وازع أساسيّ له كي يبتعد عن الرّذّائل خشية ما يصيبه من ضرر لو اطّلع الآخرون على هذه الصّفات القبيحة، فللاجتماع دوره الفعَّال في مكافحة الجريمة والرّذيلة.", "page": 41, "id": "unit-03__lesson-05__b18"}, {"type": "paragraph", "md": "بالاجتماع وخاصّة مع الصّالحين والأسوياء يتعلم المرء أخلاق إخوانه في الجماعة الحسنة، ويحاول تقليدها واكتساب أخلاقها، ثمّ يتحمّس للدِّفاع عنها ونقلها لغيره؛ فيعم الخير بذلك، ويقل الشر.", "page": 41, "id": "unit-03__lesson-05__b19"}, {"type": "paragraph", "md": "في الاجتماع دواء ناجع لكثير من الأمراض النّفسيّة كالانطواء والقلق، وخاصّة إذا علم أنّ إخوانه لن يتخلّوا عنه وقت الشّدّة فالمرء قليل بنفسه كثير بإخوانه.", "page": 41, "id": "unit-03__lesson-05__b20"}, {"type": "paragraph", "md": "الاجتماع بأهل الذّكر الذين لا يشقى جليسهم؛ غالبا ما يكون سببا لمغفرة الله ورضوانه.", "page": 41, "id": "unit-03__lesson-05__b21"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 41, "id": "unit-03__lesson-05__b22", "role": "assessment"}, {"type": "paragraph", "md": "اذكر خمسة من فوائد الاجتماع على الطاعة", "page": 41, "id": "unit-03__lesson-05__b23", "item_role": "question"}, {"type": "paragraph", "md": "هل تدخل صلاة الجماعة في الأحاديث الدالة على فضل جماعة المسلمين.", "page": 41, "id": "unit-03__lesson-05__b24", "item_role": "question"}, {"type": "paragraph", "md": "اذكر بعض مظاهر التعبد التي جعلها الله تؤدى جماعةً لأجلِ الحث على جمع كلمة المسلمين.", "page": 41, "id": "unit-03__lesson-05__b25", "item_role": "question"}, {"type": "paragraph", "md": "عدد بعض العبادات التي لا تقوم إلا بجماعة.", "page": 41, "id": "unit-03__lesson-05__b26", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط بحثي علمي", "page": 41, "id": "unit-03__lesson-05__b27", "role": "activity"}, {"type": "paragraph", "md": "ارجع إلى كتاب «العمل الإسلامي بين دواعي الاجتماع ودعاة النزاع» وأعطنا في اللقاء القادم خمس فوائد استفدتها منه", "page": 41, "id": "unit-03__lesson-05__b28", "inline": [{"t": "text", "s": "ارجع إلى كتاب "}, {"t": "quote", "s": "العمل الإسلامي بين دواعي الاجتماع ودعاة النزاع"}, {"t": "text", "s": " وأعطنا في اللقاء القادم خمس فوائد استفدتها منه"}], "item_role": "activity_step"}]' WHERE id='unit-03__lesson-05';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: ﴿قُلۡ هُوَ ٱللَّهُ أَحَدٌ ۝١ ٱللَّهُ ٱلصَّمَدُ ۝٢ لَمۡ يَلِدۡ وَلَمۡ يُولَدۡ ۝٣﴾", "page": 42, "id": "unit-04__lesson-01__b01", "inline": [{"t": "text", "s": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: "}, {"t": "ayah", "s": "قُلۡ هُوَ ٱللَّهُ أَحَدٌ ۝١ ٱللَّهُ ٱلصَّمَدُ ۝٢ لَمۡ يَلِدۡ وَلَمۡ يُولَدۡ ۝٣", "ayah": [1, 2, 3], "verses": [{"n": 1, "text": "قُلۡ هُوَ ٱللَّهُ أَحَدٌ", "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:1", "surah_name": "الإخلاص", "ayah_canonical": 1, "match": "exact", "ref": "112:1"}, {"n": 2, "text": "ٱللَّهُ ٱلصَّمَدُ", "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:2", "surah_name": "الإخلاص", "ayah_canonical": 2, "match": "exact", "ref": "112:2"}, {"n": 3, "text": "لَمۡ يَلِدۡ وَلَمۡ يُولَدۡ", "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:3", "surah_name": "الإخلاص", "ayah_canonical": 3, "match": "exact", "ref": "112:3"}], "surah": null, "ref_api": null}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 42, "id": "unit-04__lesson-01__b02", "role": "objectives"}, {"type": "paragraph", "md": "معرفة فضل سورة الإخلاص، ومقاصدها.", "page": 42, "id": "unit-04__lesson-01__b03"}, {"type": "paragraph", "md": "معرفة أهم موضوعات سورة الإخلاص والألفاظ الغريبة الواردة فيها.", "page": 42, "id": "unit-04__lesson-01__b04"}, {"type": "paragraph", "md": "معرفة المعنى الإجمالي للسورة، وأهم الفوائد العلمية والتربوية الواردة فيها.", "page": 42, "id": "unit-04__lesson-01__b05"}, {"type": "paragraph", "md": "حفظ السورة بضبط وإتقان، وتلاوتها على الشيخ تلاوة مضبوطة الأحكام التجويدية.", "page": 42, "id": "unit-04__lesson-01__b06"}, {"type": "heading", "level": 3, "text": "فضل السورة:", "page": 42, "id": "unit-04__lesson-01__b07", "role": "virtues"}, {"type": "paragraph", "md": "أنها تعدل ثلث القرآن: فعن أبي الدرداء رضي الله عنه ، عن النبي صلى الله عليه وسلم ، قال: (أيعجز أحدكم أن يقرأ في ليلة ثلث القرآن؟ قالوا: وكيف يقرأ ثلث القرآن؟ قال: ﴿قُلۡ هُوَ ٱللَّهُ أَحَدٌ ۝١﴾ تعدل ثلث القرآن).", "page": 42, "id": "unit-04__lesson-01__b08", "inline": [{"t": "text", "s": "أنها تعدل ثلث القرآن: فعن أبي الدرداء "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ، عن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، قال: (أيعجز أحدكم أن يقرأ في ليلة ثلث القرآن؟ قالوا: وكيف يقرأ ثلث القرآن؟ قال: "}, {"t": "ayah", "s": "قُلۡ هُوَ ٱللَّهُ أَحَدٌ ۝١", "ayah": [1], "verses": [{"n": 1, "text": "قُلۡ هُوَ ٱللَّهُ أَحَدٌ", "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:1", "surah_name": "الإخلاص", "ayah_canonical": 1, "match": "exact", "ref": "112:1"}], "surah": null, "ref_api": null}, {"t": "text", "s": " تعدل ثلث القرآن)."}]}, {"type": "heading", "level": 3, "text": "مقصد السورة، وأهم الموضوعات التي اشتملت عليها:", "page": 42, "id": "unit-04__lesson-01__b09", "role": "main_themes"}, {"type": "paragraph", "md": "أما مقصدها فهو: بيان ما يجب لله تعالى من صفات الكمال، وما يجب تنزيهه عنه من النقائص والأمثال.", "page": 42, "id": "unit-04__lesson-01__b10"}, {"type": "paragraph", "md": "وموضوعاتها متعددة رغم صغرها، ومن ذلك: 1- إثبات وحدانية الله تعالى في ألوهيته وربوبيته وصفاته.", "page": 42, "id": "unit-04__lesson-01__b11", "inline": [{"t": "emphasis", "s": "وموضوعاتها متعددة رغم صغرها، ومن ذلك:", "role": "emphasis"}, {"t": "text", "s": " 1- إثبات وحدانية الله تعالى في ألوهيته وربوبيته وصفاته."}]}, {"type": "paragraph", "md": "2- أن لله تعالى صفات الكمال، ولا يقصد في الحوائج غيره.", "page": 42, "id": "unit-04__lesson-01__b12", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- إبطال أن يكون الله والدا، أو أن يكون مولودا؛ فالولادة من شأن المخلوقين لا الخالق سبحانه.", "page": 42, "id": "unit-04__lesson-01__b13", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- تنزيه الله عن النظير والمثيل والشبه والمكافئ؛ فليس كمثله شيء سبحانه.", "page": 42, "id": "unit-04__lesson-01__b14", "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "غريب الكلمات:", "page": 42, "id": "unit-04__lesson-01__b15", "role": "vocabulary"}, {"type": "paragraph", "md": "﴿أَحَدُۢ ۝٤﴾: الأحد هو الذي لا ثاني له، ولم يسبقه في أوِّلِيَّته شيء، الذي توحَّد بجميع الكمالات، وتفرد بالجلال والعظمة، فلا شريك له ولا مِثل ولا نظير، وهو الوحيد الي يستحق أن يُعبد.", "page": 42, "id": "unit-04__lesson-01__b16", "inline": [{"t": "ayah", "s": "أَحَدُۢ ۝٤", "ayah": [4], "verses": [{"n": 4, "text": "أَحَدُۢ", "surah": null, "ref_api": null}], "surah": null, "ref_api": null}, {"t": "text", "s": ": الأحد هو الذي لا ثاني له، ولم يسبقه في أوِّلِيَّته شيء، الذي توحَّد بجميع الكمالات، وتفرد بالجلال والعظمة، فلا شريك له ولا مِثل ولا نظير، وهو الوحيد الي يستحق أن يُعبد."}]}, {"type": "paragraph", "md": "﴿ٱلصَّمَدُ ۝٢﴾: أي: السيد الذي يصمد إليه -أي: يقصد- في الأمور كلها ظاهرها وباطنها.", "page": 42, "id": "unit-04__lesson-01__b17", "inline": [{"t": "ayah", "s": "ٱلصَّمَدُ ۝٢", "ayah": [2], "verses": [{"n": 2, "text": "ٱلصَّمَدُ", "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:2", "surah_name": "الإخلاص", "ayah_canonical": 2, "match": "contained", "ref": "112:2"}], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي: السيد الذي يصمد إليه -أي: يقصد- في الأمور كلها ظاهرها وباطنها."}]}, {"type": "paragraph", "md": "﴿كُفُوًا﴾: أي: مثيلا أو نظيرا.", "page": 42, "id": "unit-04__lesson-01__b18", "inline": [{"t": "ayah", "s": "كُفُوًا", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي: مثيلا أو نظيرا."}]}, {"type": "paragraph", "md": "المعنى الإجمالي: افتتح الله تعالى هذه السورة الكريمة بقوله: قل -يا محمد- معرفا بالله تعالى: هو المتفرد بالوحدانية في ذاته وصفاته، الله الكامل في صفاته الذي تفتقر له جميع مخلوقاته، لم يلد أحدا ولم يلده أحد، وليس له مساو ولا نظير سبحانه وتعالى .", "page": 43, "id": "unit-04__lesson-01__b19", "inline": [{"t": "text", "s": "المعنى الإجمالي: افتتح الله تعالى هذه السورة الكريمة بقوله: قل -يا محمد- معرفا بالله تعالى: هو المتفرد بالوحدانية في ذاته وصفاته، الله الكامل في صفاته الذي تفتقر له جميع مخلوقاته، لم يلد أحدا ولم يلده أحد، وليس له مساو ولا نظير "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}]}, {"type": "heading", "level": 3, "text": "الفوائد التربوية:", "page": 43, "id": "unit-04__lesson-01__b20", "role": "benefits"}, {"type": "paragraph", "md": "1- في قوله تعالى: ﴿قُلۡ هُوَ ٱللَّهُ أَحَدٌ﴾، إفراد الله سبحانه وتعالى في العبادة، وتربية النفس على الإخلاص له سبحانه وتعالى ، فلا نقوم بأي عبادة إلا لله سبحانه وتعالى ؛ مخلصين لوجهه الكريم.", "page": 43, "id": "unit-04__lesson-01__b21", "inline": [{"t": "text", "s": "1- في قوله تعالى: "}, {"t": "ayah", "s": "قُلۡ هُوَ ٱللَّهُ أَحَدٌ", "ayah": [], "verses": [{"n": 1, "text": "قُلۡ هُوَ ٱللَّهُ أَحَدٌ", "surah": 112, "surah_name": "الإخلاص", "ref": "112:1", "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:1"}], "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:1", "surah_name": "الإخلاص", "ayah_canonical": 1, "match": "exact", "ref": "112:1"}, {"t": "text", "s": "، إفراد الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " في العبادة، وتربية النفس على الإخلاص له "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، فلا نقوم بأي عبادة إلا لله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ؛ مخلصين لوجهه الكريم."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2-من قوله: ﴿ٱللَّهُ ٱلصَّمَدُ﴾، أتعلم اللجوء لله في كل أموري وحاجاتي فهو الذي تلجأ له جميع المخلوقات.", "page": 43, "id": "unit-04__lesson-01__b22", "inline": [{"t": "text", "s": "2-من قوله: "}, {"t": "ayah", "s": "ٱللَّهُ ٱلصَّمَدُ", "ayah": [], "verses": [{"n": 2, "text": "ٱللَّهُ ٱلصَّمَدُ", "surah": 112, "surah_name": "الإخلاص", "ref": "112:2", "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:2"}], "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:2", "surah_name": "الإخلاص", "ayah_canonical": 2, "match": "exact", "ref": "112:2"}, {"t": "text", "s": "، أتعلم اللجوء لله في كل أموري وحاجاتي فهو الذي تلجأ له جميع المخلوقات."}]}, {"type": "paragraph", "md": "3-وقوله تعالى: ﴿وَلَمۡ يَكُن لَّهُۥ كُفُوًا أَحَدُۢ﴾، دليل على أن الله سبحانه مالك كل شيء، ومدبر كل شيء، لا ند له ولا مثيل ولا شبيه ولا يكافئه أحدٌ من خلقه؛ فهذا الكون له إله واحد وهو الله سبحانه.", "page": 43, "id": "unit-04__lesson-01__b23", "inline": [{"t": "text", "s": "3-وقوله تعالى: "}, {"t": "ayah", "s": "وَلَمۡ يَكُن لَّهُۥ كُفُوًا أَحَدُۢ", "ayah": [], "verses": [{"n": 4, "text": "وَلَمۡ يَكُن لَّهُۥ كُفُوًا أَحَدُۢ", "surah": 112, "surah_name": "الإخلاص", "ref": "112:4", "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:4"}], "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:4", "surah_name": "الإخلاص", "ayah_canonical": 4, "match": "exact", "ref": "112:4"}, {"t": "text", "s": "، دليل على أن الله سبحانه مالك كل شيء، ومدبر كل شيء، لا ند له ولا مثيل ولا شبيه ولا يكافئه أحدٌ من خلقه؛ فهذا الكون له إله واحد وهو الله سبحانه."}]}, {"type": "heading", "level": 3, "text": "الفوائد العلمية واللطائف:", "page": 43, "id": "unit-04__lesson-01__b24", "role": "benefits"}, {"type": "paragraph", "md": "1-قول الله تعالى: ﴿لَمۡ يَلِدۡ وَلَمۡ يُولَدۡ ۝٣﴾، ادعى المشركون أن لله ولدًا؛ فنفى الله عزوجل ذلك ونفى معه أن يكون له والدٌ، وذلك لأنَّ الذي يُجوز أن يكون لله ولد فإنه يجوز أن يكون له والد، فيكون هو مولودٌ -حاشاه سبحانه وتعالى -، فنفى الله عزوجل ذلك قبل أن يقوله الكفار تتمة للنفي وتنزيهًا له سبحانه وتعالى .", "page": 43, "id": "unit-04__lesson-01__b25", "inline": [{"t": "text", "s": "1-قول الله تعالى: "}, {"t": "ayah", "s": "لَمۡ يَلِدۡ وَلَمۡ يُولَدۡ ۝٣", "ayah": [3], "verses": [{"n": 3, "text": "لَمۡ يَلِدۡ وَلَمۡ يُولَدۡ", "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:3", "surah_name": "الإخلاص", "ayah_canonical": 3, "match": "exact", "ref": "112:3"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، ادعى المشركون أن لله ولدًا؛ فنفى الله عزوجل ذلك ونفى معه أن يكون له والدٌ، وذلك لأنَّ الذي يُجوز أن يكون لله ولد فإنه يجوز أن يكون له والد، فيكون هو مولودٌ -حاشاه "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " -، فنفى الله عزوجل ذلك قبل أن يقوله الكفار تتمة للنفي وتنزيهًا له "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "2-السورة فيها إثبات ونفي، وهما ركنا كلمة التوحيد: ففيها إثبات الكمالات لله وأنه أحد في عبادته وربوبيته وأوصافه، ونفت عنه سبحانه وتعالى الولد والوالد، والكفء والنظير والشبيه.", "page": 43, "id": "unit-04__lesson-01__b26", "inline": [{"t": "text", "s": "2-السورة فيها إثبات ونفي، وهما ركنا كلمة التوحيد: ففيها إثبات الكمالات لله وأنه أحد في عبادته وربوبيته وأوصافه، ونفت عنه "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " الولد والوالد، والكفء والنظير والشبيه."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 43, "id": "unit-04__lesson-01__b27", "role": "assessment"}, {"type": "paragraph", "md": "1- ما موضوع سورة الإخلاص؟ 2- ما معنى ﴿ٱلصَّمَدُ﴾", "page": 43, "id": "unit-04__lesson-01__b28", "inline": [{"t": "text", "s": "1- ما موضوع سورة الإخلاص؟ 2- ما معنى "}, {"t": "ayah", "s": "ٱلصَّمَدُ", "ayah": [], "verses": [{"n": 2, "text": "ٱلصَّمَدُ", "surah": 112, "surah_name": "الإخلاص", "ref": "112:2", "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:2"}], "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:2", "surah_name": "الإخلاص", "ayah_canonical": 2, "match": "contained", "ref": "112:2"}], "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "3- اذكر فائدة تربوية تعلمتها من سورة الإخلاص.", "page": 43, "id": "unit-04__lesson-01__b29", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- في السورة إثبات ونفي اشرح ذلك بأسلوبك الخاص.", "page": 43, "id": "unit-04__lesson-01__b30", "item_role": "question", "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "نشاط بحثي علمي", "page": 43, "id": "unit-04__lesson-01__b31", "role": "activity"}, {"type": "paragraph", "md": "اقرأ تفسير سورة الإخلاص من المختصر في التفسير أو تفسير السعدي واكتب أهم الفوائد التي أعجبتك.", "page": 43, "id": "unit-04__lesson-01__b32", "item_role": "activity_step"}, {"type": "paragraph", "md": "من أسماء الله «الصمد» وله عدة معاني عند أهل العلم، ابحث عن ثلاثة معاني غير التي ذُكرت أعلاه.", "page": 43, "id": "unit-04__lesson-01__b33", "inline": [{"t": "text", "s": "من أسماء الله "}, {"t": "quote", "s": "الصمد"}, {"t": "text", "s": " وله عدة معاني عند أهل العلم، ابحث عن ثلاثة معاني غير التي ذُكرت أعلاه."}], "item_role": "activity_step"}, {"type": "paragraph", "md": "ابحث عن فضائل أخرى لسورة الإخلاص غير التي ذكرت في الدرس.", "page": 43, "id": "unit-04__lesson-01__b34", "item_role": "activity_step"}]' WHERE id='unit-04__lesson-01';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رضي الله عنه أَنَّ النَّبِيَّ صلى الله عليه وسلم قَالَ: (‌بَلِّغُوا ‌عَنِّي ‌وَلَوْ ‌آيَةً، وَحَدِّثُوا عَنْ بَنِي إِسْرَاِئيلَ وَلَا حَرَجَ، وَمَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنَ النَّارِ) [صحيح البخاري].", "page": 44, "id": "unit-04__lesson-02__b01", "inline": [{"t": "text", "s": "عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " أَنَّ النَّبِيَّ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قَالَ: (‌بَلِّغُوا ‌عَنِّي ‌وَلَوْ ‌آيَةً، وَحَدِّثُوا عَنْ بَنِي إِسْرَاِئيلَ وَلَا حَرَجَ، وَمَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنَ النَّارِ) "}, {"t": "citation", "s": "[صحيح البخاري]", "source": "البخاري"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "عَنْ زَيْدِ بْنِ ثَابِتٍ رضي الله عنه قَالَ: سَمِعْتُ رَسُولَ اللَّهِ صلى الله عليه وسلم يَقُولُ: «نَضَّرَ اللَّهُ امْرَأً سَمِعَ مِنَّا حَدِيثًا، فَحَفِظَهُ حَتَّى يُبَلِّغَهُ، فَرُبَّ ‌حَامِلِ ‌فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ، وَرُبَّ ‌حَامِلِ ‌فِقْهٍ لَيْسَ بِفَقِيهٍ» [الترمذي، وصححه الألباني].", "page": 44, "id": "unit-04__lesson-02__b02", "inline": [{"t": "text", "s": "عَنْ زَيْدِ بْنِ ثَابِتٍ "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قَالَ: سَمِعْتُ رَسُولَ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يَقُولُ: "}, {"t": "hadith", "s": "نَضَّرَ اللَّهُ امْرَأً سَمِعَ مِنَّا حَدِيثًا، فَحَفِظَهُ حَتَّى يُبَلِّغَهُ، فَرُبَّ ‌حَامِلِ ‌فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ، وَرُبَّ ‌حَامِلِ ‌فِقْهٍ لَيْسَ بِفَقِيهٍ", "narrator": "زيد بن ثابت", "source": "الترمذي", "confidence": "high", "ref_api": null}, {"t": "text", "s": " [الترمذي، وصححه الألباني]."}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 44, "id": "unit-04__lesson-02__b03", "role": "objectives"}, {"type": "paragraph", "md": "أن يتعرف على صحابييَّن من صحابة النبي صلى الله عليه وسلم العظماء ويحفظ سيرتهم.", "page": 44, "id": "unit-04__lesson-02__b04", "inline": [{"t": "text", "s": "أن يتعرف على صحابييَّن من صحابة النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " العظماء ويحفظ سيرتهم."}]}, {"type": "paragraph", "md": "أن يعرف أهمية الدعوة وتبليغ العلم ولو كان قليلًا يسيرًا؛ فلعل الله ينفعه ببلاغه أكثر من عمله.", "page": 44, "id": "unit-04__lesson-02__b05"}, {"type": "paragraph", "md": "أن يعرف حرمة الكذب على الله ورسوله صلى الله عليه وسلم .", "page": 44, "id": "unit-04__lesson-02__b06", "inline": [{"t": "text", "s": "أن يعرف حرمة الكذب على الله ورسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "أن يعرف حكم التحديث عن أخبار اليهود الملاعين ويعرف اسمهم الصحيح في زماننا هذا.", "page": 44, "id": "unit-04__lesson-02__b07"}, {"type": "heading", "level": 3, "text": "راويا الحديثين:", "page": 44, "id": "unit-04__lesson-02__b08", "role": "section"}, {"type": "paragraph", "md": "1- عبد الله بن عمرو بن العاص القرشي: الإمام الحبر العابد، صاحب النبي صلى الله عليه وسلم وابن صاحبه، وله مناقب وفضائل ومقام راسخ في العلم والعمل، حمل عن النبي صلى الله عليه وسلم علما جما؛ فيبلغ ما أسنده: سبع مئة حديث اتفقا له على سبعة أحاديث، وكان من كتاب الوحي وحفظة القرآن، شديد الاجتهاد في العبادة، رغم غناه وثرائه الكبير، وشارك في فتح الشام ومصر وله مواقف مشهودة في الجهاد.", "page": 44, "id": "unit-04__lesson-02__b09", "inline": [{"t": "emphasis", "s": "1- عبد الله بن عمرو بن العاص القرشي", "role": "emphasis"}, {"t": "text", "s": ": الإمام الحبر العابد، صاحب النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وابن صاحبه، وله مناقب وفضائل ومقام راسخ في العلم والعمل، حمل عن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " علما جما؛ فيبلغ ما أسنده: سبع مئة حديث اتفقا له على سبعة أحاديث، وكان من كتاب الوحي وحفظة القرآن، شديد الاجتهاد في العبادة، رغم غناه وثرائه الكبير، وشارك في فتح الشام ومصر وله مواقف مشهودة في الجهاد."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "وُلد في السنة السابعة ق. هـ، وأسلم قبل أبيه، وتوفي سنة (65هـ)، عن اثنتين وسبعين عامًا، رضي الله عنه .", "page": 44, "id": "unit-04__lesson-02__b10", "inline": [{"t": "text", "s": "وُلد في السنة السابعة ق. هـ، وأسلم قبل أبيه، وتوفي سنة "}, {"t": "emphasis", "s": "(65هـ)", "role": "emphasis"}, {"t": "text", "s": "، عن اثنتين وسبعين عامًا، "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "2- زيد بن ثابت بن الضحاك الأنصاري الخزرجي: شيخ المقرئين والفرَضِيين، ولد قبل مقدم النبي صلى الله عليه وسلم المدينة بإحدى عشرة سنة؛ فلما هاجر النبي صلى الله عليه وسلم أسلم زيد، فأمره صلى الله عليه وسلم بتعلم خطِّ اليهود لذكائه، وقال له: (واللهِ ما آمنهم على كتابي)، فما مضى نصف شهر حتى أتقنه وكان يكتب للرسول صلى الله عليه وسلم إذا كتب لليهود.", "page": 44, "id": "unit-04__lesson-02__b11", "inline": [{"t": "emphasis", "s": "2- زيد بن ثابت بن الضحاك الأنصاري الخزرجي", "role": "emphasis"}, {"t": "text", "s": ": شيخ المقرئين والفرَضِيين، ولد قبل مقدم النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " المدينة بإحدى عشرة سنة؛ فلما هاجر النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أسلم زيد، فأمره "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بتعلم خطِّ اليهود لذكائه، وقال له: "}, {"t": "emphasis", "s": "(واللهِ ما آمنهم على كتابي)", "role": "emphasis"}, {"t": "text", "s": "، فما مضى نصف شهر حتى أتقنه وكان يكتب للرسول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " إذا كتب لليهود."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "شهد غزوة الخندق، وهي أول مغازيه، وقيل: شهد أحدًا قبلها، وتولى قسمة الغنائم في اليرموك.", "page": 44, "id": "unit-04__lesson-02__b12"}, {"type": "paragraph", "md": "جمع القرآن في عهد النبي صلى الله عليه وسلم ، وقال له أبو بكر: «إنك رجلٌ شاب عاقل لا نتهمك قد كنت تكتب الوحي لرسول الله صلى الله عليه وسلم ، فتتبع القرآن فاجمعه»، فكان على رأس من جمعوا المصحف، ثم ولاه عثمان رضي الله عنه مع ثلاثة نفر من قريش أن يجمعوا القرآن لتوحيده في مصحف واحد. توفي في المدينة سنة (45 هـ).", "page": 44, "id": "unit-04__lesson-02__b13", "inline": [{"t": "text", "s": "جمع القرآن في عهد النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، وقال له أبو بكر: "}, {"t": "hadith", "s": "إنك رجلٌ شاب عاقل لا نتهمك قد كنت تكتب الوحي لرسول الله صلى الله عليه وسلم ، فتتبع القرآن فاجمعه", "narrator": null, "source": null, "confidence": "high", "ref_api": null}, {"t": "text", "s": "، فكان على رأس من جمعوا المصحف، ثم ولاه عثمان "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " مع ثلاثة نفر من قريش أن يجمعوا القرآن لتوحيده في مصحف واحد. توفي في المدينة سنة "}, {"t": "emphasis", "s": "(45 هـ)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "شرح الحديث:", "page": 45, "id": "unit-04__lesson-02__b14", "role": "hadith_explanation"}, {"type": "paragraph", "md": "قوله (بلغوا) أمر يفيد وجوب الدعوةِ إلى الله وتبليغ ما يعلمه المرء من الدين حتى (ولو) كان قليلا، فإن (لو) تُفيد التقليل، فيجب على المتعلم أن يُسارع في تبليغ ما تعلَّمه، ومثله قوله في الحديث الآخر: (سمع مقالتي) ففيه تأكيد على أنَّ نقلَ الدين يشمل القرآن والسنة، فكلاهما وحي من الله تعالى.", "page": 45, "id": "unit-04__lesson-02__b15", "inline": [{"t": "text", "s": "قوله "}, {"t": "emphasis", "s": "(بلغوا)", "role": "lemma"}, {"t": "text", "s": " أمر يفيد وجوب الدعوةِ إلى الله وتبليغ ما يعلمه المرء من الدين حتى "}, {"t": "emphasis", "s": "(ولو)", "role": "lemma"}, {"t": "text", "s": " كان قليلا، فإن "}, {"t": "emphasis", "s": "(لو)", "role": "lemma"}, {"t": "text", "s": " تُفيد التقليل، فيجب على المتعلم أن يُسارع في تبليغ ما تعلَّمه، ومثله قوله في الحديث الآخر: "}, {"t": "emphasis", "s": "(سمع مقالتي)", "role": "lemma"}, {"t": "text", "s": " ففيه تأكيد على أنَّ نقلَ الدين يشمل القرآن والسنة، فكلاهما وحي من الله تعالى."}]}, {"type": "paragraph", "md": "ليس ثمة شك أن الله عز وجل حين أنزل القرآن الكريم شاء أن يعم نشره بين الملأ؛ لا ليجعله وقفًا على أقوامٍ يحتكرون معانيه في صدورهم، ومن صور نشره اليوم: ترجمته وإعادة نشره في وسائل النشر الحديثة باختلاف صورها، ومن صور البلاغ: دعوةُ من لا يعرف لحضور مجالس العلم ليعرف الدين.", "page": 45, "id": "unit-04__lesson-02__b16", "inline": [{"t": "text", "s": "ليس ثمة شك أن الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " حين أنزل القرآن الكريم شاء أن يعم نشره بين الملأ؛ لا ليجعله وقفًا على أقوامٍ يحتكرون معانيه في صدورهم، ومن صور نشره اليوم: ترجمته وإعادة نشره في وسائل النشر الحديثة باختلاف صورها، ومن صور البلاغ: دعوةُ من لا يعرف لحضور مجالس العلم ليعرف الدين."}]}, {"type": "paragraph", "md": "بنو إسرائيل هم اليهود، وإسرائيل هو نبي الله يعقوب عليه السلام ، والتحديث عنهم يُراد به: تناقل ما يحكونه من أخبار بغير إسناد؛ لان الإسناد لم يكن قبل هذه الأمة، فبعض الأخبار تُروى عنهم ولا تتضمن باطلا -كالتنقص من الأنبياء- فلا بأس بذكرها على سبيل الاستئناس والموعظة كقصص بعض عبادهم وزهادهم أو ما حل بمصير بعض الظالمين، ولا يُؤخذ منها حكم شرعي خاص.", "page": 45, "id": "unit-04__lesson-02__b17", "inline": [{"t": "text", "s": "بنو إسرائيل هم اليهود، وإسرائيل هو نبي الله يعقوب "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " ، والتحديث عنهم يُراد به: تناقل ما يحكونه من أخبار بغير إسناد؛ لان الإسناد لم يكن قبل هذه الأمة، فبعض الأخبار تُروى عنهم ولا تتضمن باطلا -كالتنقص من الأنبياء- فلا بأس بذكرها على سبيل الاستئناس والموعظة كقصص بعض عبادهم وزهادهم أو ما حل بمصير بعض الظالمين، ولا يُؤخذ منها حكم شرعي خاص."}]}, {"type": "paragraph", "md": "الكذب على رسول الله صلى الله عليه وسلم أمره خطير عظيم، لأن فيه إضافة شيء إلى النبي صلى الله عليه وسلم لم يقله، والكذب أصلا كبيرة عظيمة، فكيف لو أضيف للنبي صلى الله عليه وسلم ؛ إنه أشد خطرًا وإثمًا، والكذب: إخبارٌ بخلاف الواقع، فإن كذب على النبي صلى الله عليه وسلم عمدًا فقد يصل للكفر خاصة إن أحل حرامًا أو حرم حلالا بذلك، وإن كان يكون خطأً فيُعذر فيه إن لم يقصر في البحث، فيجب أن نتأكد من النقل أولا؛ حتى لا نكذب عليه صلى الله عليه وسلم .", "page": 45, "id": "unit-04__lesson-02__b18", "inline": [{"t": "text", "s": "الكذب على رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أمره خطير عظيم، لأن فيه إضافة شيء إلى النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لم يقله، والكذب أصلا كبيرة عظيمة، فكيف لو أضيف للنبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ؛ إنه أشد خطرًا وإثمًا، والكذب: إخبارٌ بخلاف الواقع، فإن كذب على النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " عمدًا فقد يصل للكفر خاصة إن أحل حرامًا أو حرم حلالا بذلك، وإن كان يكون خطأً فيُعذر فيه إن لم يقصر في البحث، فيجب أن نتأكد من النقل أولا؛ حتى لا نكذب عليه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "وقوله (نضر الله) النضارة: هي الحسن والجمال، قال تعالى: ﴿وُجُوهٞ يَوۡمَئِذٖ نَّاضِرَةٌ ۝٢٢ إِلَىٰ رَبِّهَا نَاظِرَةٞ ۝٢٣﴾؛ فلما نظرت إلى وجه الله عز وجل ازدادت جمالًا وحسنًا، والنضارة المذكورة تكون في الدنيا والآخرة؛ حيثُ تتلألأ وتشرق وجوههم عند ربهم سبحانه، وتجد وجوههم في الدنيا مشرقة نيرة كالشمس، وهذا ملاحظٌ عند أهل العلم والديانة: إذا رأيتَه رأيتَ نورًا في الوجه ولو كان أسمرَ اللون.", "page": 45, "id": "unit-04__lesson-02__b19", "inline": [{"t": "text", "s": "وقوله "}, {"t": "emphasis", "s": "(نضر الله)", "role": "lemma"}, {"t": "text", "s": " النضارة: هي الحسن والجمال، قال تعالى: "}, {"t": "ayah", "s": "وُجُوهٞ يَوۡمَئِذٖ نَّاضِرَةٌ ۝٢٢ إِلَىٰ رَبِّهَا نَاظِرَةٞ ۝٢٣", "ayah": [22, 23], "verses": [{"n": 22, "text": "وُجُوهٞ يَوۡمَئِذٖ نَّاضِرَةٌ", "surah": 75, "ref_api": "https://api.quran.com/api/v4/verses/by_key/75:22", "surah_name": "القيامة", "ayah_canonical": 22, "match": "exact", "ref": "75:22"}, {"n": 23, "text": "إِلَىٰ رَبِّهَا نَاظِرَةٞ", "surah": 75, "ref_api": "https://api.quran.com/api/v4/verses/by_key/75:23", "surah_name": "القيامة", "ayah_canonical": 23, "match": "exact", "ref": "75:23"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فلما نظرت إلى وجه الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ازدادت جمالًا وحسنًا، والنضارة المذكورة تكون في الدنيا والآخرة؛ حيثُ تتلألأ وتشرق وجوههم عند ربهم سبحانه، وتجد وجوههم في الدنيا مشرقة نيرة كالشمس، وهذا ملاحظٌ عند أهل العلم والديانة: إذا رأيتَه رأيتَ نورًا في الوجه ولو كان أسمرَ اللون."}]}, {"type": "paragraph", "md": "وقوله (سمع مقالتي) هذا يشمل الصحابة من باب أولى؛ لأنهم الذين باشروا السماع منه صلى الله عليه وسلم ، ويشمل كذلك مَن بعدهم ممن تابع أثرهم في ذلك؛ لأنه قال: (‌سمع مقالتي) أي حديثي، وما قال: ‌سمع مني، وقوله: (مقالتي) يختص بالصحيح دون المكذوب عليه صلى الله عليه وسلم ؛ لأن المكذوب لا ينسب إليه.", "page": 45, "id": "unit-04__lesson-02__b20", "inline": [{"t": "text", "s": "وقوله "}, {"t": "emphasis", "s": "(سمع مقالتي)", "role": "lemma"}, {"t": "text", "s": " هذا يشمل الصحابة من باب أولى؛ لأنهم الذين باشروا السماع منه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، ويشمل كذلك مَن بعدهم ممن تابع أثرهم في ذلك؛ لأنه قال: "}, {"t": "emphasis", "s": "(‌سمع مقالتي)", "role": "lemma"}, {"t": "text", "s": " أي حديثي، وما قال: ‌سمع مني، وقوله: "}, {"t": "emphasis", "s": "(مقالتي)", "role": "lemma"}, {"t": "text", "s": " يختص بالصحيح دون المكذوب عليه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ؛ لأن المكذوب لا ينسب إليه."}]}, {"type": "paragraph", "md": "وقوله: (فوعاها) يعني: وعى هذه المقالة، فشبَّه القلب الفاهم للشيء بالوعاء الذي قد حَفظ ما فيه فلم يفسد حين يُوضع داخله، وعلامة الوعي أنه (أداها كما سمعها) فعنده ضبط في الحفظ والفهم والأداء؛ فيأتي باللفظ كما سمعه، وهذه أعلى منازل حفظ السنة عن رسول الله صلى الله عليه وسلم .", "page": 46, "id": "unit-04__lesson-02__b21", "inline": [{"t": "text", "s": "وقوله: "}, {"t": "emphasis", "s": "(فوعاها)", "role": "lemma"}, {"t": "text", "s": " يعني: وعى هذه المقالة، فشبَّه القلب الفاهم للشيء بالوعاء الذي قد حَفظ ما فيه فلم يفسد حين يُوضع داخله، وعلامة الوعي أنه "}, {"t": "emphasis", "s": "(أداها كما سمعها)", "role": "lemma"}, {"t": "text", "s": " فعنده ضبط في الحفظ والفهم والأداء؛ فيأتي باللفظ كما سمعه، وهذه أعلى منازل حفظ السنة عن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "قوله (فرب حامل..) دليلٌ على فضل الدعوة، فلا يكتم المسلمُ هذا العلم، بل يبلغه؛ فمن بلغ حديث رسول الله صلى الله عليه وسلم إلى أحد فحفظه أو عمل به كان له مثل أجره، وهذا يبين لك فضل أصحاب النبي صلى الله عليه وسلم حيثُ بلغونا هذا الدين، فلهم أجر كل الأمة بعدهم، وقد قال صلى الله عليه وسلم : (لو أنفق أحدكم مثل أحد ذهبًا ما بلغ مُدَّ أحدهم ولا نصيفه)، فهذا هو السر في فضلهم.", "page": 46, "id": "unit-04__lesson-02__b22", "inline": [{"t": "text", "s": "قوله "}, {"t": "emphasis", "s": "(فرب حامل..)", "role": "lemma"}, {"t": "text", "s": " دليلٌ على فضل الدعوة، فلا يكتم المسلمُ هذا العلم، بل يبلغه؛ فمن بلغ حديث رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " إلى أحد فحفظه أو عمل به كان له مثل أجره، وهذا يبين لك فضل أصحاب النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " حيثُ بلغونا هذا الدين، فلهم أجر كل الأمة بعدهم، وقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لو أنفق أحدكم مثل أحد ذهبًا ما بلغ مُدَّ أحدهم ولا نصيفه)", "role": "lemma"}, {"t": "text", "s": "، فهذا هو السر في فضلهم."}]}, {"type": "paragraph", "md": "وقوله (أفقه منه) وبعدها (وليس بفقيه) دليلٌ على أن العلم مراتب، والمرء لا يترك العلم إذا كان مجرد حافظ أو فاهم، فكلهم ممدوحون، وإنما يؤدي ما يقدرُ عليه، ليكون ضمن هذه السلسلة المباركة في العلم؛ فأن يحفظه ويؤديه لمن هو أفقه منه يكفيه شرفًا، فلا يجوز للمرء أن ينقطع عن العلم لأنه لم يحقق فيه كل مقاصده في الفقه والحفظ والضبط والإتقان؛ فهذه أرزاق يقسمها الله بين من شاء.", "page": 46, "id": "unit-04__lesson-02__b23", "inline": [{"t": "text", "s": "وقوله "}, {"t": "emphasis", "s": "(أفقه منه)", "role": "lemma"}, {"t": "text", "s": " وبعدها "}, {"t": "emphasis", "s": "(وليس بفقيه)", "role": "lemma"}, {"t": "text", "s": " دليلٌ على أن العلم مراتب، والمرء لا يترك العلم إذا كان مجرد حافظ أو فاهم، فكلهم ممدوحون، وإنما يؤدي ما يقدرُ عليه، ليكون ضمن هذه السلسلة المباركة في العلم؛ فأن يحفظه ويؤديه لمن هو أفقه منه يكفيه شرفًا، فلا يجوز للمرء أن ينقطع عن العلم لأنه لم يحقق فيه كل مقاصده في الفقه والحفظ والضبط والإتقان؛ فهذه أرزاق يقسمها الله بين من شاء."}]}, {"type": "heading", "level": 3, "text": "فوائد ومسائل في الحديث النبوي الشريف:", "page": 46, "id": "unit-04__lesson-02__b24", "role": "benefits"}, {"type": "paragraph", "md": "قال (ولو آية)، ولم يقل: ولو حديث؛ لأنَّ الأمر بتبليغ الحديث يفهم بطريق الأولى، فالآيات مع انتشارها وتكفل الله بحفظها؛ إذا كانت واجبة التبليغ، فالحديث الذي لا شيء فيه من ذلك: أولى بالتبليغ.", "page": 46, "id": "unit-04__lesson-02__b25", "inline": [{"t": "text", "s": "قال "}, {"t": "emphasis", "s": "(ولو آية)", "role": "emphasis"}, {"t": "text", "s": "، ولم يقل: ولو حديث؛ لأنَّ الأمر بتبليغ الحديث يفهم بطريق الأولى، فالآيات مع انتشارها وتكفل الله بحفظها؛ إذا كانت واجبة التبليغ، فالحديث الذي لا شيء فيه من ذلك: أولى بالتبليغ."}]}, {"type": "paragraph", "md": "مصطلح «دولة إسرائيل» خاطئ والصواب «الدولة اليهودية»، لأن غالب اليهود المعاصرين ليسوا من نسل يعقوب أصلا، ولا هم أتباعه دينيا حيث كفروا به وكذبوه؛ فالمسلمون هم ورثة الأنبياء بما فيهم أنبياء بني إسرائيل، ولما كفر اليهود بأنبيائهم ولم يؤمنوا بمحمد صلى الله عليه وسلم نُزعت منهم الوراثة وصارت فينا.", "page": 46, "id": "unit-04__lesson-02__b26", "inline": [{"t": "text", "s": "مصطلح "}, {"t": "quote", "s": "دولة إسرائيل"}, {"t": "text", "s": " خاطئ والصواب "}, {"t": "quote", "s": "الدولة اليهودية"}, {"t": "text", "s": "، لأن غالب اليهود المعاصرين ليسوا من نسل يعقوب أصلا، ولا هم أتباعه دينيا حيث كفروا به وكذبوه؛ فالمسلمون هم ورثة الأنبياء بما فيهم أنبياء بني إسرائيل، ولما كفر اليهود بأنبيائهم ولم يؤمنوا بمحمد "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " نُزعت منهم الوراثة وصارت فينا."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 46, "id": "unit-04__lesson-02__b27", "role": "assessment"}, {"type": "paragraph", "md": "حدثنا عن زيد بن ثابت الأنصاري، وكم كان عمره حين تُوفي رضي الله عنه ؟", "page": 46, "id": "unit-04__lesson-02__b28", "inline": [{"t": "text", "s": "حدثنا عن زيد بن ثابت الأنصاري، وكم كان عمره حين تُوفي "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ؟"}], "item_role": "question"}, {"type": "paragraph", "md": "ما رأيك بعبارة «دولة إسرائيل» ولماذا تعتقد خطأ هذا المصطلح؟ وما الصواب فيه؟", "page": 46, "id": "unit-04__lesson-02__b29", "inline": [{"t": "text", "s": "ما رأيك بعبارة "}, {"t": "quote", "s": "دولة إسرائيل"}, {"t": "text", "s": " ولماذا تعتقد خطأ هذا المصطلح؟ وما الصواب فيه؟"}], "item_role": "question"}, {"type": "paragraph", "md": "هل قوله (ولو آية) تشمل الحديث النبوي؟ وما الدليل على ذلك من السنة النبوية والقياس؟", "page": 46, "id": "unit-04__lesson-02__b30", "inline": [{"t": "text", "s": "هل قوله "}, {"t": "emphasis", "s": "(ولو آية)", "role": "emphasis"}, {"t": "text", "s": " تشمل الحديث النبوي؟ وما الدليل على ذلك من السنة النبوية والقياس؟"}], "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط في قراءة كتاب", "page": 46, "id": "unit-04__lesson-02__b31", "role": "activity"}, {"type": "paragraph", "md": "اقرأ مع إخوانك مقتطفات من كتاب «مصطلحات يهودية احذروها» لعيسى القدومي، وأفدنا بثلاثة مصطلحات خاطئة يستعملها الناس، وقم بتصحيحها لعدد ممن حولك حتى تحقق البلاغ الوارد في الحديث", "page": 46, "id": "unit-04__lesson-02__b32", "inline": [{"t": "text", "s": "اقرأ مع إخوانك مقتطفات من كتاب "}, {"t": "quote", "s": "مصطلحات يهودية احذروها"}, {"t": "text", "s": " لعيسى القدومي، وأفدنا بثلاثة مصطلحات خاطئة يستعملها الناس، وقم بتصحيحها لعدد ممن حولك حتى تحقق البلاغ الوارد في الحديث"}], "item_role": "activity_step"}]' WHERE id='unit-04__lesson-02';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 47, "id": "unit-04__lesson-03__b01", "role": "objectives"}, {"type": "paragraph", "md": "معرفة أهمية العلم بأسماء الله وصفاته.", "page": 47, "id": "unit-04__lesson-03__b02"}, {"type": "paragraph", "md": "الإيمان باسم الله (الله) وآثاره السلوكية والإيمانية على العبد.", "page": 47, "id": "unit-04__lesson-03__b03", "inline": [{"t": "text", "s": "الإيمان باسم الله "}, {"t": "emphasis", "s": "(الله)", "role": "emphasis"}, {"t": "text", "s": " وآثاره السلوكية والإيمانية على العبد."}]}, {"type": "paragraph", "md": "الايمان باسم الله (الرحمن الرحيم) وآثارهما السلوكية والإيمانية على العبد.", "page": 47, "id": "unit-04__lesson-03__b04", "inline": [{"t": "text", "s": "الايمان باسم الله "}, {"t": "emphasis", "s": "(الرحمن الرحيم)", "role": "emphasis"}, {"t": "text", "s": " وآثارهما السلوكية والإيمانية على العبد."}]}, {"type": "heading", "level": 3, "text": "أهمية العلم بأسماء الله وصفاته سبحانه وتعالى :", "page": 47, "id": "unit-04__lesson-03__b05", "role": "section"}, {"type": "paragraph", "md": "العلم بأسماء الله الحسنى وصفاته العلى أجل العلوم وأشرفها؛ لأنه يُعَرِّفُ الناس بربهم وخالقهم، وكلما عرفوا معاني أسماء الله وصفاتها، زاد ذلك عندهم في عبادته سبحانه وتعالى ، ومحبته، وخشيته، وتعظيمه.", "page": 47, "id": "unit-04__lesson-03__b06", "inline": [{"t": "text", "s": "العلم بأسماء الله الحسنى وصفاته العلى أجل العلوم وأشرفها؛ لأنه يُعَرِّفُ الناس بربهم وخالقهم، وكلما عرفوا معاني أسماء الله وصفاتها، زاد ذلك عندهم في عبادته "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، ومحبته، وخشيته، وتعظيمه."}]}, {"type": "paragraph", "md": "يقول النبي صلى الله عليه وسلم : (تعرف على الله في الرخاء يعرفك في الشدة).", "page": 47, "id": "unit-04__lesson-03__b07", "inline": [{"t": "text", "s": "يقول النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(تعرف على الله في الرخاء يعرفك في الشدة)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وإنَّ شرف العلم يكون من شرف المعلوم، ولما كانت ثمرة تعلم أسماء الله الحسنى هو تعظيم الله جلا وعلا وتوحيده سبحانه وتعالى ؛ كان شرف تعلم أسماء الله تعالى عظيمًا، والذي يتعلم أسماء الله الحسنى وصفاته العلى يدعوه بها عبادةً لله سبحانه وتعالى وتقربًا إليه، ويناديه بالاسم الذي يرغب فيه من المعاني؛ فإن كان محتاجًا للرحمة قال: يا رحيم، وإن كان محتاجًا للرزق قال: يا رزاق؛ فإذا ألمت بالشخص مُلِمَّة، أو نزلت به نازلة، أو عاجله موت، او داهمه هَمٌّ أو مرض، فإنه يفزع إلى الله تبارك وتعالى ويصيح: «يا الله».", "page": 47, "id": "unit-04__lesson-03__b08", "inline": [{"t": "text", "s": "وإنَّ شرف العلم يكون من شرف المعلوم، ولما كانت ثمرة تعلم أسماء الله الحسنى هو تعظيم الله جلا وعلا وتوحيده "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ؛ كان شرف تعلم أسماء الله تعالى عظيمًا، والذي يتعلم أسماء الله الحسنى وصفاته العلى يدعوه بها عبادةً لله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " وتقربًا إليه، ويناديه بالاسم الذي يرغب فيه من المعاني؛ فإن كان محتاجًا للرحمة قال: يا رحيم، وإن كان محتاجًا للرزق قال: يا رزاق؛ فإذا ألمت بالشخص مُلِمَّة، أو نزلت به نازلة، أو عاجله موت، او داهمه هَمٌّ أو مرض، فإنه يفزع إلى الله "}, {"t": "honorific", "s": "تبارك وتعالى"}, {"t": "text", "s": " ويصيح: "}, {"t": "quote", "s": "يا الله"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "اسم «الله»:", "page": 47, "id": "unit-04__lesson-03__b09", "role": "section"}, {"type": "paragraph", "md": "يدور اسم «الله» على معنيين عظيمين متلازمين: المعنى الأول: هو الإله الجامع لجميع صفات الألوهية. والمعنى الثاني: هو المألوه، أي: المعبود الذي لا يستحق العبادة أحد سواه.", "page": 47, "id": "unit-04__lesson-03__b10", "inline": [{"t": "text", "s": "يدور اسم "}, {"t": "quote", "s": "الله"}, {"t": "text", "s": " على معنيين عظيمين متلازمين: "}, {"t": "emphasis", "s": "المعنى الأول", "role": "emphasis"}, {"t": "text", "s": ": هو الإله الجامع لجميع صفات الألوهية. "}, {"t": "emphasis", "s": "والمعنى الثاني", "role": "emphasis"}, {"t": "text", "s": ": هو المألوه، أي: المعبود الذي لا يستحق العبادة أحد سواه."}]}, {"type": "paragraph", "md": "الآثار الإيمانية والسلوكية للإيمان باسم «الله»:", "page": 47, "id": "unit-04__lesson-03__b11", "inline": [{"t": "text", "s": "الآثار الإيمانية والسلوكية للإيمان باسم "}, {"t": "quote", "s": "الله"}, {"t": "text", "s": ":"}]}, {"type": "paragraph", "md": "1- الأثر الأول: إثبات ما يتضمنه اسم «الله» من الصفات؛ فالله سبحانه وتعالى هو ذو الألوهية التي بها استحق أن يكون المعبودَ المألوهَ الحقَّ؛ بل استحق ألا يشاركه في هذا الوصف العظيم أحد سواه، كما قال تَعَالَى: ﴿فَذَٰلِكُمُ ٱللَّهُ رَبُّكُمُ ٱلۡحَقُّۖ فَمَاذَا بَعۡدَ ٱلۡحَقِّ إِلَّا ٱلضَّلَٰلُۖ فَأَنَّىٰ تُصۡرَفُونَ ۝٣٢﴾.", "page": 47, "id": "unit-04__lesson-03__b12", "inline": [{"t": "text", "s": "1- الأثر الأول: إثبات ما يتضمنه اسم "}, {"t": "quote", "s": "الله"}, {"t": "text", "s": " من الصفات؛ فالله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " هو ذو الألوهية التي بها استحق أن يكون المعبودَ المألوهَ الحقَّ؛ بل استحق ألا يشاركه في هذا الوصف العظيم أحد سواه، كما قال تَعَالَى: "}, {"t": "ayah", "s": "فَذَٰلِكُمُ ٱللَّهُ رَبُّكُمُ ٱلۡحَقُّۖ فَمَاذَا بَعۡدَ ٱلۡحَقِّ إِلَّا ٱلضَّلَٰلُۖ فَأَنَّىٰ تُصۡرَفُونَ ۝٣٢", "ayah": [32], "verses": [{"n": 32, "text": "فَذَٰلِكُمُ ٱللَّهُ رَبُّكُمُ ٱلۡحَقُّۖ فَمَاذَا بَعۡدَ ٱلۡحَقِّ إِلَّا ٱلضَّلَٰلُۖ فَأَنَّىٰ تُصۡرَفُونَ", "surah": 10, "ref_api": "https://api.quran.com/api/v4/verses/by_key/10:32", "surah_name": "يونس", "ayah_canonical": 32, "match": "exact", "ref": "10:32"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الأثر الثاني: الفرح والسرور بمعرفة الله سبحانه وتعالى : فالنفس أحوج ما تكون إلى معرفة خالقها ومعبودها الحق، ولا حاجة إليها فوق حاجتها إلى معرفته، فلا سعادة لها ولا فلاح ولا صلاح ولا نعيم ولا راحة لها إلا بمعرفة ربها ومعبودها وعبادته، فإذا عرفت معبودها الحق «الله» جل جلاله سعدت وفرحت بذلك أشد الفرح، قال ابن القيم رحمه الله : «ليست حاجة الأرواح قط إلى شيء أعظم منها إلى معرفة بارئها وفاطرها ومحبته وذكره والابتهاج به، وطلب الوسيلة إليه والزلفى عنده».", "page": 48, "id": "unit-04__lesson-03__b13", "inline": [{"t": "text", "s": "2- الأثر الثاني: الفرح والسرور بمعرفة الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : فالنفس أحوج ما تكون إلى معرفة خالقها ومعبودها الحق، ولا حاجة إليها فوق حاجتها إلى معرفته، فلا سعادة لها ولا فلاح ولا صلاح ولا نعيم ولا راحة لها إلا بمعرفة ربها ومعبودها وعبادته، فإذا عرفت معبودها الحق "}, {"t": "quote", "s": "الله"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "جل جلاله"}, {"t": "text", "s": " سعدت وفرحت بذلك أشد الفرح، قال ابن القيم "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "ليست حاجة الأرواح قط إلى شيء أعظم منها إلى معرفة بارئها وفاطرها ومحبته وذكره والابتهاج به، وطلب الوسيلة إليه والزلفى عنده", "speaker": "ابن القيم رحمه الله"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- الأثر الثالث: الاعتزاز بالله جل جلاله والتوكل عليه: فإذا تأمل العبد في اسم «الله» جل جلاله ، وما فيه من صفات الكمال؛ إذ هو خالق كل شيء ومالكه، ومدبر أمره، والخاضع له كل شيء الملك والمملوك، والعزيز والذليل، والغني والفقير، والقوي والضعيف، والكبير والصغير.. إذا تأمل هذا شعر بالعزة به سُبْحَانَهُ؛ فتعلق به وحده، وسقط من قلبه الخوف والهيبة من الخلق والتعلق بهم، فلم يعتزَّ ولم يحتمِ إلا به سبحانه وتعالى ، ولم يتوكل إلا عليه، قال تَعَالَى: ﴿مَن كَانَ يُرِيدُ ٱلۡعِزَّةَ فَلِلَّهِ ٱلۡعِزَّةُ جَمِيعًاۚ﴾.", "page": 48, "id": "unit-04__lesson-03__b14", "inline": [{"t": "text", "s": "3- الأثر الثالث: الاعتزاز بالله "}, {"t": "honorific", "s": "جل جلاله"}, {"t": "text", "s": " والتوكل عليه: فإذا تأمل العبد في اسم "}, {"t": "quote", "s": "الله"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "جل جلاله"}, {"t": "text", "s": " ، وما فيه من صفات الكمال؛ إذ هو خالق كل شيء ومالكه، ومدبر أمره، والخاضع له كل شيء الملك والمملوك، والعزيز والذليل، والغني والفقير، والقوي والضعيف، والكبير والصغير.. إذا تأمل هذا شعر بالعزة به سُبْحَانَهُ؛ فتعلق به وحده، وسقط من قلبه الخوف والهيبة من الخلق والتعلق بهم، فلم يعتزَّ ولم يحتمِ إلا به "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، ولم يتوكل إلا عليه، قال تَعَالَى: "}, {"t": "ayah", "s": "مَن كَانَ يُرِيدُ ٱلۡعِزَّةَ فَلِلَّهِ ٱلۡعِزَّةُ جَمِيعًاۚ", "ayah": [], "verses": [{"n": 10, "text": "مَن كَانَ يُرِيدُ ٱلۡعِزَّةَ فَلِلَّهِ ٱلۡعِزَّةُ جَمِيعًاۚ", "surah": 35, "surah_name": "فاطر", "ref": "35:10", "ref_api": "https://api.quran.com/api/v4/verses/by_key/35:10"}], "surah": 35, "ref_api": "https://api.quran.com/api/v4/verses/by_key/35:10", "surah_name": "فاطر", "ayah_canonical": 10, "match": "contained", "ref": "35:10"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- الأثر الرابع: دعاء الله تَعَالَى باسمه الأعظم: فإن العبدَ إذا آمن بأن اسم «الله» جل جلاله هو الاسم الأعظم -على قول من أقوال أهل العلم- الذي لا يخيب من دعا به ولا يرد؛ لهج بالدعاء به، ولا سيما بما ورد من الأدعية التي نص فيها رسول الله صلى الله عليه وسلم على اشتمالها على الاسم الأعظم، كالدعاء بـ: «اللهم إني أسألك بأنك أنت الله، لا إله إلا أنت الأحد الصمد، الذي لم يلد ولم يولد، ولم يكن له كفوًا أحد»، والدعاء بـ: «اللهم إني أسألك بأن لك الحمد، لا إله إلا أنت، الحنان المنان بديع السماوات والأرض، يا ذا الجلال والإكرام، يا حي يا قيوم»، ثم إذا صَاحَب الدعاءَ بهذا الاسم الأعظم حضور قلب وانكسار وذلة؛ لم تكد تُرَد الدعوة، فليحرص العبد على الإكثار من سؤال الله باسمه الأعظم موقنًا بالإجابة.", "page": 48, "id": "unit-04__lesson-03__b15", "inline": [{"t": "text", "s": "4- الأثر الرابع: دعاء الله تَعَالَى باسمه الأعظم: فإن العبدَ إذا آمن بأن اسم "}, {"t": "quote", "s": "الله"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "جل جلاله"}, {"t": "text", "s": " هو الاسم الأعظم -على قول من أقوال أهل العلم- الذي لا يخيب من دعا به ولا يرد؛ لهج بالدعاء به، ولا سيما بما ورد من الأدعية التي نص فيها رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " على اشتمالها على الاسم الأعظم، كالدعاء بـ: "}, {"t": "hadith", "s": "اللهم إني أسألك بأنك أنت الله، لا إله إلا أنت الأحد الصمد، الذي لم يلد ولم يولد، ولم يكن له كفوًا أحد", "narrator": null, "source": null, "confidence": "high", "ref_api": null}, {"t": "text", "s": "، والدعاء بـ: "}, {"t": "quote", "s": "اللهم إني أسألك بأن لك الحمد، لا إله إلا أنت، الحنان المنان بديع السماوات والأرض، يا ذا الجلال والإكرام، يا حي يا قيوم"}, {"t": "text", "s": "، ثم إذا صَاحَب الدعاءَ بهذا الاسم الأعظم حضور قلب وانكسار وذلة؛ لم تكد تُرَد الدعوة، فليحرص العبد على الإكثار من سؤال الله باسمه الأعظم موقنًا بالإجابة."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "اسمي «الرحمن، الرحيم»:", "page": 48, "id": "unit-04__lesson-03__b16", "role": "section"}, {"type": "paragraph", "md": "هذان الاسمان العظيمان يدلان على أنه جل جلاله ذو الرحمة الواسعة العظيمة التي وسعت كل شيء، وعمت كل حي، وكتبها للمتقين المتبعين لأنبيائه ورسله؛ فهؤلاء لهم الرحمة المطلقة، ومن سِواهم فلهم منها نصيب.", "page": 48, "id": "unit-04__lesson-03__b17", "inline": [{"t": "text", "s": "هذان الاسمان العظيمان يدلان على أنه "}, {"t": "honorific", "s": "جل جلاله"}, {"t": "text", "s": " ذو الرحمة الواسعة العظيمة التي وسعت كل شيء، وعمت كل حي، وكتبها للمتقين المتبعين لأنبيائه ورسله؛ فهؤلاء لهم الرحمة المطلقة، ومن سِواهم فلهم منها نصيب."}]}, {"type": "paragraph", "md": "والرحمن دال على المبالغة؛ حيث يدل على شمول رحمة الله تعالى لجميع خلقه، وأما الرحيم، فهو يدل على خصوصية الرحمة بالمؤمنين، فالرحمة التي يرحمهم الله تعالى بها أكثر من رحمته بغيرهم.", "page": 48, "id": "unit-04__lesson-03__b18", "inline": [{"t": "text", "s": "والرحمن دال على المبالغة؛ حيث يدل على شمول رحمة الله تعالى لجميع خلقه، وأما الرحيم، فهو يدل على خصوصية الرحمة بالمؤمنين، فالرحمة التي ي"}, {"t": "honorific", "s": "رحمهم الله"}, {"t": "text", "s": " تعالى بها أكثر من رحمته بغيرهم."}]}, {"type": "paragraph", "md": "الآثار الإيمانية والسلوكية للإيمان باسم «الرحمن الرحيم»:", "page": 48, "id": "unit-04__lesson-03__b19", "inline": [{"t": "text", "s": "الآثار الإيمانية والسلوكية للإيمان باسم "}, {"t": "quote", "s": "الرحمن الرحيم"}, {"t": "text", "s": ":"}]}, {"type": "paragraph", "md": "1- الأثر الأول: الرجاء والتعلق برحمة الرحمن الرحيم؛ فإذا نظر الإنسان في سعة رحمة الله وعظمتها؛ أثمر ذلك في نفسه الرجاء وعدم اليأس من رحمة الله ومغفرته؛ إذ إنه سُبْحَانَهُ علم ضعف عباده وعجزهم وسرعان سقوطهم وانحرافهم عن الحق، لا سيما أن نفوسهم رُكِّب فيها الميل للشهوات، وتسلط عليهم الشيطان، يقطع عليهم طريق الهدى، ويجلب عليهم بخيله ورجله، ويجدُّ كل الجدِّ في إضلالهم وإيقاعهم في السوء، فلا خلاص لهم من الذنوب والزلات، وكل ابن آدم خطاء؛ فهنا يأتي قوله تعالى: ﴿۞قُلۡ يَٰعِبَادِيَ ٱلَّذِينَ أَسۡرَفُواْ عَلَىٰٓ أَنفُسِهِمۡ لَا تَقۡنَطُواْ مِن رَّحۡمَةِ ٱللَّهِۚ إِنَّ ٱللَّهَ يَغۡفِرُ ٱلذُّنُوبَ جَمِيعًاۚ إِنَّهُۥ هُوَ ٱلۡغَفُورُ ٱلرَّحِيمُ﴾.", "page": 49, "id": "unit-04__lesson-03__b20", "inline": [{"t": "text", "s": "1- الأثر الأول: الرجاء والتعلق برحمة الرحمن الرحيم؛ فإذا نظر الإنسان في سعة رحمة الله وعظمتها؛ أثمر ذلك في نفسه الرجاء وعدم اليأس من رحمة الله ومغفرته؛ إذ إنه سُبْحَانَهُ علم ضعف عباده وعجزهم وسرعان سقوطهم وانحرافهم عن الحق، لا سيما أن نفوسهم رُكِّب فيها الميل للشهوات، وتسلط عليهم الشيطان، يقطع عليهم طريق الهدى، ويجلب عليهم بخيله ورجله، ويجدُّ كل الجدِّ في إضلالهم وإيقاعهم في السوء، فلا خلاص لهم من الذنوب والزلات، وكل ابن آدم خطاء؛ فهنا يأتي قوله تعالى: "}, {"t": "ayah", "s": "۞قُلۡ يَٰعِبَادِيَ ٱلَّذِينَ أَسۡرَفُواْ عَلَىٰٓ أَنفُسِهِمۡ لَا تَقۡنَطُواْ مِن رَّحۡمَةِ ٱللَّهِۚ إِنَّ ٱللَّهَ يَغۡفِرُ ٱلذُّنُوبَ جَمِيعًاۚ إِنَّهُۥ هُوَ ٱلۡغَفُورُ ٱلرَّحِيمُ", "ayah": [], "verses": [{"n": 53, "text": "۞قُلۡ يَٰعِبَادِيَ ٱلَّذِينَ أَسۡرَفُواْ عَلَىٰٓ أَنفُسِهِمۡ لَا تَقۡنَطُواْ مِن رَّحۡمَةِ ٱللَّهِۚ إِنَّ ٱللَّهَ يَغۡفِرُ ٱلذُّنُوبَ جَمِيعًاۚ إِنَّهُۥ هُوَ ٱلۡغَفُورُ ٱلرَّحِيمُ", "surah": 39, "surah_name": "الزمر", "ref": "39:53", "ref_api": "https://api.quran.com/api/v4/verses/by_key/39:53"}], "surah": 39, "ref_api": "https://api.quran.com/api/v4/verses/by_key/39:53", "surah_name": "الزمر", "ayah_canonical": 53, "match": "exact", "ref": "39:53"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الأثر الثاني: عدم الاغترار برحمة الله: إذا تيقن العبد رحمة ربه الرحمن الرحيم وسعتها، فلا بد أن يضم لهذا العلم علمًا آخر، وهو: أنه سُبْحَانَهُ شديد العقاب، شديد المحال، ذو البطش الشديد، والعذاب الأليم، قال تَعَالَى: ﴿۞نَبِّئۡ عِبَادِيٓ أَنِّيٓ أَنَا ٱلۡغَفُورُ ٱلرَّحِيمُ ۝٤٩ وَأَنَّ عَذَابِي هُوَ ٱلۡعَذَابُ ٱلۡأَلِيمُ ۝٥٠﴾، فلا يغتر برحمة الله، بل يجمع بين رجاء الرحمة، وخوف العقاب كما جمع الله بينهما في كتابه وعلى لسان رسوله صلى الله عليه وسلم .", "page": 49, "id": "unit-04__lesson-03__b21", "inline": [{"t": "text", "s": "2- الأثر الثاني: عدم الاغترار برحمة الله: إذا تيقن العبد رحمة ربه الرحمن الرحيم وسعتها، فلا بد أن يضم لهذا العلم علمًا آخر، وهو: أنه سُبْحَانَهُ شديد العقاب، شديد المحال، ذو البطش الشديد، والعذاب الأليم، قال تَعَالَى: "}, {"t": "ayah", "s": "۞نَبِّئۡ عِبَادِيٓ أَنِّيٓ أَنَا ٱلۡغَفُورُ ٱلرَّحِيمُ ۝٤٩ وَأَنَّ عَذَابِي هُوَ ٱلۡعَذَابُ ٱلۡأَلِيمُ ۝٥٠", "ayah": [49, 50], "verses": [{"n": 49, "text": "۞نَبِّئۡ عِبَادِيٓ أَنِّيٓ أَنَا ٱلۡغَفُورُ ٱلرَّحِيمُ", "surah": 15, "ref_api": "https://api.quran.com/api/v4/verses/by_key/15:49", "surah_name": "الحجر", "ayah_canonical": 49, "match": "exact", "ref": "15:49"}, {"n": 50, "text": "وَأَنَّ عَذَابِي هُوَ ٱلۡعَذَابُ ٱلۡأَلِيمُ", "surah": 15, "ref_api": "https://api.quran.com/api/v4/verses/by_key/15:50", "surah_name": "الحجر", "ayah_canonical": 50, "match": "exact", "ref": "15:50"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، فلا يغتر برحمة الله، بل يجمع بين رجاء الرحمة، وخوف العقاب كما جمع الله بينهما في كتابه وعلى لسان رسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- الأثر الثالث: محبة الله الرحمن الرحيم والحياء منه: إذا تأمل العبد في اسم الله «الرحمن، الرحيم» ونظر في آثار رحمته التي لم تزل سارية في الوجود، مالئة للموجود؛ تنزل بها الخيرات آناء الليل والنهار، وتوالى بها النعم على العباد والفواضل في السر والجهار، ورحمته سبقت غضبه وغلبته، والعطاء أحب إليه من المنع؛ قاده ذلك كله إلى محبته سبحانه وتعالى ؛ إذ النفوس جبلت على محبة من يحسن إليها ويرفق بها ويعطف، فكيف لا تحب من أفاض عليها من رحمته وعطفه ونعمه ما يفوق الحصر والعد.", "page": 49, "id": "unit-04__lesson-03__b22", "inline": [{"t": "text", "s": "3- الأثر الثالث: محبة الله الرحمن الرحيم والحياء منه: إذا تأمل العبد في اسم الله "}, {"t": "quote", "s": "الرحمن، الرحيم"}, {"t": "text", "s": " ونظر في آثار رحمته التي لم تزل سارية في الوجود، مالئة للموجود؛ تنزل بها الخيرات آناء الليل والنهار، وتوالى بها النعم على العباد والفواضل في السر والجهار، ورحمته سبقت غضبه وغلبته، والعطاء أحب إليه من المنع؛ قاده ذلك كله إلى محبته "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ؛ إذ النفوس جبلت على محبة من يحسن إليها ويرفق بها ويعطف، فكيف لا تحب من أفاض عليها من رحمته وعطفه ونعمه ما يفوق الحصر والعد."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "كما يقوده- أيضًا- إلى الحياء منه والخجل؛ إذ كيف يعصي من يحسن إليه برحمته، ولولا إحسانه ونعمته ما استطاع أن يعصيه، وكيف يعصي من هو على أخذه وعقابه قادر، إلا أنه يمهله ويحلم عليه برحمته.", "page": 49, "id": "unit-04__lesson-03__b23"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة الإثرائية:", "page": 49, "id": "unit-04__lesson-03__b24", "role": "assessment"}, {"type": "paragraph", "md": "1-اذكر أهمية تعلم معاني أسماء وصفات الله الحسنى.", "page": 49, "id": "unit-04__lesson-03__b25", "item_role": "question"}, {"type": "paragraph", "md": "2- ما معنى أسماء الله سبحانه وتعالى : «الله، الرحمن، والرحيم».", "page": 49, "id": "unit-04__lesson-03__b26", "inline": [{"t": "text", "s": "2- ما معنى أسماء الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "الله، الرحمن، والرحيم"}, {"t": "text", "s": "."}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3-اذكر أثرًا واحدًا إيمانيًا وسلوكيًا على العبد بإيمانه باسم (الله، الرحمن، الرحيم)", "page": 49, "id": "unit-04__lesson-03__b27", "inline": [{"t": "text", "s": "3-اذكر أثرًا واحدًا إيمانيًا وسلوكيًا على العبد بإيمانه باسم "}, {"t": "emphasis", "s": "(الله، الرحمن، الرحيم)", "role": "emphasis"}], "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط بحثي حواري", "page": 49, "id": "unit-04__lesson-03__b28", "role": "activity"}, {"type": "paragraph", "md": "1- ابحث في كتب أهل العلم عن مسألة اسم الله الأعظم، وانظر ماذا قال العلماء فيها.", "page": 49, "id": "unit-04__lesson-03__b29", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- قم بنشاط أنت وزملاؤك تقدمون فيه نوع من أنواع الرحمة مع أسرة فقيرة أو أطفال صغار.", "page": 49, "id": "unit-04__lesson-03__b30", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-04__lesson-03';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 50, "id": "unit-04__lesson-04__b01", "role": "objectives"}, {"type": "paragraph", "md": "بيان أحكام النجاسات وأنواعها ووجوب الحذر منها.", "page": 50, "id": "unit-04__lesson-04__b02"}, {"type": "paragraph", "md": "معرفة كيفية تطهير النجاسات شرعًا.", "page": 50, "id": "unit-04__lesson-04__b03"}, {"type": "heading", "level": 3, "text": "معنى النجاسة وبيان أنواعها:", "page": 50, "id": "unit-04__lesson-04__b04", "role": "section"}, {"type": "paragraph", "md": "النجس لغة: كل مستقذر. وشرعًا أضيق من ذلك؛ فهو: مُستقذَر يمنع صحة الصلاة، كالدم والبول.", "page": 50, "id": "unit-04__lesson-04__b05", "inline": [{"t": "emphasis", "s": "النجس لغة", "role": "emphasis"}, {"t": "text", "s": ": كل مستقذر. "}, {"t": "emphasis", "s": "وشرعًا أضيق من ذلك؛ فهو", "role": "emphasis"}, {"t": "text", "s": ": مُستقذَر يمنع صحة الصلاة، كالدم والبول."}]}, {"type": "paragraph", "md": "الأصل أنّ كُلَّ الأشياء طاهرةٌ ومُبَاحَةٌ لقوله تعالى: ﴿أَلَمۡ تَرَ أَنَّ ٱللَّهَ سَخَّرَ لَكُم مَّا فِي ٱلۡأَرۡضِ﴾، إلا ما استثنته الشريعة ونصت عليه أنه نجس، وأوجبت التطهرَ منه، والنجاسات خمس:", "page": 50, "id": "unit-04__lesson-04__b06", "inline": [{"t": "text", "s": "الأصل أنّ كُلَّ الأشياء طاهرةٌ ومُبَاحَةٌ لقوله تعالى: "}, {"t": "ayah", "s": "أَلَمۡ تَرَ أَنَّ ٱللَّهَ سَخَّرَ لَكُم مَّا فِي ٱلۡأَرۡضِ", "ayah": [], "verses": [{"n": 65, "text": "أَلَمۡ تَرَ أَنَّ ٱللَّهَ سَخَّرَ لَكُم مَّا فِي ٱلۡأَرۡضِ", "surah": 22, "surah_name": "الحج", "ref": "22:65", "ref_api": "https://api.quran.com/api/v4/verses/by_key/22:65"}], "surah": 22, "ref_api": "https://api.quran.com/api/v4/verses/by_key/22:65", "surah_name": "الحج", "ayah_canonical": 65, "match": "contained", "ref": "22:65"}, {"t": "text", "s": "، إلا ما استثنته الشريعة ونصت عليه أنه نجس، وأوجبت التطهرَ منه، و"}, {"t": "emphasis", "s": "النجاسات خمس:", "role": "emphasis"}]}, {"type": "paragraph", "md": "1- أولها: بَوْلُ الإنسان وغائطه، وهو نجس بإجماعِ المسلمين.", "page": 50, "id": "unit-04__lesson-04__b07", "inline": [{"t": "emphasis", "s": "1- أولها:", "role": "emphasis"}, {"t": "text", "s": " بَوْلُ الإنسان وغائطه، وهو نجس بإجماعِ المسلمين."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "ويُلْحَقُ بالبول: المذي لأمره صلى الله عليه وسلم بغسله كما في الصحيحين من حديث عَليٍّ فيه: (يَغْسِلُ ذَكَرَهُ ويَتَوَضَّأُ).", "page": 50, "id": "unit-04__lesson-04__b08", "inline": [{"t": "text", "s": "ويُلْحَقُ بالبول: المذي لأمره "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بغسله كما في الصحيحين من حديث عَليٍّ فيه: "}, {"t": "emphasis", "s": "(يَغْسِلُ ذَكَرَهُ ويَتَوَضَّأُ).", "role": "emphasis"}]}, {"type": "paragraph", "md": "والوَدي -وهو سائل رقيق يخرج بعد البول- فهو كالمذي لغةً ومعنًى؛ فهما نجسان بالإجماع.", "page": 50, "id": "unit-04__lesson-04__b09"}, {"type": "paragraph", "md": "وأمّا رطوبة فَرْج المرأة ومني الرجل فطاهران، وكذلك بول وروث ما يُؤكَلُ لحمه طاهران.", "page": 50, "id": "unit-04__lesson-04__b10"}, {"type": "paragraph", "md": "2- ثانيها: الخمر والمُسْكِرات لقوله تعالى: ﴿إِنَّمَا ٱلۡخَمۡرُ وَٱلۡمَيۡسِرُ وَٱلۡأَنصَابُ وَٱلۡأَزۡلَٰمُ رِجۡسٞ مِّنۡ عَمَلِ ٱلشَّيۡطَٰنِ فَٱجۡتَنِبُوهُ﴾، وهي نجسة نجاسة حسية فمن لَمسها غسل يده وجوبًا.", "page": 50, "id": "unit-04__lesson-04__b11", "inline": [{"t": "emphasis", "s": "2- ثانيها:", "role": "emphasis"}, {"t": "text", "s": " الخمر والمُسْكِرات لقوله تعالى: "}, {"t": "ayah", "s": "إِنَّمَا ٱلۡخَمۡرُ وَٱلۡمَيۡسِرُ وَٱلۡأَنصَابُ وَٱلۡأَزۡلَٰمُ رِجۡسٞ مِّنۡ عَمَلِ ٱلشَّيۡطَٰنِ فَٱجۡتَنِبُوهُ", "ayah": [], "verses": [{"n": 90, "text": "إِنَّمَا ٱلۡخَمۡرُ وَٱلۡمَيۡسِرُ وَٱلۡأَنصَابُ وَٱلۡأَزۡلَٰمُ رِجۡسٞ مِّنۡ عَمَلِ ٱلشَّيۡطَٰنِ فَٱجۡتَنِبُوهُ", "surah": 5, "surah_name": "المائدة", "ref": "5:90", "ref_api": "https://api.quran.com/api/v4/verses/by_key/5:90"}], "surah": 5, "ref_api": "https://api.quran.com/api/v4/verses/by_key/5:90", "surah_name": "المائدة", "ayah_canonical": 90, "match": "contained", "ref": "5:90"}, {"t": "text", "s": "، وهي نجسة نجاسة حسية فمن لَمسها غسل يده وجوبًا."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ثالثها: المَيْتَة، لقولهم: «إنها مَيْتة»، فقال صلى الله عليه وسلم : (هلَّا أخذتُم إهابَها)؛ فَدَلَّ على تقرير نجاستها عندهم.", "page": 50, "id": "unit-04__lesson-04__b12", "inline": [{"t": "emphasis", "s": "3- ثالثها:", "role": "emphasis"}, {"t": "text", "s": " المَيْتَة، لقولهم: "}, {"t": "quote", "s": "إنها مَيْتة"}, {"t": "text", "s": "، فقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(هلَّا أخذتُم إهابَها)", "role": "emphasis"}, {"t": "text", "s": "؛ فَدَلَّ على تقرير نجاستها عندهم."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "ويُستثنى مَيْتة الإنسان -كافرا كان أو مسلما- لتكريم الله له، وكذلك تُستثنى مَيتة البحر لحديث: (الْحِلُّ ميتتُه)، وأيضًا ميتة ما لا دَم له سائل، كالذباب والنمل والذباب، لحديث: (فَلْيَغْمِسْهُ كُلَّهُ).", "page": 50, "id": "unit-04__lesson-04__b13", "inline": [{"t": "text", "s": "ويُستثنى مَيْتة الإنسان -كافرا كان أو مسلما- لتكريم الله له، وكذلك تُستثنى مَيتة البحر لحديث: "}, {"t": "emphasis", "s": "(الْحِلُّ ميتتُه)", "role": "emphasis"}, {"t": "text", "s": "، وأيضًا ميتة ما لا دَم له سائل، كالذباب والنمل والذباب، لحديث: "}, {"t": "emphasis", "s": "(فَلْيَغْمِسْهُ كُلَّهُ)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "4- رابعها: دَمُ الآدمي؛ فكله نجس سواء دم الحيض أو غيره، وهذا اتفاق الأئمة الأربعة، والخلاف فيما يُعفَى عنه لِعِلَل؛ كاليسير الذي يشقُّ إزالته، أو ما كان بين العروق غير مسفوح، وأمَّا دمُ الشهيد فطاهرٌ في حقه لا في حق غيره على المعتمد؛ لأنه داخل في عموم الدم المسفوح، وقد نُقل الإجماع على نجاسته.", "page": 50, "id": "unit-04__lesson-04__b14", "inline": [{"t": "emphasis", "s": "4- رابعها:", "role": "emphasis"}, {"t": "text", "s": " دَمُ الآدمي؛ فكله نجس سواء دم الحيض أو غيره، وهذا اتفاق الأئمة الأربعة، والخلاف فيما يُعفَى عنه لِعِلَل؛ كاليسير الذي يشقُّ إزالته، أو ما كان بين العروق غير مسفوح، وأمَّا دمُ الشهيد فطاهرٌ في حقه لا في حق غيره على المعتمد؛ لأنه داخل في عموم الدم المسفوح، وقد نُقل الإجماع على نجاسته."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- خامسها: الكلب والخنزير؛ لقوله صلى الله عليه وسلم : (طهور إناء أحدكم إذا ولغ فيه الكلب أن يغسله سبع مرات أولاهن بالتراب) والطهر لا يكون إلا من نجاسة، والخنزير لقوله تعالى: ﴿أَوۡ لَحۡمَ خِنزِيرٖ فَإِنَّهُۥ رِجۡسٌ﴾.", "page": 51, "id": "unit-04__lesson-04__b15", "inline": [{"t": "emphasis", "s": "5- خامسها:", "role": "emphasis"}, {"t": "text", "s": " الكلب والخنزير؛ لقوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(طهور إناء أحدكم إذا ولغ فيه الكلب أن يغسله سبع مرات أولاهن بالتراب)", "role": "emphasis"}, {"t": "text", "s": " والطهر لا يكون إلا من نجاسة، والخنزير لقوله تعالى: "}, {"t": "ayah", "s": "أَوۡ لَحۡمَ خِنزِيرٖ فَإِنَّهُۥ رِجۡسٌ", "ayah": [], "verses": [{"n": 145, "text": "أَوۡ لَحۡمَ خِنزِيرٖ فَإِنَّهُۥ رِجۡسٌ", "surah": 6, "surah_name": "الأنعام", "ref": "6:145", "ref_api": "https://api.quran.com/api/v4/verses/by_key/6:145"}], "surah": 6, "ref_api": "https://api.quran.com/api/v4/verses/by_key/6:145", "surah_name": "الأنعام", "ayah_canonical": 145, "match": "contained", "ref": "6:145"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "وبقية الحيوانات طاهرة كالهرة والحمار والخيل؛ فالأصل في الحيوان الطهارة إلا ما حُكم بنجاسته.", "page": 51, "id": "unit-04__lesson-04__b16"}, {"type": "heading", "level": 3, "text": "كيفية تطهير النجاسات:", "page": 51, "id": "unit-04__lesson-04__b17", "role": "section"}, {"type": "paragraph", "md": "تُطَهَّرُ كل نجاسةٍ بحسبها:", "page": 51, "id": "unit-04__lesson-04__b18"}, {"type": "paragraph", "md": "- فالبَوْل والعَذِرَة -الغائط-: تُزَالُ بالماء حتى يذهب أثرها، أو بالحجارة حتى تذهب عينها.", "page": 51, "id": "unit-04__lesson-04__b19", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "-ويجوز تطهير بَوْلُ الصبي الذي لم يأكُل الطعام بِرَشِّ الماء على موضع بوله دون غسله؛ فنجاسته مخففة.", "page": 51, "id": "unit-04__lesson-04__b20"}, {"type": "paragraph", "md": "- وتطهير الأرض: بالمكاثرة، وهو صَبُّ الماء عليها، وكذا الماء.", "page": 51, "id": "unit-04__lesson-04__b21", "inline": [{"t": "text", "s": "- "}, {"t": "emphasis", "s": "وتطهير الأرض", "role": "emphasis"}, {"t": "text", "s": ": بالمكاثرة، وهو صَبُّ الماء عليها، وكذا الماء."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وجازَ إزالة الغائط والبول بعد قضاء الحاجة بالحجر وما في معناه كالورق إذا لم يتجاوز المحل.", "page": 51, "id": "unit-04__lesson-04__b22", "inline": [{"t": "text", "s": "- وجازَ "}, {"t": "emphasis", "s": "إزالة الغائط والبول", "role": "emphasis"}, {"t": "text", "s": " بعد قضاء الحاجة بالحجر وما في معناه كالورق إذا لم يتجاوز المحل."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وريق الكلب وقيئه وبوله إن أصاب إناء أو موضعًا؛ فإنه يُغسَلُ سَبْعًا أولاهنَّ بالتّراب.", "page": 51, "id": "unit-04__lesson-04__b23", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وأسفل الخُفِّ والثوب يَطْهُرَان بالدَّلْك؛ فإذا دلكهما وزالت النجاسة طهرا لعموم البلوى بهما.", "page": 51, "id": "unit-04__lesson-04__b24", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- وبقاءُ أَثَرُ النجاسة بعد الغسل من لون أو رائحة لا يضر؛ إلا إذا بقي عينها، وهو بقاء طعمها.", "page": 51, "id": "unit-04__lesson-04__b25", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- ويُعفَى عن يسير النجاسات مما يشقُّ إزالته، كطين الطريق ورذاذ البول، فقد بالَ رسولُ الله صلى الله عليه وسلم قائمًا، ولا شك أنه سيطير بعض الرذاذ فلا يضير ذلك، والله أعلم.", "page": 51, "id": "unit-04__lesson-04__b26", "inline": [{"t": "text", "s": "- ويُعفَى عن يسير النجاسات مما يشقُّ إزالته، كطين الطريق ورذاذ البول، فقد بالَ رسولُ الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قائمًا، ولا شك أنه سيطير بعض الرذاذ فلا يضير ذلك، والله أعلم."}], "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 51, "id": "unit-04__lesson-04__b27", "role": "assessment"}, {"type": "paragraph", "md": "ما الأصل في الأشياء: الطهارة أم النجاسة؟ دلل على ذلك.", "page": 51, "id": "unit-04__lesson-04__b28", "item_role": "question"}, {"type": "paragraph", "md": "النجاسات خمسة، عددها تعدادًا مختصرًا مع بيان فهمك لكل منها.", "page": 51, "id": "unit-04__lesson-04__b29", "item_role": "question"}, {"type": "paragraph", "md": "كيف نطهر الأمور التالية: البول والغائط، ريق الكلب، الأرض؟", "page": 51, "id": "unit-04__lesson-04__b30", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط سلوكي دعوي", "page": 51, "id": "unit-04__lesson-04__b31", "role": "activity"}, {"type": "paragraph", "md": "1- تنتشر في بعض المناطق نجاسات مثل مياه الصرف وغيرها، ويتهاون الناس فيها، ونهدفُ لنشر ثقافة تطهير النجاسات وعدم مقاربتها في المجتمع المسلم.. اسعَ لذلك بصحبة إخوانك.", "page": 51, "id": "unit-04__lesson-04__b32", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- اشرح هذا الدرس لخمسة من معارفك وأهلك، وأخبرهم عما تعلمته، ووافنا بالنتيجة.", "page": 51, "id": "unit-04__lesson-04__b33", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-04__lesson-04';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 52, "id": "unit-04__lesson-05__b01", "role": "objectives"}, {"type": "paragraph", "md": "أن يتعرف على معنى الابتهال لله تعالى.", "page": 52, "id": "unit-04__lesson-05__b02"}, {"type": "paragraph", "md": "أن يبتهل بين يدي الله تعالى ويتضرع له في دعائه.", "page": 52, "id": "unit-04__lesson-05__b03"}, {"type": "heading", "level": 3, "text": "معنى الابتهال:", "page": 52, "id": "unit-04__lesson-05__b04", "role": "section"}, {"type": "paragraph", "md": "الابتهال: هو التَّضرُّع إلى الله، بأن تمدَّ يديك إلى الله بالدّعاء مخلصا متضرِّعا.", "page": 52, "id": "unit-04__lesson-05__b05"}, {"type": "paragraph", "md": "وهو من صفات الدعاء التي تدل على تمام التضرع والتذلل بين يدي الله تعالى، على حالة المضطر المستغيث الذي يرفع كلتا يديه إذا دعا، ويستغيث بربه إذا طلب منه، فمثل هذا حري أن يُستجابَ له.", "page": 52, "id": "unit-04__lesson-05__b06"}, {"type": "paragraph", "md": "عن أنس رضي الله عنه قال: (رأيت رسول الله صلى الله عليه وسلم يرفع يديه في الدّعاء، حتّى يرى بياض إبطيه)، وعن ابن عبَّاس رضي الله عنهما قال: «المسألة أن ترفع يديك حذو منكبيك، أو نحوهما، والاستغفار: أن تشير بأصبع واحدة. والابتهال: أن تمدّ يديك جميعا».. فالدُّعاء يكون في كلّ الأحوال، وأما الابتهال فغالبا ما يكون وقت الشِّدَّة والكرب، وهو أحوج ما نحتاجه في هذا الزمان الذي اشتدَّت فيه كربات المسلمين وآلامهم.", "page": 52, "id": "unit-04__lesson-05__b07", "inline": [{"t": "text", "s": "عن أنس "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: "}, {"t": "emphasis", "s": "(رأيت رسول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "يرفع يديه في الدّعاء، حتّى يرى بياض إبطيه)", "role": "emphasis"}, {"t": "text", "s": "، وعن ابن عبَّاس "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " قال: "}, {"t": "hadith", "s": "المسألة أن ترفع يديك حذو منكبيك، أو نحوهما، والاستغفار: أن تشير بأصبع واحدة. والابتهال: أن تمدّ يديك جميعا", "narrator": "أنس", "source": "مسلم", "confidence": "high", "ref_api": null}, {"t": "text", "s": ".. فالدُّعاء يكون في كلّ الأحوال، وأما الابتهال فغالبا ما يكون وقت الشِّدَّة والكرب، وهو أحوج ما نحتاجه في هذا الزمان الذي اشتدَّت فيه كربات المسلمين وآلامهم."}]}, {"type": "heading", "level": 3, "text": "‌‌من فوائد الابتهال:", "page": 52, "id": "unit-04__lesson-05__b08", "role": "benefits"}, {"type": "paragraph", "md": "دليل على تعلّق المسلم بربِّه في قضاء حوائجه، وهذا من حبِّ الله الملجوء له في الشدة وحال اليأس.", "page": 52, "id": "unit-04__lesson-05__b09"}, {"type": "paragraph", "md": "فيه راحة للنّفس ونقاء للقلب؛ لما فيه من دليل على إخلاص الدّاعي ووثوقه من إجابة الله له.", "page": 52, "id": "unit-04__lesson-05__b10"}, {"type": "paragraph", "md": "يستجيب الله عز وجل لدعاء المسلم وابتهاله ما لم يكن يدعو بإثم أو ظلم؛ فالله يحب دعاء المبتهلين.", "page": 52, "id": "unit-04__lesson-05__b11", "inline": [{"t": "text", "s": "يستجيب الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " لدعاء المسلم وابتهاله ما لم يكن يدعو بإثم أو ظلم؛ فالله يحب دعاء المبتهلين."}]}, {"type": "paragraph", "md": "الابتهال مجلبة لنصر الله ووسيلة لدحر العدوِّ، لأنَّ المبتهل يتقوى بقوة الله القوي ويُظهر ضعفه له.", "page": 52, "id": "unit-04__lesson-05__b12"}, {"type": "paragraph", "md": "به تُرفع الرّوح المعنويّة للمقاتلين خاصّة إذا كان القائد المبتهل قريبا من الله وواثقا من نصره.", "page": 52, "id": "unit-04__lesson-05__b13"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 52, "id": "unit-04__lesson-05__b14", "role": "assessment"}, {"type": "paragraph", "md": "عرف معنى الابتهال، واذكر أحواله التي يَلجأ إليه المرء فيها، وهل جربت قبل ذلك الابتهال لله تعالى؟", "page": 52, "id": "unit-04__lesson-05__b15", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط تعبدي", "page": 52, "id": "unit-04__lesson-05__b16", "role": "activity"}, {"type": "paragraph", "md": "نتعلم الابتهال عمليا ونجرب أن نرفع أيدينا لله لوحدنا، وكذلك في دعاءٍ جماعي", "page": 52, "id": "unit-04__lesson-05__b17", "item_role": "activity_step"}]' WHERE id='unit-04__lesson-05';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: ﴿تَبَّتۡ يَدَآ أَبِي لَهَبٖ وَتَبَّ ۝١ مَآ أَغۡنَىٰ عَنۡهُ مَالُهُۥ وَمَا كَسَبَ ۝٢ سَيَصۡلَىٰ نَارٗا ذَاتَ لَهَبٖ ۝٣ وَٱمۡرَأَتُهُۥ حَمَّالَةَ ٱلۡحَطَبِ ۝٤ فِي جِيدِهَا حَبۡلٞ مِّن مَّسَدِۭ ۝٥﴾", "page": 53, "id": "unit-05__lesson-01__b01", "inline": [{"t": "text", "s": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: "}, {"t": "ayah", "s": "تَبَّتۡ يَدَآ أَبِي لَهَبٖ وَتَبَّ ۝١ مَآ أَغۡنَىٰ عَنۡهُ مَالُهُۥ وَمَا كَسَبَ ۝٢ سَيَصۡلَىٰ نَارٗا ذَاتَ لَهَبٖ ۝٣ وَٱمۡرَأَتُهُۥ حَمَّالَةَ ٱلۡحَطَبِ ۝٤ فِي جِيدِهَا حَبۡلٞ مِّن مَّسَدِۭ ۝٥", "ayah": [1, 2, 3, 4, 5], "verses": [{"n": 1, "text": "تَبَّتۡ يَدَآ أَبِي لَهَبٖ وَتَبَّ", "surah": 111, "ref_api": "https://api.quran.com/api/v4/verses/by_key/111:1", "surah_name": "المسد", "ayah_canonical": 1, "match": "exact", "ref": "111:1"}, {"n": 2, "text": "مَآ أَغۡنَىٰ عَنۡهُ مَالُهُۥ وَمَا كَسَبَ", "surah": 111, "ref_api": "https://api.quran.com/api/v4/verses/by_key/111:2", "surah_name": "المسد", "ayah_canonical": 2, "match": "exact", "ref": "111:2"}, {"n": 3, "text": "سَيَصۡلَىٰ نَارٗا ذَاتَ لَهَبٖ", "surah": 111, "ref_api": "https://api.quran.com/api/v4/verses/by_key/111:3", "surah_name": "المسد", "ayah_canonical": 3, "match": "exact", "ref": "111:3"}, {"n": 4, "text": "وَٱمۡرَأَتُهُۥ حَمَّالَةَ ٱلۡحَطَبِ", "surah": 111, "ref_api": "https://api.quran.com/api/v4/verses/by_key/111:4", "surah_name": "المسد", "ayah_canonical": 4, "match": "exact", "ref": "111:4"}, {"n": 5, "text": "فِي جِيدِهَا حَبۡلٞ مِّن مَّسَدِۭ", "surah": 111, "ref_api": "https://api.quran.com/api/v4/verses/by_key/111:5", "surah_name": "المسد", "ayah_canonical": 5, "match": "exact", "ref": "111:5"}], "surah": null, "ref_api": null}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 53, "id": "unit-05__lesson-01__b02", "role": "objectives"}, {"type": "paragraph", "md": "معرفة مقاصد وموضوعات سورة المسد.", "page": 53, "id": "unit-05__lesson-01__b03"}, {"type": "paragraph", "md": "معرفة الألفاظ الغريبة والواردة في سورة المسد والمعنى الإجمالي للسورة.", "page": 53, "id": "unit-05__lesson-01__b04"}, {"type": "paragraph", "md": "معرفة الفوائد التربوية والعلمية لسورة المسد.", "page": 53, "id": "unit-05__lesson-01__b05"}, {"type": "paragraph", "md": "حفظ السورة بضبط وإتقان.", "page": 53, "id": "unit-05__lesson-01__b06"}, {"type": "heading", "level": 3, "text": "مقصد السورة، وأهم الموضوعات التي اشتملت عليها:", "page": 53, "id": "unit-05__lesson-01__b07", "role": "main_themes"}, {"type": "paragraph", "md": "أما مقصدها وموضوعاتها فهي: الإخبار عن شقاء أبى لهب وامرأته، وعدم إغناء ماله عنه ولا كسبه.", "page": 53, "id": "unit-05__lesson-01__b08"}, {"type": "heading", "level": 3, "text": "غريب الكلمات:", "page": 53, "id": "unit-05__lesson-01__b09", "role": "vocabulary"}, {"type": "paragraph", "md": "﴿تَبَّتۡ﴾: أي: خسرت وهلكت، واليدين كناية عن الجسد كله؛ فإذا هلكت اليدان هلك الجسد كلُّه.", "page": 53, "id": "unit-05__lesson-01__b10", "inline": [{"t": "ayah", "s": "تَبَّتۡ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي: خسرت وهلكت، واليدين كناية عن الجسد كله؛ فإذا هلكت اليدان هلك الجسد كلُّه."}]}, {"type": "paragraph", "md": "﴿أَبِي لَهَبٖ﴾ اسمه عبد العزى بن عبد المطلب، وهو عم النبي صلى الله عليه وسلم ، وإنما سمي ‌أبو ‌لهب لأن وجنتيه كانتا حمراوين، كأنما يلتهب منهما النار، وهذا دليل حسن صورته.", "page": 53, "id": "unit-05__lesson-01__b11", "inline": [{"t": "ayah", "s": "أَبِي لَهَبٖ", "ayah": [], "verses": [{"n": 1, "text": "أَبِي لَهَبٖ", "surah": 111, "surah_name": "المسد", "ref": "111:1", "ref_api": "https://api.quran.com/api/v4/verses/by_key/111:1"}], "surah": 111, "ref_api": "https://api.quran.com/api/v4/verses/by_key/111:1", "surah_name": "المسد", "ayah_canonical": 1, "match": "contained", "ref": "111:1"}, {"t": "text", "s": " اسمه عبد العزى بن عبد المطلب، وهو عم النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، وإنما سمي ‌أبو ‌لهب لأن وجنتيه كانتا حمراوين، كأنما يلتهب منهما النار، وهذا دليل حسن صورته."}]}, {"type": "paragraph", "md": "﴿جِيدِهَا﴾: أي: عنقها.", "page": 53, "id": "unit-05__lesson-01__b12", "inline": [{"t": "ayah", "s": "جِيدِهَا", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي: عنقها."}]}, {"type": "paragraph", "md": "﴿مَّسَدِۭ ۝٥﴾: ما فُتِل من أي شيء كان، قيل: إنه سلسلة فتلت من الحديد فتلا محكما، ولُوِيَت ليا شديدا.", "page": 53, "id": "unit-05__lesson-01__b13", "inline": [{"t": "ayah", "s": "مَّسَدِۭ ۝٥", "ayah": [5], "verses": [{"n": 5, "text": "مَّسَدِۭ", "surah": null, "ref_api": null}], "surah": null, "ref_api": null}, {"t": "text", "s": ": ما فُتِل من أي شيء كان، قيل: إنه سلسلة فتلت من الحديد فتلا محكما، ولُوِيَت ليا شديدا."}]}, {"type": "heading", "level": 3, "text": "المعنى الإجمالي:", "page": 53, "id": "unit-05__lesson-01__b14", "role": "overall_meaning"}, {"type": "paragraph", "md": "افتتح الله تعالى هذه السورة الكريمة بقوله تعالى: خسرت وهلكت يدا أبي لهب الذي اشتد أذاه للنبي صلى الله عليه وسلم ، وقد تحققت خسارته فعلا وهلك حقيقة؛ فلم ينفعه ماله وما كَسَبه من الأولاد أو غيرهم، وسيدخل نارا ذات إحراق شديد هو وزوجته أم جميل الحمالة للحطب، وسيكون في عنق امرأته حبل مفتول من النار تخنق وتعذب به؛ لشدة ما آذوا النبي صلى الله عليه وسلم .", "page": 53, "id": "unit-05__lesson-01__b15", "inline": [{"t": "text", "s": "افتتح الله تعالى هذه السورة الكريمة بقوله تعالى: خسرت وهلكت يدا أبي لهب الذي اشتد أذاه للنبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، وقد تحققت خسارته فعلا وهلك حقيقة؛ فلم ينفعه ماله وما كَسَبه من الأولاد أو غيرهم، وسيدخل نارا ذات إحراق شديد هو وزوجته أم جميل الحمالة للحطب، وسيكون في عنق امرأته حبل مفتول من النار تخنق وتعذب به؛ لشدة ما آذوا النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "heading", "level": 3, "text": "الفوائد التربوية:", "page": 54, "id": "unit-05__lesson-01__b16", "role": "benefits"}, {"type": "paragraph", "md": "1- نزلت هذه السورة في أبي لهب وامرأته، وهما من أشرف بطنين في قريش، وأبو لهب عم النبي صلى الله عليه وسلم ؛ ففي هذا أنَّ أن الأنساب لا عبرة بها، بل صاحب الشرف يكون ذمه على تخلفه عن الواجب أعظم، كما قال تعالى: ﴿يَٰنِسَآءَ ٱلنَّبِيِّ مَن يَأۡتِ مِنكُنَّ بِفَٰحِشَةٖ مُّبَيِّنَةٖ يُضَٰعَفۡ لَهَا ٱلۡعَذَابُ ضِعۡفَيۡنِۚ﴾.", "page": 54, "id": "unit-05__lesson-01__b17", "inline": [{"t": "text", "s": "1- نزلت هذه السورة في أبي لهب وامرأته، وهما من أشرف بطنين في قريش، وأبو لهب عم النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ؛ ففي هذا أنَّ أن الأنساب لا عبرة بها، بل صاحب الشرف يكون ذمه على تخلفه عن الواجب أعظم، كما قال تعالى: "}, {"t": "ayah", "s": "يَٰنِسَآءَ ٱلنَّبِيِّ مَن يَأۡتِ مِنكُنَّ بِفَٰحِشَةٖ مُّبَيِّنَةٖ يُضَٰعَفۡ لَهَا ٱلۡعَذَابُ ضِعۡفَيۡنِۚ", "ayah": [], "verses": [{"n": 30, "text": "يَٰنِسَآءَ ٱلنَّبِيِّ مَن يَأۡتِ مِنكُنَّ بِفَٰحِشَةٖ مُّبَيِّنَةٖ يُضَٰعَفۡ لَهَا ٱلۡعَذَابُ ضِعۡفَيۡنِۚ", "surah": 33, "surah_name": "الأحزاب", "ref": "33:30", "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:30"}], "surah": 33, "ref_api": "https://api.quran.com/api/v4/verses/by_key/33:30", "surah_name": "الأحزاب", "ayah_canonical": 30, "match": "contained", "ref": "33:30"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ذَكَر امرأته لأنها أعانته على أذى النبي صلى الله عليه وسلم فكما أعانت زوجها على أذى النبي صلى الله عليه وسلم فهي معه في النار، وفيه عبرة لكل متعاونين على إثم ما، أو عدوان ما؛ فمصيرهم واحد.", "page": 54, "id": "unit-05__lesson-01__b18", "inline": [{"t": "text", "s": "2- ذَكَر امرأته لأنها أعانته على أذى النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " فكما أعانت زوجها على أذى النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " فهي معه في النار، وفيه عبرة لكل متعاونين على إثم ما، أو عدوان ما؛ فمصيرهم واحد."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- كانت امرأة أبي لهب تأتي بالشوك تطرحه بالليل في طريق النبي صلى الله عليه وسلم ، وهذا من وضع الأذى في الطريق وهو من خصال الكفار؛ فيفهم من ذلك أن إماطة الأذى عن الطريق من خصال الإيمان.", "page": 54, "id": "unit-05__lesson-01__b19", "inline": [{"t": "text", "s": "3- كانت امرأة أبي لهب تأتي بالشوك تطرحه بالليل في طريق النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، وهذا من وضع الأذى في الطريق وهو من خصال الكفار؛ فيفهم من ذلك أن إماطة الأذى عن الطريق من خصال الإيمان."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "الفوائد العلمية واللطائف:", "page": 54, "id": "unit-05__lesson-01__b20", "role": "benefits"}, {"type": "paragraph", "md": "في هذا السورة آية باهرة من آيات الله عز وجل ، وعلامة على صدق الوحي وعظمة القرآن؛ فإن الله أنزل هذه السورة، وأبو لهب وامرأته لم يموتا، وأخبر أنهما سيعذبان في النار ولا بد، ومن لازم ذلك أنهما لا يسلمان؛ فوقع كما أخبر عالِم الغيب والشهادة، ففي هذه السورة معجزة ظاهرة، ودليل واضح على النبوة.", "page": 54, "id": "unit-05__lesson-01__b21", "inline": [{"t": "text", "s": "في هذا السورة آية باهرة من آيات الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ، وعلامة على صدق الوحي وعظمة القرآن؛ فإن الله أنزل هذه السورة، وأبو لهب وامرأته لم يموتا، وأخبر أنهما سيعذبان في النار ولا بد، ومن لازم ذلك أنهما لا يسلمان؛ فوقع كما أخبر عالِم الغيب والشهادة، ففي هذه السورة معجزة ظاهرة، ودليل واضح على النبوة."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 54, "id": "unit-05__lesson-01__b22", "role": "assessment"}, {"type": "paragraph", "md": "1- ما موضوع سورة المسد؟", "page": 54, "id": "unit-05__lesson-01__b23", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما معنى ﴿تَبَّتۡ يَدَآ أَبِي لَهَبٖ وَتَبَّ ۝١﴾ كما درستَه؟", "page": 54, "id": "unit-05__lesson-01__b24", "inline": [{"t": "text", "s": "2- ما معنى "}, {"t": "ayah", "s": "تَبَّتۡ يَدَآ أَبِي لَهَبٖ وَتَبَّ ۝١", "ayah": [1], "verses": [{"n": 1, "text": "تَبَّتۡ يَدَآ أَبِي لَهَبٖ وَتَبَّ", "surah": 111, "ref_api": "https://api.quran.com/api/v4/verses/by_key/111:1", "surah_name": "المسد", "ayah_canonical": 1, "match": "exact", "ref": "111:1"}], "surah": null, "ref_api": null}, {"t": "text", "s": " كما درستَه؟"}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- اذكر فائدة تربوية وأخرى علمية تعلمتها من سورة المسد.", "page": 54, "id": "unit-05__lesson-01__b25", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4-ما المسألة التي تدل على نبوة النبي صلى الله عليه وسلم في السورة؟", "page": 54, "id": "unit-05__lesson-01__b26", "inline": [{"t": "text", "s": "4-ما المسألة التي تدل على نبوة النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في السورة؟"}], "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط خارج المجلس", "page": 54, "id": "unit-05__lesson-01__b27", "role": "activity"}, {"type": "paragraph", "md": "ابحث عن حديث في السنة النبوية المطهرة يبين أن الأنساب لا تنفع المرء عند الله إذا لم تصلح الأعمال.", "page": 54, "id": "unit-05__lesson-01__b28", "item_role": "activity_step"}, {"type": "paragraph", "md": "لماذا جعل الله امرأة أبا لهب معه في النار.. اكتب عن هذا في خمسة أسطر بعد قراءة كتب التفسير.", "page": 54, "id": "unit-05__lesson-01__b29", "item_role": "activity_step"}, {"type": "paragraph", "md": "ارجع لكتب التفسير وابحث لماذا قال الله تعالى عن أبي لهب: «تبت يدا أبي لهب وتب».", "page": 54, "id": "unit-05__lesson-01__b30", "inline": [{"t": "text", "s": "ارجع لكتب التفسير وابحث لماذا قال الله تعالى عن أبي لهب: "}, {"t": "quote", "s": "تبت يدا أبي لهب وتب", "speaker": "الله تعالى عن أبي لهب"}, {"t": "text", "s": "."}], "item_role": "activity_step"}]' WHERE id='unit-05__lesson-01';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ النبي صلى الله عليه وسلم قالَ: «والَّذِي نَفْسِي بِيَدِهِ، لقد هَمَمْتُ أَنْ آمُرَ بِحَطَبٍ فَيُحْطَبَُ، ثُمَّ آمُرَُ بِالصَّلاةِ فَيُؤَذَّنَُ لَها، ثُمَّ آمُرَُ رَجُلًا فَيَؤُمَُّ النَّاسَ، ثُمَّ أُخالِفَُ إلى رِجالٍ ‌فَأُحَرِّقَُ ‌عَلَيْهِمْ ‌بُيوتَهُمْ، والَّذِي نَفْسِي بِيَدِهِ، لَوْ يَعْلَمُ أَحَدُهُمْ أَنَّهُ يَجِدُ عَرْقًا سَمِينًا، أَوْ مرْماتَيْنِ حَسَنَتَيْنِ، لَشَهِدَ العِشاءَ» [البخاري].", "page": 55, "id": "unit-05__lesson-02__b01", "inline": [{"t": "text", "s": "عَنْ أَبِي هُرَيْرَةَ "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " أَنَّ النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قالَ: "}, {"t": "hadith", "s": "والَّذِي نَفْسِي بِيَدِهِ، لقد هَمَمْتُ أَنْ آمُرَ بِحَطَبٍ فَيُحْطَبَُ، ثُمَّ آمُرَُ بِالصَّلاةِ فَيُؤَذَّنَُ لَها، ثُمَّ آمُرَُ رَجُلًا فَيَؤُمَُّ النَّاسَ، ثُمَّ أُخالِفَُ إلى رِجالٍ ‌فَأُحَرِّقَُ ‌عَلَيْهِمْ ‌بُيوتَهُمْ، والَّذِي نَفْسِي بِيَدِهِ، لَوْ يَعْلَمُ أَحَدُهُمْ أَنَّهُ يَجِدُ عَرْقًا سَمِينًا، أَوْ مرْماتَيْنِ حَسَنَتَيْنِ، لَشَهِدَ العِشاءَ", "narrator": "أبي هريرة", "source": "البخاري", "confidence": "high", "ref_api": null}, {"t": "text", "s": " [البخاري]."}]}, {"type": "paragraph", "md": "عن ابْنِ عُمَرَ رضي الله عنهما أَنَّ النَّبيَّ صلى الله عليه وسلم قالَ: (صَلاةُ الجَماعَةِ تَفْضُلُ صَلاةَ ‌الفَذِّ بِسَبْعٍ وَعِشْرِينَ دَرَجَةً) [البخاري].", "page": 55, "id": "unit-05__lesson-02__b02", "inline": [{"t": "text", "s": "عن ابْنِ عُمَرَ "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " أَنَّ النَّبيَّ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قالَ: (صَلاةُ الجَماعَةِ تَفْضُلُ صَلاةَ ‌الفَذِّ بِسَبْعٍ وَعِشْرِينَ دَرَجَةً) [البخاري]."}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 55, "id": "unit-05__lesson-02__b03", "role": "objectives"}, {"type": "paragraph", "md": "أن يعرف حكم صلاة الجماعة وفضلها.", "page": 55, "id": "unit-05__lesson-02__b04"}, {"type": "paragraph", "md": "أن يحافظ على صلاة الجماعة في المسجد.", "page": 55, "id": "unit-05__lesson-02__b05"}, {"type": "paragraph", "md": "أن يتعرف على أحد أصحاب النبي صلى الله عليه وسلم .", "page": 55, "id": "unit-05__lesson-02__b06", "inline": [{"t": "text", "s": "أن يتعرف على أحد أصحاب النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "heading", "level": 3, "text": "التعريف براوي الحديث:", "page": 55, "id": "unit-05__lesson-02__b07", "role": "definitions"}, {"type": "paragraph", "md": "أبو هريرة الدوسي: الإمام الفقيه المجتهد عبد الرحمن بن صخر ‌الدوسي اليماني، وهو مشهور بكنيته، وفي اسمه خلافٌ كثير، أسلم عام خيبر سنة 7 هـ، وعمره نحو ثلاثين سنة، ولازم النبي صلى الله عليه وسلم ؛ فكان من أكثر الصحابة رضي الله عنهم رواية للحديث عنه، كان رضي الله عنه من أوعية العلم، ومن كبار أئمة الفتوى، مع الجلالة والعبادة والتواضع والأدب، قال البخاري: روى عنه ثمان مئة نفسٍ أو أكثر، وتوفي سنة (57 هـ) في المدينة رضي الله عنه .", "page": 55, "id": "unit-05__lesson-02__b08", "inline": [{"t": "emphasis", "s": "أبو هريرة الدوسي:", "role": "lemma"}, {"t": "text", "s": " الإمام الفقيه المجتهد عبد الرحمن بن صخر ‌الدوسي اليماني، وهو مشهور بكنيته، وفي اسمه خلافٌ كثير، أسلم عام خيبر سنة 7 هـ، وعمره نحو ثلاثين سنة، ولازم النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ؛ فكان من أكثر الصحابة "}, {"t": "honorific", "s": "رضي الله عنهم"}, {"t": "text", "s": " رواية للحديث عنه، كان "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " من أوعية العلم، ومن كبار أئمة الفتوى، مع الجلالة والعبادة والتواضع والأدب، قال البخاري: روى عنه ثمان مئة نفسٍ أو أكثر، وتوفي سنة "}, {"t": "emphasis", "s": "(57 هـ)", "role": "lemma"}, {"t": "text", "s": " في المدينة "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ."}]}, {"type": "heading", "level": 3, "text": "شرح الحديث:", "page": 55, "id": "unit-05__lesson-02__b09", "role": "hadith_explanation"}, {"type": "paragraph", "md": "قوله (والذي نفسي بيده) أي واللَّه الذي حياتي بيده، وهو قسمٌ نبوي يدل على تعظيم المحلوفِ عليه.", "page": 55, "id": "unit-05__lesson-02__b10", "inline": [{"t": "text", "s": "قوله "}, {"t": "emphasis", "s": "(والذي نفسي بيده)", "role": "lemma"}, {"t": "text", "s": " أي واللَّه الذي حياتي بيده، وهو قسمٌ نبوي يدل على تعظيم المحلوفِ عليه."}]}, {"type": "paragraph", "md": "ظِلْف الشاةظِلْف الشاةظِلْف الشاةظِلْف الشاةوقوله (هممتُ) أي قصدتُ وعزمت، والهمُّ: انبعاث النفس إلى تحصيل أمرٍ ما.", "page": 55, "id": "unit-05__lesson-02__b11", "inline": [{"t": "text", "s": "ظِلْف الشاةظِلْف الشاةظِلْف الشاةظِلْف الشاةوقوله "}, {"t": "emphasis", "s": "(هممتُ)", "role": "lemma"}, {"t": "text", "s": " أي قصدتُ وعزمت، والهمُّ: انبعاث النفس إلى تحصيل أمرٍ ما."}]}, {"type": "paragraph", "md": "وقوله (ثم أخالف إلى رجال) أي آتيهم من خلف؛ فأذهب إلى الغائبين عن الصلاة.", "page": 55, "id": "unit-05__lesson-02__b12", "inline": [{"t": "text", "s": "وقوله "}, {"t": "emphasis", "s": "(ثم أخالف إلى رجال)", "role": "lemma"}, {"t": "text", "s": " أي آتيهم من خلف؛ فأذهب إلى الغائبين عن الصلاة."}]}, {"type": "paragraph", "md": "وقوله (فأحَرِّق) أي أبالغ في تحريق بيوتهم، وتشديد الراء مبالغة في الحرق.", "page": 55, "id": "unit-05__lesson-02__b13", "inline": [{"t": "text", "s": "وقوله "}, {"t": "emphasis", "s": "(فأحَرِّق)", "role": "lemma"}, {"t": "text", "s": " أي أبالغ في تحريق بيوتهم، وتشديد الراء مبالغة في الحرق."}]}, {"type": "paragraph", "md": "وقوله (عَرْقًا سمينًا) أي العظم الذي عليه لحم، و(مرماتين) تثنية مِرماة؛ أي ما بين ظِلْفَي الشاة من اللحم، وقيل: المرماة سهم دقيق لتعلم الرمي. أي أنهم يحرصون على الطعام أو اللهو، ويفرطون بما يكون به تحصيل الدرجات العلى في الجنة.. وقد جَمَع في الحديثِ بين السِّمَنِ في العَرْق، والحُسْن في المِرْماتين ليوجد الباعث النفسي في تحصيلهما، وقد ضرب بهما مثلًا بالأشياء التافهة الحقيرة من الدنيا؛ فهو توبيخ لمن رغب عن الجماعة، مع أنه لو طمع في إدراك يسيرٍ من الدنيا لبادر إليه.", "page": 55, "id": "unit-05__lesson-02__b14", "inline": [{"t": "text", "s": "وقوله "}, {"t": "emphasis", "s": "(عَرْقًا سمينًا)", "role": "lemma"}, {"t": "text", "s": " أي العظم الذي عليه لحم، و"}, {"t": "emphasis", "s": "(مرماتين)", "role": "lemma"}, {"t": "text", "s": " تثنية مِرماة؛ أي ما بين ظِلْفَي الشاة من اللحم، وقيل: المرماة سهم دقيق لتعلم الرمي. أي أنهم يحرصون على الطعام أو اللهو، ويفرطون بما يكون به تحصيل الدرجات العلى في الجنة.. وقد جَمَع في الحديثِ بين السِّمَنِ في العَرْق، والحُسْن في المِرْماتين ليوجد الباعث النفسي في تحصيلهما، وقد ضرب بهما مثلًا بالأشياء التافهة الحقيرة من الدنيا؛ فهو توبيخ لمن رغب عن الجماعة، مع أنه لو طمع في إدراك يسيرٍ من الدنيا لبادر إليه."}]}, {"type": "heading", "level": 3, "text": "فوائد ومسائل في الحديث النبوي الشريف:", "page": 56, "id": "unit-05__lesson-02__b15", "role": "benefits"}, {"type": "paragraph", "md": "حكم صلاة الجماعة: اختلفوا فيها على أربعة أقوال، ومذهب الشافعية أنها فرض كفاية، واستدلوا بحديثِ تفضيل صلاة الجماعة على صلاة الفَذِّ، والاشتراك في أصل الفضل يعني عدم التأثم، ولكن معنى كونها فرضَ كفاية أنه لا بد من حصول الكفاية وهو ظهور شعار الإسلام، واليوم نجد كثيرًا من المساجد في وسط أسواق المسلمين وحواضرهم لا يكتمل فيها سوى صف أو صفين، فمثل هذا لا يكون إظهارًا لشعار الإسلام؛ فالكفاية ليست متحققة بهذا، وهنا يكون كل تاركٍ للجماعة آثمًا، خاصة مع التشديد الكبير في حديث الباب وهم النبي صلى الله عليه وسلم أن يحرق بيوت المتخلفين عن الجماعة، وهو حديثُ ذهب لأجله كثير من العلماء إلى اعتبار صلاة الجماعة فرض عين على كل مسلم، وهو قول جدير بالنظر.", "page": 56, "id": "unit-05__lesson-02__b16", "inline": [{"t": "emphasis", "s": "حكم صلاة الجماعة:", "role": "emphasis"}, {"t": "text", "s": " اختلفوا فيها على أربعة أقوال، ومذهب الشافعية أنها فرض كفاية، واستدلوا بحديثِ تفضيل صلاة الجماعة على صلاة الفَذِّ، والاشتراك في أصل الفضل يعني عدم التأثم، ولكن معنى كونها فرضَ كفاية أنه لا بد من حصول الكفاية وهو ظهور شعار الإسلام، واليوم نجد كثيرًا من المساجد في وسط أسواق المسلمين وحواضرهم لا يكتمل فيها سوى صف أو صفين، فمثل هذا لا يكون إظهارًا لشعار الإسلام؛ فالكفاية ليست متحققة بهذا، وهنا يكون كل تاركٍ للجماعة آثمًا، خاصة مع التشديد الكبير في حديث الباب وهم النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أن يحرق بيوت المتخلفين عن الجماعة، وهو حديثُ ذهب لأجله كثير من العلماء إلى اعتبار صلاة الجماعة فرض عين على كل مسلم، وهو قول جدير بالنظر."}]}, {"type": "paragraph", "md": "صلاة الجماعة في المسجد: ظاهر الأدلة أن الفضلَ لصلاة الجماعة لا يكون إلا في المسجد، فجماعة البيت خير من المنفرد ولكن ليست هي المقصودة بالأجر ولا يتحقق بها غرض الجماعة؛ لحديث الهم بالتحريق، ولقول ابن مسعود: «من سره أن يلقى الله غدا مسلما، فليحافظ على هؤلاء الصلوات حيث ينادى بهن؛ فإن الله شرع لنبيكم صلى الله عليه وسلم سنن الهدى، وإنهن من سنن الهدى، ولو أنكم صليتم في بيوتكم كما يصلي هذا المتخلف في بيته، لتركتم سنة نبيكم، ولو تركتم سنة نبيكم لضللتم... ولقد رأيتنا وما يتخلف عنها إلا منافق معلوم النفاق، ولقد كان الرجل يؤتى به يهادى بين الرجلين حتى يقام في الصف».", "page": 56, "id": "unit-05__lesson-02__b17", "inline": [{"t": "emphasis", "s": "صلاة الجماعة في المسجد:", "role": "emphasis"}, {"t": "text", "s": " ظاهر الأدلة أن الفضلَ لصلاة الجماعة لا يكون إلا في المسجد، فجماعة البيت خير من المنفرد ولكن ليست هي المقصودة بالأجر ولا يتحقق بها غرض الجماعة؛ لحديث الهم بالتحريق، ولقول ابن مسعود: "}, {"t": "quote", "s": "من سره أن يلقى الله غدا مسلما، فليحافظ على هؤلاء الصلوات حيث ينادى بهن؛ فإن الله شرع لنبيكم صلى الله عليه وسلم سنن الهدى، وإنهن من سنن الهدى، ولو أنكم صليتم في بيوتكم كما يصلي هذا المتخلف في بيته، لتركتم سنة نبيكم، ولو تركتم سنة نبيكم لضللتم... ولقد رأيتنا وما يتخلف عنها إلا منافق معلوم النفاق، ولقد كان الرجل يؤتى به يهادى بين الرجلين حتى يقام في الصف"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "عند مسلم زيادة لفظ: (لا يشهدون الصلاة) وفيها بيان أن هذه العقوبة على ذنب ظاهر، وهو تخلفهم عن صلاة المسجد، لا لأنهم منافقون، كما قيل؛ فالنبي صلى الله عليه وسلم لا يعاقب المنافقين على نفاقهم؛ لأنه أمر باطن، بل كان يكل سرائرهم إلى الله تعالى، ويعاملهم معاملة المسلمين في الظاهر.", "page": 56, "id": "unit-05__lesson-02__b18", "inline": [{"t": "text", "s": "عند مسلم زيادة لفظ: "}, {"t": "emphasis", "s": "(لا يشهدون الصلاة)", "role": "emphasis"}, {"t": "text", "s": " وفيها بيان أن هذه العقوبة على ذنب ظاهر، وهو تخلفهم عن صلاة المسجد، لا لأنهم منافقون، كما قيل؛ فالنبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لا يعاقب المنافقين على نفاقهم؛ لأنه أمر باطن، بل كان يكل سرائرهم إلى الله تعالى، ويعاملهم معاملة المسلمين في الظاهر."}]}, {"type": "paragraph", "md": "في الحديث دليل على جواز الحلف من غير استحلاف، وقد ذكر ابن القيم أن النبي صلى الله عليه وسلم حلف في أكثر من ثمانين موضعًا، وذكر أنه يجوز الحلف، بل يستحب على الخبر الديني الذي يريد تأكيده.", "page": 56, "id": "unit-05__lesson-02__b19", "inline": [{"t": "text", "s": "في الحديث دليل على جواز الحلف من غير استحلاف، وقد ذكر ابن القيم أن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " حلف في أكثر من ثمانين موضعًا، وذكر أنه يجوز الحلف، بل يستحب على الخبر الديني الذي يريد تأكيده."}]}, {"type": "paragraph", "md": "وفيه دليل على إثبات صفة اليد لله تعالى على ما يليق بجلاله وعظمته، إثباتًا حقيقيا بلا تكييف ولا تمثيل، وتنزيهًا بلا تحريف ولا تعطيل، كسائر أسمائه وصفاته سبحانه وتعالى .", "page": 56, "id": "unit-05__lesson-02__b20", "inline": [{"t": "text", "s": "وفيه دليل على إثبات صفة اليد لله تعالى على ما يليق بجلاله وعظمته، إثباتًا حقيقيا بلا تكييف ولا تمثيل، وتنزيهًا بلا تحريف ولا تعطيل، كسائر أسمائه وصفاته "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "وفيه دليل على جواز مباغتة الفساق في أماكن فسقهم؛ لقبضهم متلبسين بجريمتهم، وأن هذا أمر مناسب للقائم بالحسبة؛ لتقوم الحجة عليهم ويسقط عذرهم، ولا يبقى لهم شيء آخر يدرأ عنهم العقوبة.", "page": 56, "id": "unit-05__lesson-02__b21"}, {"type": "paragraph", "md": "وفيه دليل على أنَّ الإمام إذا عرض له شغل فإنه يستخلف من يصلي بالناس، وله أن يستصحب معه بعض الجماعة إذا كان هناك مصلحة، لقوله في رواية: (ثم أنطلق معي برجال معهم حزم من حطب)؛ فمصلحة متابعة المتخلفين مقدمة على الصلاة أولَ وقتها، وبهذا يستدل على أنه لا بأس بفعل المحتسبين إذا بقوا يوجهون الناس للصلاة ويتابعون المتخلفين ولو تأخروا عن الجماعة؛ لأن هذا مصلحة عامة.", "page": 57, "id": "unit-05__lesson-02__b22", "inline": [{"t": "text", "s": "وفيه دليل على أنَّ الإمام إذا عرض له شغل فإنه يستخلف من يصلي بالناس، وله أن يستصحب معه بعض الجماعة إذا كان هناك مصلحة، لقوله في رواية: "}, {"t": "emphasis", "s": "(ثم أنطلق معي برجال معهم حزم من حطب)", "role": "emphasis"}, {"t": "text", "s": "؛ فمصلحة متابعة المتخلفين مقدمة على الصلاة أولَ وقتها، وبهذا يستدل على أنه لا بأس بفعل المحتسبين إذا بقوا يوجهون الناس للصلاة ويتابعون المتخلفين ولو تأخروا عن الجماعة؛ لأن هذا مصلحة عامة."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 57, "id": "unit-05__lesson-02__b23", "role": "assessment"}, {"type": "paragraph", "md": "حدثنا عن الصحابي الجليل أبي هريرة الدوسي رضي الله عنه .", "page": 57, "id": "unit-05__lesson-02__b24", "inline": [{"t": "text", "s": "حدثنا عن الصحابي الجليل أبي هريرة الدوسي "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ."}], "item_role": "question"}, {"type": "paragraph", "md": "ما حكم ترك صلاة الجماعة من قبل بعض المحتسبين لأمر الناس بأدائها في وقتها؟", "page": 57, "id": "unit-05__lesson-02__b25", "item_role": "question"}, {"type": "paragraph", "md": "ما حكم صلاة الجماعة في ظل قلة المصلين في المساجد اليوم، خاصة من الشباب؟", "page": 57, "id": "unit-05__lesson-02__b26", "item_role": "question"}, {"type": "paragraph", "md": "هل يجوز الحلف على شيء من الخير -مثلا: أن تحلف ان من قاتل في سبيل الله حتى يُقتل دخل الجنة- من غير أن يَطلب أحدٌ منك الحلفَ عليه؟", "page": 57, "id": "unit-05__lesson-02__b27", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط مسجدي", "page": 57, "id": "unit-05__lesson-02__b28", "role": "activity"}, {"type": "image", "src": "assets/image38.jpeg", "caption": "جدول متابعة الصلاة (استمارة)", "page": 57, "id": "unit-05__lesson-02__b29"}, {"type": "paragraph", "md": "سنصلي الصوات الخمس في المسجد، وتنظيمًا للأمر سيتم توزيع جدول لمدة شهر يسجل فيه كل أخٍ الصلوات التي أداها في المسجد والأخرى التي تركها على أن يبقى هذا الجدول بينه وبين مربي الحلقة فقط", "page": 57, "id": "unit-05__lesson-02__b30", "item_role": "activity_step"}]' WHERE id='unit-05__lesson-02';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 58, "id": "unit-05__lesson-03__b01", "role": "objectives"}, {"type": "paragraph", "md": "الإيمان بأسماء الله تعالى الواردة في هذا الدرس، ومعرفة آثارها السلوكية والإيمانية على العبد.", "page": 58, "id": "unit-05__lesson-03__b02"}, {"type": "paragraph", "md": "التعرف على بعض الآثار التربوية التي تدلنا عليها أسماء الله تعالى الواردة في الدرس.", "page": 58, "id": "unit-05__lesson-03__b03"}, {"type": "heading", "level": 3, "text": "اسم الله سبحانه وتعالى «العليم»:", "page": 58, "id": "unit-05__lesson-03__b04", "role": "section"}, {"type": "paragraph", "md": "هو الذي أحاط علمه بالظواهر والبواطن، التي لا يدركها الخلق؛ قال تَعَالَى: ﴿إِنَّهُۥ عَلِيمُۢ بِذَاتِ ٱلصُّدُورِ﴾، وجاء على وزن فعيل للمبالغة في وصفه بكمال العلم، ولذلك قال سُبْحَانَهُ: ﴿وَفَوۡقَ كُلِّ ذِي عِلۡمٍ عَلِيمٞ﴾.", "page": 58, "id": "unit-05__lesson-03__b05", "inline": [{"t": "text", "s": "هو الذي أحاط علمه بالظواهر والبواطن، التي لا يدركها الخلق؛ قال تَعَالَى: "}, {"t": "ayah", "s": "إِنَّهُۥ عَلِيمُۢ بِذَاتِ ٱلصُّدُورِ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، وجاء على وزن فعيل للمبالغة في وصفه بكمال العلم، ولذلك قال سُبْحَانَهُ: "}, {"t": "ayah", "s": "وَفَوۡقَ كُلِّ ذِي عِلۡمٍ عَلِيمٞ", "ayah": [], "verses": [{"n": 76, "text": "وَفَوۡقَ كُلِّ ذِي عِلۡمٍ عَلِيمٞ", "surah": 12, "surah_name": "يوسف", "ref": "12:76", "ref_api": "https://api.quran.com/api/v4/verses/by_key/12:76"}], "surah": 12, "ref_api": "https://api.quran.com/api/v4/verses/by_key/12:76", "surah_name": "يوسف", "ayah_canonical": 76, "match": "contained", "ref": "12:76"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "الآثار الإيمانية والسلوكية للإيمان باسم «العليم»:", "page": 58, "id": "unit-05__lesson-03__b06", "inline": [{"t": "text", "s": "الآثار الإيمانية والسلوكية للإيمان باسم "}, {"t": "quote", "s": "العليم"}, {"t": "text", "s": ":"}]}, {"type": "paragraph", "md": "1- الأثر الأول: توحيد الله باسمه العليم؛ فاسم الله «العليم» يدعو العباد إلى توحيد الله سبحانه وتعالى بعلم الغيب؛ إذ لا يعلم الغيب إلا الله، قال تَعَالَى: ﴿۞وَعِندَهُۥ مَفَاتِحُ ٱلۡغَيۡبِ لَا يَعۡلَمُهَآ إِلَّا هُوَۚ﴾.", "page": 58, "id": "unit-05__lesson-03__b07", "inline": [{"t": "text", "s": "1- الأثر الأول: توحيد الله باسمه العليم؛ فاسم الله "}, {"t": "quote", "s": "العليم"}, {"t": "text", "s": " يدعو العباد إلى توحيد الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " بعلم الغيب؛ إذ لا يعلم الغيب إلا الله، قال تَعَالَى: "}, {"t": "ayah", "s": "۞وَعِندَهُۥ مَفَاتِحُ ٱلۡغَيۡبِ لَا يَعۡلَمُهَآ إِلَّا هُوَۚ", "ayah": [], "verses": [{"n": 59, "text": "۞وَعِندَهُۥ مَفَاتِحُ ٱلۡغَيۡبِ لَا يَعۡلَمُهَآ إِلَّا هُوَۚ", "surah": 6, "surah_name": "الأنعام", "ref": "6:59", "ref_api": "https://api.quran.com/api/v4/verses/by_key/6:59"}], "surah": 6, "ref_api": "https://api.quran.com/api/v4/verses/by_key/6:59", "surah_name": "الأنعام", "ayah_canonical": 59, "match": "contained", "ref": "6:59"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الأثر الثاني: تحريم إتيان من ادعى علم الغيب؛ فمن آمن باسم الله العليم؛ أيقن أن الكهان والعرافين والسحرة لا يعلمون شيئًا من الغيب، وأنهم كاذبون، يُخبرون بما تمليه عليهم الشياطين مما استرقوه من السمع؛ ولذلك جاء النهي عن سؤالهم والتغليظ في ذلك، يقول صلى الله عليه وسلم : (مَنْ أَتَى كَاهِنًا فَصَدَّقَهُ بِمَا يَقُولُ، فَقَدْ كَفَرَ بِمَا أُنْزِلَ عَلَى مُحَمَّدٍ) وقال صلى الله عليه وسلم : (مَنْ أَتَى عَرَّافًا فَصَدَّقَهُ بِمَا يَقُولُ، لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ يَوْمًا).", "page": 58, "id": "unit-05__lesson-03__b08", "inline": [{"t": "text", "s": "2- الأثر الثاني: تحريم إتيان من ادعى علم الغيب؛ فمن آمن باسم الله العليم؛ أيقن أن الكهان والعرافين والسحرة لا يعلمون شيئًا من الغيب، وأنهم كاذبون، يُخبرون بما تمليه عليهم الشياطين مما استرقوه من السمع؛ ولذلك جاء النهي عن سؤالهم والتغليظ في ذلك، يقول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(مَنْ أَتَى كَاهِنًا فَصَدَّقَهُ بِمَا يَقُولُ، فَقَدْ كَفَرَ بِمَا أُنْزِلَ عَلَى مُحَمَّدٍ)", "role": "emphasis"}, {"t": "text", "s": " وقال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(مَنْ أَتَى عَرَّافًا فَصَدَّقَهُ بِمَا يَقُولُ، لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ يَوْمًا)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- الأثر الثالث: الرضا بأقدار العليم العالم علام الغيوب: فيقين العبد باسم ربه العليم وعلمه السابق للأشياء قبل وقوعها، وكتابته لها في اللوح المحفوظ قبل خلقها؛ يجعل العبد يرضى بأقدار الله عليه، كما قال سُبْحَانَهُ: ﴿أَلَمۡ تَعۡلَمۡ أَنَّ ٱللَّهَ يَعۡلَمُ مَا فِي ٱلسَّمَآءِ وَٱلۡأَرۡضِۚ إِنَّ ذَٰلِكَ فِي كِتَٰبٍۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٞ﴾.", "page": 58, "id": "unit-05__lesson-03__b09", "inline": [{"t": "text", "s": "3- الأثر الثالث: الرضا بأقدار العليم العالم علام الغيوب: فيقين العبد باسم ربه العليم وعلمه السابق للأشياء قبل وقوعها، وكتابته لها في اللوح المحفوظ قبل خلقها؛ يجعل العبد يرضى بأقدار الله عليه، كما قال سُبْحَانَهُ: "}, {"t": "ayah", "s": "أَلَمۡ تَعۡلَمۡ أَنَّ ٱللَّهَ يَعۡلَمُ مَا فِي ٱلسَّمَآءِ وَٱلۡأَرۡضِۚ إِنَّ ذَٰلِكَ فِي كِتَٰبٍۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٞ", "ayah": [], "verses": [{"n": 70, "text": "أَلَمۡ تَعۡلَمۡ أَنَّ ٱللَّهَ يَعۡلَمُ مَا فِي ٱلسَّمَآءِ وَٱلۡأَرۡضِۚ إِنَّ ذَٰلِكَ فِي كِتَٰبٍۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٞ", "surah": 22, "surah_name": "الحج", "ref": "22:70", "ref_api": "https://api.quran.com/api/v4/verses/by_key/22:70"}], "surah": 22, "ref_api": "https://api.quran.com/api/v4/verses/by_key/22:70", "surah_name": "الحج", "ayah_canonical": 70, "match": "exact", "ref": "22:70"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "اسم الله «الرزّاق»:", "page": 58, "id": "unit-05__lesson-03__b10", "role": "section"}, {"type": "paragraph", "md": "هو المتكفل بالرزق، والقائم على كل نفس بما يقيمها من قوتها، وسع الخلق كلهم رزقه ورحمته، فلم يختص بذلك مؤمنًا دون كافر، ولا وليًّا دون عدو، يسوقه إلى الضعيف الذي لا حيلة له، كما يسوقه إلى الجلد القوي، قال سُبْحَانَهُ: ﴿وَكَأَيِّن مِّن دَآبَّةٖ لَّا تَحۡمِلُ رِزۡقَهَا ٱللَّهُ يَرۡزُقُهَا وَإِيَّاكُمۡۚ﴾، ورزق الله لعباده نوعان:", "page": 58, "id": "unit-05__lesson-03__b11", "inline": [{"t": "text", "s": "هو المتكفل بالرزق، والقائم على كل نفس بما يقيمها من قوتها، وسع الخلق كلهم رزقه ورحمته، فلم يختص بذلك مؤمنًا دون كافر، ولا وليًّا دون عدو، يسوقه إلى الضعيف الذي لا حيلة له، كما يسوقه إلى الجلد القوي، قال سُبْحَانَهُ: "}, {"t": "ayah", "s": "وَكَأَيِّن مِّن دَآبَّةٖ لَّا تَحۡمِلُ رِزۡقَهَا ٱللَّهُ يَرۡزُقُهَا وَإِيَّاكُمۡۚ", "ayah": [], "verses": [{"n": 60, "text": "وَكَأَيِّن مِّن دَآبَّةٖ لَّا تَحۡمِلُ رِزۡقَهَا ٱللَّهُ يَرۡزُقُهَا وَإِيَّاكُمۡۚ", "surah": 29, "surah_name": "العنكبوت", "ref": "29:60", "ref_api": "https://api.quran.com/api/v4/verses/by_key/29:60"}], "surah": 29, "ref_api": "https://api.quran.com/api/v4/verses/by_key/29:60", "surah_name": "العنكبوت", "ayah_canonical": 60, "match": "contained", "ref": "29:60"}, {"t": "text", "s": "، "}, {"t": "emphasis", "s": "ورزق الله لعباده نوعان:", "role": "emphasis"}]}, {"type": "paragraph", "md": "أ- رزق عام: يشمل البر والفاجر، والأولين والآخرين، وهو رزق الأبدان، ويعطيه الله لكل أحد.", "page": 58, "id": "unit-05__lesson-03__b12"}, {"type": "paragraph", "md": "ب- رزق خاص: وهو رزق القلوب بالعلم والإيمان، ويشملُ الرزقَ الحلال المعين على صلاح الدين.", "page": 59, "id": "unit-05__lesson-03__b13"}, {"type": "paragraph", "md": "الآثار الإيمانية والسلوكية للإيمان باسم «الرزاق»:", "page": 59, "id": "unit-05__lesson-03__b14", "inline": [{"t": "text", "s": "الآثار الإيمانية والسلوكية للإيمان باسم "}, {"t": "quote", "s": "الرزاق"}, {"t": "text", "s": ":"}]}, {"type": "paragraph", "md": "1- الأثر الأول: إثبات ما يتضمنه اسم الله «الرزاق» من صفات؛ فهو سبحانه وتعالى الرزاق الذي كثر رزقه، حتى وَسِعَ الخلائق كلها، كما قال سُبْحَانَهُ: ﴿۞وَمَا مِن دَآبَّةٖ فِي ٱلۡأَرۡضِ إِلَّا عَلَى ٱللَّهِ رِزۡقُهَا﴾، فخلق الخلق لعبادته وتكفل برزقهم: ﴿وَمَا خَلَقۡتُ ٱلۡجِنَّ وَٱلۡإِنسَ إِلَّا لِيَعۡبُدُونِ ۝٥٦ مَآ أُرِيدُ مِنۡهُم مِّن رِّزۡقٖ وَمَآ أُرِيدُ أَن يُطۡعِمُونِ ۝٥٧ إِنَّ ٱللَّهَ هُوَ ٱلرَّزَّاقُ ذُو ٱلۡقُوَّةِ ٱلۡمَتِينُ ۝٥٨﴾، ومن العبادة: العمل لتحصيل الرزق.", "page": 59, "id": "unit-05__lesson-03__b15", "inline": [{"t": "text", "s": "1- الأثر الأول: إثبات ما يتضمنه اسم الله "}, {"t": "quote", "s": "الرزاق"}, {"t": "text", "s": " من صفات؛ فهو "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " الرزاق الذي كثر رزقه، حتى وَسِعَ الخلائق كلها، كما قال سُبْحَانَهُ: "}, {"t": "ayah", "s": "۞وَمَا مِن دَآبَّةٖ فِي ٱلۡأَرۡضِ إِلَّا عَلَى ٱللَّهِ رِزۡقُهَا", "ayah": [], "verses": [{"n": 6, "text": "۞وَمَا مِن دَآبَّةٖ فِي ٱلۡأَرۡضِ إِلَّا عَلَى ٱللَّهِ رِزۡقُهَا", "surah": 11, "surah_name": "هود", "ref": "11:6", "ref_api": "https://api.quran.com/api/v4/verses/by_key/11:6"}], "surah": 11, "ref_api": "https://api.quran.com/api/v4/verses/by_key/11:6", "surah_name": "هود", "ayah_canonical": 6, "match": "contained", "ref": "11:6"}, {"t": "text", "s": "، فخلق الخلق لعبادته وتكفل برزقهم: "}, {"t": "ayah", "s": "وَمَا خَلَقۡتُ ٱلۡجِنَّ وَٱلۡإِنسَ إِلَّا لِيَعۡبُدُونِ ۝٥٦ مَآ أُرِيدُ مِنۡهُم مِّن رِّزۡقٖ وَمَآ أُرِيدُ أَن يُطۡعِمُونِ ۝٥٧ إِنَّ ٱللَّهَ هُوَ ٱلرَّزَّاقُ ذُو ٱلۡقُوَّةِ ٱلۡمَتِينُ ۝٥٨", "ayah": [56, 57, 58], "verses": [{"n": 56, "text": "وَمَا خَلَقۡتُ ٱلۡجِنَّ وَٱلۡإِنسَ إِلَّا لِيَعۡبُدُونِ", "surah": 51, "ref_api": "https://api.quran.com/api/v4/verses/by_key/51:56", "surah_name": "الذاريات", "ayah_canonical": 56, "match": "exact", "ref": "51:56"}, {"n": 57, "text": "مَآ أُرِيدُ مِنۡهُم مِّن رِّزۡقٖ وَمَآ أُرِيدُ أَن يُطۡعِمُونِ", "surah": 51, "ref_api": "https://api.quran.com/api/v4/verses/by_key/51:57", "surah_name": "الذاريات", "ayah_canonical": 57, "match": "exact", "ref": "51:57"}, {"n": 58, "text": "إِنَّ ٱللَّهَ هُوَ ٱلرَّزَّاقُ ذُو ٱلۡقُوَّةِ ٱلۡمَتِينُ", "surah": 51, "ref_api": "https://api.quran.com/api/v4/verses/by_key/51:58", "surah_name": "الذاريات", "ayah_canonical": 58, "match": "exact", "ref": "51:58"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، ومن العبادة: العمل لتحصيل الرزق."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الأثر الثاني: إدراك التفاوت في الأرزاق، وأنه تابع لعلم الله تعالى؛ فقد فاضل الله سبحانه وتعالى بين عباده في الرزق، فمنهم الغني ومنهم الفقير، ومنهم الموسع عليه ومنهم المقتر، ولله في ذلك حكم بالغة، قال تَعَالَى: ﴿وَٱللَّهُ فَضَّلَ بَعۡضَكُمۡ عَلَىٰ بَعۡضٖ فِي ٱلرِّزۡقِۚ﴾، وقال تَعَالَى: ﴿إِنَّ رَبَّكَ يَبۡسُطُ ٱلرِّزۡقَ لِمَن يَشَآءُ وَيَقۡدِرُۚ إِنَّهُۥ كَانَ بِعِبَادِهِۦ خَبِيرَۢا بَصِيرٗا ۝٣٠﴾، والخيرة فيما يختاره الله؛ فلعل فقيرًا لو اغتنى يضل، أو غنيا لو افتقر يهلك.", "page": 59, "id": "unit-05__lesson-03__b16", "inline": [{"t": "text", "s": "2- الأثر الثاني: إدراك التفاوت في الأرزاق، وأنه تابع لعلم الله تعالى؛ فقد فاضل الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " بين عباده في الرزق، فمنهم الغني ومنهم الفقير، ومنهم الموسع عليه ومنهم المقتر، ولله في ذلك حكم بالغة، قال تَعَالَى: "}, {"t": "ayah", "s": "وَٱللَّهُ فَضَّلَ بَعۡضَكُمۡ عَلَىٰ بَعۡضٖ فِي ٱلرِّزۡقِۚ", "ayah": [], "verses": [{"n": 71, "text": "وَٱللَّهُ فَضَّلَ بَعۡضَكُمۡ عَلَىٰ بَعۡضٖ فِي ٱلرِّزۡقِۚ", "surah": 16, "surah_name": "النحل", "ref": "16:71", "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:71"}], "surah": 16, "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:71", "surah_name": "النحل", "ayah_canonical": 71, "match": "contained", "ref": "16:71"}, {"t": "text", "s": "، وقال تَعَالَى: "}, {"t": "ayah", "s": "إِنَّ رَبَّكَ يَبۡسُطُ ٱلرِّزۡقَ لِمَن يَشَآءُ وَيَقۡدِرُۚ إِنَّهُۥ كَانَ بِعِبَادِهِۦ خَبِيرَۢا بَصِيرٗا ۝٣٠", "ayah": [30], "verses": [{"n": 30, "text": "إِنَّ رَبَّكَ يَبۡسُطُ ٱلرِّزۡقَ لِمَن يَشَآءُ وَيَقۡدِرُۚ إِنَّهُۥ كَانَ بِعِبَادِهِۦ خَبِيرَۢا بَصِيرٗا", "surah": 17, "ref_api": "https://api.quran.com/api/v4/verses/by_key/17:30", "surah_name": "الإسراء", "ayah_canonical": 30, "match": "exact", "ref": "17:30"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، والخيرة فيما يختاره الله؛ فلعل فقيرًا لو اغتنى يضل، أو غنيا لو افتقر يهلك."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- الأثر الثالث: التوكل على الرزاق في طلب الرزق؛ فاليقين بتفرد الرازق برزق العباد، وتكفله بأقواتهم، وتقديره لرزقهم قبل خلقهم، وأنه مقضي مكتوب؛ كل ذلك يثمر التوكل الصادق على الله سبحانه وتعالى في طلب الرزق، الذي يثمر بدوره الطمأنينة في القلب والسكينة وعدم الهلع والخوف على الرزق؛ لأن الله سبحانه وتعالى هو المتكفل بأرزاق عباده، ففي الصحيح: (لو أنكم تتوكلون على الله حق توكله لرزقكم كما يرزق الطير تغدو خماصًا وتروح بطانًا) أي تذهب جائعة في الصباح وترجع بما رزقها الله مساءً؛ فكيف عبيده سبحانه وتعالى ؟", "page": 59, "id": "unit-05__lesson-03__b17", "inline": [{"t": "text", "s": "3- الأثر الثالث: التوكل على الرزاق في طلب الرزق؛ فاليقين بتفرد الرازق برزق العباد، وتكفله بأقواتهم، وتقديره لرزقهم قبل خلقهم، وأنه مقضي مكتوب؛ كل ذلك يثمر التوكل الصادق على الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " في طلب الرزق، الذي يثمر بدوره الطمأنينة في القلب والسكينة وعدم الهلع والخوف على الرزق؛ لأن الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " هو المتكفل بأرزاق عباده، ففي الصحيح: "}, {"t": "emphasis", "s": "(لو أنكم تتوكلون على الله حق توكله لرزقكم كما يرزق الطير تغدو خماصًا وتروح بطانًا)", "role": "emphasis"}, {"t": "text", "s": " أي تذهب جائعة في الصباح وترجع بما رزقها الله مساءً؛ فكيف عبيده "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ؟"}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- الأثر الرابع: طلب الرزق الحلال، والحذر من الرزق الحرام؛ فاليقين بأن الله الرزاق قد تكفل للعباد بأرزاقهم؛ يدفع العبد إلى ترك الرزق الحرام، ولو كان كثيرًا موفورًا؛ لأنه يعلم أن الرزاق سيفتح له أبوابَ الرزق الحلال، وأنه لن يحصل من الرزق إلا ما قسم له، وأن ما عند الله لا ينال بمعصيته، قال صلى الله عليه وسلم : (نَفَثَ رُوحُ الْقُدُسِ فِي رَوْعِي أَنَّ نفْسًا لَنْ تَخْرُجَ مِنَ الدُّنْيَا حَتَّى تَسْتَكْمِلَ أَجَلَهَا، وَتَسْتَوْعِبَ رِزْقَهَا، فَأَجْمِلُوا فِي الطَّلَبِ، وَلَا يَحْمِلَنَّكُمِ اسْتِبْطَاءُ الرِّزْقِ أَنْ تَطْلُبُوهُ بِمَعْصِيَةِ اللهِ، فَإِنَّ اللهَ لَا يُنَالُ مَا عِنْدَهُ إِلَّا بِطَاعَتِهِ).", "page": 59, "id": "unit-05__lesson-03__b18", "inline": [{"t": "text", "s": "4- الأثر الرابع: طلب الرزق الحلال، والحذر من الرزق الحرام؛ فاليقين بأن الله الرزاق قد تكفل للعباد بأرزاقهم؛ يدفع العبد إلى ترك الرزق الحرام، ولو كان كثيرًا موفورًا؛ لأنه يعلم أن الرزاق سيفتح له أبوابَ الرزق الحلال، وأنه لن يحصل من الرزق إلا ما قسم له، وأن ما عند الله لا ينال بمعصيته، قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(نَفَثَ رُوحُ الْقُدُسِ فِي رَوْعِي أَنَّ نفْسًا لَنْ تَخْرُجَ مِنَ الدُّنْيَا حَتَّى تَسْتَكْمِلَ أَجَلَهَا، وَتَسْتَوْعِبَ رِزْقَهَا، فَأَجْمِلُوا فِي الطَّلَبِ، وَلَا يَحْمِلَنَّكُمِ اسْتِبْطَاءُ الرِّزْقِ أَنْ تَطْلُبُوهُ بِمَعْصِيَةِ اللهِ، فَإِنَّ اللهَ لَا يُنَالُ مَا عِنْدَهُ إِلَّا بِطَاعَتِهِ)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "اسم الله «العزيز»:", "page": 59, "id": "unit-05__lesson-03__b19", "role": "section"}, {"type": "paragraph", "md": "الذي له العزة كلها؛ عزة القوة، والغلبة الامتناع؛ فمُمْتَنَعٌ أن ينالَه أحد الخلق؛ فقد قهر جميع الموجودات، وخضعت الخليقة لعظمته؛ فمعاني العزة الثلاث كلها كاملة لله العظيم؛ قال تَعَالَى: ﴿فَلِلَّهِ ٱلۡعِزَّةُ جَمِيعًاۚ﴾.", "page": 59, "id": "unit-05__lesson-03__b20", "inline": [{"t": "text", "s": "الذي له العزة كلها؛ عزة القوة، والغلبة الامتناع؛ فمُمْتَنَعٌ أن ينالَه أحد الخلق؛ فقد قهر جميع الموجودات، وخضعت الخليقة لعظمته؛ فمعاني العزة الثلاث كلها كاملة لله العظيم؛ قال تَعَالَى: "}, {"t": "ayah", "s": "فَلِلَّهِ ٱلۡعِزَّةُ جَمِيعًاۚ", "ayah": [], "verses": [{"n": 10, "text": "فَلِلَّهِ ٱلۡعِزَّةُ جَمِيعًاۚ", "surah": 35, "surah_name": "فاطر", "ref": "35:10", "ref_api": "https://api.quran.com/api/v4/verses/by_key/35:10"}], "surah": 35, "ref_api": "https://api.quran.com/api/v4/verses/by_key/35:10", "surah_name": "فاطر", "ayah_canonical": 10, "match": "contained", "ref": "35:10"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "الآثار الإيمانية والسلوكية للإيمان باسم «العزيز»:", "page": 60, "id": "unit-05__lesson-03__b21", "inline": [{"t": "text", "s": "الآثار الإيمانية والسلوكية للإيمان باسم "}, {"t": "quote", "s": "العزيز"}, {"t": "text", "s": ":"}]}, {"type": "paragraph", "md": "1- الأثر الأول: الثقة بإعزاز العزيز سبحانه وتعالى لدينه؛ فإذا آمن العبد أن ربه العزيز الذي بيده العزة، يعز من يشاء ويذل من يشاء، وأنه لا يغلبه غالب ولا يقهره قاهر؛ فإنه يثق أن العزة والغلبة لدينه وأوليائه، قال سبحانه وتعالى : ﴿وَلِلَّهِ ٱلۡعِزَّةُ وَلِرَسُولِهِۦ وَلِلۡمُؤۡمِنِينَ﴾، فلا تضره قوة الباطل وظهوره فإنه زاهق لا محالة، كما قال تَعَالَى: ﴿بَلْ نَقْذِفُ بِالْحَقِّ عَلَى الْبَاطِلِ فَيَدْمَغُهُ فَإِذَا هُوَ زَاهِقٌ وَلَكُمُ الْوَيْلُ مِمَّا تَصِفُونَ﴾.", "page": 60, "id": "unit-05__lesson-03__b22", "inline": [{"t": "text", "s": "1- الأثر الأول: الثقة بإعزاز العزيز "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " لدينه؛ فإذا آمن العبد أن ربه العزيز الذي بيده العزة، يعز من يشاء ويذل من يشاء، وأنه لا يغلبه غالب ولا يقهره قاهر؛ فإنه يثق أن العزة والغلبة لدينه وأوليائه، قال "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "وَلِلَّهِ ٱلۡعِزَّةُ وَلِرَسُولِهِۦ وَلِلۡمُؤۡمِنِينَ", "ayah": [], "verses": [{"n": 8, "text": "وَلِلَّهِ ٱلۡعِزَّةُ وَلِرَسُولِهِۦ وَلِلۡمُؤۡمِنِينَ", "surah": 63, "surah_name": "المنافقون", "ref": "63:8", "ref_api": "https://api.quran.com/api/v4/verses/by_key/63:8"}], "surah": 63, "ref_api": "https://api.quran.com/api/v4/verses/by_key/63:8", "surah_name": "المنافقون", "ayah_canonical": 8, "match": "contained", "ref": "63:8"}, {"t": "text", "s": "، فلا تضره قوة الباطل وظهوره فإنه زاهق لا محالة، كما قال تَعَالَى: "}, {"t": "ayah", "s": "بَلْ نَقْذِفُ بِالْحَقِّ عَلَى الْبَاطِلِ فَيَدْمَغُهُ فَإِذَا هُوَ زَاهِقٌ وَلَكُمُ الْوَيْلُ مِمَّا تَصِفُونَ", "ayah": [], "verses": [{"n": 18, "text": "بَلْ نَقْذِفُ بِالْحَقِّ عَلَى الْبَاطِلِ فَيَدْمَغُهُ فَإِذَا هُوَ زَاهِقٌ وَلَكُمُ الْوَيْلُ مِمَّا تَصِفُونَ", "surah": 21, "surah_name": "الأنبياء", "ref": "21:18", "ref_api": "https://api.quran.com/api/v4/verses/by_key/21:18"}], "surah": 21, "ref_api": "https://api.quran.com/api/v4/verses/by_key/21:18", "surah_name": "الأنبياء", "ayah_canonical": 18, "match": "exact", "ref": "21:18"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الأثر الثاني: دعاء الله والاستعاذة بعزته؛ فالله العزيز الذي شرع لعباده سؤالَه بأسمائه الحسنى وصفاته العلا، هو القائل: ﴿وَلِلَّهِ ٱلۡأَسۡمَآءُ ٱلۡحُسۡنَىٰ فَٱدۡعُوهُ بِهَاۖ﴾، وقد كان من هديه صلى الله عليه وسلم سؤالُ الله بأسمائه وصفاته، ومن ذلك: عزته التي سأل الله بها وعلم أمته سؤال الله بها، فجاء في حديث ابن عباس رضي الله عنهما أن رسول الله صلى الله عليه وسلم ، كان يقول: (اللَّهُمَّ لَكَ أَسْلَمْتُ، وَبِكَ آمَنْتُ، وَعَلَيْكَ تَوَكَّلْتُ، وَإِلَيْكَ أَنَبْتُ، وَبِكَ خَاصَمْتُ، اللَّهُمَّ إِنِّي أَعُوذُ بِعِزَّتِكَ، لَا إِلَهَ إِلَّا أَنْتَ، أَنْ تُضِلَّنِي، أَنْتَ الحَيُّ الَّذِي لَا يَمُوتُ، والجِنُّ والإِنْسُ يَمُوتُونَ).", "page": 60, "id": "unit-05__lesson-03__b23", "inline": [{"t": "text", "s": "2- الأثر الثاني: دعاء الله والاستعاذة بعزته؛ فالله العزيز الذي شرع لعباده سؤالَه بأسمائه الحسنى وصفاته العلا، هو القائل: "}, {"t": "ayah", "s": "وَلِلَّهِ ٱلۡأَسۡمَآءُ ٱلۡحُسۡنَىٰ فَٱدۡعُوهُ بِهَاۖ", "ayah": [], "verses": [{"n": 180, "text": "وَلِلَّهِ ٱلۡأَسۡمَآءُ ٱلۡحُسۡنَىٰ فَٱدۡعُوهُ بِهَاۖ", "surah": 7, "surah_name": "الأعراف", "ref": "7:180", "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:180"}], "surah": 7, "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:180", "surah_name": "الأعراف", "ayah_canonical": 180, "match": "contained", "ref": "7:180"}, {"t": "text", "s": "، وقد كان من هديه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " سؤالُ الله بأسمائه وصفاته، ومن ذلك: عزته التي سأل الله بها وعلم أمته سؤال الله بها، فجاء في حديث ابن عباس "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " أن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، كان يقول: "}, {"t": "emphasis", "s": "(اللَّهُمَّ لَكَ أَسْلَمْتُ، وَبِكَ آمَنْتُ، وَعَلَيْكَ تَوَكَّلْتُ، وَإِلَيْكَ أَنَبْتُ، وَبِكَ خَاصَمْتُ، اللَّهُمَّ إِنِّي أَعُوذُ بِعِزَّتِكَ، لَا إِلَهَ إِلَّا أَنْتَ، أَنْ تُضِلَّنِي، أَنْتَ الحَيُّ الَّذِي لَا يَمُوتُ، والجِنُّ والإِنْسُ يَمُوتُونَ)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- الأثر الثالث: الاتصاف بالعزة بالدين: إذا علم العبد أن الله سُبْحَانَهُ العزيز الذي أعز دين الإسلام وأعز أهله فأرسل خير الرسل صلى الله عليه وسلم لبلاغه، وأنزل لبيانه كتابًا عزيزًا، ونصر أهله، ومكنهم حتى بلغوا مشارق الأرض ومغاربها، قال تَعَالَى: ﴿وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُواْ مِنكُمۡ وَعَمِلُواْ ٱلصَّٰلِحَٰتِ لَيَسۡتَخۡلِفَنَّهُمۡ فِي ٱلۡأَرۡضِ كَمَا ٱسۡتَخۡلَفَ ٱلَّذِينَ مِن قَبۡلِهِمۡ وَلَيُمَكِّنَنَّ لَهُمۡ دِينَهُمُ ٱلَّذِي ٱرۡتَضَىٰ لَهُمۡ﴾.", "page": 60, "id": "unit-05__lesson-03__b24", "inline": [{"t": "text", "s": "3- الأثر الثالث: الاتصاف بالعزة بالدين: إذا علم العبد أن الله سُبْحَانَهُ العزيز الذي أعز دين الإسلام وأعز أهله فأرسل خير الرسل "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لبلاغه، وأنزل لبيانه كتابًا عزيزًا، ونصر أهله، ومكنهم حتى بلغوا مشارق الأرض ومغاربها، قال تَعَالَى: "}, {"t": "ayah", "s": "وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُواْ مِنكُمۡ وَعَمِلُواْ ٱلصَّٰلِحَٰتِ لَيَسۡتَخۡلِفَنَّهُمۡ فِي ٱلۡأَرۡضِ كَمَا ٱسۡتَخۡلَفَ ٱلَّذِينَ مِن قَبۡلِهِمۡ وَلَيُمَكِّنَنَّ لَهُمۡ دِينَهُمُ ٱلَّذِي ٱرۡتَضَىٰ لَهُمۡ", "ayah": [], "verses": [{"n": 55, "text": "وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُواْ مِنكُمۡ وَعَمِلُواْ ٱلصَّٰلِحَٰتِ لَيَسۡتَخۡلِفَنَّهُمۡ فِي ٱلۡأَرۡضِ كَمَا ٱسۡتَخۡلَفَ ٱلَّذِينَ مِن قَبۡلِهِمۡ وَلَيُمَكِّنَنَّ لَهُمۡ دِينَهُمُ ٱلَّذِي ٱرۡتَضَىٰ لَهُمۡ", "surah": 24, "surah_name": "النور", "ref": "24:55", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:55"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:55", "surah_name": "النور", "ayah_canonical": 55, "match": "contained", "ref": "24:55"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة الإثرائية:", "page": 60, "id": "unit-05__lesson-03__b25", "role": "assessment"}, {"type": "paragraph", "md": "1- ما معنى أسماء الله سبحانه وتعالى : «العليم، العزيز».", "page": 60, "id": "unit-05__lesson-03__b26", "inline": [{"t": "text", "s": "1- ما معنى أسماء الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "العليم، العزيز"}, {"t": "text", "s": "."}], "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2-اذكر ثلاثة آثار إيمانية وسلوكية للإيمان باسم الله: «الرزاق، العزيز».", "page": 60, "id": "unit-05__lesson-03__b27", "inline": [{"t": "text", "s": "2-اذكر ثلاثة آثار إيمانية وسلوكية للإيمان باسم الله: "}, {"t": "quote", "s": "الرزاق، العزيز"}, {"t": "text", "s": "."}], "item_role": "question"}, {"type": "paragraph", "md": "3-مرَّ معك في الدرس أن الرزق نوعان، اذكرهما واشرحهما بأسلوبك الخاص.", "page": 60, "id": "unit-05__lesson-03__b28", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط حواري وسماعي", "page": 60, "id": "unit-05__lesson-03__b29", "role": "activity"}, {"type": "paragraph", "md": "1-اكتب صفحةً بالتعاون مع أصدقائك تبين فيها: كيف يعتز المؤمن بدينه، وكيف يكون عزيزًا على الكفار؟", "page": 60, "id": "unit-05__lesson-03__b30", "item_role": "activity_step"}, {"type": "paragraph", "md": "2-ابحث في السيرة النبوية عن موقف تظهر فيه عزة الإسلام، يمكنك الاستعانة بشيخك ليرشدك إلى المراجع.", "page": 60, "id": "unit-05__lesson-03__b31", "item_role": "activity_step"}, {"type": "paragraph", "md": "3- مرَّ معنا في الدروس الماضية عددًا من أسماء الله الحسنى، نرجع إلى محاضرات الشيخ «عمر محمود أبي قتادة» في شرحها، نستمع لها ونلخص أهم الفوائد الواردة فيها.", "page": 60, "id": "unit-05__lesson-03__b32", "inline": [{"t": "text", "s": "3- مرَّ معنا في الدروس الماضية عددًا من أسماء الله الحسنى، نرجع إلى محاضرات الشيخ "}, {"t": "quote", "s": "عمر محمود أبي قتادة"}, {"t": "text", "s": " في شرحها، نستمع لها ونلخص أهم الفوائد الواردة فيها."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "3"}}]' WHERE id='unit-05__lesson-03';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 61, "id": "unit-05__lesson-04__b01", "role": "objectives"}, {"type": "paragraph", "md": "معرفة معنى الاستنجاء لغة وشرعا، وبيان أحكامه وشروطه.", "page": 61, "id": "unit-05__lesson-04__b02"}, {"type": "paragraph", "md": "تعلم آداب الخلاء.", "page": 61, "id": "unit-05__lesson-04__b03"}, {"type": "heading", "level": 3, "text": "معنى الاستجمار والاستنجاء وأحكامه:", "page": 61, "id": "unit-05__lesson-04__b04", "role": "rulings"}, {"type": "paragraph", "md": "الاستجمار والاستطابة والاستنجاء كلها لمعنى واحد، وأصل ‌الاستجمار: مأخوذ من الجمار، وهي صغير الأحجار، جمع جمرة، ومنها سُميت المواضع التي ترمى جمرات لما بينهما من الملابسة.", "page": 61, "id": "unit-05__lesson-04__b05"}, {"type": "paragraph", "md": "والاستطابة: كناية عن الاستنجاء؛ من الطيب؛ لأنه يطيب جسده بإزالة ما عليه من الخبث؛ أي يُطهره.", "page": 61, "id": "unit-05__lesson-04__b06"}, {"type": "paragraph", "md": "وهو شرعًا لا يخرج عن المعنى اللغوي؛ فيُعرف بأنه: إزالة الخارج من السبِيلَيْن «القبل والدبر».", "page": 61, "id": "unit-05__lesson-04__b07", "inline": [{"t": "text", "s": "وهو شرعًا لا يخرج عن المعنى اللغوي؛ فيُعرف بأنه: إزالة الخارج من السبِيلَيْن "}, {"t": "quote", "s": "القبل والدبر"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "والاستجمار يكونُ بالماء وهو الأفضل، ويكونُ بالحجارة وما في معناها من قالعٍ للنجس كالورق والخِرَق والمحارم الناشفة -لا المعطرة-، ولو جمع بينهما فهو أفضل شيء حتى لا يمس النجس بيده.", "page": 61, "id": "unit-05__lesson-04__b08"}, {"type": "paragraph", "md": "والاستنجاء واجب، فديننا دين الطهارة والنظافة.", "page": 61, "id": "unit-05__lesson-04__b09"}, {"type": "paragraph", "md": "فإن استَجْمَرَ بالحجارة أو ما في معناها فَعَلَ ذلك ثلاثًا وجوبًا حتى وإنْ أُزِيلَتْ النَّجَاسةُ بأقل منها، وإلا زادَ.", "page": 61, "id": "unit-05__lesson-04__b10"}, {"type": "paragraph", "md": "وإن اقتصر على الحَجَر فَبَقيَ الأَثَرُ لم يَضرُّه ذلك.", "page": 61, "id": "unit-05__lesson-04__b11"}, {"type": "paragraph", "md": "والاستنجاء والاستجمار لا يجوز باليد اليُمنى.", "page": 61, "id": "unit-05__lesson-04__b12"}, {"type": "paragraph", "md": "ولا يجوز الاستجمار بمطعومٍ كالخبز، ولا بِعَظمٍ لأنَّه طعام الجن، ولا بالرَّوْثِ فهو عَلَفُ دوابّ الجنّ، وفي ذلك حديثٌ في صحيح مسلم عن حديث ابن مسعود أن النبي صلى الله عليه وسلم قال: (فلا تَسْتَنْجُوا بهِما فإنَّهُما طَعامُ إخْوانِكُمْ)، وفيه دليلٌ على منع الاستجمار بما يأكل الإنسان والدواب.", "page": 61, "id": "unit-05__lesson-04__b13", "inline": [{"t": "text", "s": "ولا يجوز الاستجمار بمطعومٍ كالخبز، ولا بِعَظمٍ لأنَّه طعام الجن، ولا بالرَّوْثِ فهو عَلَفُ دوابّ الجنّ، وفي ذلك حديثٌ في صحيح مسلم عن حديث ابن مسعود أن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قال: "}, {"t": "emphasis", "s": "(فلا تَسْتَنْجُوا بهِما فإنَّهُما طَعامُ إخْوانِكُمْ)", "role": "emphasis"}, {"t": "text", "s": "، وفيه دليلٌ على منع الاستجمار بما يأكل الإنسان والدواب."}]}, {"type": "heading", "level": 3, "text": "آداب قضاء الحاجة:", "page": 61, "id": "unit-05__lesson-04__b14", "role": "section"}, {"type": "paragraph", "md": "1- يُسْتَحَبُّ له أنْ يقول قبل الدخول: (اللهم إنِّي أعوذُ بِكَ مِنَ الخُبُثِ والخَبَائِثِ)، وإذا خرج قال: (غُفْرانَك)؛ فيستغفر حين يخرج لأنه ترك ذكر الله وقت قضاء حاجته.", "page": 61, "id": "unit-05__lesson-04__b15", "inline": [{"t": "text", "s": "1- يُسْتَحَبُّ له أنْ يقول قبل الدخول: "}, {"t": "emphasis", "s": "(اللهم إنِّي أعوذُ بِكَ مِنَ الخُبُثِ والخَبَائِثِ)", "role": "emphasis"}, {"t": "text", "s": "، وإذا خرج قال: "}, {"t": "emphasis", "s": "(غُفْرانَك)", "role": "emphasis"}, {"t": "text", "s": "؛ فيستغفر حين يخرج لأنه ترك ذكر الله وقت قضاء حاجته."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "وفي ذكر التسمية قبل دخول الخلاء خلافٌ، والأمر واسع فلا تثريب في قولها أو تركها والاكتفاء بالدعاء.", "page": 61, "id": "unit-05__lesson-04__b16"}, {"type": "paragraph", "md": "2- ويَدْخُلُ برجله اليسرى ويخرج باليمنى؛ لقاعدة الشرع في تقدمة اليمين لِمَا هو حَسَنٌ ومُكَرَّمٌ واليسار لِمَا يُسْتَقَذَرُ.. فهكذا في كل طيب يكون باليمين، وكل قذر باليسار، وما تساوى فلا بأس عليه في أيهما فعل وفعله باليمين أولى. ولا دليل على أن الأفضل الاعتماد على الرجل اليُسرى حال قضاء الحاجة.", "page": 62, "id": "unit-05__lesson-04__b17", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- وينبغي أن يدخل الخلاء بالحذاء؛ حتى لا تتنجس رجلاه إذا ما داخل حافيًا.", "page": 62, "id": "unit-05__lesson-04__b18", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- ويَبْعُدُ عن النَّاس إن كانَ في غير البيوت كالصحراء، ويَسْتُرُ عَوْرَتَهُ لئلا يطلع عليه أحد.", "page": 62, "id": "unit-05__lesson-04__b19", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- ولا يَسْتَدْبِرُ القبلة ولا يَسْتَقْبِلُهَا إنْ كان في غير البُنيان حالَ قضاء الحاجة، وأمّا حالَ الاستنجاء فلا بأس.", "page": 62, "id": "unit-05__lesson-04__b20", "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- ولا يقضي حاجَتَه في ظلِّ الناس وطريقِهم فإنه حرامٌ على الصحيح؛ لما فيه من أذى لهم.", "page": 62, "id": "unit-05__lesson-04__b21", "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "7- ويكره له أن يُطيل المكث في الخلاء بغير حاجة، فالاستعجال في قضاء الحاجة ثم الخروج: مستحب اتفاقًا، خلافًا لفعل بعضهم من فتح الهاتف في الحمام فهذا مكروه؛ لأنَّ أماكن النجس من مساكن الشيطان.", "page": 62, "id": "unit-05__lesson-04__b22", "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "8- ويستحب تغطية الرأس عند قضاء الحاجة؛ صح هذا عن أبي بكر رضي الله عنه .", "page": 62, "id": "unit-05__lesson-04__b23", "inline": [{"t": "text", "s": "8- ويستحب تغطية الرأس عند قضاء الحاجة؛ صح هذا عن أبي بكر "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ."}], "list": {"type": "ordered", "marker": "8"}}, {"type": "paragraph", "md": "9- ويستحب أن يغسل يده بالمنظفات بعد مسه النجاسة إكمالًا للطهارة، ويُستؤنس لهذا أنه صلى الله عليه وسلم كان يدلك يده بالأرض بعد أن يقضي حاجته، ثم يتوضأ بعد ذلك.", "page": 62, "id": "unit-05__lesson-04__b24", "inline": [{"t": "text", "s": "9- ويستحب أن يغسل يده بالمنظفات بعد مسه النجاسة إكمالًا للطهارة، ويُستؤنس لهذا أنه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " كان يدلك يده بالأرض بعد أن يقضي حاجته، ثم يتوضأ بعد ذلك."}], "list": {"type": "ordered", "marker": "9"}}, {"type": "paragraph", "md": "10- ويستحب له البول جالسًا إذا أمن مِن النظر، وإلا فيحرم، والبول قائمًا مباح ولو أصابه بعض الرذاذ؛ فهو معفو عنه، وإن أصابه شيء من النجاسة فلا يَبطل بها الوضوء، ولكن لا تصح صلاته إلا بتطهير ثوبه.", "page": 62, "id": "unit-05__lesson-04__b25", "list": {"type": "ordered", "marker": "10"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 62, "id": "unit-05__lesson-04__b26", "role": "assessment"}, {"type": "paragraph", "md": "عرف الاستنجاء والاستجمار، واذكر حكمه، وشروطه.", "page": 62, "id": "unit-05__lesson-04__b27", "item_role": "question"}, {"type": "paragraph", "md": "ما حكم غسل اليد بالمنظفات بعد الخروج من الخلاء وما دليل ذلك؟", "page": 62, "id": "unit-05__lesson-04__b28", "item_role": "question"}, {"type": "paragraph", "md": "عدد ثلاثا من آداب الخلاء وقضاء الحاجة.", "page": 62, "id": "unit-05__lesson-04__b29", "item_role": "question"}, {"type": "paragraph", "md": "ما حكم البول جالسًا، وقائمًا؟", "page": 62, "id": "unit-05__lesson-04__b30", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط خارج الحلقة", "page": 62, "id": "unit-05__lesson-04__b31", "role": "activity"}, {"type": "paragraph", "md": "1- عد إلى صحيح الإمام البخاري واستخرج منه حديث النهي عن استقبال القبلة واستدبارها حال قضاء الحاجة.. وانقله لإخوانك.", "page": 62, "id": "unit-05__lesson-04__b32", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما معنى الدعاء: (الخبُث والخبائث)؟ ارجع لكلام أهل العلم وانقل الأقوال في معناه..", "page": 62, "id": "unit-05__lesson-04__b33", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-05__lesson-04';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 63, "id": "unit-05__lesson-05__b01", "role": "objectives"}, {"type": "paragraph", "md": "أن يتعرف على معنى الصبر والمصابرة في طريق الدعوة والجهاد.", "page": 63, "id": "unit-05__lesson-05__b02"}, {"type": "paragraph", "md": "أن يتخلق عمليا بخلق الصبر ويسعى لأن يكون في زمرة الصابرين حتى يلقوا الله تعالى.", "page": 63, "id": "unit-05__lesson-05__b03"}, {"type": "heading", "level": 3, "text": "معنى الصبر وأنواعه:", "page": 63, "id": "unit-05__lesson-05__b04", "role": "section"}, {"type": "paragraph", "md": "الصبر ثبات القلب عند موارد الاضطراب، فهو خلق فاضل من أخلاق النفس يمتنع به الإنسان الصابر من فعل ما لا يحسن ولا يجمل شرعًا، والصبر والجزع ضدان؛ أحدهما بعكس الآخر.", "page": 63, "id": "unit-05__lesson-05__b05"}, {"type": "paragraph", "md": "والصبر قسمان: اضطراري، اختياري؛ فالصبر الاضطراري هو: الصبر على أقدار الله تعالى، ولا يعترض على القدر؛ فلا يبتلي الله عبدًا بمصيبة فيصبر عليها إلا وأعطاه أجرًا عظيمًا، قال النبي صلى الله عليه وسلم : (إن الله إذا أحب قومًا ابتلاهم، فمن رضي فله الرضا، ومن سخط فعليه السخط)، والأجر على الصبر لا على المصيبة؛ فليس كل من وقع في مصيبة يُؤجر إلا أن يصبر عليها، فحينها يتحصل له الأجر وإلا حُرم من ذلك.", "page": 63, "id": "unit-05__lesson-05__b06", "inline": [{"t": "text", "s": "والصبر قسمان: اضطراري، اختياري؛ فالصبر الاضطراري هو: الصبر على أقدار الله تعالى، ولا يعترض على القدر؛ فلا يبتلي الله عبدًا بمصيبة فيصبر عليها إلا وأعطاه أجرًا عظيمًا، قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إن الله إذا أحب قومًا ابتلاهم، فمن رضي فله الرضا، ومن سخط فعليه السخط)", "role": "emphasis"}, {"t": "text", "s": "، والأجر على الصبر لا على المصيبة؛ فليس كل من وقع في مصيبة يُؤجر إلا أن يصبر عليها، فحينها يتحصل له الأجر وإلا حُرم من ذلك."}]}, {"type": "paragraph", "md": "والصبر الاختياري: صبر عن معصية الله وعلى طاعته؛ كالصبر عن أكل الحرام، والصبر على الطاعة كإقامة الصلاة والزكاة؛ والصالح حقًّا من صبر عن المعاصي، وصبر على الطاعات، والذي يقيم الطاعات ويقع في الزلات أفضل من الذي يتركها ولا يفعل الطاعات، فالتقصير في الواجب شر من فعل المنهي عنه.", "page": 63, "id": "unit-05__lesson-05__b07"}, {"type": "paragraph", "md": "والمسلم الذي ارتضى لنفسه طريق التضحية لن يستمر في هذا الطريق ما لم يتحلَّ بالصبر، وأية فئة اختارت طريق الابتلاء فلن تدوم رابطتها وبنيتها ما لم تتواصَ بالصبر، والمؤمنون جميعًا مخاطبون بقول ربهم عز وجل : ﴿يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱصۡبِرُواْ وَصَابِرُواْ وَرَابِطُواْ وَٱتَّقُواْ ٱللَّهَ لَعَلَّكُمۡ تُفۡلِحُونَ ۝٢٠٠﴾.", "page": 63, "id": "unit-05__lesson-05__b08", "inline": [{"t": "text", "s": "والمسلم الذي ارتضى لنفسه طريق التضحية لن يستمر في هذا الطريق ما لم يتحلَّ بالصبر، وأية فئة اختارت طريق الابتلاء فلن تدوم رابطتها وبنيتها ما لم تتواصَ بالصبر، والمؤمنون جميعًا مخاطبون بقول ربهم "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱصۡبِرُواْ وَصَابِرُواْ وَرَابِطُواْ وَٱتَّقُواْ ٱللَّهَ لَعَلَّكُمۡ تُفۡلِحُونَ ۝٢٠٠", "ayah": [200], "verses": [{"n": 200, "text": "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُواْ ٱصۡبِرُواْ وَصَابِرُواْ وَرَابِطُواْ وَٱتَّقُواْ ٱللَّهَ لَعَلَّكُمۡ تُفۡلِحُونَ", "surah": 3, "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:200", "surah_name": "آل عمران", "ayah_canonical": 200, "match": "exact", "ref": "3:200"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 63, "id": "unit-05__lesson-05__b09", "role": "assessment"}, {"type": "paragraph", "md": "عرف معنى الصبر، واذكر أنواعه وأقسامه، وهل جربت قبل ذلك لذة الصبر على البلاء؟", "page": 63, "id": "unit-05__lesson-05__b10", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط تعبدي", "page": 63, "id": "unit-05__lesson-05__b11", "role": "activity"}, {"type": "paragraph", "md": "1- الصبر من أعظم مثبتات المؤمنين في النوازل والمصائب.. حدث عائلتك وإخوانك عن الصبر وعظيم فضله.", "page": 63, "id": "unit-05__lesson-05__b12", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ارجع إلى صحيح مسلم واستخرج منه قصة صبر أم سليم على فقد ولدها من أبي طلحة رضي الله عنهما .", "page": 63, "id": "unit-05__lesson-05__b13", "inline": [{"t": "text", "s": "2- ارجع إلى صحيح مسلم واستخرج منه قصة صبر أم سليم على فقد ولدها من أبي طلحة "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " ."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- اقرأ كتاب «الثمر المستطاب في سيرة القائد خطاب» ولخص منه قصة عن صبر مجاهدي الشيشان أثناء الحصار.", "page": 63, "id": "unit-05__lesson-05__b14", "inline": [{"t": "text", "s": "3- اقرأ كتاب "}, {"t": "quote", "s": "الثمر المستطاب في سيرة القائد خطاب"}, {"t": "text", "s": " ولخص منه قصة عن صبر مجاهدي الشيشان أثناء الحصار."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "3"}}]' WHERE id='unit-05__lesson-05';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: ﴿إِذَا جَآءَ نَصۡرُ ٱللَّهِ وَٱلۡفَتۡحُ ۝١ وَرَأَيۡتَ ٱلنَّاسَ يَدۡخُلُونَ فِي دِينِ ٱللَّهِ أَفۡوَاجٗا ۝٢ فَسَبِّحۡ بِحَمۡدِ رَبِّكَ وَٱسۡتَغۡفِرۡهُۚ إِنَّهُۥ كَانَ تَوَّابَۢا ۝٣﴾", "page": 64, "id": "unit-06__lesson-01__b01", "inline": [{"t": "text", "s": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: "}, {"t": "ayah", "s": "إِذَا جَآءَ نَصۡرُ ٱللَّهِ وَٱلۡفَتۡحُ ۝١ وَرَأَيۡتَ ٱلنَّاسَ يَدۡخُلُونَ فِي دِينِ ٱللَّهِ أَفۡوَاجٗا ۝٢ فَسَبِّحۡ بِحَمۡدِ رَبِّكَ وَٱسۡتَغۡفِرۡهُۚ إِنَّهُۥ كَانَ تَوَّابَۢا ۝٣", "ayah": [1, 2, 3], "verses": [{"n": 1, "text": "إِذَا جَآءَ نَصۡرُ ٱللَّهِ وَٱلۡفَتۡحُ", "surah": 110, "ref_api": "https://api.quran.com/api/v4/verses/by_key/110:1", "surah_name": "النصر", "ayah_canonical": 1, "match": "exact", "ref": "110:1"}, {"n": 2, "text": "وَرَأَيۡتَ ٱلنَّاسَ يَدۡخُلُونَ فِي دِينِ ٱللَّهِ أَفۡوَاجٗا", "surah": 110, "ref_api": "https://api.quran.com/api/v4/verses/by_key/110:2", "surah_name": "النصر", "ayah_canonical": 2, "match": "exact", "ref": "110:2"}, {"n": 3, "text": "فَسَبِّحۡ بِحَمۡدِ رَبِّكَ وَٱسۡتَغۡفِرۡهُۚ إِنَّهُۥ كَانَ تَوَّابَۢا", "surah": 110, "ref_api": "https://api.quran.com/api/v4/verses/by_key/110:3", "surah_name": "النصر", "ayah_canonical": 3, "match": "exact", "ref": "110:3"}], "surah": null, "ref_api": null}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 64, "id": "unit-06__lesson-01__b02", "role": "objectives"}, {"type": "paragraph", "md": "معرفة فضائل ومقاصد وموضوعات سورة النصر.", "page": 64, "id": "unit-06__lesson-01__b03"}, {"type": "paragraph", "md": "معرفة الألفاظ الغريبة والواردة في سورة النصر والمعنى الإجمالي للسورة.", "page": 64, "id": "unit-06__lesson-01__b04"}, {"type": "paragraph", "md": "معرفة الفوائد التربوية والعلمية لسورة النصر.", "page": 64, "id": "unit-06__lesson-01__b05"}, {"type": "paragraph", "md": "حفظ السورة بضبط وإتقان.", "page": 64, "id": "unit-06__lesson-01__b06"}, {"type": "paragraph", "md": "هذه السورة: آخر سورة نزلت كاملة، عن عبيد الله بن عبد الله بن عتبة، قال: «قال لي ابن عباس: تَعْلَم آخر سورة نزلت من القرآن نزلت جميعا؟ قلت: نعم، إذا جاء نصر الله والفتح، قال: صدقت».", "page": 64, "id": "unit-06__lesson-01__b07", "inline": [{"t": "text", "s": "هذه السورة: آخر سورة نزلت كاملة، عن عبيد الله بن عبد الله بن عتبة، قال: "}, {"t": "quote", "s": "قال لي ابن عباس: تَعْلَم آخر سورة نزلت من القرآن نزلت جميعا؟ قلت: نعم، إذا جاء نصر الله والفتح، قال: صدقت"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "مقصد السورة، وأهم الموضوعات التي اشتملت عليها:", "page": 64, "id": "unit-06__lesson-01__b08", "role": "main_themes"}, {"type": "paragraph", "md": "من أهم مقاصد هذه السورة: الإعلام بتمام الدين.", "page": 64, "id": "unit-06__lesson-01__b09", "inline": [{"t": "emphasis", "s": "من أهم مقاصد هذه السورة", "role": "emphasis"}, {"t": "text", "s": ": الإعلام بتمام الدين."}]}, {"type": "paragraph", "md": "ومن أهم الموضوعات التي اشتملت عليها هذه السورة:", "page": 64, "id": "unit-06__lesson-01__b10", "inline": [{"t": "emphasis", "s": "ومن أهم الموضوعات التي اشتملت عليها هذه السورة", "role": "emphasis"}, {"t": "text", "s": ":"}]}, {"type": "paragraph", "md": "1- وعد الله تعالى لنبيه صلى الله عليه وسلم بالنصر والفتح.", "page": 64, "id": "unit-06__lesson-01__b11", "inline": [{"t": "text", "s": "1- وعد الله تعالى لنبيه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بالنصر والفتح."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- البشارة بدخول خلائق كثيرة في الإسلام.", "page": 64, "id": "unit-06__lesson-01__b12", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- أمر الله سبحانه نبيه صلى الله عليه وسلم بالمواظبة على التسبيح بحمده واستغفاره.", "page": 64, "id": "unit-06__lesson-01__b13", "inline": [{"t": "text", "s": "3- أمر الله سبحانه نبيه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بالمواظبة على التسبيح بحمده واستغفاره."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "غريب الكلمات:", "page": 64, "id": "unit-06__lesson-01__b14", "role": "vocabulary"}, {"type": "paragraph", "md": "﴿أَفۡوَاجٗا﴾: أي: جماعات كثيرة، فوجا بعد فوج.", "page": 64, "id": "unit-06__lesson-01__b15", "inline": [{"t": "ayah", "s": "أَفۡوَاجٗا", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي: جماعات كثيرة، فوجا بعد فوج."}]}, {"type": "paragraph", "md": "﴿تَوَّابَۢا﴾: أي يُوَفِّقُ العبدَ للتوبة، ويقبلها منه، والتوبة: الرجوع إلى الله بالتزام فِعل ما يحب، وترك ما يكره.", "page": 64, "id": "unit-06__lesson-01__b16", "inline": [{"t": "ayah", "s": "تَوَّابَۢا", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي يُوَفِّقُ العبدَ للتوبة، ويقبلها منه، والتوبة: الرجوع إلى الله بالتزام فِعل ما يحب، وترك ما يكره."}]}, {"type": "heading", "level": 3, "text": "المعنى الإجمالي:", "page": 64, "id": "unit-06__lesson-01__b17", "role": "overall_meaning"}, {"type": "paragraph", "md": "افتتح الله تعالى هذه السورة الكريمة مخاطبا نبيه صلى الله عليه وسلم ، بقوله تعالى: إذا نصرك الله -يا محمد- على أعدائك، وتحقق لك فتح مكة، ورأيت العرب يدخلون في الإسلام بكثرة؛ فنزه ربك عن النقائص والعيوب تنزيها مقترنا بحمده، واطلب منه محو ذنوبك؛ فإن الله متصف أزلا وأبدا بالتوبة على عباده.", "page": 65, "id": "unit-06__lesson-01__b18", "inline": [{"t": "text", "s": "افتتح الله تعالى هذه السورة الكريمة مخاطبا نبيه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، بقوله تعالى: إذا نصرك الله -يا محمد- على أعدائك، وتحقق لك فتح مكة، ورأيت العرب يدخلون في الإسلام بكثرة؛ فنزه ربك عن النقائص والعيوب تنزيها مقترنا بحمده، واطلب منه محو ذنوبك؛ فإن الله متصف أزلا وأبدا بالتوبة على عباده."}]}, {"type": "heading", "level": 3, "text": "الفوائد التربوية:", "page": 65, "id": "unit-06__lesson-01__b19", "role": "benefits"}, {"type": "paragraph", "md": "1- قوله تعالى: ﴿فَسَبِّحۡ بِحَمۡدِ رَبِّكَ وَٱسۡتَغۡفِرۡهُۚ إِنَّهُۥ كَانَ تَوَّابَۢا ۝٣﴾ فيه دليلٌ على أنَّ الأمور الفاضلة تختم بالاستغفار، كالصلاة والحج، وغير ذلك؛ فَأَمْرُ الله لرسوله صلى الله عليه وسلم بالحمد والاستغفار في هذه الحال إشارة إلى أن أجله قد اقترب؛ فليستعد ويتهيأ للقاء ربه، ويختم عمره بأفضل ما يجده صلوات الله وسلامه عليه، فالواجب على المسلم أن يحرص -في آخر عمره أو عند خوفه من القتل كواقعنا الحالي- أن يُكثر من طاعة الله، ولا سيما ما أوجبه الله عليه، وأن يكثر من الاستغفار والحمد.", "page": 65, "id": "unit-06__lesson-01__b20", "inline": [{"t": "text", "s": "1- قوله تعالى: "}, {"t": "ayah", "s": "فَسَبِّحۡ بِحَمۡدِ رَبِّكَ وَٱسۡتَغۡفِرۡهُۚ إِنَّهُۥ كَانَ تَوَّابَۢا ۝٣", "ayah": [3], "verses": [{"n": 3, "text": "فَسَبِّحۡ بِحَمۡدِ رَبِّكَ وَٱسۡتَغۡفِرۡهُۚ إِنَّهُۥ كَانَ تَوَّابَۢا", "surah": 110, "ref_api": "https://api.quran.com/api/v4/verses/by_key/110:3", "surah_name": "النصر", "ayah_canonical": 3, "match": "exact", "ref": "110:3"}], "surah": null, "ref_api": null}, {"t": "text", "s": " فيه دليلٌ على أنَّ الأمور الفاضلة تختم بالاستغفار، كالصلاة والحج، وغير ذلك؛ فَأَمْرُ الله لرسوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بالحمد والاستغفار في هذه الحال إشارة إلى أن أجله قد اقترب؛ فليستعد ويتهيأ للقاء ربه، ويختم عمره بأفضل ما يجده صلوات الله وسلامه عليه، فالواجب على المسلم أن يحرص -في آخر عمره أو عند خوفه من القتل كواقعنا الحالي- أن يُكثر من طاعة الله، ولا سيما ما أوجبه الله عليه، وأن يكثر من الاستغفار والحمد."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- في قوله تعالى: ﴿إِنَّهُۥ كَانَ تَوَّابَۢا ۝٣﴾ إشارة إلى أنه سبحانه يقبل توبة المستغفرين المنيبين إليه؛ فهو ترغيب في الاستغفار، وحث على التوبة، حتى من الصالحين؛ فالتوبة والاستغفار ترفع درجة العباد.", "page": 65, "id": "unit-06__lesson-01__b21", "inline": [{"t": "text", "s": "2- في قوله تعالى: "}, {"t": "ayah", "s": "إِنَّهُۥ كَانَ تَوَّابَۢا ۝٣", "ayah": [3], "verses": [{"n": 3, "text": "إِنَّهُۥ كَانَ تَوَّابَۢا", "surah": 110, "ref_api": "https://api.quran.com/api/v4/verses/by_key/110:3", "surah_name": "النصر", "ayah_canonical": 3, "match": "contained", "ref": "110:3"}], "surah": null, "ref_api": null}, {"t": "text", "s": " إشارة إلى أنه سبحانه يقبل توبة المستغفرين المنيبين إليه؛ فهو ترغيب في الاستغفار، وحث على التوبة، حتى من الصالحين؛ فالتوبة والاستغفار ترفع درجة العباد."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "الفوائد العلمية واللطائف:", "page": 65, "id": "unit-06__lesson-01__b22", "role": "benefits"}, {"type": "paragraph", "md": "قول الله تعالى: ﴿فَسَبِّحۡ بِحَمۡدِ رَبِّكَ﴾ يدل على فضل التسبيح والتحميد؛ حيث جعله الله تعالى كافيا في أداء ما وجب على نبيه صلى الله عليه وسلم والأمة من بعدِه؛ في شكرِ نعمة النصر والفتح.", "page": 65, "id": "unit-06__lesson-01__b23", "inline": [{"t": "text", "s": "قول الله تعالى: "}, {"t": "ayah", "s": "فَسَبِّحۡ بِحَمۡدِ رَبِّكَ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": " يدل على فضل التسبيح والتحميد؛ حيث جعله الله تعالى كافيا في أداء ما وجب على نبيه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " والأمة من بعدِه؛ في شكرِ نعمة النصر والفتح."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 65, "id": "unit-06__lesson-01__b24", "role": "assessment"}, {"type": "paragraph", "md": "1- ما موضوع سورة النصر.", "page": 65, "id": "unit-06__lesson-01__b25", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما المقصود بالفتح والنصر المذكور في الآيات الكريمة.", "page": 65, "id": "unit-06__lesson-01__b26", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- اذكر فائدة تربوية وأخرى علمية تعلمتها من سورة النصر.", "page": 65, "id": "unit-06__lesson-01__b27", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4-على ماذا يجب أن يحرص المسلم في آخر عمره وفي خواتيم أعماله.", "page": 65, "id": "unit-06__lesson-01__b28", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط خارج المجلس", "page": 65, "id": "unit-06__lesson-01__b29", "role": "activity"}, {"type": "paragraph", "md": "ابحث في السنة النبوية المطهرة عن حديث يبين كيف كان النبي صلى الله عليه وسلم يسبح ويستغفر ربه.", "page": 65, "id": "unit-06__lesson-01__b30", "inline": [{"t": "text", "s": "ابحث في السنة النبوية المطهرة عن حديث يبين كيف كان النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يسبح ويستغفر ربه."}], "item_role": "activity_step"}, {"type": "paragraph", "md": "اقرأ تفسير سورة النصر من المختصر في التفسير أو تفسير السعدي واكتب أهم الفوائد التي أعجبتك.", "page": 65, "id": "unit-06__lesson-01__b31", "item_role": "activity_step"}, {"type": "paragraph", "md": "اسأل أهل العلم عن سورة النصر وكيف أنها كانت تخبر النبي صلى الله عليه وسلم بدنو أجله بالرغم انها لم تذكر ذلك بشكل صريح في السورة.. كيف فهم ابن عباس رضي الله عنه من السورة ذلك؟", "page": 65, "id": "unit-06__lesson-01__b32", "inline": [{"t": "text", "s": "اسأل أهل العلم عن سورة النصر وكيف أنها كانت تخبر النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بدنو أجله بالرغم انها لم تذكر ذلك بشكل صريح في السورة.. كيف فهم ابن عباس "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " من السورة ذلك؟"}], "item_role": "activity_step"}]' WHERE id='unit-06__lesson-01';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "عن عبد الله بن مسعود رضي الله عنه قال: قال لنا النبي صلى الله عليه وسلم : (يَا مَعْشَرَ الشَّبَابِ، مَنِ اسْتَطَاعَ مِنْكُمُ الْبَاءَةَ فَلْيَتَزَوَّجْ، وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ؛ ‌فَإِنَّهُ ‌لَهُ ‌وِجَاءٌ).", "page": 66, "id": "unit-06__lesson-02__b01", "inline": [{"t": "text", "s": "عن عبد الله بن مسعود "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: قال لنا النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : (يَا مَعْشَرَ الشَّبَابِ، مَنِ اسْتَطَاعَ مِنْكُمُ الْبَاءَةَ فَلْيَتَزَوَّجْ، وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ؛ ‌فَإِنَّهُ ‌لَهُ ‌وِجَاءٌ)."}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 66, "id": "unit-06__lesson-02__b02", "role": "objectives"}, {"type": "paragraph", "md": "حث الشباب المسلم المستطيع على الزواج الذي يُعف نفسَه ويكفيه شهوته.", "page": 66, "id": "unit-06__lesson-02__b03"}, {"type": "paragraph", "md": "بيان سنة الزواج في هذه الأمة، وأن المقصد منها طاعة الله وتكثير النسل.", "page": 66, "id": "unit-06__lesson-02__b04"}, {"type": "paragraph", "md": "علاج الشهوات عند الشباب يكون بالصيام والتقوى وليس باتباع الشيطان والنظر للمحرمات.", "page": 66, "id": "unit-06__lesson-02__b05"}, {"type": "heading", "level": 3, "text": "التعريف براوي الحديث:", "page": 66, "id": "unit-06__lesson-02__b06", "role": "definitions"}, {"type": "paragraph", "md": "عبد الله بن مسعود: الإمام الحبر، فقيه الأمة، المقرئ، أبو عبد الرحمن الهذلي، المكي، المهاجري، البدري، من السابقين للإسلام، روى علما كثيرا..", "page": 66, "id": "unit-06__lesson-02__b07", "inline": [{"t": "emphasis", "s": "عبد الله بن مسعود", "role": "lemma"}, {"t": "text", "s": ": الإمام الحبر، فقيه الأمة، المقرئ، أبو عبد الرحمن الهذلي، المكي، المهاجري، البدري، من السابقين للإسلام، روى علما كثيرا.."}]}, {"type": "heading", "level": 3, "text": "شرح الحديث:", "page": 66, "id": "unit-06__lesson-02__b08", "role": "hadith_explanation"}, {"type": "paragraph", "md": "قوله (المعشر) هم الطائفة الذين يشملهم وصف؛ فالشباب معشر، والشيوخ معشر.. الخ، و(الشباب) جمع شاب، وأصله الحركة والنشاط؛ لأن الإنسان أول عمره أكثر نشاطًا منه في آخره، وهو يجمع على شباب وشُبان وشَبَبَة، ويطلق على من بلغ إلى أن يكمل ثلاثين سنة. ووجه الخطاب للشباب؛ لأنَّهم مظنة ثوران الشهوة الداعية إلى الجماع، ولما فيهم من قوة داعية للزواج أكثر من غيرهم.", "page": 66, "id": "unit-06__lesson-02__b09", "inline": [{"t": "text", "s": "قوله "}, {"t": "emphasis", "s": "(المعشر)", "role": "lemma"}, {"t": "text", "s": " هم الطائفة الذين يشملهم وصف؛ فالشباب معشر، والشيوخ معشر.. الخ، و"}, {"t": "emphasis", "s": "(الشباب)", "role": "lemma"}, {"t": "text", "s": " جمع شاب، وأصله الحركة والنشاط؛ لأن الإنسان أول عمره أكثر نشاطًا منه في آخره، وهو يجمع على شباب وشُبان وشَبَبَة، ويطلق على من بلغ إلى أن يكمل ثلاثين سنة. ووجه الخطاب للشباب؛ لأنَّهم مظنة ثوران الشهوة الداعية إلى الجماع، ولما فيهم من قوة داعية للزواج أكثر من غيرهم."}]}, {"type": "paragraph", "md": "(البَاءَة) هي: مؤن النكاح من المهر والنفقة، وأصله البيت؛ لأن من تزوج امرأة بوأها بيتا، ويُستعمل بمعنى الزواج لأن أصل البِواء اللزوم، فمن كان عنده قدرة على النكاح فليسارع إليه؛ وما يُشاهَد اليوم من تأخر بعض الشباب في الزواج بحجة الدراسة والعمل غير صحيح، وكذلك المرأة إذا جاءها الكفء فأخرت؛ فالزواج من أهم أسباب النجاح لأنه يصرف الشاب عن التفكير بشهوته ويحصنه ويعفه ويعينه على غض البصر، وكذا المرأة يُخشى عليها إن تأخرت أن يذهب عنها الكفء ويأتيها من لا ترغب فيه حين تتأخر في النكاح فتتزوجه مرغمة لا مختارة، حتى يؤويها بيتٌ يضمها.", "page": 66, "id": "unit-06__lesson-02__b10", "inline": [{"t": "emphasis", "s": "(البَاءَة)", "role": "lemma"}, {"t": "text", "s": " هي: مؤن النكاح من المهر والنفقة، وأصله البيت؛ لأن من تزوج امرأة بوأها بيتا، ويُستعمل بمعنى الزواج لأن أصل البِواء اللزوم، فمن كان عنده قدرة على النكاح فليسارع إليه؛ وما يُشاهَد اليوم من تأخر بعض الشباب في الزواج بحجة الدراسة والعمل غير صحيح، وكذلك المرأة إذا جاءها الكفء فأخرت؛ فالزواج من أهم أسباب النجاح لأنه يصرف الشاب عن التفكير بشهوته ويحصنه ويعفه ويعينه على غض البصر، وكذا المرأة يُخشى عليها إن تأخرت أن يذهب عنها الكفء ويأتيها من لا ترغب فيه حين تتأخر في النكاح فتتزوجه مرغمة لا مختارة، حتى يؤويها بيتٌ يضمها."}]}, {"type": "paragraph", "md": "من فوائد الزواج في الحديث: غض البصر عن النساء من الرجل، وعن الرجال من المرأة؛ لأنه قد حصل الاستغناء والإعفاف، فكل من الزوجين قد عف الآخر، مما يؤدي لغض البصر عن الحرام.", "page": 66, "id": "unit-06__lesson-02__b11"}, {"type": "paragraph", "md": "ومن فوائده أنه: أحصن للفرج؛ لأن الزواج فيه قضاء الشهوة في وجه مشروع، فيكتفي بذلك الزوجان.", "page": 67, "id": "unit-06__lesson-02__b12"}, {"type": "paragraph", "md": "ومن لم يقدر على النكاح لعجز مالي ونحوه؛ فليلزم الصوم لكسر شهوته، فإن الصوم (وِجَاء) أي بمثابة الخِصاء يخفف الشهوة؛ والوجاء: رضُّ الخصيتين بحجر ونحوه مع بقائهما؛ لتضعف الفحولة، والعلاقة بين الوِجاء والصوم: المشابهة في أن كلًّا منهما يضعف الشهوة ويدفع شر المني؛ لأن البيضتين تصلحان المني، فتهيج الشهوة، والصوم مضعف لشهوة الجماع بسبب قلة الطعام والشراب، وفي هذا سر عظيم، فإن تقليل الطعام والشراب بلا صوم لا يفيد.", "page": 67, "id": "unit-06__lesson-02__b13", "inline": [{"t": "text", "s": "ومن لم يقدر على النكاح لعجز مالي ونحوه؛ فليلزم الصوم لكسر شهوته، فإن الصوم "}, {"t": "emphasis", "s": "(وِجَاء)", "role": "lemma"}, {"t": "text", "s": " أي بمثابة الخِصاء يخفف الشهوة؛ والوجاء: رضُّ الخصيتين بحجر ونحوه مع بقائهما؛ لتضعف الفحولة، والعلاقة بين الوِجاء والصوم: المشابهة في أن كلًّا منهما يضعف الشهوة ويدفع شر المني؛ لأن البيضتين تصلحان المني، فتهيج الشهوة، والصوم مضعف لشهوة الجماع بسبب قلة الطعام والشراب، وفي هذا سر عظيم، فإن تقليل الطعام والشراب بلا صوم لا يفيد."}]}, {"type": "heading", "level": 3, "text": "فوائد ومسائل في الحديث النبوي الشريف:", "page": 67, "id": "unit-06__lesson-02__b14", "role": "benefits"}, {"type": "paragraph", "md": "حكم الزواج: في الأصل هو سنة مؤكدة، لتكثير النسل، وإعفاف النفس، وبناء المجتمع المسلم؛ لكنه واجبٌ على من خشي الزنا إن لم يتزوج، ومكروهٌ أو حرام لمن خشي ألا يؤدي حق المرأة أو يظلمها، قال الإمام أحمد: «ليست العزوبة من أمر الإسلام في شيء»، وقال النبي صلى الله عليه وسلم : (وأما أنا فأتزوج النساء).", "page": 67, "id": "unit-06__lesson-02__b15", "inline": [{"t": "emphasis", "s": "حكم الزواج", "role": "emphasis"}, {"t": "text", "s": ": في الأصل هو سنة مؤكدة، لتكثير النسل، وإعفاف النفس، وبناء المجتمع المسلم؛ لكنه واجبٌ على من خشي الزنا إن لم يتزوج، ومكروهٌ أو حرام لمن خشي ألا يؤدي حق المرأة أو يظلمها، قال الإمام أحمد: "}, {"t": "quote", "s": "ليست العزوبة من أمر الإسلام في شيء", "speaker": "الإمام أحمد"}, {"t": "text", "s": "، وقال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(وأما أنا فأتزوج النساء)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "يبين الحديث أمرًا من أعظم حكم النكاح، وهي حفظ كل من الزوجين عن الوقوع في المحظور.", "page": 67, "id": "unit-06__lesson-02__b16"}, {"type": "paragraph", "md": "في الحديث دليل على أن الإنسان لا يتكلف للزواج بغير الممكن كالاستدانة؛ لأنه صلى الله عليه وسلم أرشد إلى الصيام، قال الله تعالى: ﴿وَلۡيَسۡتَعۡفِفِ ٱلَّذِينَ لَا يَجِدُونَ نِكَاحًا حَتَّىٰ يُغۡنِيَهُمُ ٱللَّهُ مِن فَضۡلِهِۦۗ﴾؛ فظاهر الآية أنه لا ينبغي للفقير أن يستقرض للزواج، بل يتعفف، حتى يغنيه الله، والتعفف يكون بغض البصر وحفظ الفروج.", "page": 67, "id": "unit-06__lesson-02__b17", "inline": [{"t": "text", "s": "في الحديث دليل على أن الإنسان لا يتكلف للزواج بغير الممكن كالاستدانة؛ لأنه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أرشد إلى الصيام، قال الله تعالى: "}, {"t": "ayah", "s": "وَلۡيَسۡتَعۡفِفِ ٱلَّذِينَ لَا يَجِدُونَ نِكَاحًا حَتَّىٰ يُغۡنِيَهُمُ ٱللَّهُ مِن فَضۡلِهِۦۗ", "ayah": [], "verses": [{"n": 33, "text": "وَلۡيَسۡتَعۡفِفِ ٱلَّذِينَ لَا يَجِدُونَ نِكَاحًا حَتَّىٰ يُغۡنِيَهُمُ ٱللَّهُ مِن فَضۡلِهِۦۗ", "surah": 24, "surah_name": "النور", "ref": "24:33", "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:33"}], "surah": 24, "ref_api": "https://api.quran.com/api/v4/verses/by_key/24:33", "surah_name": "النور", "ayah_canonical": 33, "match": "contained", "ref": "24:33"}, {"t": "text", "s": "؛ فظاهر الآية أنه لا ينبغي للفقير أن يستقرض للزواج، بل يتعفف، حتى يغنيه الله، والتعفف يكون بغض البصر وحفظ الفروج."}]}, {"type": "paragraph", "md": "يجوز التعالج بالأدوية لتخفيف الشهوة لمن لا يقدر على الزواج، ولكن لا يجوز الخصاء بالكلية.", "page": 67, "id": "unit-06__lesson-02__b18"}, {"type": "paragraph", "md": "في هذا الحديث دليل على تحريم الاستمناء «العادة السرية»؛ فلة كان لو كان مباحًا لأرشد إليه النبي صلى الله عليه وسلم ؛ لأنه أسهل وفيه لذة، وذلك لضرره العظيم؛ فهو يضعف البصر، وينهك البدن، ويُجهد الأعصاب، ويضعف عضو التناسل، ويجعل فاعله سريع الإنزال.. وكل هذا من أدلة حرمته.", "page": 67, "id": "unit-06__lesson-02__b19", "inline": [{"t": "text", "s": "في هذا الحديث دليل على تحريم الاستمناء "}, {"t": "quote", "s": "العادة السرية"}, {"t": "text", "s": "؛ فلة كان لو كان مباحًا لأرشد إليه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ؛ لأنه أسهل وفيه لذة، وذلك لضرره العظيم؛ فهو يضعف البصر، وينهك البدن، ويُجهد الأعصاب، ويضعف عضو التناسل، ويجعل فاعله سريع الإنزال.. وكل هذا من أدلة حرمته."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 67, "id": "unit-06__lesson-02__b20", "role": "assessment"}, {"type": "paragraph", "md": "بين حكم الاستمناء، وما الدليل على ذلك؟ 2- ما حكم الزواج من حيثُ الأصل الشرعي؟", "page": 67, "id": "unit-06__lesson-02__b21", "item_role": "question"}, {"type": "paragraph", "md": "ما معنى الكلمات الآتية: (الباءة - معشر - وِجاء). 4- ما علاج من لم يقدر على النكاح؟", "page": 67, "id": "unit-06__lesson-02__b22", "inline": [{"t": "text", "s": "ما معنى الكلمات الآتية: "}, {"t": "emphasis", "s": "(الباءة - معشر - وِجاء)", "role": "emphasis"}, {"t": "text", "s": ". 4- ما علاج من لم يقدر على النكاح؟"}], "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط شبابي حواري", "page": 67, "id": "unit-06__lesson-02__b23", "role": "activity"}, {"type": "paragraph", "md": "هل يتعارض الزواج مع العلم أو الجهاد؟ ناقش ذلك ولخصه في ورقة تسجلها..", "page": 67, "id": "unit-06__lesson-02__b24", "item_role": "activity_step"}]' WHERE id='unit-06__lesson-02';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 68, "id": "unit-06__lesson-03__b01", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على معذيات العبودية الخمسة.", "page": 68, "id": "unit-06__lesson-03__b02"}, {"type": "paragraph", "md": "معرفة فضل التوحيد وأثره في سلوك طريق الحياة المستقيم الذي يُحبه الله عز وجل .", "page": 68, "id": "unit-06__lesson-03__b03", "inline": [{"t": "text", "s": "معرفة فضل التوحيد وأثره في سلوك طريق الحياة المستقيم الذي يُحبه الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ."}]}, {"type": "heading", "level": 3, "text": "الحرية الحقيقية في عبودية الله:", "page": 68, "id": "unit-06__lesson-03__b04", "role": "section"}, {"type": "paragraph", "md": "يبحث الكافرون عن مزيد من الحرية، وإذا تعبّد أحدهم لله فعلى غير طريق العبودية الحق لله، ويبحث المسلم عن مزيد من العبودية لله، ويحاول أن يتحرّر من كل ما يستعبده سوى الله، سواء في ذلك العبودية للجاه أو للمظهر أو للمجتمع أو لغرض من أغراض الدنيا، وذلك مقتضى قوله: «لا إله إلا الله».", "page": 68, "id": "unit-06__lesson-03__b05", "inline": [{"t": "text", "s": "يبحث الكافرون عن مزيد من الحرية، وإذا تعبّد أحدهم لله فعلى غير طريق العبودية الحق لله، ويبحث المسلم عن مزيد من العبودية لله، ويحاول أن يتحرّر من كل ما يستعبده سوى الله، سواء في ذلك العبودية للجاه أو للمظهر أو للمجتمع أو لغرض من أغراض الدنيا، وذلك مقتضى قوله: "}, {"t": "quote", "s": "لا إله إلا الله"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "فالعبودية هي أرقى مقام يتطلّع إليه المسلم، وقد وصف الله عز وجل رسوله بالعبودية أثناء الكلام عن مقاماته ومعجزاته، قال تعالى: ﴿ٱلۡحَمۡدُ لِلَّهِ ٱلَّذِيٓ أَنزَلَ عَلَىٰ عَبۡدِهِ ٱلۡكِتَٰبَ﴾، وقال تعالى: ﴿سُبْحَانَ الَّذِي أَسْرَى بِعَبْدِهِ لَيْلًا مِنَ الْمَسْجِدِ الْحَرَامِ إِلَى الْمَسْجِدِ الْأَقْصَى الَّذِي بَارَكْنَا حَوْلَهُ﴾، وإذ طالب اللهُ عز وجل عبده بأن يعرف التوحيد قا: ﴿فَاعْلَمْ أَنَّهُ لَا إِلَهَ إِلَّا اللَّهُ﴾؛ فتلك مطالبة بالضرورة بأن يؤدّي واجب العبودية، والعبودية تقتضي معرفة بالعقائد، وقيامًا بالعبادات، واستقامة على منهج الحياة، واستقامة على منهج الشريعة، وكل من هذه الثلاثة يعمِّق الأخريين ويساعد عليه، وثمة معالم كبرى تغذي مقام العبودية على رأسها: توحيد الله، والمداومة على ذكره، ومعرفة منهجه في الحياة، ونصرة دينه، والإنفاق في سبيله.", "page": 68, "id": "unit-06__lesson-03__b06", "inline": [{"t": "text", "s": "فالعبودية هي أرقى مقام يتطلّع إليه المسلم، وقد وصف الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " رسوله بالعبودية أثناء الكلام عن مقاماته ومعجزاته، قال تعالى: "}, {"t": "ayah", "s": "ٱلۡحَمۡدُ لِلَّهِ ٱلَّذِيٓ أَنزَلَ عَلَىٰ عَبۡدِهِ ٱلۡكِتَٰبَ", "ayah": [], "verses": [{"n": 1, "text": "ٱلۡحَمۡدُ لِلَّهِ ٱلَّذِيٓ أَنزَلَ عَلَىٰ عَبۡدِهِ ٱلۡكِتَٰبَ", "surah": 18, "surah_name": "الكهف", "ref": "18:1", "ref_api": "https://api.quran.com/api/v4/verses/by_key/18:1"}], "surah": 18, "ref_api": "https://api.quran.com/api/v4/verses/by_key/18:1", "surah_name": "الكهف", "ayah_canonical": 1, "match": "contained", "ref": "18:1"}, {"t": "text", "s": "، وقال تعالى: "}, {"t": "ayah", "s": "سُبْحَانَ الَّذِي أَسْرَى بِعَبْدِهِ لَيْلًا مِنَ الْمَسْجِدِ الْحَرَامِ إِلَى الْمَسْجِدِ الْأَقْصَى الَّذِي بَارَكْنَا حَوْلَهُ", "ayah": [], "verses": [{"n": 1, "text": "سُبْحَانَ الَّذِي أَسْرَى بِعَبْدِهِ لَيْلًا مِنَ الْمَسْجِدِ الْحَرَامِ إِلَى الْمَسْجِدِ الْأَقْصَى الَّذِي بَارَكْنَا حَوْلَهُ", "surah": 17, "surah_name": "الإسراء", "ref": "17:1", "ref_api": "https://api.quran.com/api/v4/verses/by_key/17:1"}], "surah": 17, "ref_api": "https://api.quran.com/api/v4/verses/by_key/17:1", "surah_name": "الإسراء", "ayah_canonical": 1, "match": "contained", "ref": "17:1"}, {"t": "text", "s": "، وإذ طالب اللهُ "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " عبده بأن يعرف التوحيد قا: "}, {"t": "ayah", "s": "فَاعْلَمْ أَنَّهُ لَا إِلَهَ إِلَّا اللَّهُ", "ayah": [], "verses": [{"n": 19, "text": "فَاعْلَمْ أَنَّهُ لَا إِلَهَ إِلَّا اللَّهُ", "surah": 47, "surah_name": "محمد", "ref": "47:19", "ref_api": "https://api.quran.com/api/v4/verses/by_key/47:19"}], "surah": 47, "ref_api": "https://api.quran.com/api/v4/verses/by_key/47:19", "surah_name": "محمد", "ayah_canonical": 19, "match": "contained", "ref": "47:19"}, {"t": "text", "s": "؛ فتلك مطالبة بالضرورة بأن يؤدّي واجب العبودية، والعبودية تقتضي معرفة بالعقائد، وقيامًا بالعبادات، واستقامة على منهج الحياة، واستقامة على منهج الشريعة، وكل من هذه الثلاثة يعمِّق الأخريين ويساعد عليه، وثمة معالم كبرى تغذي مقام العبودية على رأسها: توحيد الله، والمداومة على ذكره، ومعرفة منهجه في الحياة، ونصرة دينه، والإنفاق في سبيله."}]}, {"type": "heading", "level": 3, "text": "كلمات في توحيد الله وذكره، وأثره على معنى العبودية:", "page": 68, "id": "unit-06__lesson-03__b07", "role": "section"}, {"type": "paragraph", "md": "قال تعالى: ﴿أَلَمۡ تَرَ كَيۡفَ ضَرَبَ ٱللَّهُ مَثَلٗا كَلِمَةٗ طَيِّبَةٗ كَشَجَرَةٖ طَيِّبَةٍ أَصۡلُهَا ثَابِتٞ وَفَرۡعُهَا فِي ٱلسَّمَآءِ ۝٢٤ تُؤۡتِيٓ أُكُلَهَا كُلَّ حِينِۭ بِإِذۡنِ رَبِّهَاۗ﴾؛ إن للتوحيد ثمراته الطيبة فالإيمان بضع وسبعون شعبة، كلها أثر عن كلمة التوحيد، هذه الشجرة لا بدَّ أن تسقى لتُؤتي ثمارها الطيبة اليانعة الكريمة، وسقايتها أولًا تكون بالأذكار؛ لأن الذكر هو الحياة وفي الحديث: (مثل الذي يذكر ربه والذي لا يذكر ربه كمثل الحي والميت)، والأذكار على أنواع وكلها ماء الحياة لشجرة الإيمان؛ فمن كان له حظ كبير من الذكر كان له حظه من الحياة ومَن فاته حظ من الذكر فاته قدر كبير من الحياة.", "page": 69, "id": "unit-06__lesson-03__b08", "inline": [{"t": "text", "s": "قال تعالى: "}, {"t": "ayah", "s": "أَلَمۡ تَرَ كَيۡفَ ضَرَبَ ٱللَّهُ مَثَلٗا كَلِمَةٗ طَيِّبَةٗ كَشَجَرَةٖ طَيِّبَةٍ أَصۡلُهَا ثَابِتٞ وَفَرۡعُهَا فِي ٱلسَّمَآءِ ۝٢٤ تُؤۡتِيٓ أُكُلَهَا كُلَّ حِينِۭ بِإِذۡنِ رَبِّهَاۗ", "ayah": [24], "verses": [{"n": 24, "text": "أَلَمۡ تَرَ كَيۡفَ ضَرَبَ ٱللَّهُ مَثَلٗا كَلِمَةٗ طَيِّبَةٗ كَشَجَرَةٖ طَيِّبَةٍ أَصۡلُهَا ثَابِتٞ وَفَرۡعُهَا فِي ٱلسَّمَآءِ", "surah": 14, "ref_api": "https://api.quran.com/api/v4/verses/by_key/14:24", "surah_name": "ابراهيم", "ayah_canonical": 24, "match": "exact", "ref": "14:24"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ إن للتوحيد ثمراته الطيبة فالإيمان بضع وسبعون شعبة، كلها أثر عن كلمة التوحيد، هذه الشجرة لا بدَّ أن تسقى لتُؤتي ثمارها الطيبة اليانعة الكريمة، وسقايتها أولًا تكون بالأذكار؛ لأن الذكر هو الحياة وفي الحديث: "}, {"t": "emphasis", "s": "(مثل الذي يذكر ربه والذي لا يذكر ربه كمثل الحي والميت)", "role": "emphasis"}, {"t": "text", "s": "، والأذكار على أنواع وكلها ماء الحياة لشجرة الإيمان؛ فمن كان له حظ كبير من الذكر كان له حظه من الحياة ومَن فاته حظ من الذكر فاته قدر كبير من الحياة."}]}, {"type": "paragraph", "md": "وكما أن للذكر أثره الكبير في حياة التوحيد؛ فإن للعلم أثره الكبير في تعميقه وتغذيته، وكذلك نصرة رسول الله صلى الله عليه وسلم لها أثرها الكبير في تغذية التوحيد وتقويته، وكذلك الإنفاق، قال تعالى: ﴿وَمَثَلُ ٱلَّذِينَ يُنفِقُونَ أَمۡوَٰلَهُمُ ٱبۡتِغَآءَ مَرۡضَاتِ ٱللَّهِ وَتَثۡبِيتٗا مِّنۡ أَنفُسِهِمۡ﴾، وعلى هذا فلا بدّ للمسلم أن يعرف ما يدخل في التوحيد وأن يعرف ما يقويه وأن يتحقَّق بذلك، وإذا عرفنا أن السمة الأولى للإسلام هي التوحيد وأنه بمقدار ما يكون التوحيد قويًا يكون نور المؤمن في الدنيا والبرزخ والآخرة قويًا؛ عرفنا أهمية هذا الموضوع، ونذكر هنا ببعض ما يلزم في هذا الباب؛ فنقول وبالله التوفيق:", "page": 69, "id": "unit-06__lesson-03__b09", "inline": [{"t": "text", "s": "وكما أن للذكر أثره الكبير في حياة التوحيد؛ فإن للعلم أثره الكبير في تعميقه وتغذيته، وكذلك نصرة رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لها أثرها الكبير في تغذية التوحيد وتقويته، وكذلك الإنفاق، قال تعالى: "}, {"t": "ayah", "s": "وَمَثَلُ ٱلَّذِينَ يُنفِقُونَ أَمۡوَٰلَهُمُ ٱبۡتِغَآءَ مَرۡضَاتِ ٱللَّهِ وَتَثۡبِيتٗا مِّنۡ أَنفُسِهِمۡ", "ayah": [], "verses": [{"n": 265, "text": "وَمَثَلُ ٱلَّذِينَ يُنفِقُونَ أَمۡوَٰلَهُمُ ٱبۡتِغَآءَ مَرۡضَاتِ ٱللَّهِ وَتَثۡبِيتٗا مِّنۡ أَنفُسِهِمۡ", "surah": 2, "surah_name": "البقرة", "ref": "2:265", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:265"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:265", "surah_name": "البقرة", "ayah_canonical": 265, "match": "contained", "ref": "2:265"}, {"t": "text", "s": "، وعلى هذا فلا بدّ للمسلم أن يعرف ما يدخل في التوحيد وأن يعرف ما يقويه وأن يتحقَّق بذلك، وإذا عرفنا أن السمة الأولى للإسلام هي التوحيد وأنه بمقدار ما يكون التوحيد قويًا يكون نور المؤمن في الدنيا والبرزخ والآخرة قويًا؛ عرفنا أهمية هذا الموضوع، ونذكر هنا ببعض ما يلزم في هذا الباب؛ فنقول وبالله التوفيق:"}]}, {"type": "paragraph", "md": "أكثر الخلق لا ينكرون وجود الله عز وجل ؛ لأن ذلك مغروس في فكرهم وهم يلجأون إليه عند الحاجة، ولكن أهل الإسلام وحدهم هم الذين يعرفونه حق المعرفة فيعرفون صفاته وأسماءه ويعرفون له حقوقه، وكلمة التوحيد هي الكلمة الجامعة لهذا كله؛ فاسم الجلالة «الله» علم على الذات العلية المتَّصفة بكل كمالٍ من الأسماء والصفات والأمثال، والغنية عما سواها، والمفتقر إليها ما عداها، ولها المثل الأعلى وهي وحدها تستحق التأليه، ومن ثمَّ فإن المسلم يقول «لا إله إلا الله»، ومقتضى اتصاف الله بالألوهية أن يتصف سبحانه وتعالى بالربوبية والمالكية والحاكمية: ﴿قُلۡ أَعُوذُ بِرَبِّ ٱلنَّاسِ ۝١ مَلِكِ ٱلنَّاسِ ۝٢ إِلَٰهِ ٱلنَّاسِ ۝٣﴾، ﴿إِنِ ٱلۡحُكۡمُ إِلَّا لِلَّهِۖ﴾، ومظهر حاكمية الله: اتباعُ الكتاب والسنة، ومقام المكلف في هذا الوجود: القيام لله بحقوق الألوهية والربوبية والمالكية والحاكمية وذلك يكون بالعبادة وبالعبودية، وهما يقتضيان إيمانًا برسول الله صلى الله عليه وسلم وتصديقًا بالوحي وتسليمًا واستسلامًا.", "page": 69, "id": "unit-06__lesson-03__b10", "inline": [{"t": "text", "s": "أكثر الخلق لا ينكرون وجود الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ؛ لأن ذلك مغروس في فكرهم وهم يلجأون إليه عند الحاجة، ولكن أهل الإسلام وحدهم هم الذين يعرفونه حق المعرفة فيعرفون صفاته وأسماءه ويعرفون له حقوقه، وكلمة التوحيد هي الكلمة الجامعة لهذا كله؛ فاسم الجلالة "}, {"t": "quote", "s": "الله"}, {"t": "text", "s": " علم على الذات العلية المتَّصفة بكل كمالٍ من الأسماء والصفات والأمثال، والغنية عما سواها، والمفتقر إليها ما عداها، ولها المثل الأعلى وهي وحدها تستحق التأليه، ومن ثمَّ فإن المسلم يقول "}, {"t": "quote", "s": "لا إله إلا الله"}, {"t": "text", "s": "، ومقتضى اتصاف الله بالألوهية أن يتصف "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " بالربوبية والمالكية والحاكمية: "}, {"t": "ayah", "s": "قُلۡ أَعُوذُ بِرَبِّ ٱلنَّاسِ ۝١ مَلِكِ ٱلنَّاسِ ۝٢ إِلَٰهِ ٱلنَّاسِ ۝٣", "ayah": [1, 2, 3], "verses": [{"n": 1, "text": "قُلۡ أَعُوذُ بِرَبِّ ٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:1", "surah_name": "الناس", "ayah_canonical": 1, "match": "exact", "ref": "114:1"}, {"n": 2, "text": "مَلِكِ ٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:2", "surah_name": "الناس", "ayah_canonical": 2, "match": "exact", "ref": "114:2"}, {"n": 3, "text": "إِلَٰهِ ٱلنَّاسِ", "surah": 114, "ref_api": "https://api.quran.com/api/v4/verses/by_key/114:3", "surah_name": "الناس", "ayah_canonical": 3, "match": "exact", "ref": "114:3"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "إِنِ ٱلۡحُكۡمُ إِلَّا لِلَّهِۖ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، ومظهر حاكمية الله: اتباعُ الكتاب والسنة، ومقام المكلف في هذا الوجود: القيام لله بحقوق الألوهية والربوبية والمالكية والحاكمية وذلك يكون بالعبادة وبالعبودية، وهما يقتضيان إيمانًا برسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وتصديقًا بالوحي وتسليمًا واستسلامًا."}]}, {"type": "paragraph", "md": "ومن حقوق التوحيد: أن تستشعر أن كل شيء هو فعل الله وذلك مقتضى قول الله تعالى: ﴿ٱللَّهُ خَٰلِقُ كُلِّ شَيۡءٖۖ﴾، فتستشعر بهذا في نفسك وخارجها وأن تستقبل كل شيء على أنه فعله؛ ملاحِظًا في ذلك التكليف.", "page": 69, "id": "unit-06__lesson-03__b11", "inline": [{"t": "text", "s": "ومن حقوق التوحيد: أن تستشعر أن كل شيء هو فعل الله وذلك مقتضى قول الله تعالى: "}, {"t": "ayah", "s": "ٱللَّهُ خَٰلِقُ كُلِّ شَيۡءٖۖ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، فتستشعر بهذا في نفسك وخارجها وأن تستقبل كل شيء على أنه فعله؛ ملاحِظًا في ذلك التكليف."}]}, {"type": "paragraph", "md": "ومن حقوق التوحيد: أن تستشعر أن الله يسمعك ويراك ﴿إِنَّنِي مَعَكُمَآ أَسۡمَعُ وَأَرَىٰ ۝٤٦﴾، ﴿أَلَمۡ يَعۡلَم بِأَنَّ ٱللَّهَ يَرَىٰ ۝١٤﴾. ومن حقوق التوحيد: التسليم لله في قضائه والتسليم لله في أحكامه، ومن حقوق التوحيد: القيام بأنواع العبادة له والخضوع بكل أنواع العبودية له.", "page": 69, "id": "unit-06__lesson-03__b12", "inline": [{"t": "text", "s": "ومن حقوق التوحيد: أن تستشعر أن الله يسمعك ويراك "}, {"t": "ayah", "s": "إِنَّنِي مَعَكُمَآ أَسۡمَعُ وَأَرَىٰ ۝٤٦", "ayah": [46], "verses": [{"n": 46, "text": "إِنَّنِي مَعَكُمَآ أَسۡمَعُ وَأَرَىٰ", "surah": 20, "ref_api": "https://api.quran.com/api/v4/verses/by_key/20:46", "surah_name": "طه", "ayah_canonical": 46, "match": "contained", "ref": "20:46"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "أَلَمۡ يَعۡلَم بِأَنَّ ٱللَّهَ يَرَىٰ ۝١٤", "ayah": [14], "verses": [{"n": 14, "text": "أَلَمۡ يَعۡلَم بِأَنَّ ٱللَّهَ يَرَىٰ", "surah": 96, "ref_api": "https://api.quran.com/api/v4/verses/by_key/96:14", "surah_name": "العلق", "ayah_canonical": 14, "match": "exact", "ref": "96:14"}], "surah": null, "ref_api": null}, {"t": "text", "s": ". ومن حقوق التوحيد: التسليم لله في قضائه والتسليم لله في أحكامه، ومن حقوق التوحيد: القيام بأنواع العبادة له والخضوع بكل أنواع العبودية له."}]}, {"type": "paragraph", "md": "ومن حقوق التوحيد: ألا تُعطي ما هو خاص بالله لغير الله وهذه قضية عظيمة يغفل عنها كثير من الخلق.", "page": 70, "id": "unit-06__lesson-03__b13", "inline": [{"t": "emphasis", "s": "ومن حقوق التوحيد", "role": "emphasis"}, {"t": "text", "s": ": ألا تُعطي ما هو خاص بالله لغير الله وهذه قضية عظيمة يغفل عنها كثير من الخلق."}]}, {"type": "paragraph", "md": "وثمرات التوحيد الحقة: فعل الخير كله وترك الشر كله، مع رؤية التقصير في فعل الخير والتوبة إلى الله من فعل الشر.. ذلك أنَّ شُعبَ الإيمان كلها وصفات أهل الإيمان كلها أثر من آثار التوحيد وترك الكفر وصفات أهله، ومجانبة النفاق وترك الفسوق كله أثر من آثار التوحيد.", "page": 70, "id": "unit-06__lesson-03__b14"}, {"type": "paragraph", "md": "فإذا قلنا: إن التكليف يدخل فيه ما هو فريضة أو واجب أو سنة أو أدب أو مروءة أو أريحية أو ذوق، ويدخل فيه ترك المكروه تنزيهًا أو تحريمًا أو ما هو حرام.. فكل ذلك من ثمرات التوحيد أيضًا.", "page": 70, "id": "unit-06__lesson-03__b15"}, {"type": "paragraph", "md": "إن التوحيد هو المظهر الأول والأهم لصحة طريق الدعوة والداعية إلى الله تعالى؛ فإن لم يكن التوحيد أصل دعوة الداعي فإنَّ في دعوته خللًا بينًا.. ألا ترى أن الدعوة إلى التوحيد هي السمة لدعوة الأنبياء جميعًا عليهم الصلاة والسلام؟ كما قال تعالى: ﴿وَمَآ أَرۡسَلۡنَا مِن قَبۡلِكَ مِن رَّسُولٍ إِلَّا نُوحِيٓ إِلَيۡهِ أَنَّهُۥ لَآ إِلَٰهَ إِلَّآ أَنَا۠ فَٱعۡبُدُونِ ۝٢٥﴾ وكثيرٌ من الدعاة يغفلون عن التركيز على هذه السمة العظمى لهذا الدين؛ فيتحدثون عن غير هذا الأصل وهم يستطيعون الحديث عنه، وكثيرون من الدعاة يغفلون عن مغذيات التوحيد المتكاملة فلا يحسُّون ببركات التوحيد في قلوبهم وأنفسهم ولا يدخلون الطريق الذي ينمو به هذا التوحيد، وقد لا يُدلُّونَ عليه وهذا من قصور الدعاة، ثم إن كثيرًا من المسلمين أنفسهم خالط توحيدهم شيء من الخلل، فالتوكّل فيه نقص، والإخلاص فيه نقص، وهذا كله يستدعي منا التركيز على التوحيد ومغذياته.", "page": 70, "id": "unit-06__lesson-03__b16", "inline": [{"t": "text", "s": "إن التوحيد هو المظهر الأول والأهم لصحة طريق الدعوة والداعية إلى الله تعالى؛ فإن لم يكن التوحيد أصل دعوة الداعي فإنَّ في دعوته خللًا بينًا.. ألا ترى أن الدعوة إلى التوحيد هي السمة لدعوة الأنبياء جميعًا عليهم الصلاة والسلام؟ كما قال تعالى: "}, {"t": "ayah", "s": "وَمَآ أَرۡسَلۡنَا مِن قَبۡلِكَ مِن رَّسُولٍ إِلَّا نُوحِيٓ إِلَيۡهِ أَنَّهُۥ لَآ إِلَٰهَ إِلَّآ أَنَا۠ فَٱعۡبُدُونِ ۝٢٥", "ayah": [25], "verses": [{"n": 25, "text": "وَمَآ أَرۡسَلۡنَا مِن قَبۡلِكَ مِن رَّسُولٍ إِلَّا نُوحِيٓ إِلَيۡهِ أَنَّهُۥ لَآ إِلَٰهَ إِلَّآ أَنَا۠ فَٱعۡبُدُونِ", "surah": 21, "ref_api": "https://api.quran.com/api/v4/verses/by_key/21:25", "surah_name": "الأنبياء", "ayah_canonical": 25, "match": "exact", "ref": "21:25"}], "surah": null, "ref_api": null}, {"t": "text", "s": " وكثيرٌ من الدعاة يغفلون عن التركيز على هذه السمة العظمى لهذا الدين؛ فيتحدثون عن غير هذا الأصل وهم يستطيعون الحديث عنه، وكثيرون من الدعاة يغفلون عن مغذيات التوحيد المتكاملة فلا يحسُّون ببركات التوحيد في قلوبهم وأنفسهم ولا يدخلون الطريق الذي ينمو به هذا التوحيد، وقد لا يُدلُّونَ عليه وهذا من قصور الدعاة، ثم إن كثيرًا من المسلمين أنفسهم خالط توحيدهم شيء من الخلل، فالتوكّل فيه نقص، والإخلاص فيه نقص، وهذا كله يستدعي منا التركيز على التوحيد ومغذياته."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة الإثرائية:", "page": 70, "id": "unit-06__lesson-03__b17", "role": "assessment"}, {"type": "paragraph", "md": "1- اذكر مغذيات العبودية الخمسة.", "page": 70, "id": "unit-06__lesson-03__b18", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- عدد خمسة من ثمرات التوحيد كما تعلمتها في الدرس.", "page": 70, "id": "unit-06__lesson-03__b19", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- العبودية أرقى مقام يتطلع إليه المسلم.. وضح ذلك حسب فهمك.", "page": 70, "id": "unit-06__lesson-03__b20", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "نشاط بحثي حواري", "page": 70, "id": "unit-06__lesson-03__b21", "role": "activity"}, {"type": "paragraph", "md": "1-ذكرت آيةٌ في كتاب الله أن التوحيد من ثمراته: الأمن.. ابحث عنها واقرأها وفسرها أمام إخوانك.", "page": 70, "id": "unit-06__lesson-03__b22", "item_role": "activity_step"}, {"type": "paragraph", "md": "2-افتتح الدرس بآية ﴿أَلَمۡ تَرَ كَيۡفَ ضَرَبَ ٱللَّهُ مَثَلٗا كَلِمَةٗ طَيِّبَةٗ﴾ ارجع إلى كتب التفسير وبين معناها.", "page": 70, "id": "unit-06__lesson-03__b23", "inline": [{"t": "text", "s": "2-افتتح الدرس بآية "}, {"t": "ayah", "s": "أَلَمۡ تَرَ كَيۡفَ ضَرَبَ ٱللَّهُ مَثَلٗا كَلِمَةٗ طَيِّبَةٗ", "ayah": [], "verses": [{"n": 24, "text": "أَلَمۡ تَرَ كَيۡفَ ضَرَبَ ٱللَّهُ مَثَلٗا كَلِمَةٗ طَيِّبَةٗ", "surah": 14, "surah_name": "ابراهيم", "ref": "14:24", "ref_api": "https://api.quran.com/api/v4/verses/by_key/14:24"}], "surah": 14, "ref_api": "https://api.quran.com/api/v4/verses/by_key/14:24", "surah_name": "ابراهيم", "ayah_canonical": 24, "match": "contained", "ref": "14:24"}, {"t": "text", "s": " ارجع إلى كتب التفسير وبين معناها."}], "item_role": "activity_step"}]' WHERE id='unit-06__lesson-03';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 71, "id": "unit-06__lesson-04__b01", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على خصال الفطرة وسننها.", "page": 71, "id": "unit-06__lesson-04__b02"}, {"type": "paragraph", "md": "معرفة أحكام اللحية والشارب وغيرها.", "page": 71, "id": "unit-06__lesson-04__b03"}, {"type": "heading", "level": 3, "text": "تعريف سنن الفطرة وبيانها:", "page": 71, "id": "unit-06__lesson-04__b04", "role": "definitions"}, {"type": "paragraph", "md": "عن عائشة رضي الله عنها قالت: قال صلى الله عليه وسلم : (عشر من الفطرة: 1- قص الشارب، 2- وإعفاء اللحية، 3- والسواك، 4- واستنشاق الماء، 5- وقص الأظفار، 6-وغسل البراجم، 7-ونتف الإبط، 8-وحلق العانة، 9-وانتقاص الماء - قال مصعب [أحد رواة الحديث]: 10- ونسيت العاشرة إلا أن تكون المضمضة).", "page": 71, "id": "unit-06__lesson-04__b05", "inline": [{"t": "text", "s": "عن عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " قالت: قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(عشر من الفطرة: 1- قص الشارب، 2- وإعفاء اللحية، 3- والسواك، 4- واستنشاق الماء، 5- وقص الأظفار، 6-وغسل البراجم، 7-ونتف الإبط، 8-وحلق العانة، 9-وانتقاص الماء -", "role": "lemma"}, {"t": "text", "s": " قال مصعب [أحد رواة الحديث]: 10"}, {"t": "emphasis", "s": "- ونسيت العاشرة إلا أن تكون المضمضة)", "role": "lemma"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "الفطرة هي: السنة، وفي هذه الخصال محافظة على حسن الهيئة والنظافة، وكلاهما يحصل به البقاء على السنة وكمال الخلقة التي خلق عليها الإنسان، ومخالفتها يقبحه؛ فيخرج عما تقتضيه الفطرة الأولى.", "page": 71, "id": "unit-06__lesson-04__b06"}, {"type": "paragraph", "md": "1- قص الشارب: المسلم مطلوب منه التميز عن غيره من الكفار، ولهذا نهي أن يلبس لباسهم، وأن يوافقهم في الظاهر، لما في ذلك من التشبه بهم، والتشبه في الظاهر يقود إلى التشبه بالباطن، وقص الشارب فيه تمايزٌ عنهم، وهو من النظافة خاصة في مدخل الطعام والشراب، والسلف على استحباب قص الشارب والخلاف في صفة الأخذ من الشارب؛ هل المستحب القص أو الحلق؟ والصواب أن كلاهما من السنة.", "page": 71, "id": "unit-06__lesson-04__b07", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- إعفاء اللحية: هي الشعر النابت على الخدين والذقن، وشعر الخد والرقبة ليس من اللحية، وإعفاء اللحية: واجب؛ فيُمْنَعُ أخذُ ما قَلَّ عن القبضة في كل حال. وقصها دون القبضة: حرام عند الأئمة الأربعة، قال ابن عابدين: «الأخذ من اللحية دون القبضة كما يفعله بعض مخنثة الرجال لم يبحه أحد»، وذلك للحديث الصحيح: (خالفوا المشركين، وفروا اللحى، وأحفوا الشوارب)، واللحية زينة المسلم، وشعاره الذي يتميز به؛ فهنيئًا لصاحبها، الذي يخالف الكافرين، ويتبع سنة رسول رب العالمين صلى الله عليه وسلم .", "page": 71, "id": "unit-06__lesson-04__b08", "inline": [{"t": "text", "s": "2- إعفاء اللحية: هي الشعر النابت على الخدين والذقن، وشعر الخد والرقبة ليس من اللحية، وإعفاء اللحية: "}, {"t": "emphasis", "s": "واجب؛", "role": "lemma"}, {"t": "text", "s": " فيُمْنَعُ أخذُ ما قَلَّ عن القبضة في كل حال. وقصها دون القبضة: حرام عند الأئمة الأربعة، قال ابن عابدين: "}, {"t": "quote", "s": "الأخذ من اللحية دون القبضة كما يفعله بعض مخنثة الرجال لم يبحه أحد", "speaker": "ابن عابدين"}, {"t": "text", "s": "، وذلك للحديث الصحيح: "}, {"t": "emphasis", "s": "(خالفوا المشركين، وفروا اللحى، وأحفوا الشوارب)", "role": "lemma"}, {"t": "text", "s": "، واللحية زينة المسلم، وشعاره الذي يتميز به؛ فهنيئًا لصاحبها، الذي يخالف الكافرين، ويتبع سنة رسول رب العالمين "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- السواك: ومعناه: استعمال عود ونحوه في الأسنان لإذهاب التغير واتباع السنة، وأفضله: عود الأراك، وفي الصحيح قال صلى الله عليه وسلم : (السواك مطهرة للفم مرضاة للرب)، وأجمعت الأمة على فضله قربة لله، ولا شك أن السواك أفضل من معجون الأسنان طبيًا وأيسر منه، فالسوك يُستعمل قبل الصلاة في المسجد بخلاف المعجون، ولكن من استعمل المعجون بنية التطهر قربة لله فقد أصاب السنة ويُؤجر به.", "page": 71, "id": "unit-06__lesson-04__b09", "inline": [{"t": "text", "s": "3- السواك: ومعناه: استعمال عود ونحوه في الأسنان لإذهاب التغير واتباع السنة، وأفضله: عود الأراك، وفي الصحيح قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(السواك مطهرة للفم مرضاة للرب)", "role": "lemma"}, {"t": "text", "s": "، وأجمعت الأمة على فضله قربة لله، ولا شك أن السواك أفضل من معجون الأسنان طبيًا وأيسر منه، فالسوك يُستعمل قبل الصلاة في المسجد بخلاف المعجون، ولكن من استعمل المعجون بنية التطهر قربة لله فقد أصاب السنة ويُؤجر به."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "والسواك سُنَّةٌ مُؤكَّدَةٌ في كل وقت، ويتأكَّدُ فيما يأتي: عند القيام إلى الصلاة فرضًا ونَفْلًا. وعند الوضوء. والقيام من النوم. وتغيِّر الفم. ودخول البيت. ولا يُكْرَهُ السواك بعد الزوال للصائم على الصحيح.", "page": 72, "id": "unit-06__lesson-04__b10"}, {"type": "paragraph", "md": "4- حلق العانة «الاستحداد»: أي حلق عانته بالحديد وهي الشفرة، والعانة: الشعر النابت حول القُبل والدبر، وهو سنة؛ إلا إن صار الشعر يحمل النجاسة، ويخرج الريح الكريهة فيكون واجبًا.", "page": 72, "id": "unit-06__lesson-04__b11", "inline": [{"t": "text", "s": "4- حلق العانة "}, {"t": "quote", "s": "الاستحداد"}, {"t": "text", "s": ": أي حلق عانته بالحديد وهي الشفرة، والعانة: الشعر النابت حول القُبل والدبر، وهو سنة؛ إلا إن صار الشعر يحمل النجاسة، ويخرج الريح الكريهة فيكون واجبًا."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- الختان: حكمه الوجوب، ومعناه: قطع الجلدة التي تغطي الحشفة من الذَّكَر لتظهر كلها. وهو شعار الإسلام؛ فلو وجد مختونًا بين جماعة قتلى غير مختونين صلي عليه وكانوا يبادرون له وللغسل إن أسلموا.", "page": 72, "id": "unit-06__lesson-04__b12", "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- تقليم الأظفار: وهو سنة؛ سواء للرجل والمرأة، واليدين والرجلين، إلا إن فحشت حتى إنها لا تطهر في الوضوء والغسل لما تجمعه من قذر؛ فيكون قصها واجبًا حينها، إلا في الحرب فلا بأس بتطويله لغرض مشروع في الجهاد، والسنة أنه متى طالت أظافهر قصها سواء قبل الأربعين يومًا أو بعدها.", "page": 72, "id": "unit-06__lesson-04__b13", "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "7- غسل البراجم: هي المفاصل والعقد التي تكون في ظهور الأصابع، ويجتمع فيها الوسخ، ويُقْصَدُ العناية بها لخفائها واستهانة الناس. ويلحق بالبراجم: ما يجتمع من الوسخ في معاطف الأذن وقعر الصماخ. وكذلك ما يكون تحت الدهان والمناكير ونحوه، وغسلها سنة مستقلة، ليست خاصة بالوضوء فقط؛ فنحن مأمورن بالنظافة والطهارة. وأما حكمها في الوضوء: فإذا كان الوسخ يسيرًا لا يمنع وصول الماء؛ صحت الطهارة، وإذا كان الوسخ كثيرٌ يمنعُ وصولَ الماء فلا تصح الطهارة لعدم مس الماء للبشرة.", "page": 72, "id": "unit-06__lesson-04__b14", "inline": [{"t": "text", "s": "7- غسل البراجم: هي المفاصل والعقد التي تكون في ظهور الأصابع، ويجتمع فيها الوسخ، ويُقْصَدُ العناية بها لخفائها واستهانة الناس. ويلحق بالبراجم: ما يجتمع من الوسخ في معاطف الأذن وقعر الصماخ. وكذلك ما يكون تحت الدهان والمناكير ونحوه، وغسلها سنة مستقلة، ليست خاصة بالوضوء فقط؛ فنحن مأمورن بالنظافة والطهارة. "}, {"t": "emphasis", "s": "وأما حكمها في الوضوء", "role": "lemma"}, {"t": "text", "s": ": فإذا كان الوسخ يسيرًا لا يمنع وصول الماء؛ صحت الطهارة، وإذا كان الوسخ كثيرٌ يمنعُ وصولَ الماء فلا تصح الطهارة لعدم مس الماء للبشرة."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 72, "id": "unit-06__lesson-04__b15", "role": "assessment"}, {"type": "paragraph", "md": "عدد سنن الفطرة كاملة، واشرح لنا ثلاثة منها باختيارك.", "page": 72, "id": "unit-06__lesson-04__b16", "item_role": "question"}, {"type": "paragraph", "md": "اشرح معنى «انتقاص الماء»، الختان، البراجم.", "page": 72, "id": "unit-06__lesson-04__b17", "inline": [{"t": "text", "s": "اشرح معنى "}, {"t": "quote", "s": "انتقاص الماء"}, {"t": "text", "s": "، الختان، البراجم."}], "item_role": "question"}, {"type": "paragraph", "md": "ما حكم حلق اللحية أو التقصير منها؟ ولماذا برأيك يتساهل كثير من الشباب في حلقها؟", "page": 72, "id": "unit-06__lesson-04__b18", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط بحثي تطبيقي", "page": 72, "id": "unit-06__lesson-04__b19", "role": "activity"}, {"type": "paragraph", "md": "1- تنتشر ظاهرة حلق اللحى، فلنتعاهد على إطلاقها، وليكلم كل منا ثلاثة من إخوانه عن حكمها.", "page": 72, "id": "unit-06__lesson-04__b20", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- في الحديث: (ويل للأعقاب من النار) لهذا الحديث ارتباط بأحد سنن الفطرة.. وضح ذلك كرمًا.", "page": 72, "id": "unit-06__lesson-04__b21", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-06__lesson-04';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 73, "id": "unit-06__lesson-05__b01", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على معنى الانتصار من الظالم، وعدم الرضا بظلمه وجَوره.", "page": 73, "id": "unit-06__lesson-05__b02"}, {"type": "paragraph", "md": "أن يتمثل هذا الخلق في حياته ويتحلى به في كل أوقاته مهما قوي العدو وازداد بطشه ومكره.", "page": 73, "id": "unit-06__lesson-05__b03"}, {"type": "heading", "level": 3, "text": "معنى الخلق وفضله وأهميته:", "page": 73, "id": "unit-06__lesson-05__b04", "role": "virtues"}, {"type": "paragraph", "md": "تميز ديننا بالتوازن؛ الذي يجعل المؤمن في بعض المواطن متواضعًا متسامحًا؛ يعفو ويصفح، ويغفر عند الغضب، وفي مواطن أخرى تجده أبيًّا حريصًا على مروءته، مطالبًا بحقه، مقتصًّا من ظالمه، منتصرًا من المسيء إليه، فمتى يكون الانتصار؟ يقول ابن العربي: «إذا كان الباغي معلنًا بالفجور، وقحًا في الجمهور، مؤذيًا للصغير والكبير، فيكون الانتقام منه أفضل»، وأما الحالة المقتضية للعفو «فأن تكون فلتة، أو يقع ذلك ممن يعترف بالزلة، ويسأل المغفرة؛ فالعفو أفضل»؛ جاء في تفسير قوله تعالى: ﴿وَٱلَّذِينَ إِذَآ أَصَابَهُمُ ٱلۡبَغۡيُ هُمۡ يَنتَصِرُونَ ۝٣٩﴾ أي: ينتقمون ممن بغى عليهم ولا يستسلمون لظلم المعتدي؛ فهو وصف لهم بالشجاعة بعد وصفهم بسائر الفضائل، وهذا لا ينافي وصفهم بالغفران، فإن كلًا في موضعه محمود.", "page": 73, "id": "unit-06__lesson-05__b05", "inline": [{"t": "text", "s": "تميز ديننا بالتوازن؛ الذي يجعل المؤمن في بعض المواطن متواضعًا متسامحًا؛ يعفو ويصفح، ويغفر عند الغضب، وفي مواطن أخرى تجده أبيًّا حريصًا على مروءته، مطالبًا بحقه، مقتصًّا من ظالمه، منتصرًا من المسيء إليه، فمتى يكون الانتصار؟ يقول ابن العربي: "}, {"t": "quote", "s": "إذا كان الباغي معلنًا بالفجور، وقحًا في الجمهور، مؤذيًا للصغير والكبير، فيكون الانتقام منه أفضل", "speaker": "ابن العربي"}, {"t": "text", "s": "، وأما الحالة المقتضية للعفو "}, {"t": "quote", "s": "فأن تكون فلتة، أو يقع ذلك ممن يعترف بالزلة، ويسأل المغفرة؛ فالعفو أفضل"}, {"t": "text", "s": "؛ جاء في تفسير قوله تعالى: "}, {"t": "ayah", "s": "وَٱلَّذِينَ إِذَآ أَصَابَهُمُ ٱلۡبَغۡيُ هُمۡ يَنتَصِرُونَ ۝٣٩", "ayah": [39], "verses": [{"n": 39, "text": "وَٱلَّذِينَ إِذَآ أَصَابَهُمُ ٱلۡبَغۡيُ هُمۡ يَنتَصِرُونَ", "surah": 42, "ref_api": "https://api.quran.com/api/v4/verses/by_key/42:39", "surah_name": "الشورى", "ayah_canonical": 39, "match": "exact", "ref": "42:39"}], "surah": null, "ref_api": null}, {"t": "text", "s": " أي: ينتقمون ممن بغى عليهم ولا يستسلمون لظلم المعتدي؛ فهو وصف لهم بالشجاعة بعد وصفهم بسائر الفضائل، وهذا لا ينافي وصفهم بالغفران، فإن كلًا في موضعه محمود."}]}, {"type": "paragraph", "md": "ولا يجوز للمنتصِر أن يتعدى على أخيه المسلم بأكثر مما أساء إليه، ولا يحق له أن يغمطه حقه؛ فقد قال النبي صلى الله عليه وسلم : (المُسْتبَّان على البادئ منهما ما لم يعتدِ)؛ فمن اعتدى كان آثمًا بذلك.", "page": 73, "id": "unit-06__lesson-05__b06", "inline": [{"t": "text", "s": "ولا يجوز للمنتصِر أن يتعدى على أخيه المسلم بأكثر مما أساء إليه، ولا يحق له أن يغمطه حقه؛ فقد قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(المُسْتبَّان على البادئ منهما ما لم يعتدِ)", "role": "emphasis"}, {"t": "text", "s": "؛ فمن اعتدى كان آثمًا بذلك."}]}, {"type": "paragraph", "md": "والمغلوب على أمره يتأسى بنوح عليه السلام حينما عجز عن قومه: ﴿فَدَعَا رَبَّهُۥٓ أَنِّي مَغۡلُوبٞ فَٱنتَصِرۡ ۝١٠﴾، وأما القادر على الانتصار -بقيوده وشروطه الشرعية- فلا عذر له في الخنوع والاستكانة للظالمين.", "page": 73, "id": "unit-06__lesson-05__b07", "inline": [{"t": "text", "s": "والمغلوب على أمره يتأسى بنوح "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " حينما عجز عن قومه: "}, {"t": "ayah", "s": "فَدَعَا رَبَّهُۥٓ أَنِّي مَغۡلُوبٞ فَٱنتَصِرۡ ۝١٠", "ayah": [10], "verses": [{"n": 10, "text": "فَدَعَا رَبَّهُۥٓ أَنِّي مَغۡلُوبٞ فَٱنتَصِرۡ", "surah": 54, "ref_api": "https://api.quran.com/api/v4/verses/by_key/54:10", "surah_name": "القمر", "ayah_canonical": 10, "match": "exact", "ref": "54:10"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، وأما القادر على الانتصار -بقيوده وشروطه الشرعية- فلا عذر له في الخنوع والاستكانة للظالمين."}]}, {"type": "heading", "level": 3, "text": "القيود والضوابط لجواز الانتصار من الظالم:", "page": 73, "id": "unit-06__lesson-05__b08", "role": "section"}, {"type": "paragraph", "md": "- أن يكون العفو عنه يجرؤه، أو أن يكون مسترسلًا في ظلمه ومصرًا عليه. كما أن من قيود المنتصر ألا يتعدى بأكثر مما ظلم. وألا يؤدي انتصاره إلى شر أكبر من المظلمة بحسب توقعه وراجح ظنه.", "page": 73, "id": "unit-06__lesson-05__b09", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 73, "id": "unit-06__lesson-05__b10", "role": "assessment"}, {"type": "paragraph", "md": "هل تدعو الشريعة للسكوت على الظالم أم الرد عليه؟ وما ضوابط ذلك؟", "page": 73, "id": "unit-06__lesson-05__b11", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط حواري", "page": 73, "id": "unit-06__lesson-05__b12", "role": "activity"}, {"type": "paragraph", "md": "اذكر لنا موقفًا ترى أنك انتصرتَ فيه من ظالم، أو موقفًا ظلمتَ فيه واستغفر الله منه..", "page": 73, "id": "unit-06__lesson-05__b13", "item_role": "activity_step"}]' WHERE id='unit-06__lesson-05';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: ﴿قُلۡ يَٰٓأَيُّهَا ٱلۡكَٰفِرُونَ ۝١ لَآ أَعۡبُدُ مَا تَعۡبُدُونَ ۝٢ وَلَآ أَنتُمۡ عَٰبِدُونَ مَآ أَعۡبُدُ ۝٣ وَلَآ أَنَا۠ عَابِدٞ مَّا عَبَدتُّمۡ ۝٤ وَلَآ أَنتُمۡ عَٰبِدُونَ مَآ أَعۡبُدُ ۝٥ لَكُمۡ دِينُكُمۡ وَلِيَ دِينِ ۝٦﴾", "page": 74, "id": "unit-07__lesson-01__b01", "inline": [{"t": "text", "s": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: "}, {"t": "ayah", "s": "قُلۡ يَٰٓأَيُّهَا ٱلۡكَٰفِرُونَ ۝١ لَآ أَعۡبُدُ مَا تَعۡبُدُونَ ۝٢ وَلَآ أَنتُمۡ عَٰبِدُونَ مَآ أَعۡبُدُ ۝٣ وَلَآ أَنَا۠ عَابِدٞ مَّا عَبَدتُّمۡ ۝٤ وَلَآ أَنتُمۡ عَٰبِدُونَ مَآ أَعۡبُدُ ۝٥ لَكُمۡ دِينُكُمۡ وَلِيَ دِينِ ۝٦", "ayah": [1, 2, 3, 4, 5, 6], "verses": [{"n": 1, "text": "قُلۡ يَٰٓأَيُّهَا ٱلۡكَٰفِرُونَ", "surah": 109, "ref_api": "https://api.quran.com/api/v4/verses/by_key/109:1", "surah_name": "الكافرون", "ayah_canonical": 1, "match": "exact", "ref": "109:1"}, {"n": 2, "text": "لَآ أَعۡبُدُ مَا تَعۡبُدُونَ", "surah": 109, "ref_api": "https://api.quran.com/api/v4/verses/by_key/109:2", "surah_name": "الكافرون", "ayah_canonical": 2, "match": "exact", "ref": "109:2"}, {"n": 3, "text": "وَلَآ أَنتُمۡ عَٰبِدُونَ مَآ أَعۡبُدُ", "surah": 109, "ref_api": "https://api.quran.com/api/v4/verses/by_key/109:3", "surah_name": "الكافرون", "ayah_canonical": 3, "match": "exact", "ref": "109:3"}, {"n": 4, "text": "وَلَآ أَنَا۠ عَابِدٞ مَّا عَبَدتُّمۡ", "surah": 109, "ref_api": "https://api.quran.com/api/v4/verses/by_key/109:4", "surah_name": "الكافرون", "ayah_canonical": 4, "match": "exact", "ref": "109:4"}, {"n": 5, "text": "وَلَآ أَنتُمۡ عَٰبِدُونَ مَآ أَعۡبُدُ", "surah": 109, "ref_api": "https://api.quran.com/api/v4/verses/by_key/109:5", "surah_name": "الكافرون", "ayah_canonical": 5, "match": "exact", "ref": "109:5"}, {"n": 6, "text": "لَكُمۡ دِينُكُمۡ وَلِيَ دِينِ", "surah": 109, "ref_api": "https://api.quran.com/api/v4/verses/by_key/109:6", "surah_name": "الكافرون", "ayah_canonical": 6, "match": "exact", "ref": "109:6"}], "surah": null, "ref_api": null}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 74, "id": "unit-07__lesson-01__b02", "role": "objectives"}, {"type": "paragraph", "md": "معرفة فضل سورة الكافرون، ومقاصدها، وأهم موضوعاتها.", "page": 74, "id": "unit-07__lesson-01__b03"}, {"type": "paragraph", "md": "معرفة المعنى الإجمالي لسورة الكافرون، والفوائد التربوية والعلمية.", "page": 74, "id": "unit-07__lesson-01__b04"}, {"type": "paragraph", "md": "حفظ السورة بضبط وإتقان.", "page": 74, "id": "unit-07__lesson-01__b05"}, {"type": "heading", "level": 3, "text": "فضل السورة:", "page": 74, "id": "unit-07__lesson-01__b06", "role": "virtues"}, {"type": "paragraph", "md": "1-يستحب قراءتها عند النوم، وهي براءة من الشرك؛ فعن نوفل الأشجعي رضي الله عنه ، أن النبي صلى الله عليه وسلم قال له: (اقرأ عند منامك قل يا أيها الكافرون، قال: ثم نم على خاتمتها؛ فإنها براءة من الشرك).", "page": 74, "id": "unit-07__lesson-01__b07", "inline": [{"t": "text", "s": "1-يستحب قراءتها عند النوم، وهي براءة من الشرك؛ فعن نوفل الأشجعي "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ، أن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قال له: "}, {"t": "emphasis", "s": "(اقرأ عند منامك قل يا أيها الكافرون، قال: ثم نم على خاتمتها؛ فإنها براءة من الشرك)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "2- كان النبي صلى الله عليه وسلم يقرأ بها وبـ﴿قُلۡ هُوَ ٱللَّهُ أَحَدٌ﴾ في ركعتي الفجر، فعن أبي هريرة رضي الله عنه : (أن رسول الله صلى الله عليه وسلم قرأ في ركعتي الفجر: قل يا أيها الكافرون وقل هو الله أحد).", "page": 74, "id": "unit-07__lesson-01__b08", "inline": [{"t": "text", "s": "2- كان النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يقرأ بها وبـ"}, {"t": "ayah", "s": "قُلۡ هُوَ ٱللَّهُ أَحَدٌ", "ayah": [], "verses": [{"n": 1, "text": "قُلۡ هُوَ ٱللَّهُ أَحَدٌ", "surah": 112, "surah_name": "الإخلاص", "ref": "112:1", "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:1"}], "surah": 112, "ref_api": "https://api.quran.com/api/v4/verses/by_key/112:1", "surah_name": "الإخلاص", "ayah_canonical": 1, "match": "exact", "ref": "112:1"}, {"t": "text", "s": " في ركعتي الفجر، فعن أبي هريرة "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(أن رسول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "قرأ في ركعتي الفجر: قل يا أيها الكافرون وقل هو الله أحد)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "وعن عائشة رضي الله عنها ، قالت: كان رسول الله صلى الله عليه وسلم يصلي ركعتين قبل الفجر، وكان يقول: (نعم السورتان هما، تقرؤونهما في الركعتين قبل الفجر: قل يا أيها الكافرون، وقل هو الله أحد).", "page": 74, "id": "unit-07__lesson-01__b09", "inline": [{"t": "text", "s": "وعن عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " ، قالت: كان رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يصلي ركعتين قبل الفجر، وكان يقول: "}, {"t": "emphasis", "s": "(نعم السورتان هما، تقرؤونهما في الركعتين قبل الفجر: قل يا أيها الكافرون، وقل هو الله أحد)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "مقصد السورة، وأهم الموضوعات التي اشتملت عليها:", "page": 74, "id": "unit-07__lesson-01__b10", "role": "main_themes"}, {"type": "paragraph", "md": "من أهم مقاصد هذه السورة: البراءة المطلقة بين الموحدين والمشركين.", "page": 74, "id": "unit-07__lesson-01__b11", "inline": [{"t": "emphasis", "s": "من أهم مقاصد هذه السورة", "role": "emphasis"}, {"t": "text", "s": ": البراءة المطلقة بين الموحدين والمشركين."}]}, {"type": "paragraph", "md": "ومن أهم الموضوعات التي اشتملت عليها هذه السورة: أمر الله تعالى نبيه صلى الله عليه وسلم أن يعلن براءته من الكافرين، وأن ينفي عبادته لمعبوداتهم الباطلة، وينفي أن يكونوا عابدين للإله الحق الذي يعبده، وأن يعلن براءته من دينهم، فلهم دينهم وله دينه.", "page": 74, "id": "unit-07__lesson-01__b12", "inline": [{"t": "emphasis", "s": "ومن أهم الموضوعات التي اشتملت عليها هذه السورة", "role": "emphasis"}, {"t": "text", "s": ": أمر الله تعالى نبيه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أن يعلن براءته من الكافرين، وأن ينفي عبادته لمعبوداتهم الباطلة، وينفي أن يكونوا عابدين للإله الحق الذي يعبده، وأن يعلن براءته من دينهم، فلهم دينهم وله دينه."}]}, {"type": "heading", "level": 3, "text": "المعنى الإجمالي:", "page": 74, "id": "unit-07__lesson-01__b13", "role": "overall_meaning"}, {"type": "paragraph", "md": "افتتح الله تعالى هذه السورة الكريمة مخاطبا نبيه صلى الله عليه وسلم ، بقوله تعالى: قل -يا محمد- لجميع الكافرين معلنا البراءة من دينهم وعبادتهم: يا أيها الكافرون بالله، لا أعبد ما تعبدونه الآن، ولا أنتم -أيها الكافرون ما دمتم مستمرين على ضلالكم- عابدون الله الذي أعبده، ولا أنا عابد ما عبدتموه من معبودات باطلة، ولا أنتم عابدون الله الذي أعبده؛ فلكم دينكم الذي تبرأت منه، ولي دين الإسلام والتوحيد.", "page": 75, "id": "unit-07__lesson-01__b14", "inline": [{"t": "text", "s": "افتتح الله تعالى هذه السورة الكريمة مخاطبا نبيه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، بقوله تعالى: قل -يا محمد- لجميع الكافرين معلنا البراءة من دينهم وعبادتهم: يا أيها الكافرون بالله، لا أعبد ما تعبدونه الآن، ولا أنتم -أيها الكافرون ما دمتم مستمرين على ضلالكم- عابدون الله الذي أعبده، ولا أنا عابد ما عبدتموه من معبودات باطلة، ولا أنتم عابدون الله الذي أعبده؛ فلكم دينكم الذي تبرأت منه، ولي دين الإسلام والتوحيد."}]}, {"type": "heading", "level": 3, "text": "الفوائد التربوية:", "page": 75, "id": "unit-07__lesson-01__b15", "role": "benefits"}, {"type": "paragraph", "md": "1- في هذه السورة منهج إصلاحي، وهو عدم قبول أنصاف الحلول؛ لأن ما عرضه المشركون على النبي صلى الله عليه وسلم من المشاركة في العبادة -على ما قيل في سبب نزولها- يعتبر في مقياس المنطق حلًّا وسطا؛ لاحتمال إصابة الحق في أحد الجانبين، فجاء الرد حاسما وزاجرا وبشدة؛ لأن فيما عرضوه مساواة للباطل بالحق، وفيه تعليق المشكلة، وفيه إقرار بالباطل إن هو وافقهم ولو لحظة.", "page": 75, "id": "unit-07__lesson-01__b16", "inline": [{"t": "text", "s": "1- في هذه السورة منهج إصلاحي، وهو عدم قبول أنصاف الحلول؛ لأن ما عرضه المشركون على النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " من المشاركة في العبادة -على ما قيل في سبب نزولها- يعتبر في مقياس المنطق حلًّا وسطا؛ لاحتمال إصابة الحق في أحد الجانبين، فجاء الرد حاسما وزاجرا وبشدة؛ لأن فيما عرضوه مساواة للباطل بالحق، وفيه تعليق المشكلة، وفيه إقرار بالباطل إن هو وافقهم ولو لحظة."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- قوله تعالى: ﴿ٱلۡكَٰفِرُونَ﴾ يشمل كل كافر، سواء كان من المشركين، أو اليهود، أو النصارى، أو الشيوعيين.. الخ، فكل كافر يجب أن تناديه بقلبك أو بلسانك -إن كان حاضرا-؛ لتتبرأ منه ومن عبادته.", "page": 75, "id": "unit-07__lesson-01__b17", "inline": [{"t": "text", "s": "2- قوله تعالى: "}, {"t": "ayah", "s": "ٱلۡكَٰفِرُونَ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": " يشمل كل كافر، سواء كان من المشركين، أو اليهود، أو النصارى، أو الشيوعيين.. الخ، فكل كافر يجب أن تناديه بقلبك أو بلسانك -إن كان حاضرا-؛ لتتبرأ منه ومن عبادته."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "الفوائد العلمية واللطائف:", "page": 75, "id": "unit-07__lesson-01__b18", "role": "benefits"}, {"type": "paragraph", "md": "1- سورتا الكافرون والإخلاص هما سورتا الإخلاص؛ فـ﴿ٱلۡكَٰفِرُونَ﴾ فيها إخلاص القصد، والإخلاص فيها إخلاص العقيدة؛ فالتوحيد في سورة الإخلاص علمي عقدي، وفي سورة الكافرون عملي إرادي.", "page": 75, "id": "unit-07__lesson-01__b19", "inline": [{"t": "text", "s": "1- سورتا الكافرون والإخلاص هما سورتا الإخلاص؛ فـ"}, {"t": "ayah", "s": "ٱلۡكَٰفِرُونَ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": " فيها إخلاص القصد، والإخلاص فيها إخلاص العقيدة؛ فالتوحيد في سورة الإخلاص علمي عقدي، وفي سورة الكافرون عملي إرادي."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2-قوله تعالى: ﴿لَكُمۡ دِينُكُمۡ وَلِيَ دِينِ﴾ هذه كلمة تقتضي براءته من دينهم، ولا تقتضي رضاه بذلك، كما قال تعالى في الآية الأخرى: ﴿وَإِن كَذَّبُوكَ فَقُل لِّي عَمَلِي وَلَكُمۡ عَمَلُكُمۡۖ أَنتُم بَرِيٓـُٔونَ مِمَّآ أَعۡمَلُ وَأَنَا۠ بَرِيٓءٞ مِّمَّا تَعۡمَلُونَ ۝٤١﴾؛ ومن ظن من الملاحدة أن هذا رضا منه بدين الكفار فهو من أكذب الناس وأكفرهم.", "page": 75, "id": "unit-07__lesson-01__b20", "inline": [{"t": "text", "s": "2-قوله تعالى: "}, {"t": "ayah", "s": "لَكُمۡ دِينُكُمۡ وَلِيَ دِينِ", "ayah": [], "verses": [{"n": 6, "text": "لَكُمۡ دِينُكُمۡ وَلِيَ دِينِ", "surah": 109, "surah_name": "الكافرون", "ref": "109:6", "ref_api": "https://api.quran.com/api/v4/verses/by_key/109:6"}], "surah": 109, "ref_api": "https://api.quran.com/api/v4/verses/by_key/109:6", "surah_name": "الكافرون", "ayah_canonical": 6, "match": "exact", "ref": "109:6"}, {"t": "text", "s": " هذه كلمة تقتضي براءته من دينهم، ولا تقتضي رضاه بذلك، كما قال تعالى في الآية الأخرى: "}, {"t": "ayah", "s": "وَإِن كَذَّبُوكَ فَقُل لِّي عَمَلِي وَلَكُمۡ عَمَلُكُمۡۖ أَنتُم بَرِيٓـُٔونَ مِمَّآ أَعۡمَلُ وَأَنَا۠ بَرِيٓءٞ مِّمَّا تَعۡمَلُونَ ۝٤١", "ayah": [41], "verses": [{"n": 41, "text": "وَإِن كَذَّبُوكَ فَقُل لِّي عَمَلِي وَلَكُمۡ عَمَلُكُمۡۖ أَنتُم بَرِيٓـُٔونَ مِمَّآ أَعۡمَلُ وَأَنَا۠ بَرِيٓءٞ مِّمَّا تَعۡمَلُونَ", "surah": 10, "ref_api": "https://api.quran.com/api/v4/verses/by_key/10:41", "surah_name": "يونس", "ayah_canonical": 41, "match": "exact", "ref": "10:41"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ ومن ظن من الملاحدة أن هذا رضا منه بدين الكفار فهو من أكذب الناس وأكفرهم."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 75, "id": "unit-07__lesson-01__b21", "role": "assessment"}, {"type": "paragraph", "md": "1- ما موضوع سورة الكافرون، ومن هم الكافرون المقصودون في السورة؟", "page": 75, "id": "unit-07__lesson-01__b22", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- اذكر فائدة تربوية وأخرى علمية تعلمتها من سورة الكافرون.", "page": 75, "id": "unit-07__lesson-01__b23", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- كيف نستفيد من السورة المباركة الثبات على الدين وعدم التنازل للكفار.", "page": 75, "id": "unit-07__lesson-01__b24", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "نشاط بحثي", "page": 75, "id": "unit-07__lesson-01__b25", "role": "activity"}, {"type": "paragraph", "md": "اقرأ تفسير سورة الكافرون من المختصر في التفسير أو تفسير السعدي واكتب أهم الفوائد التي أعجبتك.", "page": 75, "id": "unit-07__lesson-01__b26", "item_role": "activity_step"}, {"type": "paragraph", "md": "تفكر وانظر في كتب التفسير: لماذا كرر الله سبحانه وتعالى قوله: ﴿وَلَآ أَنتُمۡ عَٰبِدُونَ مَآ أَعۡبُدُ ۝٣ - 5﴾ مرتين.", "page": 75, "id": "unit-07__lesson-01__b27", "inline": [{"t": "text", "s": "تفكر وانظر في كتب التفسير: لماذا كرر الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " قوله: "}, {"t": "ayah", "s": "وَلَآ أَنتُمۡ عَٰبِدُونَ مَآ أَعۡبُدُ ۝٣ - 5", "ayah": [3], "verses": [{"n": 3, "text": "وَلَآ أَنتُمۡ عَٰبِدُونَ مَآ أَعۡبُدُ", "surah": 109, "ref_api": "https://api.quran.com/api/v4/verses/by_key/109:3", "surah_name": "الكافرون", "ayah_canonical": 3, "match": "exact", "ref": "109:3"}], "surah": null, "ref_api": null}, {"t": "text", "s": " مرتين."}], "item_role": "activity_step"}]' WHERE id='unit-07__lesson-01';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "عن سَلَمَةَ بن نُفَيْلٍ الكِنْديّ رضي الله عنه قال: كنتُ جالسًا عند رسول الله صلى الله عليه وسلم ، فقال رجلٌ: يا رسولَ الله، أذالَ النَّاسُ الخَيْلَ، ووضَعُوا السلاح، وقالوا: لا جِهادَ، قد وضَعَتِ الحرب أوزارَها، فأقبلَ رسولُ الله صلى الله عليه وسلم بوجهه، وقال: (كَذَبُوا، الآنَ ‌الآنَ ‌جاءَ ‌القتال، ولا يزالُ من أمَّتي أمَّةٌ يُقاتِلونَ على الحَقِّ، ويُزِيعُ اللهُ لهم قلوبَ أقوام، ويرزقُهم منهم حتى تقومَ السَّاعة، وحتى يأتي وَعْدُ الله، والخيلُ معقودٌ في نَواصِيها الخيرُ إلى يومِ القيامة، وهو يُوحَى إِليَّ أَنِّي مقبوضٌ غيرُ مُلَبَّث، وأنتم تَتَّبَعُوني أَفْنادًا يضربُ بعضُكم رِقابَ بعض، وعُقْرُ دارِ المؤمنينَ الشَّام) [النسائي، وصححه الألباني].", "page": 76, "id": "unit-07__lesson-02__b01", "inline": [{"t": "text", "s": "عن سَلَمَةَ بن نُفَيْلٍ الكِنْديّ "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: كنتُ جالسًا عند رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، فقال رجلٌ: يا رسولَ الله، أذالَ النَّاسُ الخَيْلَ، ووضَعُوا السلاح، وقالوا: لا جِهادَ، قد وضَعَتِ الحرب أوزارَها، فأقبلَ رسولُ الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بوجهه، وقال: (كَذَبُوا، الآنَ ‌الآنَ ‌جاءَ ‌القتال، ولا يزالُ من أمَّتي أمَّةٌ يُقاتِلونَ على الحَقِّ، ويُزِيعُ اللهُ لهم قلوبَ أقوام، ويرزقُهم منهم حتى تقومَ السَّاعة، وحتى يأتي وَعْدُ الله، والخيلُ معقودٌ في نَواصِيها الخيرُ إلى يومِ القيامة، وهو يُوحَى إِليَّ أَنِّي مقبوضٌ غيرُ مُلَبَّث، وأنتم تَتَّبَعُوني أَفْنادًا يضربُ بعضُكم رِقابَ بعض، وعُقْرُ دارِ المؤمنينَ الشَّام) [النسائي، وصححه الألباني]."}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 76, "id": "unit-07__lesson-02__b02", "role": "objectives"}, {"type": "paragraph", "md": "معرفة أنَّ الجهاد مستمر في هذه الأمة، وخاصة في الشام؛ فلا يوقفه بطش كافر ولا جور جائر.", "page": 76, "id": "unit-07__lesson-02__b03"}, {"type": "paragraph", "md": "معرفة حكم الجهاد في هذا الزمان وأنَّه فرض عين على كل مسلم رجل قادر على حمل السلاح.", "page": 76, "id": "unit-07__lesson-02__b04"}, {"type": "paragraph", "md": "معرفة أن الفتنة بين المسلمين والخلافات الداخلية لا تمنع من قتال الكفار.", "page": 76, "id": "unit-07__lesson-02__b05"}, {"type": "paragraph", "md": "معرفة فضل الشام وبركتها، وأنها موئل المؤمنين وعقر دار الموحدين.", "page": 76, "id": "unit-07__lesson-02__b06"}, {"type": "heading", "level": 3, "text": "التعريف براوي الحديث:", "page": 76, "id": "unit-07__lesson-02__b07", "role": "definitions"}, {"type": "paragraph", "md": "سلمة بن نُفَيْل الكِنْدِي الحضرمي الشَّامِي: صحابي يمني، نزل في حمص واستقرَّ بها، فصار معدودًا في أهل الشام رضي الله عنه ، وهو من المقلين في الرواية فليس له سوى حديث أو اثنين عن النبي صلى الله عليه وسلم .", "page": 76, "id": "unit-07__lesson-02__b08", "inline": [{"t": "emphasis", "s": "سلمة بن نُفَيْل الكِنْدِي الحضرمي الشَّامِي:", "role": "lemma"}, {"t": "text", "s": " صحابي يمني، نزل في حمص واستقرَّ بها، فصار معدودًا في أهل الشام "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ، وهو من المقلين في الرواية فليس له سوى حديث أو اثنين عن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "heading", "level": 3, "text": "شرح الحديث:", "page": 76, "id": "unit-07__lesson-02__b09", "role": "hadith_explanation"}, {"type": "paragraph", "md": "قولهم: (أذال الناس الخيل) أي أهانوها بالرغبة عنها وتركها، وإذالة الخيل: امتهانها بالعمل والحمل عليها، وعدم جعلها في القتال والنزال، ومثله: (وضعوا السلاح) أي تركوا القتال به.", "page": 76, "id": "unit-07__lesson-02__b10", "inline": [{"t": "text", "s": "قولهم: "}, {"t": "emphasis", "s": "(أذال الناس الخيل)", "role": "lemma"}, {"t": "text", "s": " أي أهانوها بالرغبة عنها وتركها، وإذالة الخيل: امتهانها بالعمل والحمل عليها، وعدم جعلها في القتال والنزال، ومثله: "}, {"t": "emphasis", "s": "(وضعوا السلاح)", "role": "lemma"}, {"t": "text", "s": " أي تركوا القتال به."}]}, {"type": "paragraph", "md": "قولهم: (‌وضعت ‌الحرب ‌أوزارها) عبارة عن انقضائها وانتهائها؛ لأنَّ أهلها يضعون أسلحتهم حينئذ حيثُ لم يبقَ قتال، وسُمِّيَ السلاح وِزرًا لأنه يثقل على لابسه.", "page": 76, "id": "unit-07__lesson-02__b11", "inline": [{"t": "text", "s": "قولهم: "}, {"t": "emphasis", "s": "(‌وضعت ‌الحرب ‌أوزارها)", "role": "lemma"}, {"t": "text", "s": " عبارة عن انقضائها وانتهائها؛ لأنَّ أهلها يضعون أسلحتهم حينئذ حيثُ لم يبقَ قتال، وسُمِّيَ السلاح وِزرًا لأنه يثقل على لابسه."}]}, {"type": "paragraph", "md": "قوله صلى الله عليه وسلم (الآن جَاءَ الْقِتَالُ) أي: شرع اللَّه تعالى القتال الآن، فكيف يُرفع عنهم سريعًا. أو المعنى: بل الآن اشتدَّ القتال، فإنهم قبل ذلك كانوا في أرضهم، واليوم جاء وقت الخروج إلى الأراضي البعيدة.", "page": 76, "id": "unit-07__lesson-02__b12", "inline": [{"t": "text", "s": "قوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "(الآن جَاءَ الْقِتَالُ)", "role": "lemma"}, {"t": "text", "s": " أي: شرع اللَّه تعالى القتال الآن، فكيف يُرفع عنهم سريعًا. أو المعنى: بل الآن اشتدَّ القتال، فإنهم قبل ذلك كانوا في أرضهم، واليوم جاء وقت الخروج إلى الأراضي البعيدة."}]}, {"type": "paragraph", "md": "وقوله (‌يُزيغ الله قلوبَ أقوام) من أَزَاغ: إذا مال، والغالبُ استعماله في الميلِ عن الحق إلى الباطل، والمراد: يُمِيلُ الله ‌قلوبَ ‌أقوامٍ عن الإيمان إلى الكفر ليُقاتلوهم، ويأخذوا مالهم ويستمر جهادهم. أو أن المراد: يُميل اللهُ ‌قلوبَ ‌أقوام من الأمة إليهم؛ ليُعينوهم على قتال عدوهم، فالمرادُ على هذا بالأمةِ: الرؤساءُ، وبالأقوامِ: الأتباعُ، وأما على المعنى الأول؛ فالمرادُ بالأمة المجاهدون، وبالأقوامِ الكفرةُ.", "page": 77, "id": "unit-07__lesson-02__b13", "inline": [{"t": "text", "s": "وقوله "}, {"t": "emphasis", "s": "(‌يُزيغ الله قلوبَ أقوام)", "role": "lemma"}, {"t": "text", "s": " من أَزَاغ: إذا مال، والغالبُ استعماله في الميلِ عن الحق إلى الباطل، والمراد: يُمِيلُ الله ‌قلوبَ ‌أقوامٍ عن الإيمان إلى الكفر ليُقاتلوهم، ويأخذوا مالهم ويستمر جهادهم. أو أن المراد: يُميل اللهُ ‌قلوبَ ‌أقوام من الأمة إليهم؛ ليُعينوهم على قتال عدوهم، فالمرادُ على هذا بالأمةِ: الرؤساءُ، وبالأقوامِ: الأتباعُ، وأما على المعنى الأول؛ فالمرادُ بالأمة المجاهدون، وبالأقوامِ الكفرةُ."}]}, {"type": "paragraph", "md": "قوله (وَالْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ) الناصية: الشعر النازل على الجبهة، وهي مقدم الخيل فيكون المقصود بذلك الخيل كله، والخير المراد في الخيل يكون في (الأجر والمغنم) كما في حديثٍ آخر، ويَدخل في ذلك اليوم: كل من جمع هذين الوصفين للمجاهد؛ كالسلاح والمركب الخاص بالجهاد كالميتور الجبلي والشاص؛ إذا حبسه المرء بنية الجهاد في سبيل الله، ففي الصحيح: (الخيل في نواصيها الخير معقود إلى يوم القيامة، فمن ربطها عُدّةً في سبيل اللَّه، وأنفق عليها احتسابًا، كان شبعها، وجوعها، وريُّها، وظمؤها، وأرواثها، وأبوالُها فلاحًا في موازينه يوم القيامة).", "page": 77, "id": "unit-07__lesson-02__b14", "inline": [{"t": "text", "s": "قوله "}, {"t": "emphasis", "s": "(وَالْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ)", "role": "lemma"}, {"t": "text", "s": " الناصية: الشعر النازل على الجبهة، وهي مقدم الخيل فيكون المقصود بذلك الخيل كله، والخير المراد في الخيل يكون في "}, {"t": "emphasis", "s": "(الأجر والمغنم)", "role": "lemma"}, {"t": "text", "s": " كما في حديثٍ آخر، ويَدخل في ذلك اليوم: كل من جمع هذين الوصفين للمجاهد؛ كالسلاح والمركب الخاص بالجهاد كالميتور الجبلي والشاص؛ إذا حبسه المرء بنية الجهاد في سبيل الله، ففي الصحيح: "}, {"t": "emphasis", "s": "(الخيل في نواصيها الخير معقود إلى يوم القيامة، فمن ربطها عُدّةً في سبيل اللَّه، وأنفق عليها احتسابًا، كان شبعها، وجوعها، وريُّها، وظمؤها، وأرواثها، وأبوالُها فلاحًا في موازينه يوم القيامة)", "role": "lemma"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "قوله (وَهُوَ يُوحَى إِلَيّ أنِّي مَقْبُوضٌ غَيْرُ مُلَبَّثِ) أي أوحى الله إليَّ كوني ميتًا عن قريب، غير مؤخّر في الدنيا، بل أنتقل للدار الآخرة (وَأَنْتُمْ تَتَّبِعُونِي) أي تكونون بعدي، فإن التابع يكون بعد المتبوع، وتلحقون بي بالموت (أَفْنَادًا) جمع فِنْد؛ أي جماعات متفرقين، قومًا بعد قوم.", "page": 77, "id": "unit-07__lesson-02__b15", "inline": [{"t": "text", "s": "قوله "}, {"t": "emphasis", "s": "(وَهُوَ يُوحَى إِلَيّ أنِّي مَقْبُوضٌ غَيْرُ مُلَبَّثِ)", "role": "lemma"}, {"t": "text", "s": " أي أوحى الله إليَّ كوني ميتًا عن قريب، غير مؤخّر في الدنيا، بل أنتقل للدار الآخرة "}, {"t": "emphasis", "s": "(وَأَنْتُمْ تَتَّبِعُونِي)", "role": "lemma"}, {"t": "text", "s": " أي تكونون بعدي، فإن التابع يكون بعد المتبوع، وتلحقون بي بالموت "}, {"t": "emphasis", "s": "(أَفْنَادًا)", "role": "lemma"}, {"t": "text", "s": " جمع فِنْد؛ أي جماعات متفرقين، قومًا بعد قوم."}]}, {"type": "paragraph", "md": "قوله (يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ) أي سيتبعه كثير من الصحابة بعد فتنةٍ تقع بينهم، وقد حصل ذلك بين علي ومعاوية رضي الله عنهما ؛ في معركة صفين والجمل، وهي فتنة وقى الله أسيافنا شرها، فلا نخوض فيها بألسنتنا، ونترضى عن كل الصحابة قاتلهم ومقتولهم، ونراهم متأولين يدورون بين الأجر والأجرين.", "page": 77, "id": "unit-07__lesson-02__b16", "inline": [{"t": "text", "s": "قوله "}, {"t": "emphasis", "s": "(يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ)", "role": "lemma"}, {"t": "text", "s": " أي سيتبعه كثير من الصحابة بعد فتنةٍ تقع بينهم، وقد حصل ذلك بين علي ومعاوية "}, {"t": "honorific", "s": "رضي الله عنهما"}, {"t": "text", "s": " ؛ في معركة صفين والجمل، وهي فتنة وقى الله أسيافنا شرها، فلا نخوض فيها بألسنتنا، ونترضى عن كل الصحابة قاتلهم ومقتولهم، ونراهم متأولين يدورون بين الأجر والأجرين."}]}, {"type": "paragraph", "md": "قوله (وعُقْرُ دَارِ الْمُؤْمِنِينَ الشَّامُ) أي أصل دارهم، وموضعها؛ كأنه أشار إلى وقت الفتن، فتكون الشام يومئذ أمنًا من كل فتنة، وأهل الإسلام بها أسلم من خارجها، وهذه فضيلة عظيمة للشام وأهلها.", "page": 77, "id": "unit-07__lesson-02__b17", "inline": [{"t": "text", "s": "قوله "}, {"t": "emphasis", "s": "(وعُقْرُ دَارِ الْمُؤْمِنِينَ الشَّامُ)", "role": "lemma"}, {"t": "text", "s": " أي أصل دارهم، وموضعها؛ كأنه أشار إلى وقت الفتن، فتكون الشام يومئذ أمنًا من كل فتنة، وأهل الإسلام بها أسلم من خارجها، وهذه فضيلة عظيمة للشام وأهلها."}]}, {"type": "heading", "level": 3, "text": "فوائد ومسائل في الحديث النبوي الشريف:", "page": 77, "id": "unit-07__lesson-02__b18", "role": "benefits"}, {"type": "paragraph", "md": "القتال أخص أوصاف أهل الطائفة المنصورة؛ فهو شعارهم ودثارهم، ودنياهم وآخرتهم؛ عَكفوا عليه، وتنادوا إليه: فكان التسابق: زرافاتٍ ووحدانًا، وعبر عن هذه الصفة بلفظ «القتال» وليس «الجهاد»؛ قطعًا للطريق على من أُشربوا في قلوبهم حب التأويل -وحقيقته التحريف-؛ ليمنعهم من تحريف هذه الصفة عن حقيقتها اتباعا لشهواتهم وشبهاتهم؛ فيضعهم في مواجهة أنفسهم: إما القيام بأمر الله وتحقيق شرط صحة النسبة للطائفة المنصورة وأهلها، وإما التخاذل؛ الذي يبطل به نسبتهم لها، وانكشاف ادعائهم.", "page": 77, "id": "unit-07__lesson-02__b19", "inline": [{"t": "emphasis", "s": "القتال أخص أوصاف أهل الطائفة المنصورة", "role": "emphasis"}, {"t": "text", "s": "؛ فهو شعارهم ودثارهم، ودنياهم وآخرتهم؛ عَكفوا عليه، وتنادوا إليه: فكان التسابق: زرافاتٍ ووحدانًا، وعبر عن هذه الصفة بلفظ "}, {"t": "quote", "s": "القتال"}, {"t": "text", "s": " وليس "}, {"t": "quote", "s": "الجهاد"}, {"t": "text", "s": "؛ قطعًا للطريق على من أُشربوا في قلوبهم حب التأويل -وحقيقته التحريف-؛ ليمنعهم من تحريف هذه الصفة عن حقيقتها اتباعا لشهواتهم وشبهاتهم؛ فيضعهم في مواجهة أنفسهم: إما القيام بأمر الله وتحقيق شرط صحة النسبة للطائفة المنصورة وأهلها، وإما التخاذل؛ الذي يبطل به نسبتهم لها، وانكشاف ادعائهم."}]}, {"type": "paragraph", "md": "في قوله (فأقبلَ رسولُ الله صلى الله عليه وسلم بوجهه) دليل على أدب نبوي، بأن يواجه المرء من يخاطبه بكليته، ولا يكلمه بطرف رأسه فقط؛ فإذا كان الخطاب مواجهة أثَّرَ في نفوس المخاطَبِين.", "page": 78, "id": "unit-07__lesson-02__b20", "inline": [{"t": "text", "s": "في قوله "}, {"t": "emphasis", "s": "(فأقبلَ رسولُ الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "بوجهه)", "role": "emphasis"}, {"t": "text", "s": " دليل على أدب نبوي، بأن يواجه المرء من يخاطبه بكليته، ولا يكلمه بطرف رأسه فقط؛ فإذا كان الخطاب مواجهة أثَّرَ في نفوس المخاطَبِين."}]}, {"type": "paragraph", "md": "إذا كان القائل في زمن الفتوح إن الجهاد قد توقف كاذب؛ فكيفَ في زماننا هذا الذي احتُلت به ديار الإسلام، واغتصبت النساء، ومُلئت السجون بأسرى المسلمين، وغُيبت الشريعة عن الحكم؟! لا شك أنَّ الجهاد اليوم بإجماع المسلمين فرضُ عين، لا يختلف في ذلك عالمٌ بالشريعة وأحوال الأمة.", "page": 78, "id": "unit-07__lesson-02__b21"}, {"type": "paragraph", "md": "في آخر الحديث يُخبر صلى الله عليه وسلم عن وقوع فتنة بين الصحابة، وفي مطلعه يذكر أنَّ الجهاد باقٍ إلى قيام الساعة؛ مما يدل على أن الفتنة بين المسلمين لا تُوقف الجهاد وليست عذرًا لإلقاء السلاح؛ فيقاتل المسلمُ مع البر والفاجر ضد الكفار، ولا تمنعه المظالم بين المسلمين من قتال الكافرين؛ لكن هذا لا يُبيح له أن يشارك الأمراء في ظلمهم، ففي الصحيح قال صلى الله عليه وسلم : (إنه ستكون أمراء تعرفون وتنكرون؛ فمن أنكر، فقد برئ، ومن كره، فقد سلم، ‌ولكن ‌من ‌رضي ‌وتابع)، فيُنكر المسلمُ الباطلَ الواقع من الأمراء ولا يفعله معهم، ولكنه في نفس الوقت يكون معهم في المعروف والخير، وعلى رأس المعروف: قتال الكفار.", "page": 78, "id": "unit-07__lesson-02__b22", "inline": [{"t": "text", "s": "في آخر الحديث يُخبر "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " عن وقوع فتنة بين الصحابة، وفي مطلعه يذكر أنَّ الجهاد باقٍ إلى قيام الساعة؛ مما يدل على أن الفتنة بين المسلمين لا تُوقف الجهاد وليست عذرًا لإلقاء السلاح؛ فيقاتل المسلمُ مع البر والفاجر ضد الكفار، ولا تمنعه المظالم بين المسلمين من قتال الكافرين؛ لكن هذا لا يُبيح له أن يشارك الأمراء في ظلمهم، ففي الصحيح قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إنه ستكون أمراء تعرفون وتنكرون؛ فمن أنكر، فقد برئ، ومن كره، فقد سلم، ‌ولكن ‌من ‌رضي ‌وتابع)", "role": "emphasis"}, {"t": "text", "s": "، فيُنكر المسلمُ الباطلَ الواقع من الأمراء ولا يفعله معهم، ولكنه في نفس الوقت يكون معهم في المعروف والخير، وعلى رأس المعروف: قتال الكفار."}]}, {"type": "paragraph", "md": "للشام فضائل كثيرة منها: أنها أرض مباركة في الدين والدنيا كما ثبت في خمس آيات من القرآن الكريم، والملائكة تبسط أجنحتها على الشام، وقد تكفل الله بالشام وأهله، وإن عمود الكتاب والإسلام بالشام، وهي أرض الطائفة المنصورة، وقد أوصى النبي صلى الله عليه وسلم بالتوجه إليها، واعتبرها من خير المدائن، وفيها ينزل عيسى ابن مريم عليه السلام ، وهي عُقر دار المؤمنين، وفيها يهلك المسيح الدجال.", "page": 78, "id": "unit-07__lesson-02__b23", "inline": [{"t": "text", "s": "للشام فضائل كثيرة منها: أنها أرض مباركة في الدين والدنيا كما ثبت في خمس آيات من القرآن الكريم، والملائكة تبسط أجنحتها على الشام، وقد تكفل الله بالشام وأهله، وإن عمود الكتاب والإسلام بالشام، وهي أرض الطائفة المنصورة، وقد أوصى النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بالتوجه إليها، واعتبرها من خير المدائن، وفيها ينزل عيسى ابن مريم "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " ، وهي عُقر دار المؤمنين، وفيها يهلك المسيح الدجال."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 78, "id": "unit-07__lesson-02__b24", "role": "assessment"}, {"type": "paragraph", "md": "اشرح العبارات الآتية: (أذال الناس الخيل - يزيغ الله لهم قلوب أقوم).", "page": 78, "id": "unit-07__lesson-02__b25", "inline": [{"t": "text", "s": "اشرح العبارات الآتية: "}, {"t": "emphasis", "s": "(أذال الناس الخيل - يزيغ الله لهم قلوب أقوم)", "role": "emphasis"}, {"t": "text", "s": "."}], "item_role": "question"}, {"type": "paragraph", "md": "هل الفتنة التي تفع بين المسلمين، والمظالم الحاصلة من الأمراء: سبب شرعي لترك الجهاد؟", "page": 78, "id": "unit-07__lesson-02__b26", "item_role": "question"}, {"type": "paragraph", "md": "اذكر أدبًا نبويا تعلمتَه من هذا الحديث.", "page": 78, "id": "unit-07__lesson-02__b27", "item_role": "question"}, {"type": "paragraph", "md": "اذكر ثلاث فضائل للشام وأهلها، من حفظك.", "page": 78, "id": "unit-07__lesson-02__b28", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط في قراءة كتاب", "page": 78, "id": "unit-07__lesson-02__b29", "role": "activity"}, {"type": "paragraph", "md": "اقرأ كتاب: «الدفاع عن أراضي المسلمين أهم فروض الأعيان» للشيخ عبد الله عزام، ولخِّص فكرتَه لإخوانك، ثم أجب في المجلس القادم على سؤال: ما حكم الجهاد اليوم؟! كما في الكتاب..", "page": 78, "id": "unit-07__lesson-02__b30", "inline": [{"t": "text", "s": "اقرأ كتاب: "}, {"t": "quote", "s": "الدفاع عن أراضي المسلمين أهم فروض الأعيان"}, {"t": "text", "s": " للشيخ عبد الله عزام، ولخِّص فكرتَه لإخوانك، ثم أجب في المجلس القادم على سؤال: ما حكم الجهاد اليوم؟! كما في الكتاب.."}], "item_role": "activity_step"}]' WHERE id='unit-07__lesson-02';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 79, "id": "unit-07__lesson-03__b01", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على حديث جبريل الذي يبين أصول الإسلام والإيمان.", "page": 79, "id": "unit-07__lesson-03__b02"}, {"type": "paragraph", "md": "معرفة بعض أقوال العلماء في شرح الحديث وأهميته.", "page": 79, "id": "unit-07__lesson-03__b03"}, {"type": "heading", "level": 3, "text": "نص حديث جبريل عليه الصلاة والسلام :", "page": 79, "id": "unit-07__lesson-03__b04", "role": "section"}, {"type": "paragraph", "md": "عن عمر بن الخطاب رضي الله عنه ، قال: (بينما نحن عند رسول الله صلى الله عليه وسلم ذات يوم إذ طَلَعَ علينا رجلٌ شديد بياض الثياب، شديد سواد الشعر، لا يُرى عليه أثرُ السفر ولا يعرفه منَّا أحدٌ، حتى جلس إلى النَّبيِّ صلى الله عليه وسلم ؛ فأسنَد ركبتيه إلى ركبتيه، ووضع كفَّيه على فخذيه، وقال: يا محمد أخبرني عن الإسلام؟ فقال رسول الله صلى الله عليه وسلم : الإسلامُ أن تشهدَ أن لا إله إلا الله وأنَّ محمدًا رسول الله صلى الله عليه وسلم ، وتقيم الصلاة، وتؤتي الزكاة، وتصوم رمضان، وتحج البيت إن استطعتَ إليه سبيلًا، قال: صدقتَ، قال: فعجبنا له يسأله ويصدِّقه، قال: فأخبرني عن الإيمان؟ قال: أن تؤمنَ بالله وملائكته وكُتبه ورسله واليوم الآخر، وتؤمن بالقدر خيره وشره، قال: صدقتَ، قال: فأخبرني عن الإحسان؟ قال: أن تعبدَ الله كأنَّك تراه، فإن لَم تكن تراه فإنَّه يراك، قال: فأخبرني عن الساعة؟ قال: ما المسئول عنها بأعلمَ من السائل، قال: فأخبرني عن أمَاراتِها؟ قال: أن تلدَ الأَمَةُ ربَّتَها، وأن ترى الحُفاةَ العُراة العالة رِعاء الشاءِ يتطاولون في البُنيان، قال: ثمَّ انطلق فلبثت مليًّا ثم قال لي: يا عمر أتدري مَن السائل؟ قلت: الله ورسوله أعلم، قال: فإنَّه جبريل أتاكم يعلِّمُكم دينَكم) [رواه البخاري من حديث أبي هريرة، ومسلم من حديث عمر واللفظ له].", "page": 79, "id": "unit-07__lesson-03__b05", "inline": [{"t": "text", "s": "عن عمر بن الخطاب "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ، قال: "}, {"t": "emphasis", "s": "(بينما نحن عند رسول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "ذات يوم إذ طَلَعَ علينا رجلٌ شديد بياض الثياب، شديد سواد الشعر، لا يُرى عليه أثرُ السفر ولا يعرفه منَّا أحدٌ، حتى جلس إلى النَّبيِّ", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "؛ فأسنَد ركبتيه إلى ركبتيه، ووضع كفَّيه على فخذيه، وقال: يا محمد أخبرني عن الإسلام؟ فقال رسول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": ": الإسلامُ أن تشهدَ أن لا إله إلا الله وأنَّ محمدًا رسول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، وتقيم الصلاة، وتؤتي الزكاة، وتصوم رمضان، وتحج البيت إن استطعتَ إليه سبيلًا، قال: صدقتَ، قال: فعجبنا له يسأله ويصدِّقه، قال: فأخبرني عن الإيمان؟ قال: أن تؤمنَ بالله وملائكته وكُتبه ورسله واليوم الآخر، وتؤمن بالقدر خيره وشره، قال: صدقتَ، قال: فأخبرني عن الإحسان؟ قال: أن تعبدَ الله كأنَّك تراه، فإن لَم تكن تراه فإنَّه يراك، قال: فأخبرني عن الساعة؟ قال: ما المسئول عنها بأعلمَ من السائل، قال: فأخبرني عن أمَاراتِها؟ قال: أن تلدَ الأَمَةُ ربَّتَها، وأن ترى الحُفاةَ العُراة العالة رِعاء الشاءِ يتطاولون في البُنيان، قال: ثمَّ انطلق فلبثت مليًّا ثم قال لي: يا عمر أتدري مَن السائل؟ قلت: الله ورسوله أعلم، قال: فإنَّه جبريل أتاكم يعلِّمُكم دينَكم) "}, {"t": "citation", "s": "[رواه البخاري من حديث أبي هريرة، ومسلم من حديث عمر واللفظ له]", "source": "البخاري ومسلم"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "بعض أقوال العلماء في هذا الحديث العظيم الملقبِ بـ«أُمِّ السنة»:", "page": 79, "id": "unit-07__lesson-03__b06", "role": "section"}, {"type": "paragraph", "md": "قال القاضي عياض: «وهذا الحديث قد اشتمل على شرح جميع وظائف العبادات الظاهرة والباطنة؛ من عقود الإيمان وأعمال الجوارح وإخلاص السرائر والتحفظ من آفات الأعمال، حتى إنَّ علومَ الشريعة كلَّها راجعةٌ إليه ومتشعِّبةٌ منه».", "page": 79, "id": "unit-07__lesson-03__b07", "inline": [{"t": "text", "s": "قال القاضي عياض: "}, {"t": "quote", "s": "وهذا الحديث قد اشتمل على شرح جميع وظائف العبادات الظاهرة والباطنة؛ من عقود الإيمان وأعمال الجوارح وإخلاص السرائر والتحفظ من آفات الأعمال، حتى إنَّ علومَ الشريعة كلَّها راجعةٌ إليه ومتشعِّبةٌ منه", "speaker": "القاضي عياض"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "قال النووي: «هذا الحديث يجمع أنواعًا من العلوم والمعارف والآداب واللطائف بل هو أصل الإسلام».", "page": 79, "id": "unit-07__lesson-03__b08", "inline": [{"t": "text", "s": "قال النووي: "}, {"t": "quote", "s": "هذا الحديث يجمع أنواعًا من العلوم والمعارف والآداب واللطائف بل هو أصل الإسلام", "speaker": "النووي"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "قال القرطبي: «هذا الحديث يصلح أن يُقال له أم السنَّة؛ لِمَا تضمَّنه من جُمل علم السنَّة».", "page": 79, "id": "unit-07__lesson-03__b09", "inline": [{"t": "text", "s": "قال القرطبي: "}, {"t": "quote", "s": "هذا الحديث يصلح أن يُقال له أم السنَّة؛ لِمَا تضمَّنه من جُمل علم السنَّة", "speaker": "القرطبي"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "قال ابن دقيق العيد: «هو كالأمِّ للسنَّة، كما سُمِّيت الفاتحة أم القرآن؛ لما تضمَّنته من جمعها معاني القرآن».", "page": 80, "id": "unit-07__lesson-03__b10", "inline": [{"t": "text", "s": "قال ابن دقيق العيد: "}, {"t": "quote", "s": "هو كالأمِّ للسنَّة، كما سُمِّيت الفاتحة أم القرآن؛ لما تضمَّنته من جمعها معاني القرآن", "speaker": "ابن دقيق العيد"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "قال ابن رجب: «حديث عظيم يشتمل على شرح الدِّين كلِّه، ففي آخره: (جبريل أتاكم يعلِّمكم دينكم)».", "page": 80, "id": "unit-07__lesson-03__b11", "inline": [{"t": "text", "s": "قال ابن رجب: "}, {"t": "quote", "s": "حديث عظيم يشتمل على شرح الدِّين كلِّه، ففي آخره: (جبريل أتاكم يعلِّمكم دينكم)", "speaker": "ابن رجب"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وقال الطيبي: «لهذه النكتة استفتح به البغوي كتابيه «المصابيح« و«شرح السنة» اقتداء بالقرآن في افتتاحه بالفاتحة، لأنها تضمنت علوم القرآن إجمالا».", "page": 80, "id": "unit-07__lesson-03__b12", "inline": [{"t": "text", "s": "وقال الطيبي: "}, {"t": "quote", "s": "لهذه النكتة استفتح به البغوي كتابيه «المصابيح« و«شرح السنة", "speaker": "الطيبي"}, {"t": "text", "s": " اقتداء بالقرآن في افتتاحه بالفاتحة، لأنها تضمنت علوم القرآن إجمالا»."}]}, {"type": "heading", "level": 3, "text": "آداب مستفادة من الحديث:", "page": 80, "id": "unit-07__lesson-03__b13", "role": "section"}, {"type": "paragraph", "md": "من هدي النبي صلى الله عليه وسلم مجالسة أصحابه، وهذا الهدي يدل على حسن خلق النبي صلى الله عليه وسلم .", "page": 80, "id": "unit-07__lesson-03__b14", "inline": [{"t": "text", "s": "من هدي النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " مجالسة أصحابه، وهذا الهدي يدل على حسن خلق النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "حسن أدب المتعلم أمام المعلم: حيث جلس جبريل عليه الصلاة والسلام أمام النبي صلى الله عليه وسلم هذه الجلسة الدالة على الأدب والإصغاء والاستعداد لما يلقى إليه، فأسند ركبتيه إلى ركبتيه ووضع كفيه على فخذيه.", "page": 80, "id": "unit-07__lesson-03__b15", "inline": [{"t": "text", "s": "حسن أدب المتعلم أمام المعلم: حيث جلس جبريل "}, {"t": "honorific", "s": "عليه الصلاة والسلام"}, {"t": "text", "s": " أمام النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " هذه الجلسة الدالة على الأدب والإصغاء والاستعداد لما يلقى إليه، فأسند ركبتيه إلى ركبتيه ووضع كفيه على فخذيه."}]}, {"type": "paragraph", "md": "جواز سؤال الإنسان عما يعلم من أجل تعليم من لا يعلم؛ لأن جبريل كان يعلم الجواب؛ لقوله في الحديث (صدقت)؛ فلا بأس بالسؤال أمام مَن لا يعلم تعليمًا له بصورة غير مباشرة.", "page": 80, "id": "unit-07__lesson-03__b16", "inline": [{"t": "text", "s": "جواز سؤال الإنسان عما يعلم من أجل تعليم من لا يعلم؛ لأن جبريل كان يعلم الجواب؛ لقوله في الحديث "}, {"t": "emphasis", "s": "(صدقت)", "role": "emphasis"}, {"t": "text", "s": "؛ فلا بأس بالسؤال أمام مَن لا يعلم تعليمًا له بصورة غير مباشرة."}]}, {"type": "paragraph", "md": "المتسبب في الفعل له حكم من باشر الفعل، إذا كانت المباشرة مبنية على السبب؛ لقول النبي صلى الله عليه وسلم : (هذا جبريل أتاكم يعلمكم دينكم)، مع أن المعلم هو الرسول عليه الصلاة والسلام ؛ لكن لمَّا كان جبريل هو السبب لسؤاله جعله الرسول عليه الصلاة والسلام هو المعلم.", "page": 80, "id": "unit-07__lesson-03__b17", "inline": [{"t": "text", "s": "المتسبب في الفعل له حكم من باشر الفعل، إذا كانت المباشرة مبنية على السبب؛ لقول النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(هذا جبريل أتاكم يعلمكم دينكم)", "role": "emphasis"}, {"t": "text", "s": "، مع أن المعلم هو الرسول "}, {"t": "honorific", "s": "عليه الصلاة والسلام"}, {"t": "text", "s": " ؛ لكن لمَّا كان جبريل هو السبب لسؤاله جعله الرسول "}, {"t": "honorific", "s": "عليه الصلاة والسلام"}, {"t": "text", "s": " هو المعلم."}]}, {"type": "paragraph", "md": "ولأهمية هذا الحديث ومركزيته في بيان الدين وحقيقته؛ سنتعرضُ لشرحه في الدروس القادمة حتى نفصلَ كل مسائله وأبوابه، فإذا وعاه المسلم وفهم معانيه صح اعتقاده إن شاء الله تعالى.", "page": 80, "id": "unit-07__lesson-03__b18"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة الإثرائية:", "page": 80, "id": "unit-07__lesson-03__b19", "role": "assessment"}, {"type": "paragraph", "md": "1- اذكر نص حديثِ جبريل في الإسلام والإيمان والإحسان.", "page": 80, "id": "unit-07__lesson-03__b20", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما أهمية هذا الحديث العظيم الذي مرَّ عليكَ في الدرس.", "page": 80, "id": "unit-07__lesson-03__b21", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- اذكر فائدتين جميلتين تسفيدهما من الكتاب المذكور.", "page": 80, "id": "unit-07__lesson-03__b22", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "نشاط سماعي وبحثي", "page": 80, "id": "unit-07__lesson-03__b23", "role": "activity"}, {"type": "paragraph", "md": "1- شرح الشيخ المحدث العلامة «عبد العزيز الطريفي» هذا الحديث العظيم في (4) دروس؛ استمعها وانشرها بين إخوانك وأهلك، ثم اذكر لنا أهم ما استفدتَه من هذه الدروس.", "page": 80, "id": "unit-07__lesson-03__b24", "inline": [{"t": "text", "s": "1- شرح الشيخ المحدث العلامة "}, {"t": "quote", "s": "عبد العزيز الطريفي"}, {"t": "text", "s": " هذا الحديث العظيم في (4) دروس؛ استمعها وانشرها بين إخوانك وأهلك، ثم اذكر لنا أهم ما استفدتَه من هذه الدروس."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2-هذا الحديث من أدلة «جوامع الكلم» التي اختص بها النبي صلى الله عليه وسلم ؛ فما معنى هذه الجملة؟ فسرها لنا في خمسة أسطر تكتبها عن مصطلح «جوامع الكلم» وتذكر له مثالين.", "page": 80, "id": "unit-07__lesson-03__b25", "inline": [{"t": "text", "s": "2-هذا الحديث من أدلة "}, {"t": "quote", "s": "جوامع الكلم"}, {"t": "text", "s": " التي اختص بها النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ؛ فما معنى هذه الجملة؟ فسرها لنا في خمسة أسطر تكتبها عن مصطلح "}, {"t": "hadith", "s": "جوامع الكلم", "narrator": null, "source": null, "confidence": "high", "ref_api": null}, {"t": "text", "s": " وتذكر له مثالين."}], "item_role": "activity_step"}]' WHERE id='unit-07__lesson-03';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 81, "id": "unit-07__lesson-04__b01", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على أحكام الوضوء ومعرفة فرائضه وسننه وصفته.", "page": 81, "id": "unit-07__lesson-04__b02"}, {"type": "paragraph", "md": "التمييز بين الفرض والسنة في الوضوء وأثر ذلك.", "page": 81, "id": "unit-07__lesson-04__b03"}, {"type": "paragraph", "md": "تعريف الوضوء: استعمال الماء في أعضاء مخصوصة مفتتحًا بنية.", "page": 81, "id": "unit-07__lesson-04__b04"}, {"type": "paragraph", "md": "أركانه سبعة -والركن هو: جزء الشيء الذي لا يتحقق بدونه، وهو جزء منه-.", "page": 81, "id": "unit-07__lesson-04__b05"}, {"type": "paragraph", "md": "دلَّ على هذه الأركان قوله تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ وَأَيْدِيَكُمْ إِلَى الْمَرَافِقِ وَامْسَحُوا بِرُءُوسِكُمْ وَأَرْجُلَكُمْ إِلَى الْكَعْبَيْنِ﴾، وهي سبعة أركان:", "page": 81, "id": "unit-07__lesson-04__b06", "inline": [{"t": "text", "s": "دلَّ على هذه الأركان قوله تعالى: "}, {"t": "ayah", "s": "يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ وَأَيْدِيَكُمْ إِلَى الْمَرَافِقِ وَامْسَحُوا بِرُءُوسِكُمْ وَأَرْجُلَكُمْ إِلَى الْكَعْبَيْنِ", "ayah": [], "verses": [{"n": 6, "text": "يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ وَأَيْدِيَكُمْ إِلَى الْمَرَافِقِ وَامْسَحُوا بِرُءُوسِكُمْ وَأَرْجُلَكُمْ إِلَى الْكَعْبَيْنِ", "surah": 5, "surah_name": "المائدة", "ref": "5:6", "ref_api": "https://api.quran.com/api/v4/verses/by_key/5:6"}], "surah": 5, "ref_api": "https://api.quran.com/api/v4/verses/by_key/5:6", "surah_name": "المائدة", "ayah_canonical": 6, "match": "contained", "ref": "5:6"}, {"t": "text", "s": "، وهي "}, {"t": "emphasis", "s": "سبعة أركان", "role": "emphasis"}, {"t": "text", "s": ":"}]}, {"type": "paragraph", "md": "النية: لأن الوضوء عبادة محضة فيفتقر إليها، ومحلها القلب، ونطقها باللسان لا وجهَ ولا دليل له.", "page": 81, "id": "unit-07__lesson-04__b07", "inline": [{"t": "emphasis", "s": "النية", "role": "emphasis"}, {"t": "text", "s": ": لأن الوضوء عبادة محضة فيفتقر إليها، ومحلها القلب، ونطقها باللسان لا وجهَ ولا دليل له."}]}, {"type": "paragraph", "md": "غسل الوجه: مأخوذ من المواجهة، وحَدُّهُ: من منابت شعر الرأس المعتاد إلى أسفل الذقن طولًا، ومن طرف الأُذُن إلى طرف الأُذُن الأخرى عرضًا. وليسَ عليه غسل الرقبة وما تحت الذقن.", "page": 81, "id": "unit-07__lesson-04__b08", "inline": [{"t": "emphasis", "s": "غسل الوجه", "role": "emphasis"}, {"t": "text", "s": ": مأخوذ من المواجهة، وحَدُّهُ: من منابت شعر الرأس المعتاد إلى أسفل الذقن طولًا، ومن طرف الأُذُن إلى طرف الأُذُن الأخرى عرضًا. وليسَ عليه غسل الرقبة وما تحت الذقن."}]}, {"type": "paragraph", "md": "غَسْلُ اليَدَيْنِ إلى المِرْفَقَيْنِ: والمِرْفَقُ من اليد، وتبدأ هذه الغسلة التي هي ركن من طرف الأصابع.", "page": 81, "id": "unit-07__lesson-04__b09", "inline": [{"t": "emphasis", "s": "غَسْلُ اليَدَيْنِ إلى المِرْفَقَيْنِ", "role": "emphasis"}, {"t": "text", "s": ": والمِرْفَقُ من اليد، وتبدأ هذه الغسلة التي هي ركن من طرف الأصابع."}]}, {"type": "paragraph", "md": "مَسْحُ الرأس: ومقدار الواجب بعضه، ولو مسحه كله فهو أحوط، ومسح الأذنين سنة لا فرض.", "page": 81, "id": "unit-07__lesson-04__b10", "inline": [{"t": "emphasis", "s": "مَسْحُ الرأس", "role": "emphasis"}, {"t": "text", "s": ": ومقدار الواجب بعضه، ولو مسحه كله فهو أحوط، ومسح الأذنين سنة لا فرض."}]}, {"type": "paragraph", "md": "غسل القدمين مع الكَعْبَيْن الناتئين عند مِفْصَل الساق والقدم، قال صلى الله عليه وسلم : (وَيْلٌ لِلأَعْقَابِ مِنَ النَّارِ).", "page": 81, "id": "unit-07__lesson-04__b11", "inline": [{"t": "emphasis", "s": "غسل القدمين مع الكَعْبَيْن", "role": "emphasis"}, {"t": "text", "s": " الناتئين عند مِفْصَل الساق والقدم، قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(وَيْلٌ لِلأَعْقَابِ مِنَ النَّارِ)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "الترتيب: بين أعضاء الوضوء، على الصفة المذكورة سابقًا؛ فلم ينقل عن النبي صلى الله عليه وسلم إلا مُرتبًا.", "page": 81, "id": "unit-07__lesson-04__b12", "inline": [{"t": "emphasis", "s": "الترتيب", "role": "emphasis"}, {"t": "text", "s": ": بين أعضاء الوضوء، على الصفة المذكورة سابقًا؛ فلم ينقل عن النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " إلا مُرتبًا."}]}, {"type": "paragraph", "md": "الموالاة -وهو مذهب الشافعي القديم-: فهي عمل الرسول صلى الله عليه وسلم في وضوئه طول عمره، ولم يؤثر عنه ما يدل على جواز التفريق بين أعضاء الوضوء؛ فمن غسل بعض أعضاء الوضوء بنية الوضوء، ثم انصرف إلى عمل آخر، ثم عاد ليتم ما بدأ به من غير ضرورة؛ فعمله مردود في ظاهر الأدلة، وقد أَمَرَ النبيُّ صلى الله عليه وسلم صاحب اللُمْعَةِ -التارك لموضع ظفر على قدمه- أنْ يُعيدَ وضوءَه وصلاتَه.", "page": 81, "id": "unit-07__lesson-04__b13", "inline": [{"t": "emphasis", "s": "الموالاة -وهو مذهب الشافعي القديم-", "role": "emphasis"}, {"t": "text", "s": ": فهي عمل الرسول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في وضوئه طول عمره، ولم يؤثر عنه ما يدل على جواز التفريق بين أعضاء الوضوء؛ فمن غسل بعض أعضاء الوضوء بنية الوضوء، ثم انصرف إلى عمل آخر، ثم عاد ليتم ما بدأ به من غير ضرورة؛ فعمله مردود في ظاهر الأدلة، وقد أَمَرَ النبيُّ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " صاحب اللُمْعَةِ -التارك لموضع ظفر على قدمه- أنْ يُعيدَ وضوءَه وصلاتَه."}]}, {"type": "heading", "level": 3, "text": "سُنَن الوضُوء:", "page": 81, "id": "unit-07__lesson-04__b14", "role": "section"}, {"type": "paragraph", "md": "التسمية: والتسمية سُنّةٌ على كل حال؛ فالوضوء كذلك، وتكون بدايته؛ فإن نَسِيَهَا سمَّى أثناءَ الوضوء.", "page": 81, "id": "unit-07__lesson-04__b15", "inline": [{"t": "emphasis", "s": "التسمية", "role": "emphasis"}, {"t": "text", "s": ": و"}, {"t": "emphasis", "s": "التسمية", "role": "emphasis"}, {"t": "text", "s": " سُنّةٌ على كل حال؛ فالوضوء كذلك، وتكون بدايته؛ فإن نَسِيَهَا سمَّى أثناءَ الوضوء."}]}, {"type": "paragraph", "md": "غَسْلُ الكَفَّيْن ثلاثًا: قبل إدخالهما الإناء، وذلك لأن المرء لا يدري أين باتت يده في طُهر أم نجس.", "page": 81, "id": "unit-07__lesson-04__b16", "inline": [{"t": "emphasis", "s": "غَسْلُ الكَفَّيْن ثلاثًا", "role": "emphasis"}, {"t": "text", "s": ": قبل إدخالهما الإناء، وذلك لأن المرء لا يدري أين باتت يده في طُهر أم نجس."}]}, {"type": "paragraph", "md": "المضمضة والاستنشاق ثلاثًا: والمبالغة في ذلك إلا أن تكون صائمًا، والجمع بينهما بغَرفَةٍ واحدةٍ سُنَّة. والاستنثار يكون بالشمال -وهو إخراج الماء من الأنف-، وأخذُ الماء لكليهما باليمين.", "page": 82, "id": "unit-07__lesson-04__b17"}, {"type": "paragraph", "md": "السواك: قبل الوضوء أو قبل غسل الفم أثناء الوضوء.", "page": 82, "id": "unit-07__lesson-04__b18"}, {"type": "paragraph", "md": "المثالثة والميامنة: فيُسَنُّ غسل الوجه ثلاثًا، واليدين والرجلين ثلاثًا لكل منهما، بادئًا باليد والرجل اليمنى، ويُكره الزيادة على ثلاث، وأما الرأس فيمسحه مرة واحدة فقط.", "page": 82, "id": "unit-07__lesson-04__b19"}, {"type": "paragraph", "md": "ويُسَنُّ غسل ما استرسل من اللحية وما نزل منها، مع تخليلها، وأما غسل الذقن وأصل اللحية فرُكن.", "page": 82, "id": "unit-07__lesson-04__b20"}, {"type": "paragraph", "md": "ويُسَنُّ مَسْحُه الرأس كاملًا؛ فيبدأ من المُقدَّم للمؤخِّر ثم يعيد من مؤخِّر الرأس إلى مُقَدَّمهِ بنفس الماء.", "page": 82, "id": "unit-07__lesson-04__b21"}, {"type": "paragraph", "md": "مَسْحُ الأُذُنَيْن: فيمسح باطنهما بالسبابتين، وظاهرهما بالإبهامين، ويدخل الأصبعين في صماخهما.", "page": 82, "id": "unit-07__lesson-04__b22"}, {"type": "paragraph", "md": "الدعاء بعد الوضوء: (أشهد أن لا إله إلا الله، وأشهد أن محمدًا عبده ورسوله، اللهم اجعلني من التوابين واجعلني من المتطهرين، سُبْحَانَكَ اللَّهمَّ وَبِحَمْدِكَ أَشْهَدَ أَنْ لَا إِلَهَ إلَّا أَنْتَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ).", "page": 82, "id": "unit-07__lesson-04__b23", "inline": [{"t": "text", "s": "الدعاء بعد الوضوء: "}, {"t": "emphasis", "s": "(أشهد أن لا إله إلا الله، وأشهد أن محمدًا عبده ورسوله، اللهم اجعلني من التوابين واجعلني من المتطهرين، سُبْحَانَكَ اللَّهمَّ وَبِحَمْدِكَ أَشْهَدَ أَنْ لَا إِلَهَ إلَّا أَنْتَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ).", "role": "emphasis"}]}, {"type": "paragraph", "md": "صلاة ركعتين بعد الوضوء، فقد قال صلى الله عليه وسلم كما في حديث عثمان: (مَن تَوَضَّأَ نَحْوَ وُضُوئِي هذا، ثُمَّ صَلَّى رَكْعَتَيْنِ لا يُحَدِّثُ فِيهِما نَفْسَهُ، غَفَرَ اللَّهُ له ما تَقَدَّمَ مِن ذَنْبِهِ).", "page": 82, "id": "unit-07__lesson-04__b24", "inline": [{"t": "text", "s": "صلاة ركعتين بعد الوضوء، فقد قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " كما في حديث عثمان: "}, {"t": "emphasis", "s": "(مَن تَوَضَّأَ نَحْوَ وُضُوئِي هذا، ثُمَّ صَلَّى رَكْعَتَيْنِ لا يُحَدِّثُ فِيهِما نَفْسَهُ، غَفَرَ اللَّهُ له ما تَقَدَّمَ مِن ذَنْبِهِ).", "role": "emphasis"}]}, {"type": "paragraph", "md": "صفة الوضوء الكامل: أن ينوي المتوضئ بقلبه رفع الحدث، ويسميَ الله تعالى، ويفرغ الماء على كفيه ثلاثًا، ويتمضمض ويستنشق ويستنثر ثلاثًا، ويغسل وجهه ثلاثًا، ويغسل يديه إلى المرفقين ثلاثًا بادئًا باليُمنى، ويمسح برأسه مرة واحدة يبدأ بمقدم رأسه، ثم يذهب بيديه إلى قفاه، يقبل بهما ويدبر، ويمسح أذنيه ثلاثا، ثم يغسل رجليه إلى ما فوق الكعبين ثلاثا بادئًا باليمنى مع الدلك، وندعو آخره.", "page": 82, "id": "unit-07__lesson-04__b25"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 82, "id": "unit-07__lesson-04__b26", "role": "assessment"}, {"type": "paragraph", "md": "للوضوء سبعة أركان: اذكرها مع بيان معنى الركن والفرق بينه وبين السنة.", "page": 82, "id": "unit-07__lesson-04__b27", "item_role": "question"}, {"type": "paragraph", "md": "عدد خمسة سنن من سنن الوضوء العشرة المذكورة في الدرس.", "page": 82, "id": "unit-07__lesson-04__b28", "item_role": "question"}, {"type": "paragraph", "md": "اشرح لنا صفة الوضوء الكاملة نظريًّا.", "page": 82, "id": "unit-07__lesson-04__b29", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط تطبيقي ودعوي", "page": 82, "id": "unit-07__lesson-04__b30", "role": "activity"}, {"type": "paragraph", "md": "1- نذهب إلى المتوضأ ونقوم بتطبيق الوضوء عمليا، كل واحد منا عى انفراده، حتى إتقانه تمامًا.", "page": 82, "id": "unit-07__lesson-04__b31", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- يطبق كل منا ما تعمله على أسرته وأصحابه، ويتحين فرصة مناسبة ليتوضأ أمامهم فيتعلموا منه.", "page": 82, "id": "unit-07__lesson-04__b32", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-07__lesson-04';
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 83, "id": "unit-07__lesson-05__b01", "role": "objectives"}, {"type": "paragraph", "md": "أن يتعرف على معنى الثقة بالله في ظل واقع ضعف المسلمين.", "page": 83, "id": "unit-07__lesson-05__b02"}, {"type": "paragraph", "md": "أن يتمثل هذا الخلق في حياته ويتحلى به في كل أوقاته مهما اشتدت الكروب والخطوب.", "page": 83, "id": "unit-07__lesson-05__b03"}, {"type": "heading", "level": 3, "text": "لماذا نثق بنصرةِ هذا الدين؟!", "page": 83, "id": "unit-07__lesson-05__b04", "role": "section"}, {"type": "paragraph", "md": "تظهر حقيقة اليقين بالله في مراحل الضعف؛ إذ ليس صاحب اليقين من يتهلل وجهه حين يرى قوة الإسلام وبشائر نصره، وإنما المستيقن هو صاحب الثقة بالله إذا اشتد الضيق والكرب، وتكالبت الأمم، والمسلم الذي يسعى لإقامة دين الله في الأرض؛ زاده في الطريق: الصبر واليقين، قال ابن القيم: «سمعت شيخ الإسلام ابن تيمية يقول: بالصبر واليقين تُنال الإمامة في الدين».", "page": 83, "id": "unit-07__lesson-05__b05", "inline": [{"t": "text", "s": "تظهر حقيقة اليقين بالله في مراحل الضعف؛ إذ ليس صاحب اليقين من يتهلل وجهه حين يرى قوة الإسلام وبشائر نصره، وإنما المستيقن هو صاحب الثقة بالله إذا اشتد الضيق والكرب، وتكالبت الأمم، والمسلم الذي يسعى لإقامة دين الله في الأرض؛ زاده في الطريق: الصبر واليقين، قال ابن القيم: "}, {"t": "quote", "s": "سمعت شيخ الإسلام ابن تيمية يقول: بالصبر واليقين تُنال الإمامة في الدين", "speaker": "ابن القيم"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ولا تهلِكُ هذه الأمة إلا حين يبخَل أبناؤها بتقديم الجهود المتاحة لنصرتها، ثم يتجرَّعون كؤوس الأمل بلا عمل؛ لذلك قال صلى الله عليه وسلم : (صلاح أول هذه الأمة بالزهد واليقين، ويهلِك آخرها بالبخل والأمل).", "page": 83, "id": "unit-07__lesson-05__b06", "inline": [{"t": "text", "s": "ولا تهلِكُ هذه الأمة إلا حين يبخَل أبناؤها بتقديم الجهود المتاحة لنصرتها، ثم يتجرَّعون كؤوس الأمل بلا عمل؛ لذلك قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(صلاح أول هذه الأمة بالزهد واليقين، ويهلِك آخرها بالبخل والأمل)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ولأن الله وحده عالم الغيب فلا ندري متى النصر، ويكفينا أن نعلم أنَّ أمتنا أمة منصورة من الله -ولو بعد حين- قال صلى الله عليه وسلم : (مَثَل أمتي مَثَل المطر، لا يُدرَى أوله خير أم آخره)، وقال: (لا يزال الله يغرِسُ في هذا الدين غرسًا يستعملهم فيه بطاعته إلى يوم القيامة) فواجبنا غرس بذور النصر وعلى الله إنباتُها؛ فالأصل في الإسلام العلوُّ والسيادة والتمكين، فلا نستيئس من ضعف المسلمين زمنًا ما؛ قال النبي صلى الله عليه وسلم : (الإسلام يعلو ولا يُعلى)، وقال: (بشَّر هذه الأمة بالسناء والدين والرفعة والنصر والتمكن في الأرض..).", "page": 83, "id": "unit-07__lesson-05__b07", "inline": [{"t": "text", "s": "ولأن الله وحده عالم الغيب فلا ندري متى النصر، ويكفينا أن نعلم أنَّ أمتنا أمة منصورة من الله -ولو بعد حين- قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(مَثَل أمتي مَثَل المطر، لا يُدرَى أوله خير أم آخره)", "role": "emphasis"}, {"t": "text", "s": "، وقال: "}, {"t": "emphasis", "s": "(لا يزال الله يغرِسُ في هذا الدين غرسًا يستعملهم فيه بطاعته إلى يوم القيامة)", "role": "emphasis"}, {"t": "text", "s": " فواجبنا غرس بذور النصر وعلى الله إنباتُها؛ فالأصل في الإسلام العلوُّ والسيادة والتمكين، فلا نستيئس من ضعف المسلمين زمنًا ما؛ قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(الإسلام يعلو ولا يُعلى)", "role": "emphasis"}, {"t": "text", "s": "، وقال: "}, {"t": "emphasis", "s": "(بشَّر هذه الأمة بالسناء والدين والرفعة والنصر والتمكن في الأرض..)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ونحن اليوم قد نرى القوةَ بيد أعدائنا، والغلبة لهم علينا، ولكن لا ننسى أن الله هو المتصرِّف بهذا الكون، وعينُه لا تغفُلُ عن عبادة المؤمنين، ولن يرضى لهم دوام الذلة واستمرار القهر، كما قال رسول الله صلى الله عليه وسلم : (الميزان بيد الرحمن، يرفع أقوامًا، ويضع آخرين)، ولابد أن يرفعَنا بعد أن وضعنا؛ بشرطٍ مهم وهو أن يرى منا صدقَ السعي لمرضاته ونصرة دينه.", "page": 83, "id": "unit-07__lesson-05__b08", "inline": [{"t": "text", "s": "ونحن اليوم قد نرى القوةَ بيد أعدائنا، والغلبة لهم علينا، ولكن لا ننسى أن الله هو المتصرِّف بهذا الكون، وعينُه لا تغفُلُ عن عبادة المؤمنين، ولن يرضى لهم دوام الذلة واستمرار القهر، كما قال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(الميزان بيد الرحمن، يرفع أقوامًا، ويضع آخرين)", "role": "emphasis"}, {"t": "text", "s": "، ولابد أن يرفعَنا بعد أن وضعنا؛ بشرطٍ مهم وهو أن يرى منا صدقَ السعي لمرضاته ونصرة دينه."}]}, {"type": "paragraph", "md": "فلنتواصَ بالصبر على البلاء، والثبات إذا وقع القضاء، ولنكن بشيرَ خيرٍ، ولا نكوننَّ نذير شر، ولنقُلْ للمتشائمين بعد طول انتظار كما قال النبي صلى الله عليه وسلم لأصحابه حينما اشتكوا من كثرة البلاء وشدته: (واللهِ ليُتِمَّن الله هذا الأمر.. ولكنكم تستعجلون).", "page": 84, "id": "unit-07__lesson-05__b09", "inline": [{"t": "text", "s": "فلنتواصَ بالصبر على البلاء، والثبات إذا وقع القضاء، ولنكن بشيرَ خيرٍ، ولا نكوننَّ نذير شر، ولنقُلْ للمتشائمين بعد طول انتظار كما قال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لأصحابه حينما اشتكوا من كثرة البلاء وشدته: "}, {"t": "emphasis", "s": "(واللهِ ليُتِمَّن الله هذا الأمر.. ولكنكم تستعجلون)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "إن عقيدة الإيمان بالقدر أهم مصادر الثقة بأن العاقبة للمتقين، ولذلك قال صلى الله عليه وسلم : (إن لكل شيء حقيقة، وما بلغ عبد حقيقة الإيمان، حتى يعلم أن ما أصابه لم يكن ليخطئَه، وما أخطأه لم يكن ليصيبه).", "page": 84, "id": "unit-07__lesson-05__b10", "inline": [{"t": "text", "s": "إن عقيدة الإيمان بالقدر أهم مصادر الثقة بأن العاقبة للمتقين، ولذلك قال "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إن لكل شيء حقيقة، وما بلغ عبد حقيقة الإيمان، حتى يعلم أن ما أصابه لم يكن ليخطئَه، وما أخطأه لم يكن ليصيبه)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ولِمَا يخشاه الشهداء على مَن بعدهم من الأحياء من ضعفِ الثقة المُفضِي إلى الزهد بالجهاد، أو اليأس من ثماره، أو الخوف من القتل؛ جاء في الصحيح أنهم يقولون لربهم سبحانه وتعالى : (مَن يبلِّغ إخواننا عنَّا أنَّا أحياء في الجنة نُرزق؛ لئلا يزهدوا في الجهاد، ولا ينكلوا عند الحرب، فقال الله سبحانه: أنا أبلغهم عنكم..).", "page": 84, "id": "unit-07__lesson-05__b11", "inline": [{"t": "text", "s": "ولِمَا يخشاه الشهداء على مَن بعدهم من الأحياء من ضعفِ الثقة المُفضِي إلى الزهد بالجهاد، أو اليأس من ثماره، أو الخوف من القتل؛ جاء في الصحيح أنهم يقولون لربهم "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(مَن يبلِّغ إخواننا عنَّا أنَّا أحياء في الجنة نُرزق؛ لئلا يزهدوا في الجهاد، ولا ينكلوا عند الحرب، فقال الله سبحانه: أنا أبلغهم عنكم..)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "‌‌من فوائد اليقين بالله وثماره:", "page": 84, "id": "unit-07__lesson-05__b12", "role": "benefits"}, {"type": "paragraph", "md": "- صاحب اليقين واثق بالله مهما ضاقت عليه الدنيا؛ فبالصبر واليقين تُنال الإمامة في الدين.", "page": 84, "id": "unit-07__lesson-05__b13", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- اليقين خير ما يُؤتاه المرء، وبه صلَحت الأمة.", "page": 84, "id": "unit-07__lesson-05__b14", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- لا يزال الله يغرِسُ لهذا الدين، والخير آتٍ بإذن الله، ولكن الله هو الذي يحدِّد ميقاته.", "page": 84, "id": "unit-07__lesson-05__b15", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- النصر آتٍ ولكن الناس يستعجلون، أو يشكون ويضعف إيمانهم بالقدر.", "page": 84, "id": "unit-07__lesson-05__b16", "list": {"type": "unordered"}}, {"type": "paragraph", "md": "- لا حرج في قلة الأتباع على الحق، ولكن الحرج في التقصير في الأخذ بالأسباب.", "page": 84, "id": "unit-07__lesson-05__b17", "list": {"type": "unordered"}}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 84, "id": "unit-07__lesson-05__b18", "role": "assessment"}, {"type": "paragraph", "md": "1- كيف نثق بالله في ظل واقع المسلمين الحالي؟", "page": 84, "id": "unit-07__lesson-05__b19", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- وما الأسباب الداعية لهذه الثقة بنصر الدين؟", "page": 84, "id": "unit-07__lesson-05__b20", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- اذكر ثلاثة فوائد نستفيدها من التخلق بخلق الثقة بنصرِ الله.", "page": 84, "id": "unit-07__lesson-05__b21", "item_role": "question", "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "نشاط إعلامي وبحثي", "page": 84, "id": "unit-07__lesson-05__b22", "role": "activity"}, {"type": "paragraph", "md": "1- نتدارسُ سويةً بعض أحوال المسلمين المعاصرة التي كانت غاية في الضعف ثم نصرها الله وننشرها على صفحاتنا في وسائل التواصل الاجتماعي، لبثِّ اليقين بنصر الدين بين عموم المسلمين", "page": 84, "id": "unit-07__lesson-05__b23", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- اقرأ وشارك معنا تفسير آية: ﴿أَمۡ حَسِبۡتُمۡ أَن تَدۡخُلُواْ ٱلۡجَنَّةَ وَلَمَّا يَأۡتِكُم مَّثَلُ ٱلَّذِينَ خَلَوۡاْ مِن قَبۡلِكُمۖ مَّسَّتۡهُمُ ٱلۡبَأۡسَآءُ وَٱلضَّرَّآءُ وَزُلۡزِلُواْ حَتَّىٰ يَقُولَ ٱلرَّسُولُ وَٱلَّذِينَ ءَامَنُواْ مَعَهُۥ مَتَىٰ نَصۡرُ ٱللَّهِۗ أَلَآ إِنَّ نَصۡرَ ٱللَّهِ قَرِيبٞ ۝٢١٤﴾", "page": 84, "id": "unit-07__lesson-05__b24", "inline": [{"t": "text", "s": "2- اقرأ وشارك معنا تفسير آية: "}, {"t": "ayah", "s": "أَمۡ حَسِبۡتُمۡ أَن تَدۡخُلُواْ ٱلۡجَنَّةَ وَلَمَّا يَأۡتِكُم مَّثَلُ ٱلَّذِينَ خَلَوۡاْ مِن قَبۡلِكُمۖ مَّسَّتۡهُمُ ٱلۡبَأۡسَآءُ وَٱلضَّرَّآءُ وَزُلۡزِلُواْ حَتَّىٰ يَقُولَ ٱلرَّسُولُ وَٱلَّذِينَ ءَامَنُواْ مَعَهُۥ مَتَىٰ نَصۡرُ ٱللَّهِۗ أَلَآ إِنَّ نَصۡرَ ٱللَّهِ قَرِيبٞ ۝٢١٤", "ayah": [214], "verses": [{"n": 214, "text": "أَمۡ حَسِبۡتُمۡ أَن تَدۡخُلُواْ ٱلۡجَنَّةَ وَلَمَّا يَأۡتِكُم مَّثَلُ ٱلَّذِينَ خَلَوۡاْ مِن قَبۡلِكُمۖ مَّسَّتۡهُمُ ٱلۡبَأۡسَآءُ وَٱلضَّرَّآءُ وَزُلۡزِلُواْ حَتَّىٰ يَقُولَ ٱلرَّسُولُ وَٱلَّذِينَ ءَامَنُواْ مَعَهُۥ مَتَىٰ نَصۡرُ ٱللَّهِۗ أَلَآ إِنَّ نَصۡرَ ٱللَّهِ قَرِيبٞ", "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:214", "surah_name": "البقرة", "ayah_canonical": 214, "match": "exact", "ref": "2:214"}], "surah": null, "ref_api": null}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-07__lesson-05';
